-- Poems batch 291
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5d956bd2-2230-4635-9ca8-db1c3669cc79','蒼筤源','劉敞','宋','宋诗','song-poetry','','[]','日出江氣暖，步行村落間。',96,'全唐诗/poet.song.27000.json','["日出江氣暖，步行村落間。", "偶逢蒼筤息，若在山中閒。", "綠篠既蒙密，清波自回環。", "初疑人迹絕，久有笑語諠。", "脱足涉澗水，隔林叩柴關。", "主人疏世事，相見亦歡然。", "稍覺耳目曠，久之遂忘還。", "歸來詫舟子，適過武陵源。"]'),
('6286ae98-cafb-4a01-aa7a-4f0ebee443f1','樂郊陳漁臺下柏林中結茅作小亭命曰幽素本懿臣刑部之書也謝且戱之','劉敞','宋','宋诗','song-poetry','','[]','結茅更何好，列柏自成林。',60,'全唐诗/poet.song.27000.json','["結茅更何好，列柏自成林。", "素履宜獨往，幽人欣宿心。", "炎輝翳羽蓋，清吹和瑤琴。", "稍與事物遠，忽如丘壑深。", "良無山水趣，安得契知音。"]'),
('c82c248f-2f10-4184-8b1f-ca5880566d11','種蔬二首  其一','劉敞','宋','宋诗','song-poetry','','[]','時雨破膏壤，荷鋤回城陰。',120,'全唐诗/poet.song.27000.json','["時雨破膏壤，荷鋤回城陰。", "疾耕意不足，覆隴力可任。", "里巷多父兄，往來迹相尋。", "見我山野服，欣然用盡簪。", "勸我勿滅裂，哀我識浮沈。", "雖微生平故，頗用愧其心。", "採芝商於嶺，食薇首陽岑。", "念我非其人，豈敢慕山林。", "聊以資素飽，身世實崎嶔。", "丈人不我厭，荷蓧時見臨。"]'),
('3ae11af0-e7d9-4ce9-9ecc-40fa0fdda674','種蔬二首  其二','劉敞','宋','宋诗','song-poetry','','[]','種蔬南岡下，地薄旱亦久。',120,'全唐诗/poet.song.27000.json','["種蔬南岡下，地薄旱亦久。", "抱甕出復入，拮据病两手。", "輟耕起長歎，四海萬億畝。", "過亢今若兹，我誰與餬口。", "縣官祈雨澤，四望已並走。", "巫女歌且舞，土龍矯其首。", "上天何寥寥，百請未一偶。", "霖雨待爾輩，古人亦可醜。", "咄嗟雲漢詩，萬古竟何有。", "天地何不仁，百姓爲芻狗。"]'),
('8843b50d-ac1c-4857-813c-08f181ad4307','重陽','劉敞','宋','宋诗','song-poetry','','[]','勞生惜流陰，徂歲逼窮律。',84,'全唐诗/poet.song.27000.json','["勞生惜流陰，徂歲逼窮律。", "燦燦黄菊花，離離紫茱實。", "芳香不可再，採掇自有術。", "零落勢足悲，盛時亦未失。", "登高散百慮，驅馬恣所出。", "或云避陽九，可以納元吉。", "嘉願誰間然，且當醉終日。"]'),
('2178753c-5179-4a89-9449-a9749814e504','浚井','劉敞','宋','宋诗','song-poetry','','[]','鑿井勿憚深，汲繩欲令長。',72,'全唐诗/poet.song.27000.json','["鑿井勿憚深，汲繩欲令長。", "鑿深源不竭，汲遠氣自涼。", "豈如潢汙水，汩汩道路旁。", "雖復不遠求，飲之劇燖湯。", "虚煩生四支，淟涊不自强。", "野語合爲國，願君著巖廊。"]'),
('15f2ada5-afd3-4c8b-8872-87af301ce236','古寺','劉敞','宋','宋诗','song-poetry','','[]','唐殿弛棟梁，空庭長荆棘。',96,'全唐诗/poet.song.27000.json','["唐殿弛棟梁，空庭長荆棘。", "坳堂客水腥，壞碣苔蘚積。", "經營東晋始，遠近千歲逼。", "興廢紛可悲，徘徊意不懌。", "尚餘土木巧，未露斤斧迹。", "使鬼固已勞，斯民忍終役。", "悠悠競頽波，擾擾非一國。", "臺城更荒唐，萬古共悽惻。"]'),
('3e3f59da-04aa-4d80-acbf-8f9d4042575f','書候潮亭','劉敞','宋','宋诗','song-poetry','','[]','滄江浸長空，天使限南北。',144,'全唐诗/poet.song.27000.json','["滄江浸長空，天使限南北。", "繁陰屬暮歲，波浪無時息。", "烈風何轟豗，深木騰霹靂。", "遠吹湖中白，來蔽江南碧。", "巉巖千峰玉，變化不可測。", "恐是時向晚，鬼神任胸臆。", "燭龍銜長耀，來集崑嶺側。", "又疑吳王兵，如荼壓上國。", "勇氣吞中原，晶光洞江北。", "久望生悸慄，嗟我問津客。", "横流豈難制，路險未可得。", "吾道固當然，滔滔欲誰易。"]'),
('56d27fc1-477a-48c8-9d0d-57700026df00','徐安撫','劉敞','宋','宋诗','song-poetry','','[]','伏波喜功名，南伐終不返。',84,'全唐诗/poet.song.27000.json','["伏波喜功名，南伐終不返。", "死餘薏苡謗，生恨鷦鳥晚。", "干戈非一方，智勇易謀顯。", "富貴誰不然，枯榮子何反。", "冥冥炎州隔，杳杳天道遠。", "荆楚猶古風，招魂動哀挽。", "從人除憂謗，不得志者罕。"]'),
('a15575e2-0cc2-41d8-bac6-36622b0139d6','石首縣','劉敞','宋','宋诗','song-poetry','','[]','叢石浮水中，峻隄缺復連。',144,'全唐诗/poet.song.27000.json','["叢石浮水中，峻隄缺復連。", "往往爲深潭，波流自回環。", "秋山未搖落，碧樹皆參天。", "仰觀積水痕，仍在高樹巔。", "里人半巢居，出入隨烏鳶。", "令尹亦菜色，市樓寂無烟。", "皇天不純命，百姓何震愆。", "苦云耕織廢，租税尚未蠲。", "赤子向漂蕩，所存皆偶然。", "雖知負官輸，未忍更棄捐。", "奈何唐堯世，復見昏墊年。", "何以救汝饑，朝廷急憂邊。"]'),
('a4164b10-bc62-4e09-9226-9a50966d0fe8','召諸弟博飲','劉敞','宋','宋诗','song-poetry','','[]','今日寒頗甚，淮南似京土。',96,'全唐诗/poet.song.27000.json','["今日寒頗甚，淮南似京土。", "江風既落木，山雪亦带雨。", "幽居自無聊，病卧亦寡侣。", "壯心顧牢落，出門孔多阻。", "古人戯梟盧，志氣本尚武。", "勝來在快意，百萬不足數。", "恨無酒如澠，杯盂空屢舉。", "開顔强隱几，豈必歎貧窶。"]'),
('b84cd391-b62e-4aa4-85c9-fcd7d323d550','别和弟','劉敞','宋','宋诗','song-poetry','','[]','暫會復遠别，惆悵終無極。',120,'全唐诗/poet.song.27000.json','["暫會復遠别，惆悵終無極。", "人生非神仙，豈有頭不白。", "維舟相邀宿，淮水風浪黑。", "輾轉不復眠，四聽人盡息。", "丈夫非懷安，少壯宜努力。", "況子行多歡，自怪情不懌。", "誰言冬宵永，達旦才頃刻。", "雞鳴日光出，握手各南北。", "仰謝雲中鴈，羣飛接羽翼。", "何以紓我懷，作詩寄相憶。"]'),
('16ac2afe-f814-4238-b3ce-f6fa85a4f45d','舟中夜飲憶和弟聯句','劉敞','宋','宋诗','song-poetry','','[]','人生如浮雲，聚散苦不定。',120,'全唐诗/poet.song.27000.json','["人生如浮雲，聚散苦不定。", "向來詩酒歡，雖唱誰與應。", "蟋蟀鳴在戶，玉衡逼冬孟。", "悠悠千里思，寂寂中夜静。", "豈曰無他人，不如我同姓。", "吁嗟繋名利，有若置機阱。", "窘然塵埃中，恥無六翮勁。", "訪戴舟已慚，攀嵇駕難命。", "臨觴置不飲，引領起獨詠。", "莽莽天地昏，誰知我心怲。"]'),
('2d14e79c-f735-45b3-85fb-6ea3e24f803e','蘇安上之淮南十八舍弟之河北十九舍弟之漢中皆會予賦三韻爲送','劉敞','宋','宋诗','song-poetry','','[]','攜手常苦難，傾蓋不易得。',36,'全唐诗/poet.song.27000.json','["攜手常苦難，傾蓋不易得。", "今宵四面坐，明日異鄉客。", "秋風楚懷悲，出處各努力。"]'),
('52dff823-84d8-4041-b38c-3ff882641eb9','鳳凰篇贈府公給事别','劉敞','宋','宋诗','song-poetry','','["\u8861\u5c71"]','鳯凰起北海，少留南嶽巔。',96,'全唐诗/poet.song.27000.json','["鳯凰起北海，少留南嶽巔。", "梧桐有餘音，烏鵲相回旋。", "耳聞和聲樂，目怪文采鮮。", "雖知非儔匹，慕用亦欣然。", "祥飇卷層雲，迅羽凌九天。", "卑飛忽如縶，絕迹不可攀。", "徘徊故林下，歎息高風前。", "願及夔作韶，率舞如舜年。"]'),
('60ace47e-f612-449a-a0b9-a946827fc8f2','深甫往固陵','劉敞','宋','宋诗','song-poetry','','[]','聞君異鄉客，歲暮江淮間。',72,'全唐诗/poet.song.27000.json','["聞君異鄉客，歲暮江淮間。", "山雪夜多興，桂枝春可攀。", "南風玩啙窳，浮俗矜游閒。", "安所彈長鋏，何當問刀環。", "天倫眉最白，子舍衣仍斑。", "勿學髠接輿，佯狂因不還。"]'),
('4362f0c0-589c-46cc-9755-98809e88e090','飲郇公園贈章湖州何漢州','劉敞','宋','宋诗','song-poetry','','[]','朝暉散浮陰，天氣清且佳。',168,'全唐诗/poet.song.27000.json','["朝暉散浮陰，天氣清且佳。", "春城足行樂，況此公侯家。", "珍館深窈窕，茂林揚芬葩。", "幽禽囀新聲，宿草含芳芽。", "覽物曲池平，置酒白日斜。", "因歌雍門詩，四座皆歎嗟。", "平生布衣願，不過東陵瓜。", "致求多嬴餘，竟是迷紛華。", "一醉稱日富，此風獨可嘉。", "安能拘浮俗，局若井底蛙。", "客有章與何，高冠耀文緺。", "方爲二千石，會促别且賒。", "他日還相思，當在天一涯。", "歡極情難忘，願君盡流霞。"]'),
('6f95f522-7eea-4191-af4b-00cb15e84923','雪後到薦福寺梅下','劉敞','宋','宋诗','song-poetry','','[]','行尋殘雪遠，暖就梅陰坐。',48,'全唐诗/poet.song.27000.json','["行尋殘雪遠，暖就梅陰坐。", "悟彼寒氣消，識此春景破。", "留僧迨日暮，聽鳥忘巾墮。", "從此到芬芳，應須數來過。"]'),
('52d01853-25aa-4b8b-9525-383a46cdc694','呈獻臣','劉敞','宋','宋诗','song-poetry','','[]','兹心厭囂冗，幸與上清鄰。',84,'全唐诗/poet.song.27000.json','["兹心厭囂冗，幸與上清鄰。", "上清何崔嵬，高静違飆塵。", "珍林散玲瓏，寶氣浮氤氳。", "綠華未及衰，絳蘂忽復新。", "閒館賓列仙，秘殿朝衆真。", "濃香無停期，豔彩驚幽人。", "顧謝武陵子，四時長見春。"]'),
('4720d232-d154-4dee-9db7-b0c8a335c94e','寄吳江大博徐君章','劉敞','宋','宋诗','song-poetry','','[]','吏退簿書斂，日落風景涼。',96,'全唐诗/poet.song.27000.json','["吏退簿書斂，日落風景涼。", "偶無事物累，真得逍遙鄉。", "疏花媚空園，脩竹蔭廣坐。", "濁酒不難醉，磐石可徑卧。", "何必凌江漢，乃能濯埃塵。", "何必潛山林，乃能寄隱淪。", "人多笑此言，此言未易笑。", "非君契心賞，誰肯過蓬藋。"]'),
('c34a4be5-d7c3-4c93-ae91-112f5d501726','觀魚臺','劉敞','宋','宋诗','song-poetry','','[]','城下春池深，潛魚時復躍。',48,'全唐诗/poet.song.27000.json','["城下春池深，潛魚時復躍。", "高臺可以望，暇日從爾樂。", "散懷混飛沈，適意宜丘壑。", "始悟濠梁翁，荒唐謝名爵。"]'),
('6f5dcfaf-c28b-4581-a4a0-5c1e9d05d948','府公射堂飲酒輒陪尊丈侍郎兼揖諸孫拜獻拙詩','劉敞','宋','宋诗','song-poetry','','[]','煌煌南極星，粲粲北維斗。',132,'全唐诗/poet.song.27000.json','["煌煌南極星，粲粲北維斗。", "稟齡瑞明時，運柄燮萬有。", "降神非尋常，希世曾一偶。", "積善如公家，于今見純佑。", "安車告歸日，三府升平久。", "萬石均祿秩，魯公拜前後。", "茫茫周漢來，此事復聞否。", "黄金鑄大印，綠絲綰長綬。", "方爲累世滎，況多後來秀。", "戲禽試强弩，勸客滿春酒。", "賤子敢再拜，願公更眉壽。"]'),
('3a401af7-b1c3-4141-b7ff-cb94473b66dc','秋陰','劉敞','宋','宋诗','song-poetry','','[]','浮雲初無心，已南復更北。',60,'全唐诗/poet.song.27000.json','["浮雲初無心，已南復更北。", "蕭蕭清風急，忽忽白日匿。", "時逝物稍變，感集意鮮適。", "玄蟬號庭樹，蟋蟀吟四壁。", "自古共此悲，豈伊越鄉客。"]'),
('b374b3af-0a1d-4429-9926-ec68a3aff9ca','久陰','劉敞','宋','宋诗','song-poetry','','[]','南方信卑濕，風雨無時節。',48,'全唐诗/poet.song.27000.json','["南方信卑濕，風雨無時節。", "春風仍晚寒，陽和恐中絕。", "蛟龍乘江湖，雲霧欺日月。", "驅除懷熏風，悒悒生內熱。"]'),
('808b92b5-2fda-46a1-9b98-49b12ddb5559','蟋蟀','劉敞','宋','宋诗','song-poetry','','[]','七月鳴在野，八月鳴在宇。',60,'全唐诗/poet.song.27000.json','["七月鳴在野，八月鳴在宇。", "九月登我堂，十月入床下。", "滔滔歲方晏，促促聲亦苦。", "悲秋不悲己，終夜如獨語。", "時俗有新聲，誰能一聽汝。"]'),
('bacd54db-1759-4ea3-a243-936ce333885a','送王十二還乾州','劉敞','宋','宋诗','song-poetry','','[]','窮通蓋有命，富貴不能早。',84,'全唐诗/poet.song.27000.json','["窮通蓋有命，富貴不能早。", "君侯希世珍，三十未爲老。", "棲遲升斗祿，奔走周秦道。", "及親固爲榮，捧檄豈辭小。", "北風正凝霜，千里徑無草。", "人生貴感激，豈以外物擾。", "當爲昂藏駒，勿自使枯槁。"]'),
('8cd23981-2e06-4a57-8af5-d71fb2401bd1','坐嘯亭納涼','劉敞','宋','宋诗','song-poetry','','[]','長嘯振林木，半空鸞鶴聲。',36,'全唐诗/poet.song.27000.json','["長嘯振林木，半空鸞鶴聲。", "清風蘋末來，孤月海上生。", "坐久物色改，如有神仙迎。"]'),
('65ea60e8-c56f-4776-a53d-dbc72ee7470e','王昭君','劉敞','宋','宋诗','song-poetry','','[]','嬋娟巫峽女，秀色傾陽臺。',120,'全唐诗/poet.song.27000.json','["嬋娟巫峽女，秀色傾陽臺。", "昔爲一片雲，飛入漢宫來。", "明鏡徒自姸，幽蘭誰爲媒。", "丹青固難恃，遠嫁委塵埃。", "十步一反顧，百步一徘徊。", "出門如萬里，淚下成霰摧。", "左右相娛樂，絲竹聲正哀。", "豈不强言笑，鬱鬱不可開。", "黄河入東海，還從天上回。", "嗟爾獨抱恨，一往擲蒿萊。"]'),
('bde9c6ec-4d9f-4e50-ad7b-9120a42ed6ab','重一首同聖俞鄰幾持國作用前韻','劉敞','宋','宋诗','song-poetry','','[]','昭君信絕世，窈窕秘瑤臺。',120,'全唐诗/poet.song.27000.json','["昭君信絕世，窈窕秘瑤臺。", "歲華坐將晚，玉輦何當來。", "一以畫爲賞，有如鴆爲媒。", "含悲下紫殿，即路指黄埃。", "光艷動左右，君心再徘徊。", "白水不可變，孤芳從此摧。", "盛時能幾何，千載獨餘哀。", "至今青塚傍，積怨昏不開。", "掖庭用色選，丹青以利回。", "寄語閨中子，何憾處蒿萊。"]'),
('b4cdf475-3966-4606-aa18-7bebda7fed7d','憶松','劉敞','宋','宋诗','song-poetry','','[]','松陰何婆娑，松蓋何偃蹇。',108,'全唐诗/poet.song.27000.json','["松陰何婆娑，松蓋何偃蹇。", "松香不堪折，松色無可選。", "旦暮青松間，吟懷未嘗遠。", "嚴霜百木死，高秀初欲展。", "泠泠海風飄，輝輝甘露泫。", "去矣混塵滓，懷哉邈林巘。", "諒無刀斧憂，千載行可踐。", "輦轂念山海，誰期共攀搴。", "獨有風入聲，琴中尚悠衍。"]'),
('524cafde-c288-439d-8830-e0b389d83db8','留侯','劉敞','宋','宋诗','song-poetry','','[]','張良韓孺子，夙昔志未伸。',96,'全唐诗/poet.song.27000.json','["張良韓孺子，夙昔志未伸。", "授書黄石公，問禮倉海君。", "契合見神助，濟時効經綸。", "指揮轉雷電，顧盻定楚秦。", "以伋三寸舌，抗兹百萬軍。", "一爲帝王師，晚就赤松賓。", "富貴心不屑，功名諒誰論。", "出處何昭昭，賢哉古之人。"]'),
('c5bd240f-0c2b-48f2-9427-1c4ec7d99a33','録近文呈晏公','劉敞','宋','宋诗','song-poetry','','[]','麟趾感素文，躍魚赴鳴琴。',108,'全唐诗/poet.song.27000.json','["麟趾感素文，躍魚赴鳴琴。", "殊類豈自識，至和動其心。", "濟世有先覺，鑄人不鑄金。", "刪詩在正始，好樂非好音。", "萬生依陶冶，一氣諧飛沈。", "賤子晚及門，獨學謬知今。", "趨隅誦所志，踴躍不自任。", "救渇而飲河，栖枝以巢林。", "量微志復小，俛仰感高深。"]'),
('8d36c443-98a7-4968-8030-9c40457a2369','讀晏子春秋','劉敞','宋','宋诗','song-poetry','','[]','平生實善交，厚薄等新故。',84,'全唐诗/poet.song.27000.json','["平生實善交，厚薄等新故。", "觧驂濟越石，調祿謂車御。", "猶稱禮偪下，未免儉則固。", "高風往既息，頽迹後方騖。", "陳妾輕綺紈，賢士敝襦袴。", "若人不重得，遺論今始布。", "吾亦太史徒，執鞭所欣慕。"]'),
('3cf9b17c-85e7-43c4-b402-dffe2193264b','以近文投謝學士','劉敞','宋','宋诗','song-poetry','','[]','自昔周旦死，珍鳯閟空巒。',144,'全唐诗/poet.song.27000.json','["自昔周旦死，珍鳯閟空巒。", "民斯未嘗見，猶取圖象觀。", "況彼聖人沒，衆說紛無端。", "能言拒楊墨，豈秪均遺鸞。", "念我生苦後，讀書樂瓢簞。", "潛精探遺文，倣象良云難。", "猶如琢圭玉，考法求所安。", "雖無繩與矩，我知不爲丸。", "凝誠矢弗變，勢利非攸歡。", "譬于寸木微，積久能巑岏。", "有羽必懷聳，有聲必希彈。", "方期沐清德，敢不振斯冠。"]'),
('0d3d3c5f-bb23-4f1a-acd1-355cf41df147','答吳沖卿學士','劉敞','宋','宋诗','song-poetry','','[]','人生若浮雲，聚散不自知。',168,'全唐诗/poet.song.27000.json','["人生若浮雲，聚散不自知。", "昔與子相逢，綵衣汝水湄。", "兩家賀羊酒，道路生光輝。", "變故一朝革，各在天一涯。", "我病陳蔡間，固窮莫自持。", "君爲周南居，流涕極所思。", "日月忽已改，舊游不可追。", "豈悟羣玉峰，攜手如素期。", "感愴從中來，當歡反成悲。", "求友聆嘉音，喟然見新詩。", "廢學老將落，積憂志益衰。", "俛仰諸公間，嘿嘿慚見嗤。", "子我平生交，夙昔聆箴規。", "相愛當見朂，勿同衆人爲。"]'),
('178654f5-65e2-4d83-b6d4-5ba776f3dcc9','寄朱三學士','劉敞','宋','宋诗','song-poetry','','[]','憶在京輦居，相與巷南北。',96,'全唐诗/poet.song.27000.json','["憶在京輦居，相與巷南北。", "幸非勢利合，同有春秋癖。", "往來熟杖屨，假借通經籍。", "誰謂數斯疏，要云諒且直。", "别離淹日月，寤寐見顔色。", "惠我以好音，欣然對真迹。", "微官事如毛，徇俗頭欲白。", "庸知尚可敎，願子更良食。"]'),
('29723b67-ab4e-4304-af50-627235215873','送李綖學士請示江韓諸君','劉敞','宋','宋诗','song-poetry','','[]','我醉闕門外，卧備東藩臣。',96,'全唐诗/poet.song.27000.json','["我醉闕門外，卧備東藩臣。", "君從天上來，秀色落青雲。", "留連三日語，多得所未聞。", "僻陋不自知，喟予久離羣。", "南風吹白沙，六月天晝昏。", "送行不盡境，引望空復勤。", "相識何必舊，白頭或如新。", "有信當寄書，毋遺傾蓋人。"]'),
('621b39a0-1444-4439-9996-9e7efecdad8f','今旦','劉敞','宋','宋诗','song-poetry','','[]','今旦風淒冷，始覺陰氣繁。',96,'全唐诗/poet.song.27000.json','["今旦風淒冷，始覺陰氣繁。", "白日無光彩，未敢啓前軒。", "卜居止容膝，他時用爲嘆。", "及此殊覺勝，閉塞有餘温。", "撥棄當世慮，縱觀上古言。", "禹稷稱櫛風，孔顔樂閉門。", "窮通或相背，勞逸足自論。", "優游蓋卒歲，達者嘗有言。"]'),
('8b776feb-376b-46f0-b921-bde214758cf1','送李才元','劉敞','宋','宋诗','song-poetry','','[]','車馬何赫奕，觀者更歎息。',120,'全唐诗/poet.song.27000.json','["車馬何赫奕，觀者更歎息。", "冨貴歸故鄉，任州二千石。", "賜金爲親壽，衣錦供子職。", "里閈納華駟，公堂列嚴戟。", "地兼百城會，衆有萬戶籍。", "指撝吏奔走，宣布民悅懌。", "丈夫雖非通，豈負稽古力。", "懷章過故人，笑别見顔色。", "吾徒若匏瓜，長繋慚不食。", "贈君當何言，有信勉相憶。"]'),
('66a6f473-17dc-468e-8a6a-d07c3aa34dab','送焦生','劉敞','宋','宋诗','song-poetry','','[]','蒼鷹懷風雲，六月不忘習。',132,'全唐诗/poet.song.27000.json','["蒼鷹懷風雲，六月不忘習。", "寒蛟待雷雨，深水聊自蟄。", "多君起江湖，力學如不及。", "擇師視洙泗，履奥窺所立。", "翰飛自兹遠，變化誰能縶。", "孤劍屢感激，四方慎翔集。", "公子誠愛客，相門許長揖。", "結轡因北游，揮手謝朋執。", "藏書就史氏，觀國榮天邑。", "藉甚諸公間，青紫亦可拾。", "寧復悲歸來，眷眷兒女泣。"]'),
('fede7275-6152-420e-9be2-4b0d9779e7d4','聖俞受詔行田是時聖俞葬其弟公異未畢而去','劉敞','宋','宋诗','song-poetry','','[]','蟲潦敗耕耘，西成絕人望。',156,'全唐诗/poet.song.27000.json','["蟲潦敗耕耘，西成絕人望。", "鄉農籲天意，守闕書屢上。", "憂民聖天子，擇吏賢宰相。", "王畿蓋根本，歲賦在寛放。", "曰君往行田，究彼荒稔狀。", "一當薄其租，用以息民謗。", "朝廷慎指使，推擇無與讓。", "非君精明姿，曷以致忠諒。", "憂公劇私爲，即夕治行仗。", "懷悲念其弟，卜日不果葬。", "乃知體純粹，世士難以尚。", "德澤既敷宣，風謠還歷訪。", "歸來悟明主，自致誰云妄。"]'),
('7f568b15-0eee-4e13-91aa-ebb4f2b80bc6','張老子出田所','劉敞','宋','宋诗','song-poetry','','[]','魯人有林類，底春獨被裘。',84,'全唐诗/poet.song.27000.json','["魯人有林類，底春獨被裘。", "沿畦拾遺穗，带索仍長謳。", "知命忘其老，樂天固不憂。", "既驚端木賜，復感東家丘。", "夫翁何爲者，歲暮亦遠遊。", "北風吹白髮，蕭颯田隴頭。", "此意如昔賢，世人知爾不。"]'),
('be5a7489-0295-4c0d-b006-1df26b3527cd','同聖民圍棋釣魚','劉敞','宋','宋诗','song-poetry','','[]','山林自微尚，軒冕非所營。',96,'全唐诗/poet.song.27000.json','["山林自微尚，軒冕非所營。", "每及逍遙趣，欣然得吾生。", "春塘漾綠水，珍樹啼黄鶯。", "心遠忘外喧，境幽適人情。", "垂釣如有求，而無得失驚。", "臨局非期勝，聊爲白黑争。", "得意物可遺，忘言賞逾精。", "此理俗鮮悟，固當屬淵明。"]'),
('00d3f232-328d-4b3a-b01e-75713a1253d7','秋園晚步','劉敞','宋','宋诗','song-poetry','','[]','秋物足悲咤，丘園良考槃。',84,'全唐诗/poet.song.27000.json','["秋物足悲咤，丘園良考槃。", "翺翔攄結慮，徙倚縱遐觀。", "爽氣使心厲，淒風令自單。", "酸念無逕託，那使百憂寛。", "鳥下見人寂，螿啼知露寒。", "夕煙起城際，反照映林端。", "佇立不能返，迷懷增屢歎。"]'),
('d7235de2-d750-47a6-a0b7-db1b5f0d5e4a','競渡','劉敞','宋','宋诗','song-poetry','','[]','三閭雖已死，郢人獨見思。',96,'全唐诗/poet.song.27000.json','["三閭雖已死，郢人獨見思。", "五月江水深，遶城碧邐迤。", "輕舟爛龍鱗，利楫劇鳥飛。", "簫鼓駭蛟龜，鷹隼亂旌旗。", "争先愛中流，觀者被水湄。", "漠漠懷沙魂，一去不可追。", "千載萬歲後，兒女以爲嬉。", "已矣國無人，終焉莫子知。"]'),
('6bf5293b-159a-44fe-be70-949af175e961','讀離騷','劉敞','宋','宋诗','song-poetry','','[]','空庭衆囂息，風葉獨紛紛。',96,'全唐诗/poet.song.27000.json','["空庭衆囂息，風葉獨紛紛。", "秋期此時改，感歎坐黄昏。", "遠懷靈均子，著書爲平分。", "念爾剛直心，吐茲清麗文。", "上嘉唐虞世，下悼商周君。", "能與日月争，不能卻浮雲。", "浮雲蔽日月，歲暮奈憂勤。", "精誠誰謂遠，恍惚若相聞。"]'),
('14384439-cefb-40e9-a38e-d5b9830be9ac','秋過臨波亭寄陜府資政給事','劉敞','宋','宋诗','song-poetry','','[]','不復池上遊，秋意忽已繁。',72,'全唐诗/poet.song.27000.json','["不復池上遊，秋意忽已繁。", "卧柳半死生，枯荷自翩翻。", "憶昔載後車，逍遙臨中園。", "觀魚有縱辨，運斤契忘言。", "豈獨歲月晚，正傷離别魂。", "人遐室空邇，幽興誰與論。"]'),
('fde3c2eb-bd11-41c6-84d0-02c634c12f53','讀聖俞我今五十二詩感之','劉敞','宋','宋诗','song-poetry','','[]','子真神仙吏，不識傷别離。',96,'全唐诗/poet.song.27000.json','["子真神仙吏，不識傷别離。", "忽逢舊交歎，始悟人間悲。", "歲月流水逝，富貴浮雲馳。", "徘徊撫往事，感激吐新詩。", "流水難以追，浮雲難以推。", "百年半如此，萬事從可知。", "且欲拂衣行，聊及鱸魚期。", "君若變名姓，相逢復何時。"]'),
('1748e0cf-9670-4092-917a-162fbb794d30','上嶺下嶺','劉敞','宋','宋诗','song-poetry','','[]','上嶺惟恐遲，下嶺懼顛覆。',36,'全唐诗/poet.song.27000.json','["上嶺惟恐遲，下嶺懼顛覆。", "一嶺但數里，思慮千盈腹。", "不聞二大夫，致身未嘗辱。"]'),
('3ab3e80c-6c06-4a46-a7f6-46301a0731a6','送袁同年殿丞陟通判撫州因還洪井舊居袁在朝數上書言當世事某與袁别十年矣語舊多可悲者留三日乃去','劉敞','宋','宋诗','song-poetry','','[]','輕舟何翩翩，斵冰浮清川。',120,'全唐诗/poet.song.27000.json','["輕舟何翩翩，斵冰浮清川。", "問之亦奚樂，歲宴道且邅。", "云我大梁客，游說萬乘前。", "畫策不見收，故鄉復言旋。", "薄祿及吾親，就官若歸田。", "名實两有適，遠近誰間然。", "憶昔都門别，爾來彌十年。", "蒼蒼豫章質，更覺摩青天。", "語舊或涕流，舉觴愧留連。", "相從且未果，使我心勞悁。"]'),
('aef501fb-d524-449a-80db-bd5a16fa22dc','送裴殿丞','劉敞','宋','宋诗','song-poetry','','[]','君已頭髪白，猶著五綵衣。',60,'全唐诗/poet.song.27000.json','["君已頭髪白，猶著五綵衣。", "出門我意失，贈别雙涕揮。", "自古不澤祿，念公早旋歸。", "天歡固爲樂，外物焉足希。", "達矣老萊子，千年見餘輝。"]'),
('c3ef7677-8897-4f57-991f-b507cab05b4e','裴殿丞訪别說春秋期歲初復來','劉敞','宋','宋诗','song-poetry','','[]','吾衰不夢周，知我在春秋。',48,'全唐诗/poet.song.27000.json','["吾衰不夢周，知我在春秋。", "斯道宜未墜，夫公能見求。", "相看頭可白，感别歲空遒。", "念子期雞黍，母懷汗漫遊。"]'),
('047b43ff-c051-4e10-9073-3257a52d3f2b','送雍秀才歸瑯琊山','劉敞','宋','宋诗','song-poetry','','[]','希聲未易合，皇華衆方笑。',96,'全唐诗/poet.song.27000.json','["希聲未易合，皇華衆方笑。", "與子東西人，相逢偶同調。", "億年寄神觧，萬里在心照。", "此間豈容言，吾得安蓬藋。", "煌煌千金珠，舉世矜賞好。", "安知緯蕭翁，棄置久高蹈。", "盛論山水趣，局促恨未到。", "江湖且相望，送子一長嘯。"]'),
('eed5116f-f6d0-422e-89ca-333b5baee352','鳴禽','劉敞','宋','宋诗','song-poetry','','[]','朝日升屋梁，喧禽鳴樹巔。',96,'全唐诗/poet.song.27000.json','["朝日升屋梁，喧禽鳴樹巔。", "東風不相期，自與春意旋。", "振衣起前庭，天色綠窅然。", "非煙颺微和，目極相綿綿。", "行尋林間步，荑英已可攀。", "萬物在陽舒，胡爲慘不歡。", "幸有二三子，采芳玩華年。", "不及古之人，幽懷聊復蠲。"]'),
('dd4d7060-9f20-4782-bf39-eb88bff149c4','驚禽','劉敞','宋','宋诗','song-poetry','','[]','幽鳥何所託，高棲衆林端。',84,'全唐诗/poet.song.27000.json','["幽鳥何所託，高棲衆林端。", "風巢雛鷇危，露葉毛羽寒。", "半夜吐明月，驚鳴遞囂讙。", "迎光怪焚巢，顧影疑飛丸。", "何爲貪擇木，通夕不自安。", "乘高非爾謀，宜下易所觀。", "不見丹穴鳯，深居全綵翰。"]'),
('85356e3c-67fd-407e-9da9-4c2097776399','八角井','劉敞','宋','宋诗','song-poetry','','[]','誰鑿八角井，不方亦不圓。',48,'全唐诗/poet.song.27000.json','["誰鑿八角井，不方亦不圓。", "此地饒美水，此井獨苦泉。", "泉甘常早竭，泉苦更永年。", "浪得世上名，對之還慨然。"]'),
('3ea1f29a-e217-4eff-9bfa-dab3b26c562f','雨過張先生','劉敞','宋','宋诗','song-poetry','','[]','禀生本迂闊，習性益疏嬾。',96,'全唐诗/poet.song.27000.json','["禀生本迂闊，習性益疏嬾。", "遇境賸欲留，得人輒迷返。", "先生老鄉曲，素髪頗樗散。", "相遇年已忘，心親禮逾簡。", "幸無富貴憂，時可青白眼。", "驚呵左右人，邂逅以繾綣。", "初隨朝陽出，忽報山雨晚。", "天路良幽艱，歸途失平坦。"]'),
('314bb33a-ae54-4c0c-a352-0e98e39ca27c','寄公默先生','劉敞','宋','宋诗','song-poetry','','[]','昔賢避言色，先覺如觀火。',72,'全唐诗/poet.song.27000.json','["昔賢避言色，先覺如觀火。", "作者有七人，清風緬遺我。", "浮俗滋鈌鈌，羈人畏瑣瑣。", "知言豈易值，卷迹恨莫果。", "所願學孔子，無可無不可。", "寡過知未能，同聲賴銘左。"]'),
('f845a3c4-d926-436e-ab17-1a73caab236b','恩賜御書呈同舍諸公','劉敞','宋','宋诗','song-poetry','','[]','聖神紹先古，述作備新書。',168,'全唐诗/poet.song.27000.json','["聖神紹先古，述作備新書。", "微生濫中秘，重賜等諸儒。", "日月明天文，龜龍粲河圖。", "精神駭耳目，黼藻賁泥塗。", "發揮箧中藏，更得神宗初。", "光華混新舊，筆墨肖錙銖。", "幸生堯禹間，而見典與謨。", "上爲四方賀，善繼古所無。", "下竊私室榮，搢紳誰與俱。", "漢史探會稽，周臣覽崑墟。", "蕭條千萬里，筋力固已劬。", "而我獨何人，荷寵安厥居。", "受學庶無負，傳家既多餘。", "願從二三子，講誦無時虚。"]'),
('bb0eb61e-f9d0-4dd0-bbf5-fa04c66ca68d','與景仁聖俞飲景彝西園','劉敞','宋','宋诗','song-poetry','','[]','鬢髪今日白，山林未能往。',120,'全唐诗/poet.song.27000.json','["鬢髪今日白，山林未能往。", "每逢負郭趣，嘿有歸田想。", "置酒松柏間，當春更蕭爽。", "欣欣二三子，相與留一賞。", "早花何娟娟，秀色傾宿莽。", "馴禽聲喧呼，永不忌羅網。", "物情樂于適，未必在深廣。", "育育井中魚，胡然困偃佒。", "佳哉主人翁，示我以天壤。", "放懷寓一醉，益愧鳴佩響。"]'),
('658c1d70-15be-42e3-aa35-64d70cf4cc28','送懷安李使君屯田','劉敞','宋','宋诗','song-poetry','','[]','汝潁多奇士，磊落布方冊。',156,'全唐诗/poet.song.27000.json','["汝潁多奇士，磊落布方冊。", "先進存古風，若人復令德。", "詩書秀英華，鷹鶻勇排擊。", "曩者從軍行，早聞平戎策。", "縱横志未展，慷慨意更激。", "坐驚齒牙脱，忽使頭髪白。", "頗與嵇阮同，閉關以藏迹。", "老驥甘道路，黄鵠羞斥澤。", "復持一麾去，堅取萬里役。", "旌旗暗長亭，已想蜀山碧。", "鼓吹喧前除，稍知楚風易。", "專城自足貴，遠覽固多適。", "胡爲結離愁，恨此晚同得。"]'),
('2d829c00-31ed-426d-8a4b-942ca6513c10','題賈大夫射雉圖','劉敞','宋','宋诗','song-poetry','','[]','控弦誰家子，馳射落名翬。',72,'全唐诗/poet.song.27000.json','["控弦誰家子，馳射落名翬。", "傾城絕代女，巧笑揚脩眉。", "覽古按圖畫，悵然增我唏。", "壯士不擊賊，顧從兒女嬉。", "威弧無用世，反事禽荒爲。", "嘿嘿千歲後，正爲來者嗤。"]'),
('e871e2b0-2aec-428e-b2f8-710b14ee8b53','示張直温','劉敞','宋','宋诗','song-poetry','','[]','築山必使高，鑿井必使深。',84,'全唐诗/poet.song.27000.json','["築山必使高，鑿井必使深。", "百工戒淺近，盛德羞浮沈。", "焉有尺寸枝，能棲垂天禽。", "焉有升斗泉，能容横江鱘。", "借兹喻物理，足以開君心。", "隘在容不足，弱在力不任。", "大道如路然，固無古與今。"]'),
('7b0b8eca-b30a-4a41-a636-47255bdff5c3','臨淵亭望鳯凰等山作','劉敞','宋','宋诗','song-poetry','','[]','孟公多勝詣，故在杯酒間。',72,'全唐诗/poet.song.27000.json','["孟公多勝詣，故在杯酒間。", "雖非菊花時，輒復尋龍山。", "平明騎馬出，日暮倒幘還。", "若人難重得，此風猶可攀。", "問我亦何爲，翛然方閉關。", "忘言在得意，獨往路已難。"]'),
('ed1dbf7a-b0e5-42bd-86c8-795480d21542','聞隱直欲調官','劉敞','宋','宋诗','song-poetry','','[]','蛟龍居池中，仰活數掬水。',96,'全唐诗/poet.song.27000.json','["蛟龍居池中，仰活數掬水。", "虎豹離山林，求食輒搖尾。", "張君宜大用，亦是龍虎比。", "何得圖小官，折腰五斗米。", "屈伸蓋時命，隱顯乃君子。", "譬由合抱材，當自毫末起。", "昔爲青雲高，今落塵土裏。", "可喭復可驚，誰能叩天耳。"]'),
('61e2a298-fc6c-4e93-b8b7-05509239266d','津亭','劉敞','宋','宋诗','song-poetry','','[]','西風豁愁陰，天水兩涵泳。',72,'全唐诗/poet.song.27000.json','["西風豁愁陰，天水兩涵泳。", "微波蕩寒日，極目萬里浄。", "離披蒹葭老，蕭瑟原野迥。", "物容驚客懷，櫓聲動歸興。", "倦游髪恐白，多慮身復病。", "緬慕蒼梧雲，無心自輝映。"]'),
('73e9083c-248a-4dc4-8891-1fdeca50864a','和持國登開寶寺上方院寄孔寧極崔象之孫曼叔','劉敞','宋','宋诗','song-poetry','','[]','重山抱城起，清川带野回。',192,'全唐诗/poet.song.27000.json','["重山抱城起，清川带野回。", "深嚴古佛寺，嵽嵲聳高臺。", "此地宜眺覽，冠絕都城隈。", "遠近見千里，令人心目開。", "憶在七月中，丞相自魏來。", "百官迎道傍，休騎兹徘徊。", "衣冠相勝凌，塵土如炎灰。", "我隨衆人趨，出入再歷階。", "不得及此時，披襟濯氛埃。", "至今意耿耿，負愧不可裁。", "邇來讀君詩，足慰平生懷。", "忽如升其巔，四顧心悠哉。", "往者不可及，信陵久已頽。", "來者不可見，孔侯與孫崔。", "古今殊茫茫，慨嘆成歡哀。", "會復從君遊，于焉謝崔嵬。"]'),
('d81ff525-f49b-461a-b5db-314399c59604','臨波亭飲席贈徐二','劉敞','宋','宋诗','song-poetry','','[]','華星爛長天，明月被清池。',96,'全唐诗/poet.song.27000.json','["華星爛長天，明月被清池。", "良景豈易得，佳賓共在兹。", "形骸久相忘，巵酒安足辭。", "高歌激風飆，宜笑散春暉。", "中置浩長歎，民生信多爲。", "非無逍遙鄉，固在閒暇時。", "及爾不快飲，歲月忽欲馳。", "世事紛悠悠，放言爲吾師。"]'),
('8ee44031-7d0c-4cf3-882c-da4cc67e2ce2','送張四隱直遊邊','劉敞','宋','宋诗','song-poetry','','[]','吾昔讀漢書，遠嘉馬文淵。',228,'全唐诗/poet.song.27000.json','["吾昔讀漢書，遠嘉馬文淵。", "慷慨有大志，不辭走窮邊。", "嘗言功名期，當及少壯年。", "生圖萬里勛，死裹馬革還。", "此語頗豪蕩，書之在青編。", "其人雖已亡，其意猶凛焉。", "羌戎未伏誅，王旅多喪偏。", "安得如此人，西行隴與汧。", "借籌資方略，還爲天子言。", "海上惟歎息，今時豈無賢。", "忽聞張公子，奮起殊欣然。", "歷覽涇渭旁，究觀敵根源。", "寧復謝古人，正堪豁憂煎。", "衛青出行伍，去病幸有天。", "相繼取封侯，有若翻手間。", "男兒誰不如，可得甘棄捐。", "讀書反三黜，何用師孔宣。", "我豈少游徒，規規守鄉田。", "力弱非志弱，送君心長懸。"]'),
('718a0f64-131b-4530-a379-a785fe961375','同貢甫詠丁晋公園池','劉敞','宋','宋诗','song-poetry','','[]','一死復一生，一虛復一盈。',48,'全唐诗/poet.song.27000.json','["一死復一生，一虛復一盈。", "猶悲門易軌，況乃谷爲陵。", "曲池久蕪沒，高屋尚峥嶸。", "自古若傳舍，毋爲方歎驚。"]'),
('5fe86629-15af-47bd-934c-ca77578d30ee','送韓七寺丞知蕭山','劉敞','宋','宋诗','song-poetry','','[]','君家潁川上，時論數八龍。',144,'全唐诗/poet.song.27000.json','["君家潁川上，時論數八龍。", "聲華自照映，遠與高陽同。", "季慈又青出，秀氣凌秋空。", "安步可遠到，何爲菰蘆中。", "會稽自禹來，山水天下雄。", "古人每獨往，勝事殊未窮。", "聊欲因弦歌，登臨極江東。", "超然語高邁，令人愧樊籠。", "我昔更此邑，稚年尚兒童。", "邇來成夢寐，自笑成秃翁。", "安得方寸金，換君腰下銅。", "越吟不自然，極目南飛鴻。"]'),
('6d5e4495-188e-4d16-acc6-834ba03cbdb5','初夜','劉敞','宋','宋诗','song-poetry','','[]','汲汲書彌短，悠悠夜增長。',120,'全唐诗/poet.song.27000.json','["汲汲書彌短，悠悠夜增長。", "貧家不具燭，坐須明月光。", "隱几四寂默，陰蟲鳴我傍。", "天時有推敚，物性隨悲傷。", "感彼忽自驚，喟然發心狂。", "壯年何所成，憂患攢中腸。", "咄嗟牛衣叟，婦女知激昂。", "國恥吾亦羞，如何埽封疆。", "譬如籠中禽，左右不得翔。", "知音古亦稀，誰謂歌中商。"]'),
('ac5c207e-9f17-4eab-acf0-1d390642ec29','静夜','劉敞','宋','宋诗','song-poetry','','[]','花影不可埽，縱横月明中。',36,'全唐诗/poet.song.27000.json','["花影不可埽，縱横月明中。", "光芒裛新露，香氣生微風。", "夜永興不淺，幽人與誰同。"]'),
('a58c593d-4616-4012-932a-717949662500','迎恩甫','劉敞','宋','宋诗','song-poetry','','[]','相别才一月，相憶如一年。',60,'全唐诗/poet.song.27000.json','["相别才一月，相憶如一年。", "豈無白首游，不及夫子賢。", "邂逅發寤寐，奮飛絕由緣。", "忽聞乘春浪，千里下歸船。", "雞黍可以具，班荆暢幽悁。"]'),
('3a979d92-abc5-4c8a-b317-5d0085bfe4db','雨中獨居有懷江梅','劉敞','宋','宋诗','song-poetry','','[]','晨起風雨交，蕭蕭秋意寒。',96,'全唐诗/poet.song.27000.json','["晨起風雨交，蕭蕭秋意寒。", "出門無所詣，行道如此難。", "思我平生游，相得他日歡。", "興來未嘗約，趣合不待言。", "濁酒有與醉，孤琴能一彈。", "時時商聲歌，磊落千琅玕。", "浮雲歸無期，宿草秋向殘。", "獨咏雞鳴詩，一唱三四歎。"]'),
('4b4b1c05-b7d6-439e-a522-9e422a87e562','過聖俞讀其近文明日寄之','劉敞','宋','宋诗','song-poetry','','[]','昨日過君家，雙瞳偶清刮。',48,'全唐诗/poet.song.27000.json','["昨日過君家，雙瞳偶清刮。", "非無塵俗累，喜見秋陰豁。", "注瑟請新聲，瑤音邈超越。", "神驚自束躅，不爲天寒發。"]'),
('4e4d566b-9d4c-4a4a-9234-d3bf9e039093','憶梅','劉敞','宋','宋诗','song-poetry','','[]','豈無棟梁材，爲君構明堂。',96,'全唐诗/poet.song.27000.json','["豈無棟梁材，爲君構明堂。", "豈無調羹資，爲君致烹鬺。", "獨使限荒鄙，委之道路旁。", "歲晏吐奇秀，芬芬有餘香。", "疾風見松柏，衆穢知蕙芳。", "譬彼君子質，幽沈道逾彰。", "安得假神術，徙根儷長楊。", "遼哉計不果，我心不能忘。"]'),
('c432fefc-f0d6-4a26-9a31-026d45f97617','傷胡二','劉敞','宋','宋诗','song-poetry','','[]','人生期百齡，子適四之一。',96,'全唐诗/poet.song.27000.json','["人生期百齡，子適四之一。", "人仕期萬石，子適升斗秩。", "禀靈甚純粹，守道復貞吉。", "無負於神明，如何有倉猝。", "雖登爵一命，亦治邑千室。", "名竟未達君，澤亦不被物。", "鬼神莽無狀，天道眇難詰。", "冥冥九原深，永與顔賈匹。"]'),
('c86579e6-4da0-423a-8525-7f31cee6dd31','觀永叔五代史','劉敞','宋','宋诗','song-poetry','','[]','大均運元和，萬物分一氣。',288,'全唐诗/poet.song.27000.json','["大均運元和，萬物分一氣。", "相雜以成文，自然故爲貴。", "道衰三王末，議出百家沸。", "仲尼日月也，薄日爲之既。", "春秋曰筆削，天地復經緯。", "大法初粲然，亂臣以爲畏。", "微言迨秦漢，變雅從晉魏。", "逐末競錐刀，澆淳玩花卉。", "安知作述本，庸識文章意。", "中間馬與班，二子稱彷彿。", "猶云崇貨力，尚或排剛毅。", "才難乃其然，可以長歔欷。", "退之不爲史，于道其猶未。", "胡爲體明哲，曾是回怨誹。", "國典竟蕪雜，唐風亦隱厞。", "陵夷九易姓，禍亂森如蝟。", "儒術駭中絕，斯民遲攸塈。", "紛紜混朱紫，清濁誰涇渭。", "龍飛真人出，虎變斯文蔚。", "天意晚有屬，先生拔乎彚。", "是非原正始，簡古斥辭費。", "哀善傷獲麟，疾邪記有蜚。", "處心必至公，撥亂豈多諱。", "何必藏名山，端如避羅罻。"]'),
('831c545d-3702-48a0-8ec4-9fadd54c502c','寄張拱辰','劉敞','宋','宋诗','song-poetry','','[]','楚人少眉壽，此翁七十餘。',96,'全唐诗/poet.song.27000.json','["楚人少眉壽，此翁七十餘。", "剕士多輕揚，此翁乃好書。", "世醫悅膚淺，此翁識古初。", "習俗争錐刀，此翁尚玄虚。", "數欲見此翁，爲其亦起予。", "責人必求備，堯舜猶病諸。", "漁者公閱休，逸人狂接輿。", "有之幸見告，我且從彼居。"]'),
('68b7b471-6162-4d0c-a8fc-601a2c53f131','竹牀','劉敞','宋','宋诗','song-poetry','','[]','櫛櫛裁脩竹，熒熒粲寒光。',60,'全唐诗/poet.song.27000.json','["櫛櫛裁脩竹，熒熒粲寒光。", "浮筠凝烟霧，疏節留雪霜。", "甘寝百疾觧，側身夏日長。", "此時四海波，亦已如探湯。", "嗟我智慮短，苟爲安一牀。"]'),
('18ee3751-c0b2-4c78-b5bf-4aaf97e734d2','哀三良詩','劉敞','宋','宋诗','song-poetry','','[]','士爲知己死，女爲悅己容。',96,'全唐诗/poet.song.27000.json','["士爲知己死，女爲悅己容。", "咄嗟彼三良，殺身徇穆公。", "丹青懷信誓，夙昔哀樂同。", "人命要有訖，奈何愛厥躬。", "國人悲且歌，黄鳥存古風。", "死復不食言，生寧廢其忠。", "存爲百夫防，逝爲萬鬼雄。", "豈與小丈夫，事君謬始終。"]'),
('b89df17e-e31e-4ba3-a97b-1cae4554d079','馬生自汝南來求入太學不得請詩以歸','劉敞','宋','宋诗','song-poetry','','[]','士貧謀國拙，安得辭泥塗。',120,'全唐诗/poet.song.27000.json','["士貧謀國拙，安得辭泥塗。", "馬生負長劍，嘆曰歸來乎。", "尺薪等芳桂，斗粟兼明珠。", "王門不見容，憔悴如枯魚。", "我無升斗水，慰子朝夕須。", "亦有西江濤，疏遠不可圖。", "相勸早旋歸，詩書自爲娛。", "男兒患無術，餘事從卷舒。", "時至當奮飛，翩如巢中雛。", "微物尚變化，況君七尺軀。"]'),
('2064cc9f-b327-4a9e-a702-bdecbda2206d','詠史','劉敞','宋','宋诗','song-poetry','','[]','主父希世者，畫策妙縱横。',72,'全唐诗/poet.song.27000.json','["主父希世者，畫策妙縱横。", "指麾一言用，震動諸侯驚。", "日暮臨遠塗，中道方倒行。", "不忍藜藿食，意從五鼎烹。", "寧知鹿門翁，白首長躬耕。", "天下非所保，功名安足營。"]'),
('6ce9c929-5867-4a93-bf49-8de1df2bd721','入荆江','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','此江自岷山，浩瀚浮西極。',180,'全唐诗/poet.song.27000.json','["此江自岷山，浩瀚浮西極。", "中爲三峽束，壅閼氣憤激。", "崩騰得平地，千里怒未息。", "雖投洞庭闊，争道猶逼窄。", "觸岸皆倒流，勢兼萬牛力。", "渾黄不可鑒，咫尺瞢玄白。", "頗似崑崙流，洩源下積石。", "逶迤屢屈折，九曲乃大直。", "始信枉渚歌，至今猶悽惻。", "中流忽沙沸，惨惨半江黑。", "俄頃成丘陵，方舟渡安得。", "坤儀理專静，何故輙損益。", "多異真窮鄉，所逢豈中國。", "墨生忍黔突，孔子不暖席。", "賢聖亦遠遊，吾寧倦行役。"]'),
('c2d75148-5509-4237-b199-ac683a3f2078','和鄰幾持國景德寺納涼','劉敞','宋','宋诗','song-poetry','','[]','四時急相乘，五月大火中。',168,'全唐诗/poet.song.27000.json','["四時急相乘，五月大火中。", "天地爲熾爐，萬物皆沸銅。", "吁嗟望雲漢，長嘯懷清風。", "覆載雖高厚，跼蹐似不容。", "蚩蚩道旁子，奔走勞厥躬。", "外以塵土傷，內爲利害攻。", "狂酲無由濯，勢與羣物終。", "安知逍遙遊，采真得所從。", "寶宇豁高嚴，劇談叩真空。", "虚白從中來，清涼脱樊籠。", "惜哉但獨樂，不與斯人同。", "作詩寄妙賞，藐若凌青穹。", "依隱或玩世，詭時在不逢。", "三復金玉音，曠然已發矇。"]'),
('bc0912dd-0b67-4215-80bf-8c0da14013b5','送劉初平謁會稽范吏部','劉敞','宋','宋诗','song-poetry','','[]','劉生大梁客，五十恥獨醒。',240,'全唐诗/poet.song.27000.json','["劉生大梁客，五十恥獨醒。", "觀書泛爲通，不肯明一經。", "壯歲懷慷慨，邊游忍伶仃。", "擔簦售白璧，垂蒯提青萍。", "歸來面朝士，口寫山川形。", "公侯盡高意，禮數争分庭。", "落魄破小節，浮游謝塵冥。", "詼諧若流輠，捷勝如建瓴。", "荏苒混朝市，繽紛邁年齡。", "有云致官爵，百說無一聽。", "二子才劍吷，衆豪固螟蛉。", "以兹滯玉帛，亦不羞巖坰。", "太尉辟開府，中丞請居廷。", "拂衣東南走，高揖千巖青。", "禹穴發窮寶，雷門叩驚霆。", "邦侯萬人傑，憂國心無寧。", "得善輙觧榻，發奇肖開硎。", "抽辭肯聽瑩，宴舊方淹停。", "箬下進醇酎，鑑中結飛鈴。", "高哉鴻鵠心，去矣窮滄溟。"]'),
('ac754f1c-e08c-4c4c-b086-6f46f823caa1','謝主簿示雜文','劉敞','宋','宋诗','song-poetry','','[]','少不學爲吏，僶俛亦非良。',96,'全唐诗/poet.song.27000.json','["少不學爲吏，僶俛亦非良。", "終日簿書間，忽疑鬢髪蒼。", "無聞畏後生，素習成兼忘。", "吾子豈獨迷，相從道文章。", "上論聖賢心，下救世俗荒。", "磊落古人風，粲然在我旁。", "精莩眩日月，爰居惑鏗鏘。", "置此但爲好，切磋非所望。"]'),
('03899d1f-67dd-4606-b959-381431eda89f','開元寺','劉敞','宋','宋诗','song-poetry','','[]','自古皆有死，豈惟直如弦。',96,'全唐诗/poet.song.27000.json','["自古皆有死，豈惟直如弦。", "魯公既中夭，狂宼不獨延。", "茲寺數經亂，叢林廢爲煙。", "若人昔所居，故老廣其傳。", "直氣觸白日，沈憂凌青天。", "悠悠穹壤間，肯與蛛蟻捐。", "事往理冥漠，悲來涕潺湲。", "作詩識其處，尚想音容全。"]'),
('e17d30ef-476c-4974-b54b-1b2670ba1c43','漢武帝二首  其一','劉敞','宋','宋诗','song-poetry','','[]','武帝固英雄，總擥皆軼材。',96,'全唐诗/poet.song.27000.json','["武帝固英雄，總擥皆軼材。", "南并桂林地，北守單于臺。", "軍費累萬金，馬迹窮九垓。", "時獨卜大夫，規規輸其財。", "忠義豈不然，告緡自此開。", "茫茫文景後，田野卒汙萊。", "孰謂將相謀，竟貽黔首哀。", "晚悟富民侯，後時信悠哉。"]'),
('4081940f-4562-4506-bb16-4419b07183b6','漢武帝二首  其二','劉敞','宋','宋诗','song-poetry','','[]','洪波漏金堤，河伯獨不仁。',96,'全唐诗/poet.song.27000.json','["洪波漏金堤，河伯獨不仁。", "不有封禪行，安知愁吾民。", "翩翩海濱子，自以通鬼神。", "黄金成虚言，鴻飛邈無因。", "武安玩天時，獨秉萬國鈞。", "愴似宣房詩，郎吏終負薪。", "寂寞千載間，真僞共沉淪。", "何乃忘謗書，世固無直言。"]'),
('e4f10c2b-e097-44a5-97d4-51d2921ee87b','楚風四首  其一','劉敞','宋','宋诗','song-poetry','','[]','三楚多秀士，從古謂之然。',60,'全唐诗/poet.song.27000.json','["三楚多秀士，從古謂之然。", "接輿既髠首，三閭復沈淵。", "大屈備時玩，白珩爲世傳。", "粃糠鳳鳥歌，瓦礫離騷篇。", "已矣德既隱，孔車爲回旋。"]'),
('a66dea5d-1481-4607-a712-4f5dbd866300','楚風四首  其二','劉敞','宋','宋诗','song-poetry','','[]','嚴嚴章華宫，灼灼高唐觀。',48,'全唐诗/poet.song.27000.json','["嚴嚴章華宫，灼灼高唐觀。", "慶弔隨俯仰，離合異昏旦。", "人生詎能幾，物化毎交亂。", "千秋萬歲後，寂寞江與漢。"]'),
('5c208330-7aff-4542-b804-604dd7fb1e3e','楚風四首  其三','劉敞','宋','宋诗','song-poetry','','[]','宜僚樂市肆，叔敖榮寝丘。',48,'全唐诗/poet.song.27000.json','["宜僚樂市肆，叔敖榮寝丘。", "不惡漁釣卑，吾聞公閲休。", "顛冥天地間，世與我悠悠。", "豈悟多種橘，可齊千戶侯。"]'),
('addfcb3b-8457-4582-af98-5e4de3d620d2','楚風四首  其四','劉敞','宋','宋诗','song-poetry','','[]','唐侯兩驌驦，夙昔困多難。',48,'全唐诗/poet.song.27000.json','["唐侯兩驌驦，夙昔困多難。", "蔡國雙狐白，豈知反爲患。", "世衰道爲遹，服美自取間。", "敝緼可終身，鴻飛諒何簒。"]'),
('21a1c006-7946-4827-9309-7d49dc211124','雜詠','劉敞','宋','宋诗','song-poetry','','[]','今年四十一，髪白牙齒脱。',156,'全唐诗/poet.song.27000.json','["今年四十一，髪白牙齒脱。", "未能遊逍遙，意毎不自豁。", "偶尋樂天詩，往在江州日。", "年幾與我同，哀疾與我埒。", "伊人了無生，外物均寂滅。", "而且于形骸，變化難自適。", "況我狹中者，萬緣日相伐。", "力小覺任重，憂多使內熱。", "安能保平和，但有就衰竭。", "賢哉香山翁，精誠妙前哲。", "懸車未六十，鼓缶終大耋。", "以茲揆損益，亦似有與奪。", "至理何心得，吾其守茲說。"]'),
('45acd7b9-aba7-4e29-8def-83e72b294320','二十六日大風寄貢甫','劉敞','宋','宋诗','song-poetry','','[]','雨止天大風，草木皆怒號。',108,'全唐诗/poet.song.27000.json','["雨止天大風，草木皆怒號。", "居人不得寐，起見星月高。", "鳥獸羣悲鳴，空虚如波濤。", "行子今安至，愴愴我心勞。", "山川幸非遠，歲月亦未滔。", "自傷下澤車，不及鄉里豪。", "衮衮隨飛蓬，悲歌撃長刀。", "丈夫寒如此，何愧兒女曹。", "無由託飛雲，更寄身上袍。"]'),
('9e03bdec-4e1c-4ab1-ae83-150ec14bb418','墨河館連日大風','劉敞','宋','宋诗','song-poetry','','[]','空桐倚不周，近戴北斗魁。',192,'全唐诗/poet.song.27000.json','["空桐倚不周，近戴北斗魁。", "上天限夷夏，自古常風霾。", "我行迫隆冬，周覽窮荒回。", "魑魅醜正直，共工負其材。", "初如百萬兵，鳴鼓天上來。", "日月慘不光，星辰爲之頹。", "又如海水翻，洪洞奔天臺。", "四顧無復人，但聽萬壑雷。", "搖山墮危石，略野荒纖荄。", "鳥雀失食悲，虎豹忘羣哀。", "大呌不自聞，卻行尚欲摧。", "而我仗漢節，何由脱氛埃。", "先王外荒服，赤子棄草萊。", "陰奸竊號令，天網殊恢恢。", "我車傷崔嵬，我馬勞虺隤。", "感彼雞鳴詩，聊以慰永懷。"]'),
('7aa35441-e283-4d75-ae12-5a6b57011591','奉和永叔夜聞風聲有感用其韻','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','往爲名山客，浩蕩多奇觀。',192,'全唐诗/poet.song.27000.json','["往爲名山客，浩蕩多奇觀。", "六月湖海卧，飄飄生羽翰。", "悮升紫垣籍，草野非所安。", "金火三伏交，束带愁衣冠。", "飛塵變形骸，內熱焦肺肝。", "豈惟天有時，人事亦可歎。", "適有凉風來，蕭騷庭葉乾。", "感之意飛動，忽若驂龍鸞。", "銀漢水可涉，枯槎去無難。", "洞庭魚正肥，遊子行足歡。", "飲酒讀離騷，睥睨天壤寛。", "要當以樂死，日月誰控摶。", "夫子文章伯，已在青雲端。", "且方濟一世，詎肯哀盤桓。", "作詩破冥煩，磊落冰雪顔。", "懔懔屈宋詞，千秋劇椒蘭。"]'),
('8dd5d7a4-e1ef-4ebd-8064-634a2511b98e','春旱天多風贈深甫','劉敞','宋','宋诗','song-poetry','','[]','春旱天多風，十步不見人。',108,'全唐诗/poet.song.27000.json','["春旱天多風，十步不見人。", "自非勢利役，誰肯輕出門。", "我亦閉戶居，寂寞臥晏温。", "歎息中庭花，散隨扶搖翻。", "百芳半摧折，白日或翳昏。", "安得超塵埃，高乘雲雷奔。", "壯心更激烈，中熱生肺肝。", "愧君憂陋巷，眷眷迂輕軒。", "高論清我懷，忽然失冥煩。"]'),
('6be23d8b-b559-4e90-b354-af8fae1ed2da','呂梁','劉敞','宋','宋诗','song-poetry','','[]','呂梁信天險，魚鼈不可游。',96,'全唐诗/poet.song.27000.json','["呂梁信天險，魚鼈不可游。", "引棹出叢石，一絙用百牛。", "洶湧含風電，蜿蜒噴蛟虬。", "世自有畏塗，吾仍恥隨流。", "側見百仞奔，俯窺千丈幽。", "自非跂達觀，未易寛百憂。", "夙昔涉老莊，縱心會虚舟。", "忠信猶足恃，放言禮門由。"]'),
('b5137279-c846-4110-a847-f5e6c9f87fcb','蜀岡南麓','劉敞','宋','宋诗','song-poetry','','[]','山深行易迷，南麓偶清曠。',96,'全唐诗/poet.song.27000.json','["山深行易迷，南麓偶清曠。", "雞犬鳴谷中，樵童戲巖上。", "茅茨肖浮居，牖戶相背向。", "竹徑通往來，清陰亦彌望。", "白頭三四老，相見語歡暢。", "心疑避世子，形迹一何放。", "行将從之遊，自恨苦羈鞅。", "不能問姓名，聊作招隱唱。"]'),
('dad48b36-ce30-42e2-8b38-38f11940a07f','種竹偶書','劉敞','宋','宋诗','song-poetry','','[]','少有王子癖，長憐此君雅。',144,'全唐诗/poet.song.27000.json','["少有王子癖，長憐此君雅。", "常嫌地喧窄，不敢謀瀟灑。", "昨日山客來，勸我栽砌下。", "感荷知我心，遂得移遶舍。", "其中置磐石，可以措尊斚。", "于此更一座，以待違名者。", "山禽時復來，清囀如郊野。", "其餘即無見，不辨春與夏。", "吾惟厭時俗，人亦來者寡。", "順然兩無議，外譽焉足假。", "新筍漸盈尺，新枝已鋪瓦。", "燕雀勿相驚，深沈似隆夏。"]'),
('e6b36506-5ab7-477a-bc3a-39d3e2f82ce0','勸思弟于南軒種竹','劉敞','宋','宋诗','song-poetry','','[]','世皆笑幽獨，何不少自貶。',120,'全唐诗/poet.song.27000.json','["世皆笑幽獨，何不少自貶。", "種竹南軒間，亦足以相檢。", "況兹歲華晚，衆卉日凋歛。", "清節良自如，栽培匪爲諂。", "豈知窗戶側，秀色窺荏苒。", "會茲東南美，相對情不慊。", "楚人昔頌橘，行比伯夷忝。", "此君最孤高，堅直難外掩。", "凛氣有精粹，筠光射圭琰。", "他時雪中客，往往疑清剡。"]'),
('bff6de0f-afcb-41af-9f52-a86c6b740820','古俠客行','劉敞','宋','宋诗','song-poetry','','[]','壮年志慷慨，結交慕英雄。',60,'全唐诗/poet.song.27000.json','["壮年志慷慨，結交慕英雄。", "大梁多長者，燕趙有古風。", "千金起爲壽，一諾不顧躬。", "自謂松與柏，忽爲萍與蓬。", "市道今乃知，利窮非義窮。"]'),
('029f75ac-e45f-4c95-acab-09bce667def3','深甫過留宿并示近詩','劉敞','宋','宋诗','song-poetry','','[]','别長會時稀，樂少憂日多。',120,'全唐诗/poet.song.27000.json','["别長會時稀，樂少憂日多。", "邂逅非素期，悲歡奈君何。", "明燈照空窗，風雪滿天地。", "此時坐相對，達旦終不寐。", "少年慕結交，徒以此方寸。", "危生始自感，來日安可問。", "意氣久已奪，形髪亦已衰。", "如何切磋意，不廢平生時。", "驚禽墜虚弦，病葉隕輕露。", "一聞傷心奏，涕下已如注。"]'),
('2195c482-d133-46fc-a5e7-15bf825aef47','留張十二宿','劉敞','宋','宋诗','song-poetry','','[]','少年有佳趣，老夫意獨驩。',48,'全唐诗/poet.song.27000.json','["少年有佳趣，老夫意獨驩。", "常恨離别久，忽忘會聚難。", "殷勤置杯杓，蕭散遺衣冠。", "誠知惜短夜，爲我强盤桓。"]'),
('6f8155c3-b954-4c4b-8721-794206ff1ce6','和鄰幾八月十五日夜對月','劉敞','宋','宋诗','song-poetry','','[]','外事已波濤，回首已陳迹。',156,'全唐诗/poet.song.27000.json','["外事已波濤，回首已陳迹。", "獨有雲間月，相見不改色。", "慰我平生懷，故在中秋夕。", "我髪見二毛，羈旅多所歷。", "毎逢桂花秋，興發勸更劇。", "江湖與山林，所至得真適。", "今年都城游，日與賤事逼。", "得閒輙昏醉，向晦專寝默。", "覺醒忽天明，不見千里白。", "誰令心賞違，坐使歳華隔。", "徘徊不自愜，悵望空歎息。", "見君新詩章，暫若對寒魄。", "清光動人目，諷詠當自釋。"]'),
('021e3b2c-249b-474f-a7a7-2bf711f67f41','腳冷','劉敞','宋','宋诗','song-poetry','','[]','踐霜腳如脱，知我血氣衰。',48,'全唐诗/poet.song.27000.json','["踐霜腳如脱，知我血氣衰。", "况復齒牙落，鬢邊亦有絲。", "人生會當老，何計遲速爲。", "但願多美酒，憂來忽如遺。"]'),
('7066e7ca-5cc0-4b09-aae0-3f3d34fab38b','和江十飲范景仁家晚宿秘閣睹伯鎮題壁記番直日月感之作五古','劉敞','宋','宋诗','song-poetry','','[]','阮公有大度，于世無所營。',216,'全唐诗/poet.song.27000.json','["阮公有大度，于世無所營。", "顧獨好飲酒，而欣爲步兵。", "未嘗語是非，舉俗駭且驚。", "夫豈知胸中，磥磈獨不平。", "西登廣武原，咄嗟豎子明。", "朅來蓬池上，詠懷激哀聲。", "此風久不聞，寥落成千齡。", "鄰幾頗其流，貧賤能忘形。", "校書天祿閣，不忍游公卿。", "時從好事飲，傲兀人間情。", "髪白不自疑，歸來臥前楹。", "顧是壁上書，始知歳月傾。", "喟然感舊交，因欲東南行。", "黄鵠真去矣，白雲遠冥冥。", "吾聞至人語，大塊勞我生。", "天地一毫間，出處何重輕。", "但使樽有酒，長醉不用醒。", "君當觧此意，獨往何必清。"]'),
('7cf3798b-3790-4a45-92bf-2138af008bbc','賀王介甫初就職秘閣','劉敞','宋','宋诗','song-poetry','','[]','鳳凰信高遠，矰繳安得羈。',96,'全唐诗/poet.song.27000.json','["鳳凰信高遠，矰繳安得羈。", "非君九韶奏，詎肯一來儀。", "王子美無度，孤飛絕雲霓。", "常恐濁一世，斯人莫見之。", "天子蹈軒虞，公卿聚臯夔。", "孰言阿閣下，定有朝陽詩。", "願得調律呂，聆音辨雄雌。", "毋空著圖象，但取夸童兒。"]'),
('e5161f02-92d9-48ea-a49f-8501a6cc38d9','修府學後同官僚見諸生','劉敞','宋','宋诗','song-poetry','','[]','用儒沐休運，撫俗奉明詔。',120,'全唐诗/poet.song.27000.json','["用儒沐休運，撫俗奉明詔。", "雖愧文翁治，猶非武城笑。", "兹堂丞相規，頗盡泮宫妙。", "高閣横青冥，長廊騖䆗窱。", "春秋大復古，修舊非所誚。", "庭壇一已新，丹堊欻相照。", "迂疏賴衆才，簡默希坐嘯。", "况多都邑賢，歷講道術要。", "藩籬可目涉，弦誦或耳剽。", "氾鄉亦何人，千載名獨劭。"]'),
('e831f110-219b-4950-9ad7-322fa97e41dd','煌煌京洛行','劉敞','宋','宋诗','song-poetry','','[]','紫極開天門，慶雲麗皇居。',120,'全唐诗/poet.song.27000.json','["紫極開天門，慶雲麗皇居。", "卜郊定九鼎，懸闕觀寶書。", "德澤浸無疆，風俗返華胥。", "冠蓋百萬家，車馬十二衢。", "輕肥耀朝日，富庶極中區。", "游俠信陵後，節義大梁餘。", "顧盼生光輝，吹拂動萎枯。", "貴賤且貿遷，高陵忽爲墟。", "變化若有神，升沉豈嘗拘。", "咄嗟鄒魯士，何用空躊躇。"]'),
('22af51fc-3844-4d46-b75b-fdc18f2d544f','代書寄鴨腳子于都下親友','劉敞','宋','宋诗','song-poetry','','[]','予指老無力，不能苦多書。',72,'全唐诗/poet.song.27000.json','["予指老無力，不能苦多書。", "書苟過百字，便覺筋攣拘。", "京都多豪英，往往在石渠。", "作書不可周，寄聲亦已疏。", "後園植佳果，遠贈當鯉魚。", "中雖無尺素，加餐意何如。"]'),
('a36c7033-0a9c-4ee0-b570-22edc5924379','寄貢甫時隨侍入蜀','劉敞','宋','宋诗','song-poetry','','[]','曩别百里近，愁心亂清秋。',96,'全唐诗/poet.song.27000.json','["曩别百里近，愁心亂清秋。", "今别百里遙，秋色縈遠愁。", "我飛乏羽翰，我居悵淹留。", "忽如轅下馬，局足難自謀。", "古人有先覺，不願往諸侯。", "我乃今知之，曰歸邈無由。", "朝吟南陵篇，暮弦梁山謳。", "離魂如明月，昔昔西南流。"]'),
('2fdd7ccc-dd9d-4a56-9946-6798a4255f49','戴村','劉敞','宋','宋诗','song-poetry','','[]','羈旅淹歳改，江臯屬春早。',72,'全唐诗/poet.song.27000.json','["羈旅淹歳改，江臯屬春早。", "幽村屢獨往，勝事時默討。", "深竹尚殘雪，陽崖已芳草。", "茅茨忽連接，鄰里自相保。", "人猶安道族，景是山陰道。", "徘徊問耆舊，或遇棲真老。"]'),
('e3766716-7c16-43f8-84f2-c38fa3e13c03','種瓜瓠','劉敞','宋','宋诗','song-poetry','','[]','吾生拙用大，江海思遠適。',96,'全唐诗/poet.song.27000.json','["吾生拙用大，江海思遠適。", "豈獨爲瓠瓜，長繫取不食。", "漆園有遺意，放蕩豁心臆。", "樹此無何鄉，近身見多益。", "五日拙一旬，十日成百尺。", "纍蔓更相引，甘實行可摘。", "因之浮汗漫，去矣笑跼蹐。", "從我其誰與，由也不可得。"]'),
('a4e41166-e2ab-48cb-bf20-1f9b4691f3fa','簡深甫','劉敞','宋','宋诗','song-poetry','','[]','與君一城居，其實跬步間。',120,'全唐诗/poet.song.27000.json','["與君一城居，其實跬步間。", "慊慊不相從，十日俄忽然。", "一城豈爲遠，十日豈爲短。", "客子局人事，心與迹相反。", "而況各異鄉，茫茫隔山陂。", "歲時若奔車，過去誰復推。", "伊昔厭幽獨，願子東西鄰。", "雖鄰尚不覿，何似南北人。", "人間實如此，千别能一會。", "興來即上馬，埽塌聊相對。"]'),
('b81c3af6-72a8-4443-b298-d4ed78e535ef','贈陳襄秘丞自峽中召歸','劉敞','宋','宋诗','song-poetry','','[]','淮海南國衝，冠蓋結浮雲。',120,'全唐诗/poet.song.27000.json','["淮海南國衝，冠蓋結浮雲。", "面交固不數，白首猶若新。", "之子天際來，各自東西人。", "一語旦連夕，歡如平生親。", "豈伊名聞久，固以意氣均。", "馳騖詩書間，博哉醇乎醇。", "我昔病俗學，莫明聖與仁。", "常恐遂至地，豈期晚有鄰。", "君還覲清光，一二席上珍。", "賢者任必重，勉旃覺斯民。"]'),
('4ec218ba-2d97-4214-9e3a-943587e91799','送沖卿守高郵','劉敞','宋','宋诗','song-poetry','','[]','雞騖守樊籠，鴻鵠游四溟。',72,'全唐诗/poet.song.27000.json','["雞騖守樊籠，鴻鵠游四溟。", "羡君一麾去，不負人間名。", "孤帆西北風，海日東南明。", "回首笑富貴，浮雲亦何輕。", "我憶童子時，綵衣戲五亭。", "離懷重自感，堕淚沾長纓。"]'),
('2385b09d-23a4-4a5f-8a95-9d4be2257326','聞王十八除檢討','劉敞','宋','宋诗','song-poetry','','[]','滄海有蓬萊，去人初不遠。',96,'全唐诗/poet.song.27000.json','["滄海有蓬萊，去人初不遠。", "舟車有難到，方士曾空返。", "聞子騎鯨魚，姓名已金簡。", "誰云路幽險，但怪波清淺。", "俯窺紫貝闕，洞視白玉版。", "神仙豈學致，變化絕微顯。", "乃知淮南藥，力可及雞犬。", "相望雲霧深，冥冥白日晚。"]'),
('21295711-6368-46da-873d-82c62027262b','任城道中','劉敞','宋','宋诗','song-poetry','','[]','驅車太山下，過憩任與樊。',120,'全唐诗/poet.song.27000.json','["驅車太山下，過憩任與樊。", "此地昔建侯，邈哉羲皇孫。", "市朝非一世，茂草空平原。", "三十餘萬歲，忽如飛鴻奔。", "毁墓骨已銷，但有石槨存。", "縱横委路隅，冥漠游岱魂。", "古今一邱貉，成敗誰復論。", "區區東家翁，乃復哀璵璠。", "牛山顧千駟，涕下何由諼。", "忠義獨不朽，庶幾長者言。"]'),
('e3ef5b84-a31d-4167-b515-bacd3f57a474','陳橋别隱直','劉敞','宋','宋诗','song-poetry','','[]','柔遠在無外，飲冰寧顧家。',120,'全唐诗/poet.song.27000.json','["柔遠在無外，飲冰寧顧家。", "旌麾辭北闕，原隰生光華。", "水涸雨亦收，勁風卷驚沙。", "送車何其多，高蓋垂文緺。", "張侯平生親，情義固所加。", "哀我志慷慨，睠我天一涯。", "出宿水上亭，暮談見晨霞。", "百里亦已遠，心乎不云遐。", "我自東西人，豈能守蓬麻。", "周爰愧靡及，敢不重拜嘉。"]'),
('1682b7e2-904b-4043-8eff-28b3aa98efe7','答江鄰幾到潁州見寄并封示晏公送行','劉敞','宋','宋诗','song-poetry','','[]','日夕風雪佳，相念思乘興。',132,'全唐诗/poet.song.27000.json','["日夕風雪佳，相念思乘興。", "忽憶君在遠，離憂紛難定。", "入門對新詩，滿眼冰玉瑩。", "因疑君居側，恍惚不自勝。", "别来雖無幾，日月稍已迸。", "一葦悲河廣，况乃山川迥。", "遠遊殊風土，孤響謬羣聽。", "常恐弔原憲，夫子歎何病。", "幸傳丞相篇，復見仁者贈。", "懸知愜真賞，有以誇歷聘。", "何用慰索居，一朝再三詠。"]'),
('89a744e3-8954-4e69-adb0-c58bd1134a05','寄深甫兄弟時在潁','劉敞','宋','宋诗','song-poetry','','[]','回面簿領役，終歲無一欣。',96,'全唐诗/poet.song.27000.json','["回面簿領役，終歲無一欣。", "思君阻晤語，坐想如古人。", "百里非遐方，書疏絕相聞。", "亦知平生懷，未爲疏數分。", "昔君幸見憐，約禮博以文。", "今也知不及，瞠然已絕塵。", "裹飯更欲馳，漭漭風雪晨。", "高會汝潁間，千秋愧荀陳。"]'),
('a94a80d2-9688-4254-9792-5777fd052d3d','舟次潁上寄貢甫','劉敞','宋','宋诗','song-poetry','','[]','我詩持寄君，宛在汝水潯。',96,'全唐诗/poet.song.27000.json','["我詩持寄君，宛在汝水潯。", "君詩欲寄我，蒼茫烟浪深。", "寒水争赴壑，駛流激清音。", "扁舟泝游往，寂寞嗟獨尋。", "潁烟稍塞望，淮月初清心。", "恨無知賞同，樽酒誰獻斟。", "相思意不極，宛抑訴鳴琴。", "曉燈半明滅，抱膝成苦吟。"]'),
('07d94ee2-6dfd-4d62-96e8-72a8e6155097','古意三首  其一','劉敞','宋','宋诗','song-poetry','','[]','相逢偶相識，相識竟相離。',48,'全唐诗/poet.song.27000.json','["相逢偶相識，相識竟相離。", "會知别情苦，寧作未相知。", "相見如夢中，夢中還相見。", "薄帷鑒明月，恍惚仍對面。"]'),
('c93a0025-d4d5-4a59-8f2c-f987ddf184bf','古意三首  其二','劉敞','宋','宋诗','song-poetry','','[]','主父昔未仕，頗爲鄉人輕。',60,'全唐诗/poet.song.27000.json','["主父昔未仕，頗爲鄉人輕。", "上書雖晚達，稱說何縱横。", "不忍脱粟飯，甘爲五鼎烹。", "豈不愛厥身，徒爲喪其生。", "吾聞南山翁，軒冕不得榮。"]'),
('3296b1cb-eecb-44cb-b3ce-0878b39ef908','古意三首  其三','劉敞','宋','宋诗','song-poetry','','[]','柳下不違俗，獨恥伐國言。',60,'全唐诗/poet.song.27000.json','["柳下不違俗，獨恥伐國言。", "三黜何嘗憂，一問遂慘然。", "世衰狙詐用，賢者防其源。", "孟軻不言利，顧有仁義存。", "何乃百世後，功名爲時敦。"]'),
('1f3af6d6-2b8c-4ce3-b66f-f762007edafa','秋意四首  其一','劉敞','宋','宋诗','song-poetry','','[]','陰蟲鳴空階，危葉墮高樹。',48,'全唐诗/poet.song.27000.json','["陰蟲鳴空階，危葉墮高樹。", "秋風雖昨日，所遇已如故。", "悠悠歲方晏，采采行多露。", "芳香日可閔，宛彼蘭與杜。"]'),
('132c701d-7b65-435e-a5e4-05e0551caca4','秋意四首  其二','劉敞','宋','宋诗','song-poetry','','[]','鴻鴈起海濱，凌風自翺翔。',48,'全唐诗/poet.song.27000.json','["鴻鴈起海濱，凌風自翺翔。", "冥冥清雲間，矰繳安可望。", "千里一悲鳴，一里一徬徨。", "時變感自深，豈伊恨越鄉。"]'),
('c39dde98-ef06-4595-bf41-e6934417ffd7','秋意四首  其三','劉敞','宋','宋诗','song-poetry','','[]','鷾鴯信多智，出處能自謀。',48,'全唐诗/poet.song.27000.json','["鷾鴯信多智，出處能自謀。", "非無人間畏，而襲人間遊。", "微風動高林，梁棟生早秋。", "歛翼從所願，落實安得留。"]'),
('3714a8ca-ef37-4082-a5bd-7b97b0d4dac7','秋意四首  其四','劉敞','宋','宋诗','song-poetry','','[]','翻翻林間藿，昔惟桃李華。',48,'全唐诗/poet.song.27000.json','["翻翻林間藿，昔惟桃李華。", "飄颻終焉薄，江海無津涯。", "榮華寄須臾，憔悴空泥沙。", "良無凌霜節，安得復嘆嗟。"]'),
('5e2f4211-586c-4e58-ab0d-9687e2a821d8','雨晴率張生及諸弟到建福僧居','劉敞','宋','宋诗','song-poetry','','[]','沈陰天氣昏，忽霽景物好。',120,'全唐诗/poet.song.27000.json','["沈陰天氣昏，忽霽景物好。", "牆陰且殘雪，池岸已芳草。", "愁懷無端涯，强出慰枯槁。", "白日當青天，所至豁如埽。", "山僧一飯畢，鐘鼓不復考。", "庭宇若無人，窗軒照丹藻。", "徒行不知遠，適興愜所禱。", "如覺逍遙遊，頗堪謝煩惱。", "諸子吾宗秀，張生一經老。", "相顧能不言，歡然屢絕倒。"]'),
('d71c984c-4cc5-404b-a74b-62d8abc09a39','初鴈','劉敞','宋','宋诗','song-poetry','','[]','翩翩南飛鴈，契闊萬里道。',72,'全唐诗/poet.song.27000.json','["翩翩南飛鴈，契闊萬里道。", "朔雪常逼秋，知幾諒宜早。", "敵兵盛西北，弓矢斷飛鳥。", "側翅鋒鏑間，悲鳴觸懷抱。", "往時商山翁，自放亦忘老。", "避地吾所師，相望戒輕矯。"]'),
('e1f69b60-a87c-40ce-8571-df6b932f5826','始聞鴈','劉敞','宋','宋诗','song-poetry','','[]','冬夜何漫漫，北風扇凄惻。',84,'全唐诗/poet.song.27000.json','["冬夜何漫漫，北風扇凄惻。", "始聞南飛羽，稍稍過我側。", "来賓無乃後，恐非歲時忒。", "朔方稽常貢，物性隨變易。", "哀音一何厲，路遠霜雪積。", "就陽既云歸，感義寧自默。", "胡爲堂上士，撫劍重歎激。"]'),
('698ab92f-eeef-4a08-94b6-0c1bb9f91c95','沒蕃士','劉敞','宋','宋诗','song-poetry','','[]','丁年仕轅門，欲食萬里肉。',264,'全唐诗/poet.song.27000.json','["丁年仕轅門，欲食萬里肉。", "敵兵方强梁，邊境日局縮。", "是時十月交，轉戰大河曲。", "落日天地昏，風塵蔽川陸。", "我師自憑陵，虜騎出深谷。", "路窮矢交墜，壮士同僇辱。", "投身致網罟，南向長慟哭。", "忠義安可論，功名亦已覆。", "悠悠捐歲序，忽忽抱心曲。", "每生悔爲禍，致死倘還福。", "夜渡黄河冰，獨依荒榛宿。", "狐狸鳴我旁，虎豹相馳逐。", "脱身僅毫毛，夜動晝必伏。", "肌膚存空骨，性命半鬼籙。", "十月到亭堠，門人識風俗。", "回頭復長望，慷慨淚盈目。", "憶昔萬人出，今還一身復。", "可憐同時輩，視我猶鴻鵠。", "永棄絕域中，幾時脱臣僕。", "叩門謁主帥，長跪向人哭。", "可汗甚桀黠，其下亦輯睦。", "弩力思長策，勿輕用人屬。"]'),
('c5763678-4d66-4273-a56d-e15a075dc5e2','寄子華內翰時亦宿齋是夕風雨','劉敞','宋','宋诗','song-poetry','','[]','君居白玉堂，我在紅藥署。',48,'全唐诗/poet.song.27000.json','["君居白玉堂，我在紅藥署。", "出處豈不同，咫尺限相遇。", "風雨聞雞鳴，節物驚歲暮。", "思君正展轉，夢中亦知路。"]'),
('105f372c-ab6e-4c98-b25b-484feae76033','和江鄰幾雪軒與持國同賦二首  其一','劉敞','宋','宋诗','song-poetry','','[]','君居近城市，每獨厭囂煩。',60,'全唐诗/poet.song.27000.json','["君居近城市，每獨厭囂煩。", "積雪成高卧，故人来在門。", "埽除更爽塏，談笑寂無喧。", "開窗延寒月，拂席置清樽。", "真得酒中趣，安知狐白温。"]'),
('c7548a54-f54d-4246-84b1-1f47cde17487','和江鄰幾雪軒與持國同賦二首  其二','劉敞','宋','宋诗','song-poetry','','[]','長安雖大雪，車馬無休時。',72,'全唐诗/poet.song.27000.json','["長安雖大雪，車馬無休時。", "窮巷有高士，閉門獨何爲。", "朝烟不黔突，彈琴方賦詩。", "逍遙無忤色，慷慨多逸辭。", "適有感同好，寄聲贈所思。", "調高當和寡，無以答君知。"]'),
('21a68cc5-ef33-4055-ad22-f718c7df5551','養雞','劉敞','宋','宋诗','song-poetry','','[]','茅茨一畝宮，生理備委曲。',120,'全唐诗/poet.song.27000.json','["茅茨一畝宮，生理備委曲。", "雞豚自古昔，豢養隨世俗。", "鑿垣安其棲，幼長何碌碌。", "旦出四散飛，暮還相從宿。", "頗哀鴻鵠輩，飲啄不充腹。", "何事萬里遊，羈旅傷局促。", "衣冠相嫵媚，庭廡更追逐。", "未悟糞土非，豈知稻粱辱。", "物理常有此，人情苦不足。", "安見避世翁，頽然卧空谷。"]'),
('6ec06cce-11b6-4016-85ea-6f8f85106bd6','乘小舟入朝京門訪安道','劉敞','宋','宋诗','song-poetry','','[]','南山厭清流，春光滿上頭。',48,'全唐诗/poet.song.27000.json','["南山厭清流，春光滿上頭。", "懷人不勝意，乘興去扁舟。", "静吟日光午，孤棹正脩脩。", "固當見安道，曷若王子猷。"]'),
('df2162ee-127b-495a-92c3-4449bc97a8ab','送陳奇秘校遊寝邱','劉敞','宋','宋诗','song-poetry','','[]','世往人物非，古今共滔滔。',132,'全唐诗/poet.song.27000.json','["世往人物非，古今共滔滔。", "聞君寝邱客，因憶孫叔敖。", "脱身田野間，功業青雲高。", "憂國不顧家，子孫負薪勞。", "苟無滑稽士，亦已埋蓬蒿。", "嗟来千戶封，晚受侯王褒。", "賢卿尚遺忘，反慕貪與饕。", "况彼里閭人，安能厭糠糟。", "伊昔方斷蛇，許身輕鴻毛。", "陰德尚有報，天寧紿吾曹。", "努力道路勤，我心良鬱陶。"]'),
('c57d0788-f9c0-49b0-aaad-8e017c8be109','宴得解進士','劉敞','宋','宋诗','song-poetry','','[]','汝潁紀南國，星極麗中州。',120,'全唐诗/poet.song.27000.json','["汝潁紀南國，星極麗中州。", "多奇兆兩漢，粹氣兼九邱。", "里巷含古風，文章耀前修。", "上恩榮計偕，博選充詔求。", "雜沓會駿骨，軒昂出驊騮。", "日余瞢深識，有司屬同憂。", "攻玉固以石，妍媸豈云侔。", "登龜但投餌，美惡非其儔。", "堂上歌鹿鳴，樽前親獻酬。", "有功幸九錫，與祭爲諸侯。"]'),
('227336ee-6849-4aee-b4d7-268fb7e8058f','送胥元衡殿丞通判湖州','劉敞','宋','宋诗','song-poetry','','[]','平生笑山濤，非隱復非吏。',120,'全唐诗/poet.song.27000.json','["平生笑山濤，非隱復非吏。", "今更欲似之，顛瞑老将至。", "羡君負清識，於世寡所求。", "能從魏闕下，徑取江湖遊。", "扁舟駕長風，千里破高浪。", "倚檣一清嘯，佚氣横雲上。", "醲碧箬下酒，紅鱗苕溪魚。", "綵衣起爲壽，此樂天下無。", "誰不慕軒冕，顧多困朝市。", "人生難自諧，祿仕當若此。"]'),
('d2f81eb1-f02e-4ec3-843f-da73ade51d90','譏謝十三','劉敞','宋','宋诗','song-poetry','','[]','利交勢相營，義交氣相得。',96,'全唐诗/poet.song.27000.json','["利交勢相營，義交氣相得。", "千歲若旦暮，萬里猶咫尺。", "昔我相聞聲，但嫌未相識。", "今我相同遊，又恨莫相益。", "同時復同道，同官又同籍。", "平生重結交，然諾亦自惜。", "子爲太守丞，我爲里中客。", "雖復戒疏數，不應事形迹。"]'),
('0f98bad1-857c-4f09-ad7b-1bd57d7cfd42','宿九里潭','劉敞','宋','宋诗','song-poetry','','[]','潭樹老垂葉，蔭兹千百尋。',36,'全唐诗/poet.song.27000.json','["潭樹老垂葉，蔭兹千百尋。", "蛟潛伏遺劍，魚躍應鳴琴。", "遠客何所羡，神淵涵净心。"]'),
('7363f105-62f2-42b5-ad9f-ee9a11a633c8','橄攬','劉敞','宋','宋诗','song-poetry','','[]','吾昔評橄欖，不在百果後。',168,'全唐诗/poet.song.27000.json','["吾昔評橄欖，不在百果後。", "其材中棟梁，其實過橙楱。", "俗人多未識，至美或莫售。", "材以遠見遺，實以苦爲詬。", "華堂娛嘉賓，甘脆陳左右。", "此物萬里来，真味寧免陋。", "欲觀絕倫效，宜與危事遘。", "江魚肆潛毒，頃刻輒僵仆。", "昔酒發狂醒，千日尚沈瞀。", "性命如危絃，一絕不可救。", "幸能服刀圭，咄嗟反其舊。", "此亦天下奇，能使夭者壽。", "豈殊魯連子，談笑解紛鬭。", "功成歸海濱，不願千乘富。"]'),
('b2ddba70-7fce-4bfa-880c-e7399bb5585b','聞伯庸再安撫涇原','劉敞','宋','宋诗','song-poetry','','[]','西師又失律，将帥各顛覆。',216,'全唐诗/poet.song.27000.json','["西師又失律，将帥各顛覆。", "流血丹川原，積屍委山谷。", "咄嗟仁壽域，短夭生理促。", "王命有不行，國威爲之衂。", "鄙夫無憂責，感慨祗慟哭。", "况聞哀痛詔，輟食想頗牧。", "朝廷足名卿，多壘各含辱。", "謀議宜深長，瘡痍待湔浴。", "使乎非常任，天子意所屬。", "百萬氣未蘇，吾民且局縮。", "賢人勤功名，報國忍勞篤。", "往者博望侯，昔時来君叔。", "再三持漢節，白髪走川陸。", "豈不久憔悴，事業光簡牘。", "關河據上游，郡國同心腹。", "征膳向五年，强宗亦單獨。", "君乘赤輪車，一一詢比屋。", "唐虞升平風，惆悵難再沐。"]'),
('e5f5e6e8-25a5-4495-8792-c46ba8c7bda5','鄰幾過門不留戯作','劉敞','宋','宋诗','song-poetry','','[]','陳平少負郭，亦回長者車。',120,'全唐诗/poet.song.27000.json','["陳平少負郭，亦回長者車。", "貧賤雖足羞，猶問道何如。", "此風固宜少，未謂今便無。", "所望臺閣賢，尚能念古初。", "左轓塗朱漆，長綬要銀魚。", "化我不少留，始知心見疏。", "彌年寄祿仕，竟日勞簿書。", "相與同笑言，俱幸逃空虚。", "春秋期知我，雅頌誨起予。", "兹意未可忘，君宜誦權輿。"]'),
('7a4067b8-bf32-433c-a2b2-52efc1382e49','秋雪','劉敞','宋','宋诗','song-poetry','','[]','剝候凋羣陽，幽陰肆騰涌。',180,'全唐诗/poet.song.27000.json','["剝候凋羣陽，幽陰肆騰涌。", "清霜飛雲初，大雪吁不凶。", "繽紛舞鴻鵠，細碎翻蠛蠓。", "北風故相資，凍雨仍更縱。", "泥塗絕行道，珠璧棄郊壟。", "峩峩九重高，兀兀雙玉聳。", "寒光坐輝映，凛氣彌衝擁。", "壮士歌慷慨，儒生議刑寵。", "長年昔未逢，噤語空多悚。", "皇天無私尤，德惠答虔鞏。", "豈伊傷時和，盖亦遵順動。", "况兹秋方高，民麥皆在隴。", "龍蛇蟄既坯，鳥獸毛亦氄。", "農夫樂休役，天子寛垂拱。", "信此豐年祥，爾曹何必恐。"]'),
('0ad18867-4b76-4a4c-8880-30bff3dc6db0','秋雪寄獻臣','劉敞','宋','宋诗','song-poetry','','[]','三年海水旁，卑濕厭歊熱。',72,'全唐诗/poet.song.27000.json','["三年海水旁，卑濕厭歊熱。", "都城幸相從，比歲秋逢雪。", "秦吳乖風土，南北異時節。", "惟君歲寒姿，一致乃欲别。", "出門顧道路，冰霰埋車轍。", "咫尺阻相過，誰當慰寥泬。"]'),
('81595a3b-eb90-41f4-a5c5-a0b73e014ef5','城樓','劉敞','宋','宋诗','song-poetry','','[]','新晴彊人意，步上西城樓。',48,'全唐诗/poet.song.27000.json','["新晴彊人意，步上西城樓。", "雲烟開井邑，綺繡錯田疇。", "離離麥就熟，翳翳桑尚柔。", "懷歸感初服，覽物悵淹留。"]'),
('d3490bec-55cd-4319-83ae-cef320f3b473','子高作司諫見舉自代','劉敞','宋','宋诗','song-poetry','','[]','智短多不堪，冗官略自保。',96,'全唐诗/poet.song.27000.json','["智短多不堪，冗官略自保。", "念非撥煩用，猶覬趙魏老。", "故人紫微仙，自致青雲早。", "回首記平昔，露章慰枯槁。", "先容輪囷木，進取萬里道。", "妄意巉巖石，庶幾千金寶。", "過聽爲君羞，貪名怯陰討。", "人亦謂我何，自笑方絕倒。"]'),
('142402d8-d8d6-4651-92be-de799c4e002f','聞子飛作諫官寄隱直','劉敞','宋','宋诗','song-poetry','','[]','玉以二獻珍，金以百鍊精。',120,'全唐诗/poet.song.27000.json','["玉以二獻珍，金以百鍊精。", "錢侯困躓時，詎免時俗輕。", "感激生憤勇，辛勤就功名。", "居然取高第，自此凌諸生。", "諫官近冕旒，地望臨公卿。", "報國須薦賢，致君在舉能。", "蕭朱尚結綬，張杜猶提衡。", "小雅紀伐木，微禽識同聲。", "此風久已無，賢者當肯行。", "念子早治装，復令世人驚。"]'),
('b5f4b001-41f4-4c85-b172-661e7039f62b','賀隱直','劉敞','宋','宋诗','song-poetry','','[]','三年守一官，五年調一職。',132,'全唐诗/poet.song.27000.json','["三年守一官，五年調一職。", "選門萬餘人，過半頭髪白。", "賢愚必待次，先後各循格。", "相與爲波流，其誰辨白黑。", "子今特招起，方與塵土隔。", "翰林誠知人，中丞亦好德。", "古来御史屬，自與二府敵。", "於今任雖卑，其實名不易。", "必将寄紀綱，豈獨親簿籍。", "鴻鵠須遠飛，騏驥無近迹。", "往矣勿自疑，天方佑正直。"]'),
('75f1f4d9-e612-415e-a170-0efb4fcc66ea','賀王純臣','劉敞','宋','宋诗','song-poetry','','[]','昔者巖穴客，多隨辟書起。',120,'全唐诗/poet.song.27000.json','["昔者巖穴客，多隨辟書起。", "榮名耀山澤，高閣下閭里。", "此道不復振，此時竟已矣。", "不圖廷中賢，有意及之子。", "十年困鄉書，三黜竟不仕。", "一朝遘知音，籍籍到天耳。", "窮通諒有數，自古多若此。", "年華猶未晚，富良方自治。", "伐木情所深，彈冠坐增喜。", "請歌反招隱，以激南州士。"]'),
('db53240d-f88b-49c2-bfb5-0ae82dfbe5f1','詠庭檜贈深甫','劉敞','宋','宋诗','song-poetry','','[]','自吾卧家巷，幽獨謝鄰里。',96,'全唐诗/poet.song.27000.json','["自吾卧家巷，幽獨謝鄰里。", "顧憐庭中檜，常以比君子。", "春秋色不變，朝夕影雙峙。", "誰言冰霰繁，稍亂蒹葭毁。", "始知歲寒甚，慘慘不自喜。", "悵然對之歎，爾復那至此。", "陳蔡稱愠見，由也德可鄙。", "天損吾能違，放歌有焱氏。"]'),
('8f53b76a-e4d4-4aa9-85d4-0f03ea7f47e4','檜花','劉敞','宋','宋诗','song-poetry','','[]','百花乘春輝，紅白相嫵媚。',120,'全唐诗/poet.song.27000.json','["百花乘春輝，紅白相嫵媚。", "暫開已半落，過眼如夢寐。", "繁奢能幾時，寂寞都埽地。", "兒童惜徘徊，婦女瞻歔欷。", "中庭兩檜樹，百尺浮雲際。", "芳意不玩俗，秀色亦自喜。", "綠烟凝參差，金粟點細碎。", "霏霏墮疏香，裊裊隔清吹。", "足明後凋節，不與衆草類。", "忽思折瑤花，自放天宇外。"]'),
('c71016ab-89cc-4559-8ec3-74062439286d','初秋病中作五言呈君錫待制介夫學士','劉敞','宋','宋诗','song-poetry','','[]','蹇淺闇聞道，螴蜳自焚和。',120,'全唐诗/poet.song.27000.json','["蹇淺闇聞道，螴蜳自焚和。", "負兹歲陰改，閉閣秋風過。", "濃露變園草，號蟬翳庭柯。", "覽時悵頽暮，顧影驚婆娑。", "平生江湖尚，薄遊不願多。", "奚爲役外物，况乃淹舊疴。", "徂西識艽野，采菽聆悲歌。", "今昔容不同，情感殆靡他。", "勞生共逆旅，馳景均騰波。", "行矣自免歸，息陰安薜蘿。"]'),
('09b09542-8453-4c2c-b9bf-4b4261ffc1f6','送王子直還斤溝','劉敞','宋','宋诗','song-poetry','','[]','薄薄雲蔽日，凄凄寒中人。',48,'全唐诗/poet.song.27000.json','["薄薄雲蔽日，凄凄寒中人。", "飛飛燕歸蟄，漠漠鴈来賓。", "送子獨無友，悲秋空病身。", "登山復臨水，便覺二毛新。"]'),
('9896801f-c72f-4daf-9873-3c9f65e44ea8','初卜潁州城西新居','劉敞','宋','宋诗','song-poetry','','[]','羈鳥能擇木，游魚知赴淵。',72,'全唐诗/poet.song.27000.json','["羈鳥能擇木，游魚知赴淵。", "飛沈豈異意，行止私自憐。", "玩世本無術，辟人庸得賢。", "卜居幸樂國，負廓依良田。", "心與地俱遠，我徒共熙然。", "生涯亦何有，聊以忘吾年。"]'),
('38aaaec3-2ec4-4e02-8a98-384f8749c2c1','早行','劉敞','宋','宋诗','song-poetry','','[]','虚舟却煩暑，初旦更清和。',72,'全唐诗/poet.song.27000.json','["虚舟却煩暑，初旦更清和。", "塵襟暫軒豁，幽興亦滋多。", "黄鳥囀深樹，良魚躍層波。", "岸花間紅紫，村叟雜笑歌。", "稍忘溯洄力，未悟歲時過。", "側肩市朝客，偃蹇奈予何。"]'),
('a3f9e86e-def2-4e58-baaf-ff19d3e137fd','晴日後園','劉敞','宋','宋诗','song-poetry','','[]','羣鳥飛朝日，鳴鶴響晴空。',72,'全唐诗/poet.song.27000.json','["羣鳥飛朝日，鳴鶴響晴空。", "宿雪乍消釋，滯陰反冲融。", "幽居亦可愛，老圃願與同。", "負暄空林下，遊目故城東。", "世事見流水，歲華指飛蓬。", "酣歌用自適，貧賤何必終。"]'),
('189b134d-cff6-44c7-beff-5d86bd043a3b','新作石林亭','劉敞','宋','宋诗','song-poetry','','[]','朝廷入忘返，山林往不還。',144,'全唐诗/poet.song.27000.json','["朝廷入忘返，山林往不還。", "念無高世姿，聊處可否間。", "築基倣崔巍，鞭石輕險艱。", "羣玉相磊落，萬峰正孱顔。", "種樹亦蒼蒼，激流復潺潺。", "湡浯歘在眼，崐閬若可攀。", "自我嬰世網，邇来鬚毛斑。", "丘壑成弱喪，簿書常自環。", "及爾滅聞見，曠如遠塵寰。", "豈敢同避世，庶幾善閉關。", "子牟困懷魏，謝傅悲徂山。", "兹焉可遺老，詎厭終歲閒。"]'),
('c4bde588-91c6-46ab-a664-8d9c5a0c1714','樊口','劉敞','宋','宋诗','song-poetry','','[]','回舟武昌郭，暫往樊水上。',144,'全唐诗/poet.song.27000.json','["回舟武昌郭，暫往樊水上。", "樊水何清冷，樊山亦孤壮。", "壽藤驗百歲，喬木過十丈。", "絕俗殊崎嶇，攀緣幸可傍。", "林端見漁舍，戶牖相背向。", "雞犬鳴雲中，神仙豈殊状。", "昔聞元次山，於焉寄荒浪。", "鄰里俱已非，陵谷平得喪。", "茅茨固微物，蕪滅不可訪。", "向乏數卷書，終隨衆人葬。", "清時易直道，末俗擯高尚。", "陳迹成渺茫，孤吟屢惆悵。"]'),
('8c04c42a-31a6-47de-8e1a-0c533011af94','宿州道中逢聖俞入京','劉敞','宋','宋诗','song-poetry','','[]','翩翩河中船，一西復一東。',72,'全唐诗/poet.song.27000.json','["翩翩河中船，一西復一東。", "相逢且不留，相别何時逢。", "黄鵠安稻粱，有時顧池籠。", "一爲滄浪去，不復思樊中。", "哀君蒼髪白，擾擾悲途窮。", "努力千萬乘，寄聲謝醉翁。"]'),
('a90833c6-9ae6-4bb6-8462-bea5f6dfe07f','謝學士赴闕還京師','劉敞','宋','宋诗','song-poetry','','[]','公提史臣筆，記注天子側。',108,'全唐诗/poet.song.27000.json','["公提史臣筆，記注天子側。", "日成唐虞風，噩噩在典策。", "家聲繼純粹，論著多切直。", "周南未成書，流涕嘗感激。", "忽從東溟飛，上拱宸斗極。", "清淮净無波，歸馬閑且奕。", "帝宫青冥間，白日升曉色。", "儒人相慶語，文道宜久職。", "公歸演綸誥，制度期能覿。"]'),
('2f657e9c-073b-4490-8f3c-40ef8dab7636','和甫自京師至','劉敞','宋','宋诗','song-poetry','','[]','過事與日多，歡憂兩如夢。',96,'全唐诗/poet.song.27000.json','["過事與日多，歡憂兩如夢。", "安知盈樽酒，此國今宵共。", "寸心不如昔，感遇每易動。", "孤笑破羣愁，强顔不爲用。", "天河轉屋角，缺月照樑棟。", "燼落屢繽紛，良時亦倥偬。", "驪駒晨在門，十里起相送。", "暫醉醒不遲，舊愁来更重。"]'),
('9ffec023-1e03-4674-b79f-753e5be06c88','得鄰幾書','劉敞','宋','宋诗','song-poetry','','[]','君乘使者車，我爲列郡守。',144,'全唐诗/poet.song.27000.json','["君乘使者車，我爲列郡守。", "地理秦與越，天文井兼斗。", "夢寐且不通，言笑安得同。", "忽傳咫尺書，遠愧西南風。", "衰老容貌遷，憂患志氣落。", "聞君白紛如，我亦不如昨。", "捨書計離别，忽忽三四年。", "一日成九秋，此語猶信然。", "天地大逆旅，外物不可必。", "出處多舛馳，相逢定何日。", "尚禽晚且游，沮溺長耦耕。", "此意雖未合，且當勤寄聲。"]'),
('e445ad3a-06b4-41aa-b796-5763663caa1f','答李谷同年書','劉敞','宋','宋诗','song-poetry','','[]','歸客江南来，迢迢數千里。',72,'全唐诗/poet.song.27000.json','["歸客江南来，迢迢數千里。", "故人遺我書，細字三四紙。", "上言平生懷，伐木義所倚。", "下道相知心，結綬方獨喜。", "寧知淮陽翁，棄外甘卧理。", "不預朝廷議，何由發吾子。"]'),
('75675ce4-1ef3-4436-936c-a229b00ccf45','楊彦文過','劉敞','宋','宋诗','song-poetry','','[]','病起時節改，遶池飛脊令。',108,'全唐诗/poet.song.27000.json','["病起時節改，遶池飛脊令。", "賓交絕来往，門戶常晝扄。", "朔風捭閶闔，凍雨翻滄溟。", "泥塗墊后土，氣象昏圓靈。", "局促久增欷，據梧目思瞑。", "窅然顧環堵，嗒若忘我形。", "夫子亦何事，羈旅復伶仃。", "孔懷在接淅，過我不遑寧。", "歲晏絕晤語，誰當慰長醒。"]'),
('cc58a0c6-c391-4271-b560-7bb7572f1dd1','晚過深甫','劉敞','宋','宋诗','song-poetry','','[]','忽忽衡門下，幾希田舍翁。',84,'全唐诗/poet.song.27000.json','["忽忽衡門下，幾希田舍翁。", "有時寄一笑，目送南飛鴻。", "今旦天正佳，草樹搖春容。", "忽驚枝上花，飄落隨西風。", "偶然幽興展，思樂古人同。", "塵埃比殊深，杖屢亦可通。", "誰謂車馬多，澹如初不逢。"]'),
('576c8ee3-001a-4724-a071-b46468922a9d','讀鄰幾泰山十二詩','劉敞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','宿心慕鄒魯，寤寐泰山杪。',156,'全唐诗/poet.song.27000.json','["宿心慕鄒魯，寤寐泰山杪。", "慷慨念遐觀，滯留想輕矯。", "人寰何鼎鼎，羣動困擾擾。", "安知有神靈，獨立萬物表。", "圓天似車蓋，滄海稱池沼。", "丹梯無留迹，絕壑通過鳥。", "古今更廢興，萬事論莽眇。", "七十二家舊，永興耳目窅。", "羡君能自力，窮覽謝煩湫。", "超然昔賢趣，處覺兹世少。", "吐詩状奇麗，思與雲縹緲。", "忽如按圖畫，所向得了了。", "悠哉仲尼意，信彼天下小。"]'),
('3de21e5b-9398-4008-bc2e-071a448eabc5','送從兄','劉敞','宋','宋诗','song-poetry','','[]','東門楊柳深，下有還鄉路。',96,'全唐诗/poet.song.27000.json','["東門楊柳深，下有還鄉路。", "之子千里行，春風三月暮。", "旅心常草草，飄忽不可駐。", "居者空徘徊，行者亦反顧。", "丈夫方貧賤，四海無所遇。", "不如轍中魚，猶以沫相喣。", "悠悠大江水，日夕自東注。", "何當激風雷，慰爾饑渴慕。"]'),
('35605453-944a-4d09-9505-377af2f446b5','山光寺送獻臣','劉敞','宋','宋诗','song-poetry','','[]','嘉集常苦難，送歸豈辭遠。',96,'全唐诗/poet.song.27000.json','["嘉集常苦難，送歸豈辭遠。", "檥舟故相逐，携手行自挽。", "古寺何崔巍，深林象巖巘。", "幽尋取乘興，造適非素選。", "寒泉冰深池，衰草被長坂。", "歲窮景蕭條，僧老意繾綣。", "勝賞竟誰同，相知幸非晚。", "離懷自無極，日暮仍忘返。"]'),
('6c3b8c79-594c-4aeb-a539-d167d38ec218','燕譽堂飲别朱著作','劉敞','宋','宋诗','song-poetry','','[]','歲晚節物變，會難羈旅悲。',48,'全唐诗/poet.song.27000.json','["歲晚節物變，會難羈旅悲。", "疏燈照四座，殘菊醉空巵。", "歌闋風雨起，舞餘冠佩攲。", "天明念陳迹，忽忽叢予思。"]'),
('e5fec5f9-a64d-4123-96fc-6e2599bd26a3','以石爲玉','劉敞','宋','宋诗','song-poetry','','[]','梧臺有沈璞，由来非一春。',48,'全唐诗/poet.song.27000.json','["梧臺有沈璞，由来非一春。", "時無司南駕，自比連城珍。", "寧如崑邱叟，相與笑緇磷。", "勿以名夸世，而将暗投人。"]'),
('6c78fac3-6397-461c-9c35-d1900aa0ae3f','夜分東窗見月','劉敞','宋','宋诗','song-poetry','','[]','逾望月彌晚，宵分在東窗。',48,'全唐诗/poet.song.27000.json','["逾望月彌晚，宵分在東窗。", "隨風漏疏隙，散彩奪寒釭。", "留翫坐忘寐，啓書對空缸。", "惜哉皆陳迹，誰爲足經邦。"]'),
('f85737d5-db0c-4768-ab67-a9efcfc88917','酬某','劉敞','宋','宋诗','song-poetry','','[]','讀書與博簺，亡羊信多岐。',96,'全唐诗/poet.song.27000.json','["讀書與博簺，亡羊信多岐。", "何以消煩憂，謝墅觀奕棋。", "寓物多歡適，吾道有張弛。", "誰能長刺促，屈首就鞅羈。", "陳遵嗜杯酒，柏松見誚嗤。", "袁絲沈里閭，劇孟相追隨。", "君方總府事，吏牘正紛披。", "走見固所願，清閒在他時。"]'),
('6f4c8b47-dad4-49df-b1f3-b993bcc3ae5c','酬林國華先輩','劉敞','宋','宋诗','song-poetry','','[]','昔吾臨汝南，休騎思俊賢。',216,'全唐诗/poet.song.27000.json','["昔吾臨汝南，休騎思俊賢。", "此邦號多士，今世猶依然。", "奉詔選計偕，至者皆比肩。", "子時避逃我，常獨懷悁悁。", "豈我非其人，長鯨隘蹄泉。", "将由求之失，黄鵠去不還。", "察亷未塞責，負課終彌年。", "解印歸卧家，百憂正纒綿。", "聞子来仕門，華裾燦雲烟。", "手携一卷書，金碧紛蟬聯。", "慰我平生懷，意好何深堅。", "始知向難進，非以相棄捐。", "鄉評讓父兄，觀國氣無前。", "翰飛果自致，大笑諸老先。", "毫末爲豫章，衆流成深淵。", "物常積於久，念子亦勉旃。", "令名百世榮，文學貴本元。", "愛至相期深，愧無長者言。"]'),
('2249d2c7-2265-4e27-b582-b67743b26c0b','夜雨','劉敞','宋','宋诗','song-poetry','','[]','盛陽爍微陰，五月氣藴隆。',96,'全唐诗/poet.song.27000.json','["盛陽爍微陰，五月氣藴隆。", "天地爲大爐，萬物皆廢銅。", "俯欲濯江漢，仰思凌蒼穹。", "縮身投蝸角，救暍號天公。", "天亦哀人謀，玄雲送雷風。", "須臾雨如瀉，一埽萬里空。", "有似脱炮烙，又如逃祖龍。", "大哉造化力，因見王霸功。"]'),
('33c1e95e-512e-4fe0-99d1-c839377d60a1','登呂屯田清暑亭','劉敞','宋','宋诗','song-poetry','','[]','日永雖徂暑，虚堂自清幽。',72,'全唐诗/poet.song.27000.json','["日永雖徂暑，虚堂自清幽。", "主人意未展，改席兹城樓。", "嘉樹遠近合，清川縱横流。", "好風萬里至，浩蕩開客愁。", "長嘯欲飛動，勞生局遠遊。", "眇然不自愜，目極孤雲浮。"]'),
('23ac0c83-1fe3-4eac-8a27-f587d7b32767','許州西湖','劉敞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','羈旅懷江湖，氛埃願臯壤。',84,'全唐诗/poet.song.27000.json','["羈旅懷江湖，氛埃願臯壤。", "及兹已俱適，初意恨獨往。", "樓觀湧參差，軒欞豁高爽。", "清光見毛髪，衆影兼俯仰。", "昔者廊廟客，於兹濯塵網。", "疏源不憚遠，勝事日以廣。", "美矣流水意，當爲知音賞。"]'),
('173204c7-8d30-4da9-aa93-b9e34abb7e08','晚過西湖','劉敞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','日暮無與適，緩带此逍遙。',60,'全唐诗/poet.song.27000.json','["日暮無與適，緩带此逍遙。", "湖光悅我心，步上西城橋。", "遠烟被林莽，樓閣隱岧嶤。", "歸鳥先後飛，夕風正飄飄。", "悵然念遠渚，興盡復行謡。"]'),
('c912a0a3-c5c0-45e3-8b83-05866b0338a1','睡起','劉敞','宋','宋诗','song-poetry','','[]','日午更稍休，池上逍遙眠。',72,'全唐诗/poet.song.27000.json','["日午更稍休，池上逍遙眠。", "水木澹相映，庭戶清無喧。", "時有山中禽，来鳴高樹巔。", "微風拂徑過，會意成翛然。", "有生滯形役，萬物安静便。", "愧無淮陽績，高卧亦終年。"]'),
('c73d8563-eb88-46cc-848c-c87d6b25b37f','奉和府公新作盆山激水若泉見招十二韻','劉敞','宋','宋诗','song-poetry','','[]','誰謂山水秀，忽登君子堂。',144,'全唐诗/poet.song.27000.json','["誰謂山水秀，忽登君子堂。", "乃知仁智樂，不與冠蓋妨。", "濃靄萬叠碧，懸流百尋長。", "列峰映落落，遶溜含蒼蒼。", "氣爽變衡霍，聲幽激瀟湘。", "意真景自遠，趣逸累已忘。", "鳴玉無時續，翠屏終日張。", "賞音得虛寂，寓興成軒昂。", "夙昔慕丘壑，邇来倦簪裳。", "欣符洗耳願，遽有尋源狂。", "縱目寄歷覽，挟琴寫鏗鏘。", "但疑主人厭，應接殊未央。"]'),
('bcc40d9c-fd5f-43ec-9b49-9aa7f734a5cf','遊五嶽觀寄鄰幾聖俞','劉敞','宋','宋诗','song-poetry','','[]','五嶽神仙境，可聞不可攀。',204,'全唐诗/poet.song.27000.json','["五嶽神仙境，可聞不可攀。", "安知采真遊，近在都城間。", "樓觀横飛雲，虎豹司重關。", "車馬自兹止，始覺非人寰。", "層波漲滄溟，參差出三山。", "金銀麗宫闕，日月相循環。", "東来復幾時，花草紛斑斑。", "長楊垂輕絲，若委千髻鬟。", "氛埃無由及，魚鳥相與閒。", "造適不自知，忽如脱沈瘝。", "那得窺壺中，逍遙去塵闤。", "主人自瑤杯，勸客流霞殷。", "此中可遺老，豈獨聊忘還。", "嗟嗟二三子，世路迷險艱。", "流光競奔走，俯仰移朱顔。", "誰肯委俗紛，相從解朝班。", "濯君冠與纓，春谷水潺潺。"]'),
('7fef0f9e-d39c-4699-ac29-584868a7f2ec','谿上避暑','劉敞','宋','宋诗','song-poetry','','[]','滴瀝松下雨，清微萍際風。',48,'全唐诗/poet.song.27000.json','["滴瀝松下雨，清微萍際風。", "欣然此時賞，我與斯人同。", "倦鳥墮水上，游魚翔鑑中。", "不言閲羣動，未覺幽興窮。"]'),
('253cf599-9b12-42fe-bc56-66cb1d3d82ba','東館避暑','劉敞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','虚館含微風，高梧散層陰。',72,'全唐诗/poet.song.27000.json','["虚館含微風，高梧散層陰。", "逍遙敞戶牖，曠蕩披煩襟。", "雲光壓孤城，火氣連千岑。", "四海俱探湯，獨清亦何心。", "願傾西湖水，起就三日霖。", "落落抱寸誠，此志誰能任。"]'),
('9f8aff1f-5dbb-4424-a601-2d25f1821bcb','得隱直書','劉敞','宋','宋诗','song-poetry','','[]','庭柯結浮陰，深竹聽鳴鵙。',72,'全唐诗/poet.song.27000.json','["庭柯結浮陰，深竹聽鳴鵙。", "晚凉愛軒宇，默念得佳客。", "適有南逝鳥，墮君一封帛。", "眷予方幽獨，慰我正相憶。", "洛中輕肥地，子復憔悴色。", "富貴若可求，吾從執鞭役。"]'),
('80dfcef4-e509-428f-9a24-30c0826fff9a','隱直近詣闕獻書報聞','劉敞','宋','宋诗','song-poetry','','[]','炎暉若探湯，周道行倭遲。',168,'全唐诗/poet.song.27000.json','["炎暉若探湯，周道行倭遲。", "之子忍重跰，斯人方病痱。", "上書蒼龍闕，移副鼎足司。", "卓躒動羣聽，謂言即張弛。", "虞卿萬乘相，子房帝王師。", "古事可彷彿，世塗實參差。", "天閽虎豹深，棄我忽若遺。", "却走國西門，素衣化爲緇。", "行行屢回首，未忍從此辭。", "賢者愛其君，肯如悻悻爲。", "吾聞先達語，進退自有時。", "版築不爲辱，飯牛豈嫌遲。", "男兒建功名，或與老大期。", "努力梁甫吟，古人不予欺。"]'),
('0725f742-9a26-4aab-80f3-018abde5c89a','将入京得淮南王工部書及遣壽州官船以来五言寄之','劉敞','宋','宋诗','song-poetry','','[]','生理厭漂蕩，三年若棲苴。',132,'全唐诗/poet.song.27000.json','["生理厭漂蕩，三年若棲苴。", "春深感松柏，流涕望京華。", "誰言數舍近，局滯成天涯。", "鬢色新二毛，悵然空復嗟。", "明侯平生意，雖遠不云遐。", "叩君金玉音，眷我需於沙。", "旭日明清川，扁舟問貧家。", "雖非方外遊，此亦海上槎。", "盡日庇短篷，不慚負舍蝸。", "愧君濟川才，引領隔雲霞。", "何由一乘興，世累紛如麻。"]'),
('58847d54-7df9-45f4-97d0-b06f5d63c99f','答君章譽兩兒見寄','劉敞','宋','宋诗','song-poetry','','[]','窺鏡見二毛，自憐憂患餘。',252,'全唐诗/poet.song.27000.json','["窺鏡見二毛，自憐憂患餘。", "豈惟壮心盡，方與功名疏。", "終歲不捉筆，歷時長束書。", "顧常念絕學，正復傷離居。", "忽忽莫自聊，悠悠空歲除。", "過壮而無聞，我其衆人歟。", "故人来江南，丹轂映隼旟。", "尚持平生意，期我相得初。", "殷勤作新詩，爛漫聯瓊琚。", "溢美及兒曹，伻来問起予。", "雖知非其實，但愧情相於。", "矧乃筆力雄，駸駸逼曹徐。", "一讀必三歎，何由望儲胥。", "故人昔流落，襟抱久不攄。", "乃者始再遷，通直承明廬。", "蒼龍脱韝絏，快馬從輕車。", "神至氣自豪，心廣體亦舒。", "淵源未易測，變化天池魚。", "寧獨揚子雲，其工似相如。", "苟能哀憔悴，有似慰空虗。", "月寄三四幅，窮愁直見祛。"]'),
('65a46eb5-353c-446d-abe2-98f854b9ea0f','答徐無逸秀才寄示新文','劉敞','宋','宋诗','song-poetry','','[]','金華神仙境，山川天下無。',96,'全唐诗/poet.song.27000.json','["金華神仙境，山川天下無。", "之子復清發，自與常人殊。", "問學當世賢，不違智如愚。", "歸来守桑梓，寂寞安故廬。", "此風足蠣俗，有以光吾儒。", "如何卧空谷，自樂詩與書。", "我辱廷中臣，一麾寄江湖。", "薦賢力不足，相望空長吁。"]'),
('7e11d85e-0c00-48c1-9253-3651530dc513','對酒憶諸子','劉敞','宋','宋诗','song-poetry','','[]','此酒自足飲，胡爲坐無歡。',84,'全唐诗/poet.song.27000.json','["此酒自足飲，胡爲坐無歡。", "念我意中人，四顧用長歎。", "平生交遊少，而復聚會難。", "萬古膠漆姿，各在天一端。", "用兵輕文儒，諸子俱小官。", "物生繫所逢，窮達何足言。", "但恨適有酒，共醉乃無緣。"]'),
('2d2a7c67-4b46-4ad9-a79a-5c5d52150dc0','出塞曲三首  其一','劉敞','宋','宋诗','song-poetry','','[]','桓桓良家子，趫趫羽林兒。',48,'全唐诗/poet.song.27000.json','["桓桓良家子，趫趫羽林兒。", "恩讐久未報，感激氣拂霓。", "無用丈二組，不須一丸泥。", "獨身斬胡頸，手攬封侯圭。"]'),
('9ba39af7-32da-42ab-af5f-581e01dd4b73','出塞曲三首  其二','劉敞','宋','宋诗','song-poetry','','[]','丈夫不懼死，所懼潛闒茸。',48,'全唐诗/poet.song.27000.json','["丈夫不懼死，所懼潛闒茸。", "出身義許國，桀石賈餘勇。", "豈無親戚憐，决去甘登隴。", "人生在奮發，将相寧有種。"]'),
('dbf5ff53-6108-459d-af32-40c7e332add2','出塞曲三首  其三','劉敞','宋','宋诗','song-poetry','','[]','茫茫郊塞遠，木落原野空。',48,'全唐诗/poet.song.27000.json','["茫茫郊塞遠，木落原野空。", "鼓鼙濕前雨，笳吹悲後風。", "山州行無極，敵窟未可窮。", "生當取榮名，死當爲鬼雄。"]'),
('fc954622-b1f5-4c4c-b47a-96fed7596165','移葦','劉敞','宋','宋诗','song-poetry','','[]','蕭蕭江上葦，夏老叢已深。',96,'全唐诗/poet.song.27000.json','["蕭蕭江上葦，夏老叢已深。", "悠悠文王死，常懼牛羊侵。", "遷根横汙池，慰我江湖心。", "清風日夕過，白鷺時見臨。", "疏響拂琴瑟，綠華曠衣襟。", "處卑節不改，習静情足欽。", "炎暉已堪愛，秋景坐可尋。", "願及搆明堂，甘心辭故林。"]'),
('d371ce46-1ce4-478d-bdb2-fe58b8a8820f','欲於舊州石橋作偶浯臺以備遊覽先爲五言','劉敞','宋','宋诗','song-poetry','','[]','河決鉅野溢，此時吾山平。',156,'全唐诗/poet.song.27000.json','["河決鉅野溢，此時吾山平。", "百川會兩澤，千里圍孤城。", "桑野就蕪漫，石橋尚峥嶸。", "往往有白鶴，飛来羣悲鳴。", "我欲覽風土，因之省民耕。", "誰能同我樂，誰肯從我行。", "楚人哀江南，倚沼而畦瀛。", "臨高誦斯語，正復傷人情。", "當築十丈臺，偶浯爲之名。", "上可容宴豆，下堪列旆旌。", "棹歌出中流，簫鼓會前楹。", "浮雲来東山，落日隱北溟。", "此樂或難忘，請公爲我評。"]'),
('fe1a60ea-31f0-4ac2-93ae-b431482fe42f','章華臺','劉敞','宋','宋诗','song-poetry','','[]','楚子志方盛，築臺臨章華。',96,'全唐诗/poet.song.27000.json','["楚子志方盛，築臺臨章華。", "度高累百尋，計産逾萬家。", "參差蔽日月，煥爛生烟霞。", "侍酒皆列侯，佐歡盡名娃。", "嬉遊未云樂，荆棘紛已芽。", "奈何竭民力，用此爲盗誇。", "蔓草匿頽基，長風卷飛沙。", "廢興若糾纒，故老猶咨嗟。"]'),
('da9fa3c5-2fbb-4889-95b4-f14a743daa13','曲水臺','劉敞','宋','宋诗','song-poetry','','[]','杖履不能遠，逍遙池上林。',72,'全唐诗/poet.song.27000.json','["杖履不能遠，逍遙池上林。", "微風起衆響，炎日隔繁陰。", "斐亹激流泉，間關語鳴禽。", "放懷在離人，寄賞欣會心。", "既謝朝市喧，亦忘山谷深。", "雖知非吾室，猶以開煩襟。"]'),
('796df3d5-8531-4b38-89f8-bfd0ae257a2e','暖景偶作','劉敞','宋','宋诗','song-poetry','','[]','垂楊欲吐花，芳草遍抽芽。',36,'全唐诗/poet.song.27000.json','["垂楊欲吐花，芳草遍抽芽。", "低風動簾幕，細雨濕堤沙。", "暖景蕩愁思，一城千萬家。"]'),
('dad67a29-99a6-401e-ac6d-fd4410b4a2f6','冬雨偶作','劉敞','宋','宋诗','song-poetry','','[]','江上朝来雨，城中起寒色。',48,'全唐诗/poet.song.27000.json','["江上朝来雨，城中起寒色。", "凄凄濕塵土，漠漠蔽空碧。", "築場看已晚，及物悵無益。", "苞蓍怨下泉，客子長太息。"]'),
('e9eabafc-418a-4eb3-a63c-0c325bed3d21','豫章儒者','劉敞','宋','宋诗','song-poetry','','[]','豫章有儒者，讀書三十年。',288,'全唐诗/poet.song.27000.json','["豫章有儒者，讀書三十年。", "但識上古風，不知時俗遷。", "一聞西戎叛，有意摧羣頑。", "詣闕上封章，臣知用兵權。", "不在勞士卒，不須役戈鋋。", "要先正其本，本正末自安。", "臣觀朝廷中，或有可廢員。", "臣觀草澤中，或有可用賢。", "國家既失此，奸吏隨矯虔。", "吏奸萬事隳，外患隨因緣。", "所以子玉存，文公積愁顔。", "所以汲黯亡，淮南爲無難。", "天子覽表歎，當朝常拳拳。", "迴頭謂羣公，可付史館編。", "可使靡好爵，以補風化源。", "豈知貴臣忌，投爾南海壖。", "不得面指陳，胸襟曷由宣。", "卒走驅使行，行行酌貪泉。", "名與囚隸俱，位乃胥校聯。", "九重竟不知，猶謂列王官。", "奈何樂堯舜，乃是取危顛。", "誰云遇明主，未免遭棄捐。", "遂令天下士，齚舌戒勿言。", "寧有死壑中，安有議君前。"]'),
('1a3d33af-843f-47b6-b987-b168e3975bd8','賀尹學士辟經略府','劉敞','宋','宋诗','song-poetry','','[]','年来方苦兵，蠻夷久滑夏。',216,'全唐诗/poet.song.27000.json','["年来方苦兵，蠻夷久滑夏。", "西陲亭障盡，人骨蔽荒野。", "漢家飛将多，程李相上下。", "試問誰董之，王朝大司馬。", "分廷授斧鉞，號令從此把。", "主憂臣當辱，開府納儒雅。", "堂堂蒙山舊，乃是謫仙者。", "謀畫當代無，胸襟一朝寫。", "誠知鑠鉛鑛，不合煩大冶。", "要使借前籌，非公諒誰假。", "鷹饑肯擇肉，驥逸始流赭。", "由来抱軒昂，可得不脱灑。", "昨聞賦芻粟，中戶困楚檟。", "此事已大急，哀哉動鰥寡。", "兵家尚神速，世務忌苟且。", "願公更深謀，郤敵如破瓦。", "䲔鯢埽封境，疲瘵沐純嘏。", "豈令魯仲尼，獨贊王孫賈。"]'),
('c55e5646-e6ff-4019-9f63-ae9271c153d3','鷾鴯巾','劉敞','宋','宋诗','song-poetry','','[]','遠思意而子，因作鷾鴯中。',48,'全唐诗/poet.song.27000.json','["遠思意而子，因作鷾鴯中。", "慮世本遺物，全生翻近人。", "輕凉便肌髪，瀟灑外埃塵。", "山林有獨往，此亦陶唐民。"]'),
('a15134aa-c6e3-4708-b594-aa105cf78d6f','望洞庭','劉敞','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','洞庭七百里，浩蕩敵溟渤。',288,'全唐诗/poet.song.27000.json','["洞庭七百里，浩蕩敵溟渤。", "雲夢開其胸，巴陵束喉舌。", "東流匯羣川，盛漲五六月。", "飄颻浮乾坤，倚蓋低兀臲。", "吾行寰海間，未見此水闊。", "峡流下衣带，島嶼盡毫末。", "高秋卷氛翳，兩涯浴日月。", "何得徑寸珠，晦明互出沒。", "蒼茫蛟龍宅，溷雜魚鼈窟。", "太古到於今，沈潛孰分别。", "風帆引北極，波浪限百越。", "國絕南顧憂，獻琛各通達。", "山川非一險，此實輔明哲。", "俯笑三苗愚，竟爲獨夫滅。", "遠遊世俗隘，偶此耳目豁。", "淅瀝臨清風，滂沱濯炎熱。", "蕭蕭霜林暮，藹藹芳草歇。", "壮觀激我懷，當歌意復咽。", "寂寥軒轅樂，萬古逸響絕。", "慘淡虞帝魂，九疑莽嵽嵲。", "况聞屈賈輩，各賜楚漢玦。", "至德無復還，後王寝衰缺。", "滔滔更南征，鬱鬱抱忉怛。", "太湖雖云深，未救懷古渴。"]'),
('acc3c781-ecee-4cab-8ff5-2c90162e7832','同聖俞寄金山曇頻次韻','劉敞','宋','宋诗','song-poetry','','[]','我雖游都城，心亦無所住。',108,'全唐诗/poet.song.27000.json','["我雖游都城，心亦無所住。", "誤得世俗償，形骸寓冠屨。", "少時侍吾親，游覽愛北顧。", "至今頗思之，想見江上鶩。", "白頭曇道人，夙昔竟未遇。", "聞其最安禪，無念無作故。", "勞生有喧寂，得意無早暮。", "塵埃未易厭，臯壤固多趣。", "若復乘桴行，從君款幽素。"]'),
('8ff308f4-f658-4742-a91b-8ccbb2b7bcba','送僧歸君山','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','羈旅頭髪白，寤寐君山青。',120,'全唐诗/poet.song.27000.json','["羈旅頭髪白，寤寐君山青。", "遠遊負雅志，舉俗笑獨醒。", "西風吹新秋，幽興浮洞庭。", "忽見九疑峰，如列枕上屏。", "遼遼伯牙意，寂然誰爲聽。", "歸客適我願，歡然叩柴扃。", "振錫循東道，泛槎問南星。", "瀟湘落君手，去矣鴻冥冥。", "橘柚雨初熟，杜蘭晚更馨。", "上方試回顧，笑指江漢萍。"]'),
('bfb65dfd-defb-4328-a328-6e30db42c6aa','入山','劉敞','宋','宋诗','song-poetry','','[]','連山何叢叢，相背復相向。',180,'全唐诗/poet.song.27000.json','["連山何叢叢，相背復相向。", "盤溪殆千曲，險石彌萬狀。", "或疑天地翻，斗起渤碣浪。", "蹙沓更騰凌，變化倐奇壯。", "舟車未爲用，夷夏永觖望。", "鑿空伊誰氏，重譯肇霸王。", "茫茫千萬歲，冉冉道交喪。", "薄伐策已卑，割據事逾妄。", "衣冠慘分裂，玉帛敝辭讓。", "至仁有柔服，遠馭恥懲創。", "非無一丸泥，不乏萬人將。", "齊讎紓九世，魯錦輕百兩。", "羊腸勞躋攀，魚齒困沿並。", "彼岐亦云岨，易簡德固曠。", "大哉天作詩，因見聖者量。"]'),
('d5e67a46-1ff5-4e27-90ce-43a104cb47eb','治渠','劉敞','宋','宋诗','song-poetry','','[]','旱久溝畎廢，忽雨浸我廬。',120,'全唐诗/poet.song.27000.json','["旱久溝畎廢，忽雨浸我廬。", "晨興不及屨，出門自手鋤。", "一直復一曲，水流若江湖。", "蚯蚓爲蛟龍，蟻封即丘墟。", "生理避燥濕，一室足有餘。", "人事戒偷安，未能輕須臾。", "豈恨規摹小，所傷筋力劬。", "衰疾實使然，不勝一匹雛。", "伊昔論五帝，毎嫌盡信書。", "及兹始欲歎，微禹吾其魚。"]'),
('31892159-514d-4f61-8a35-16f3c7648012','東門行','劉敞','宋','宋诗','song-poetry','','[]','拂衣趨長道，撫劍獨歎息。',96,'全唐诗/poet.song.27000.json','["拂衣趨長道，撫劍獨歎息。", "并歲不易衣，期旦曾一食。", "悠悠風俗薄，顧我若異域。", "積金要能笑，彈鋏輕下客。", "豈辭蓬蒿居，未與塵世隔。", "黄鵠非池禽，東南舉六翮。", "出門尚徘徊，悲鳴念舊國。", "何日復來還，爲君涕沾臆。"]'),
('0959fde8-b380-447c-8f29-8910227e9284','步登南門呈府公','劉敞','宋','宋诗','song-poetry','','[]','秋至久獨醒，今旦始一醉。',84,'全唐诗/poet.song.27000.json','["秋至久獨醒，今旦始一醉。", "非公愛賓客，何以强茲意。", "清風與人期，蕭瑟萬里至。", "落日高城西，參差數間地。", "顧茲景方夕，悟彼歲亦逝。", "造適常若希，開懷欲誰忌。", "暢然就酩酊，更盡酒中味。"]'),
('54c7ae54-2e89-4b94-b509-8c3eceec3948','小雨','劉敞','宋','宋诗','song-poetry','','[]','春陽轉爲旱，惠澤積不泄。',120,'全唐诗/poet.song.27000.json','["春陽轉爲旱，惠澤積不泄。", "稼穡亦已晚，泉湧爲之竭。", "吁嗟叫蒼天，閶闔不可越。", "精誠憑土龍，神化空怳惚。", "今旦微風來，朝陰度城闕。", "霏霏墮疏潤，稍稍漏白日。", "塵埃暫埽地，草樹纔沐髮。", "終宜雲漢枯，尚喜雷電發。", "帝方復威令，世莫患妖魃。", "寧作成湯時，彌年困饑渴。"]'),
('c66350c3-d763-45ae-bddc-18f0e63e9781','淮上微雨寄天隱彦文','劉敞','宋','宋诗','song-poetry','','[]','海風吹微雲，載雨淮上來。',72,'全唐诗/poet.song.27000.json','["海風吹微雲，載雨淮上來。", "灑埽區宇間，削然無塵埃。", "四月雖徂暑，幽襟爲之開。", "思我同心人，閟兹千里懷。", "悠悠日巳遠，勤勤首屢回。", "安得乘輕飇，相從孝王臺。"]'),
('3aa8e99f-df32-443c-907e-185cab20dc9f','細雨','劉敞','宋','宋诗','song-poetry','','[]','小雨滿前軒，濃陰不時卷。',60,'全唐诗/poet.song.27000.json','["小雨滿前軒，濃陰不時卷。", "隨風氣潛潤，竟日花微泫。", "池光慘澹昏，樓危依微辨。", "寒添夕景長，坐逼秋容晚。", "楚客歌泬寥，吟懷孰云淺。"]'),
('f1fb32ba-4403-4b81-ad62-84c9b35cc1ec','吳九秋過西池作詩持國和之邀予同賦','劉敞','宋','宋诗','song-poetry','','[]','三山凌波濤，雲漢邈氛埃。',132,'全唐诗/poet.song.27000.json','["三山凌波濤，雲漢邈氛埃。", "世無乘槎客，安得窮昭回。", "天門洞閶闔，海池含風雷。", "淵淪蛟龍室，焜炫金銀臺。", "西顥何蕭條，百芳日已摧。", "誰能瑩心賞，喟子懷仙才。", "時變感所思，駐車載徘徊。", "已秋孰願夏，覽物彌歡哀。", "韓生肆爽言，觀變均齊諧。", "而我拘俗者，俊游日已乖。", "欲濯纓上塵，何時與君偕。"]'),
('87f17668-eb53-4030-ae7d-cdd983d78d96','讀雜說小書','劉敞','宋','宋诗','song-poetry','','[]','長日無與語，聊及齊諧書。',72,'全唐诗/poet.song.27000.json','["長日無與語，聊及齊諧書。", "紛紜六合外，莽眇三皇初。", "近既難必有，遠亦非必無。", "古今夢寐間，過事蚊虻如。", "達生齊萬物，曲士拘一隅。", "苟以忘吾憂，焉能識其餘。"]'),
('5557b42d-08b9-439c-8517-b0c2187531ed','初到淮西讀書申申堂寄友','劉敞','宋','宋诗','song-poetry','','[]','禀性實無用，干名謬所望。',120,'全唐诗/poet.song.27000.json','["禀性實無用，干名謬所望。", "中爲祿仕逼，誤有世俗償。", "組綬見羈縻，簿書正搶攘。", "語言畏時忌，談笑憂事妨。", "往者託山林，未能下羲皇。", "邇來失吾真，終日幾發狂。", "期會非本務，米鹽豈大方。", "灑心賴篇籍，發興依松篁。", "朋友素所畏，道路阻且長。", "怨極倘見思，寄聲慰離腸。"]'),
('6621511e-81c4-493d-a2ce-fabc1c701f14','夜讀漢書','劉敞','宋','宋诗','song-poetry','','[]','明燈一編書，往古千歲事。',72,'全唐诗/poet.song.27000.json','["明燈一編書，往古千歲事。", "值歡輙孤笑，觸憤還累欷。", "四旁寂無聲，童僕正熟寐。", "歡憤雖不同，均非平和氣。", "可憐自戕伐，忽忽老將至。", "反愛童僕愚，冥然不識字。"]'),
('db932d5b-8c1b-4fd0-88ab-62b28770c1cd','和永叔寒夜會飲寄江十','劉敞','宋','宋诗','song-poetry','','[]','昔與江翁别，酣歌國門道。',144,'全唐诗/poet.song.27000.json','["昔與江翁别，酣歌國門道。", "黄花落酒罇，白髮藉霜草。", "本謂此行遠，定知此樂難。", "豈意二三子，復爲今夕歡。", "主人文章伯，談道輒忘倦。", "每至絕倒處，恨不使君見。", "鳥迹上古書，龍頭冢中器。", "其人骨已朽，感此相與醉。", "呼問西飛雲，游子何當返。", "寒風吟枯梧，歲月益已晚。", "吾聞太華峰，乃有神仙居。", "莫逐秦時人，獨結山中廬。"]'),
('e0d667ac-f581-4b45-8d72-dee1ce6b2800','三日同景仁鄰幾濟川晦叔景□呂秘校劉判官會南曹飲五君皆尚書外郎劉呂修唐書官','劉敞','宋','宋诗','song-poetry','','[]','秋氣迎節至，涼雨乘高風。',96,'全唐诗/poet.song.27000.json','["秋氣迎節至，涼雨乘高風。", "車馬散北闕，冠蓋會南宫。", "從吏殆成隱，玩歲復將窮。", "簿書幸無他，談笑偶多同。", "郎選冠一時，史才映羣公。", "著書駭深妙，聞道惴顓蒙。", "但願竊餘論，常此樽不空。", "寄迹三署老，不慚顔與馮。"]'),
('ab564e21-cb12-40ef-8a69-d7228f85100b','期鄰幾飲不至醉作江侯詩并解座客','劉敞','宋','宋诗','song-poetry','','[]','秋雲樂邂逅，拂我榻上塵。',108,'全唐诗/poet.song.27000.json','["秋雲樂邂逅，拂我榻上塵。", "江侯舊多信，今作叵信人。", "我求江侯意，因得江侯真。", "乘興本當出，興盡便回輪。", "已諾雖可嘉，將非俗中倫。", "棄言似不誠，未害方外羣。", "江侯不爲名，名者實之賓。", "江侯不爲貌，貌疏意自親。", "作詩解江侯，饑渴夜復晨。"]'),
('7151986d-1ee8-4a53-8526-ad36e633f52e','十月二日邀鄰幾飲裴二如晦來遂留至夕','劉敞','宋','宋诗','song-poetry','','[]','晚下渠石閣，方轡得傾盖。',120,'全唐诗/poet.song.27000.json','["晚下渠石閣，方轡得傾盖。", "天寒畏干人，巵酒自相對。", "裴侯非宿約，來預心賞會。", "吾季方家居，四坐客解帯。", "獻酬雜嘲謔，歡笑以爲快。", "幸無俗中士，形迹一不怪。", "蟋蟀鳴高堂，歲月聿已邁。", "于今鮮吏責，無所憂其外。", "但當勤來顧，數醉此庭內。", "良無德與汝，聊足紓慷慨。"]'),
('303c0dbe-6ba5-4e02-9bae-171a7e494427','和貢甫瓜步詩','劉敞','宋','宋诗','song-poetry','','[]','江介多悲風，川廣不可越。',144,'全唐诗/poet.song.27000.json','["江介多悲風，川廣不可越。", "畏塗非吾土，游子愴明發。", "羣山起楚蜀，衆水會溟渤。", "地險自適然，天衷豈端設。", "憑陵三國際，偃蹇五胡末。", "非無英雄姿，于此智勇竭。", "疑城尚虎踞，虜馬餘飲窟。", "人謀雖工拙，神物有予奪。", "請陳真人朔，頗事丹浦伐。", "風雲埽氛埃，雷雨救焚暍。", "禹功東漸海，漢使南誚越。", "太平自茲始，盛德信貽厥。"]'),
('a97ae828-b1da-402c-bf66-43422f08a2a5','和江十雨中與持國師直飲','劉敞','宋','宋诗','song-poetry','','[]','旦上天祿閣，暮直承明廬。',156,'全唐诗/poet.song.27000.json','["旦上天祿閣，暮直承明廬。", "避喧雖足慰，取適固已疏。", "佳雨及我暇，兹晨殊晏如。", "紾絺委冠帯，高枕睨庭除。", "熏風散微涼，潤氣浮郊墟。", "沸聲湧江瀬，暝色晦綺疏。", "驚電時爍目，疾雷不廢書。", "商歌勤金石，塵谷盈鼃魚。", "此樂不可改，古人良起予。", "惜無同音賞，幽獨成離居。", "聞君達亹亹，樽酒會朋裾。", "高賢卧家巷，固多長者車。", "寧無寂寞者，閉關講玄虚。"]'),
('abbd97c4-4982-44e6-b86f-4731869e8e14','不飲','劉敞','宋','宋诗','song-poetry','','[]','憶昔常好飲，非以酒多味。',84,'全唐诗/poet.song.27000.json','["憶昔常好飲，非以酒多味。", "親友惠兹適，笑語坦無畏。", "不知天地廣，豈問歲月逝。", "爾來顧可憐，自覺不如意。", "秋風正蕭騷，萬物盡憔悴。", "頗欲濯旅懷，無人共昏醉。", "獨遊何時歡，白眼向兹世。"]'),
('0a12da63-38d9-4d75-ad26-660564fadc6e','石頭城','劉敞','宋','宋诗','song-poetry','','[]','石頭非人力，翠壁百仞高。',216,'全唐诗/poet.song.27000.json','["石頭非人力，翠壁百仞高。", "上盤巉巖雲，下激涌湧濤。", "攀躋猿猱苦，游涌魚鼈勞。", "乃知百萬師，未易損一毛。", "混茫有開鑿，形勢豈一朝。", "太古至德世，斯民各逍遙。", "艱難非所嬰，秦漢仍寂寥。", "發揮自孫氏，力控劉與曹。", "基業何崔巍，謀謨亦雄豪。", "龍蟠與虎踞，勢足萬古牢。", "德義苟不修，忽焉亡其操。", "繽紛不一姓，氣象何蕭條。", "往者游獵區，盡爲黍稷苗。", "前事不可忘，後來鑒孔昭。", "客行倦煩促，勝槩愜所遭。", "眇然抱幽想，慷慨成鬱陶。", "古人若騰波，逝者日已滔。", "壯觀誰與論，悠悠背行舠。"]'),
('0283baf3-bf1d-45ac-aa7f-f6e84b58d070','直舍留道粹廣淵君實聖民伯初飲是日鄰幾濟川宴王金吾園亭不預會戯作五言寄之','劉敞','宋','宋诗','song-poetry','','[]','校讎中秘書，聞子宴城隅。',168,'全唐诗/poet.song.27000.json','["校讎中秘書，聞子宴城隅。", "大第丞相府，主人執金吾。", "浮雲駐清唱，回雪舞妖姝。", "金罍溢醇液，犀筯厭鮮腴。", "高談鬱不發，應接固已劬。", "我從四五公，置酒此石渠。", "開窗埽殘雪，列俎焚枯魚。", "谹言規姚姒，小說本虞初。", "不知敝緼寒，未覺膏粱殊。", "從容忽竟日，此樂亦誰如。", "長安事交游，貧富固有徒。", "不恨我失君，恨子不顧予。", "回頭成陳迹，萬事與化俱。", "題詩寄餘歡，毋乃笑其迂。"]'),
('2be36854-b039-4aa3-b405-a1f687790dcb','過聖俞飲','劉敞','宋','宋诗','song-poetry','','[]','積雨不出門，局促如井蛙。',168,'全唐诗/poet.song.27000.json','["積雨不出門，局促如井蛙。", "初晴强人意，今日來君家。", "下馬笑握手，埽階去塵沙。", "銀瓶撥醅酒，紫碗雙井茶。", "黄雀隨素魴，安榴雜木瓜。", "舉非一方物，遠或萬里遐。", "不知王侯宅，此味何以加。", "扶疏庭下槐，燦爛盤中花。", "春事豈不多，遊覽何必賒。", "與公平生親，總角見髪華。", "飲當外形骸，語當恕喧譁。", "縱心倒所詣，相對白日斜。", "江韓亦我徒，但恨宿約差。", "願使公多財，此樂寧有涯。"]'),
('d2d7c47c-e64a-4c01-983c-157196da1a90','招鄰幾聖俞和叔于東齋飲觀孔雀白鷴及周亞夫玉印赫連勃勃龍雀刀辟邪宫璽數物又使女奴奏伎行酒聖俞首示長篇因而報之','劉敞','宋','宋诗','song-poetry','','[]','前日俱遠别，夢中毎難期。',168,'全唐诗/poet.song.27000.json','["前日俱遠别，夢中毎難期。", "何言一堂上，相與同宴嬉。", "幸勿卑陋巷，陋巷何獨卑。", "幸勿辭樽酒，樽酒安足辭。", "君看籠中禽，亦有山林思。", "習習不如意，焉用文章爲。", "君尋古人物，信有陵谷悲。", "擾擾不自適，會爲後世嗤。", "促節無窄袖，緩歌逐鳴絲。", "自美亦自惡，貴賤吾不知。", "縱談劇虚舟，快飲若漏巵。", "人生但如此，爲樂自一時。", "誰言冬夜長，俛仰星漢移。", "念無千金壽，愧子勤稱詩。"]'),
('c1ed5962-70fa-4bd8-9056-0ed8bfa5c196','答黄寺丞紫薇五言','劉敞','宋','宋诗','song-poetry','','[]','紫薇異衆木，名與星垣同。',120,'全唐诗/poet.song.27000.json','["紫薇異衆木，名與星垣同。", "應是天上花，偶然落塵中。", "豔色麗朝日，繁香散清風。", "㛹娟雖自喜，幽寂逝將終。", "主人謫仙籍，浩歌滄浪翁。", "卜居抗静節，搴秀憐芳叢。", "猗狔庭中華，固爲悅已容。", "如何又將去，含意默忡忡。", "青苔侵履綦，搖落知歲窮。", "獨賴君子德，庶幾甘棠封。"]'),
('bc9cf0d4-4291-4630-955d-d790edb2b03b','曲陽亭送别','劉敞','宋','宋诗','song-poetry','','[]','海濱寂寥地，送别何須頻。',72,'全唐诗/poet.song.27000.json','["海濱寂寥地，送别何須頻。", "數上曲陽亭，自然愁旅人。", "晴日排寒色，清光湛奫淪。", "微風海上來，滿目飛魚鱗。", "孤雲去無所，野鳥鳴相馴。", "信美非吾土，送目倦南津。"]'),
('d4cc0cf0-a619-4419-9be7-f35b18ac21f2','寄貢弟','劉敞','宋','宋诗','song-poetry','','[]','勁雲翔空林，積雨荒茂草。',72,'全唐诗/poet.song.27000.json','["勁雲翔空林，積雨荒茂草。", "哀鳴聞離獸，驚棲見羈鳥。", "時逝運自頽，物壯勢還老。", "感至境寥愴，悲來色枯槁。", "玩此豈有極，辨之苦不早。", "如何復傷别，咫尺成遠道。"]'),
('e21887d1-b805-4d8d-a363-59733fbc9902','和弟自京師來','劉敞','宋','宋诗','song-poetry','','[]','四海無風濤，五年再相逢。',120,'全唐诗/poet.song.27000.json','["四海無風濤，五年再相逢。", "會合如此難，況我罹百凶。", "悲端素填膺，觸事涙滿胸。", "欲言不能語，豈知涕所從。", "良久得仰視，恍忽如夢中。", "非復平昔遊，豈復平昔容。", "危生若霜葉，懔懔待烈風。", "不有親戚歡，其如憂患攻。", "破啼强爲笑，意氣徒衰翁。", "慰爾友于情，急難義所隆。"]'),
('77c986ba-efcc-46ea-b627-84ed778b86a6','送秦州通判陸學','劉敞','宋','宋诗','song-poetry','','[]','秦地天下險，秦兵天下强。',276,'全唐诗/poet.song.27000.json','["秦地天下險，秦兵天下强。", "曩在景祐末，叛國正陸梁。", "渡河窺中原，不見飛鳥翔。", "漢將雖城守，覆沒猶相望。", "時秦獨高枕，毫髪無所傷。", "豈惟形勢然，固亦任使良。", "近者敵已弱，旄頭滅無光。", "尚須得猛士，分命修封疆。", "陸子吳中賢，英英富文章。", "作人易感激，遇事殊軒昂。", "舊知軍中樂，復愛邊地涼。", "不忍京塵間，著書鬢毛蒼。", "拜疏如終軍，請纓督羣羌。", "大笑朱買臣，衣錦憐故鄉。", "旌旗導前車，絲竹嗚後房。", "指呼百夫走，談笑千里康。", "雖云半刺史，其實專一方。", "古來成功名，奇偶不可常。", "得時或幸會，微賤升廟堂。", "況君閲詩書，智策未易量。", "協心得元帥，展意輸所長。", "朝廷酹勳閥，曾不矜銀黄。", "他日重見君，非復東觀郎。"]'),
('b39e2f04-ba59-4a40-a090-777d0bd25a2f','貢甫在京口阻潮未渡','劉敞','宋','宋诗','song-poetry','','[]','向晦月消魄，楚濤爲之衰。',84,'全唐诗/poet.song.27000.json','["向晦月消魄，楚濤爲之衰。", "坳堂無深涉，客子緩歸期。", "吟遶沙步闊，眺賞秋山奇。", "大川漲南島，落日明西垂。", "登高既易賦，懷古豈難詩。", "喟彼一带阻，積此三歲思。", "何當命海若，利涉慰調饑。"]'),
('ccdabc0f-4c1b-475f-963a-d2b68edf5c5a','淮西延平以詩見寄因書陜城即事用酬來唱','劉敞','宋','宋诗','song-poetry','','[]','陜郊古云重，雄勝地所該。',108,'全唐诗/poet.song.27000.json','["陜郊古云重，雄勝地所該。", "羣山左右顧，大河西北來。", "府署憑中高，一日萬景開。", "是時八九月，秋色清池臺。", "樽酒雨餘酌，笙歌雲際回。", "追歡緬前會，真樂非昔陪。", "賓客雖日過，禮俗多嫌猜。", "于焉備廚傳，安得忘形骸。", "神交與心賞，懷舊何悠哉。"]'),
('c04b59db-cac8-41f0-b0e3-b19e9cb94454','送獻臣是時獻臣侍親之淮南予亦且侍行臨荆州獻臣先從東門出故有此作','劉敞','宋','宋诗','song-poetry','','[]','風土樂荆楚，塵埃倦都洛。',36,'全唐诗/poet.song.27000.json','["風土樂荆楚，塵埃倦都洛。", "東遊欣邂逅，勿復驚離索。", "尚悔不同舟，令人慚李郭。"]'),
('f61e15d3-273e-43ff-9f5a-2b928c9d3c60','送客不及','劉敞','宋','宋诗','song-poetry','','[]','欲折楊柳枝，贈言别所思。',48,'全唐诗/poet.song.27000.json','["欲折楊柳枝，贈言别所思。", "日落飛鳥息，孤帆奔何之。", "行人樂前途，何以寛我懷。", "還將别離思，吹示横笛兒。"]'),
('7f4db66b-9d04-4808-9907-33a7735f6181','送鄰幾','劉敞','宋','宋诗','song-poetry','','[]','日沒崑丘峰，月出滄海波。',96,'全唐诗/poet.song.27000.json','["日沒崑丘峰，月出滄海波。", "區區三萬里，相望能幾何。", "一出仍一處，一合復一離。", "正爾人間世，無復歡笑時。", "子行何怱怱，將老思所試。", "恨我無羽翰，不能省君治。", "黄河從天來，太華出雲上。", "登臨若相思，寄聲問無恙。"]'),
('a77ce956-f062-4d97-8fca-741907264d9a','送彦猷','劉敞','宋','宋诗','song-poetry','','[]','蒼蒼南山桂，歲暮獨華滋。',120,'全唐诗/poet.song.27000.json','["蒼蒼南山桂，歲暮獨華滋。", "非無棟梁用，道遠莫致之。", "黄雀巢其巔，螻蟻穴其卑。", "全生亦以遂，匠石空復悲。", "兩唐邁青節，千歲接光輝。", "珪璋固特達，鴻鵠佳羽儀。", "庶幾朝廷老，出入王者師。", "何事江湖間，浮沈衆人爲。", "我實牛馬走，不能强縶維。", "欲往路苦艱，愴兹四愁詩。"]'),
('72e59c9b-b71a-4412-a6c9-3aaafd036b74','送直温','劉敞','宋','宋诗','song-poetry','','[]','終軍西入關，棄繻笑路旁。',120,'全唐诗/poet.song.27000.json','["終軍西入關，棄繻笑路旁。", "丈夫貴成名，用此還故鄉。", "雖無魯儒操，意氣殊激昂。", "稚齡如頽波，詎忍鬢髪蒼。", "古人汝南秀，契闊升我堂。", "宿昔夢生翼，已排九門翔。", "未盡復來歸，帝閽隔微茫。", "高卧三年喑，忽隨南風揚。", "萬里快超詣，豈知道路長。", "努力戒後時，相勸不可忘。"]'),
('278e6c36-2aa8-47dc-85b5-0c2980057d25','送孜生','劉敞','宋','宋诗','song-poetry','','[]','遭遇爵位輕，治平進取難。',168,'全唐诗/poet.song.27000.json','["遭遇爵位輕，治平進取難。", "不見明經士，白首成一官。", "憐爾吾家駒，學問知所安。", "得名萬衆中，奮迅生羽翰。", "天子臨廣廷，公卿肅衣冠。", "傳呼署甲乙，誰不傾目觀。", "我時忝陪侍，趨拜玉座前。", "鄂秀莩亦榮，不自知欣懽。", "勿言勢尚卑，無以地固寒。", "鸞鳯曾棘棲，蛟龍亦泥蟠。", "孟軻稱三樂，富貴不與焉。", "恨我不如爾，千鍾益悲歎。", "奈何方遠别，浩蕩江湖間。", "臨分豈自勝，流涕空汍瀾。"]'),
('0e80ff44-c114-48fa-b589-d334d7ae5322','送楊十一公緼之延平','劉敞','宋','宋诗','song-poetry','','[]','寡欲求易給，縦心居常安。',96,'全唐诗/poet.song.27000.json','["寡欲求易給，縦心居常安。", "一爲淮陽卧，及再芳歲單。", "處事非事事，居官豈官官。", "念以拙者效，而爲朝責寛。", "故人懷英邁，撫轡辱盤桓。", "心期謝外奬，談笑用爲歡。", "淹泊遂將永，望舒毁其團。", "别君感匏繫，更欲愁且歎。"]'),
('1d3c9b15-be8a-48ee-a58e-3e1c23a9bff3','送王國卿','劉敞','宋','宋诗','song-poetry','','[]','功名世所濟，時節不可遲。',96,'全唐诗/poet.song.27000.json','["功名世所濟，時節不可遲。", "夙昔聞斯語，至今良獨疑。", "筋力與時背，進取將願違。", "譬如寶燕石，無用于重貲。", "不恨歲月晚，畏爲豪俊嗤。", "見君復感歎，吾道其如台。", "古之英賢人，隱顯亦不齊。", "出處各努力，悠悠慰我思。"]'),
('fb2378e3-4314-44a4-ab7d-19758196cf4d','送子南','劉敞','宋','宋诗','song-poetry','','[]','南師鼓琴者，餘力推步精。',144,'全唐诗/poet.song.27000.json','["南師鼓琴者，餘力推步精。", "千里求知音，徒步入王城。", "能高頗自負，一一游公卿。", "朝廷富貴人，寵辱心若驚。", "聞至必解榻，招邀劇生平。", "以兹祿命術，獨得當時名。", "朱絃與素徽，棄置莫爲聽。", "往往默自撫，或疑非斷聲。", "紅塵車馬中，隨俗翻營營。", "振衣忽長歎，吾已知時情。", "卷槖郤東下，野風蕭然清。", "且賫山水意，永待鍾期生。"]'),
('cb51be5f-b3a7-49ff-8473-bfdabca2fa3d','幽懷','劉敞','宋','宋诗','song-poetry','','[]','山梁鳴雌雉，節物春已深。',72,'全唐诗/poet.song.27000.json','["山梁鳴雌雉，節物春已深。", "故花稍辭枝，新葉漸成陰。", "流光不可挽，四序密相尋。", "今晨已非昔，明日豈復今。", "自我愜幽獨，放言冥此心。", "胡爲復屢嘆，孔聖有遺音。"]'),
('72e2168e-df60-4c18-bcbb-0535f785c87c','送隱直侍行陜郊','劉敞','宋','宋诗','song-poetry','','[]','相如忽將老，推挽竟無力。',96,'全唐诗/poet.song.27000.json','["相如忽將老，推挽竟無力。", "如何羈旅後，棄我復遠適。", "貧病束我身，送子恨不得。", "時登高丘望，塵土蔽西北。", "山河繞秦隴，關陜入胸臆。", "形勝懸眼前，顧盼生感激。", "指陳出圖像，踴躍効功績。", "朝廷厭兵久，勉上平戎策。"]'),
('57dd1963-a142-4b10-b132-43018a168e4b','九月三日遊樂郊作五言贈同遊','劉敞','宋','宋诗','song-poetry','','[]','昔在西省直，常有中園思。',120,'全唐诗/poet.song.27000.json','["昔在西省直，常有中園思。", "今來非吾室，猶稱宣城詩。", "芳郊後搖落，秋初尚華滋。", "丹寶何纂纂，黄花復離離。", "俯見淵魚翔，仰觀雲鳥嬉。", "物性附所適，吾生亦爾期。", "置酒得同好，追勝不知疲。", "和歌涼風起，看舞白日移。", "興言想丘壑，弱喪慚旌麾。", "負郭如辦此，懷金寧足爲。"]'),
('53a691a7-40ca-4578-9b3f-1a1fc10e72e0','夜月露卧','劉敞','宋','宋诗','song-poetry','','[]','微月翳西林，繁星燦如錦。',60,'全唐诗/poet.song.27000.json','["微月翳西林，繁星燦如錦。", "歡言戀清景，展席不遑寢。", "涼風能相期，沆瀣若可飲。", "勞生傷局促，徂歲急苒荏。", "爲君捐萬慮，高卧且安枕。"]'),
('dbd17f62-285c-4b6b-975b-47c4bd08d96d','因季點同幕中諸君過車輞湖步行野間','劉敞','宋','宋诗','song-poetry','','[]','山野宜獨往，出郭愧賓從。',120,'全唐诗/poet.song.27000.json','["山野宜獨往，出郭愧賓從。", "終爲吏事役，猶與賢者共。", "平湖色清淺，霜落冰始凍。", "遠郊氣氤氲，臘近春稍動。", "鳥飛甚閒暇，獸起或驚縱。", "愛此去人遠，相勸解君鞚。", "崇岡象崤阪，宿莽似雲夢。", "游目際天地，褰裳凌菰葑。", "吟非騷人怨，賞及舞雩誦。", "塗遠意逾適，笑彼阮籍慟。"]'),
('550201a8-f812-4efc-b8af-df6e57a39526','適野','劉敞','宋','宋诗','song-poetry','','[]','夏至無與適，驅馬出東城。',84,'全唐诗/poet.song.27000.json','["夏至無與適，驅馬出東城。", "漸去市井喧，稍增耳目明。", "風勁山瘦高，露寒水澄清。", "造景不及言，暢然得此生。", "姓名謝朝隱，出處與物冥。", "豈伊漁樵合，鳥獸亦不驚。", "待此用卒歲，優游諧我情。"]'),
('83112eb0-9290-4d9c-8d2a-86747a2a3e54','挽葉翰林','劉敞','宋','宋诗','song-poetry','','[]','翰林氣英發，博學起徒步。',144,'全唐诗/poet.song.27000.json','["翰林氣英發，博學起徒步。", "初射東堂策，巳稱濟時具。", "出入三千歲，差池千一遇。", "青雲得自致，白眼與俗迕。", "勁節凌秋旻，玄文匿深霧。", "尺璧可令毁，堅石難使鑄。", "董生膠西相，賈子長沙傅。", "終疑希世才，良用制作誤。", "銜悲去修門，觖望動行路。", "落落長松姿，歲晏悴霜露。", "平生慕高名，邂逅隔清晤。", "心許千金劍，無由挂君墓。"]'),
('b471d201-b543-4af7-94ac-f9271f8bb029','端居','劉敞','宋','宋诗','song-poetry','','[]','端居亦無賴，幽賞每多違。',36,'全唐诗/poet.song.27000.json','["端居亦無賴，幽賞每多違。", "扁舟試獨泛，鷗鳥肯相依。", "日暮無所詣，興盡復還歸。"]'),
('f46aa145-3b24-4510-80be-abd8a2663d81','答黄寺丞九月二十一日出郊','劉敞','宋','宋诗','song-poetry','','[]','閉關予非用，適野子能謀。',48,'全唐诗/poet.song.27000.json','["閉關予非用，適野子能謀。", "勿言雅俗異，卒歲共優游。", "清詩狀景物，秀氣豁霜秋。", "篇終寄一笑，因以緩心憂。"]'),
('123cdb1f-6ae6-4a5b-b4e0-772b7d5f3f44','讀三國志','劉敞','宋','宋诗','song-poetry','','[]','獨夜一卷史，上尋千歲間。',96,'全唐诗/poet.song.27000.json','["獨夜一卷史，上尋千歲間。", "咄嗟興廢更，俯仰朝市遷。", "古人病無聞，愚智矜後先。", "共樂無窮中，正如朝露然。", "向觀功名際，自以皆萬年。", "邇來令人悲，蚊蚋過目前。", "安得謝浮俗，高舉凌九天。", "捐書以絕學，寄心崆峒仙。"]'),
('1ce7df5c-7b33-4284-bb8e-a8609493bb32','十二月二十一日雪中早朝','劉敞','宋','宋诗','song-poetry','','[]','海風水羣飛，中夜滿城雪。',72,'全唐诗/poet.song.27000.json','["海風水羣飛，中夜滿城雪。", "聞雞倒衣起，猶謂庭下月。", "出門望天地，高下同瑩潔。", "念非汗漫期，驅馬正迷轍。", "我本江湖人，雲端想華闕。", "今來怳自失，旅唱空愁絕。"]'),
('f77ecb70-1577-41dc-b61f-c593c2765e91','得彦文書將遊吳中','劉敞','宋','宋诗','song-poetry','','[]','微霜下芳草，日月逝逾邁。',72,'全唐诗/poet.song.27000.json','["微霜下芳草，日月逝逾邁。", "青青松與柏，歲暮兩相對。", "念我平生遊，孤懷用慷慨。", "誰言干里近，引領若海外。", "清潁流東南，浮雲向吳會。", "臨風意莫展，將子多自愛。"]'),
('d53b1566-71af-46f0-8eff-34d051673b67','寄王子堅時在寢丘治東臯','劉敞','宋','宋诗','song-poetry','','[]','達人視天下，輕重如浮雲。',72,'全唐诗/poet.song.27000.json','["達人視天下，輕重如浮雲。", "震雷不經聽，蟲飛寧足分。", "吾慕龐德公，谷口自耕耘。", "身世兩相棄，放言麋鹿羣。", "此風久難尚，之子今復聞。", "我亦問津者，滔滔遠慚君。"]'),
('c2ce2dca-6917-40e6-b2b2-d4fb8f73db84','菊花枕','劉敞','宋','宋诗','song-poetry','','[]','鮮鮮秋菊花，粲粲黄金錢。',120,'全唐诗/poet.song.27000.json','["鮮鮮秋菊花，粲粲黄金錢。", "採掇時苦晚，棄遺情所憐。", "道人教爲枕，示可以延年。", "早昧攝生術，恐爲多病纒。", "又從省俗事，視聽苦不便。", "往往發昏憒，未知所除蠲。", "但使寐無覺，不謂藥可痊。", "今者誠有遇，秘之慎其傳。", "愈風得難老，高卧齊古賢。", "作詩叙終始，物薄戒輕捐。"]'),
('cc7889d1-ef5f-44b9-b219-63588e071cc1','答張洞推官','劉敞','宋','宋诗','song-poetry','','[]','憂患使志衰，羈旅哀年邁。',96,'全唐诗/poet.song.27000.json','["憂患使志衰，羈旅哀年邁。", "夙昔仰高山，邇來得傾蓋。", "孤游幸無恨，三益良有待。", "惠我金玉音，醒如濯聾瞶。", "悵然反自感，久矣病昏憊。", "微君念氣臭，誰與振菅蒯。", "聆弦感英韶，觀海憚珍怪。", "內省終懸罄，無由報雜佩。"]'),
('4f9115e4-40ca-4396-b33b-b094d710be8f','洪州黄推官','劉敞','宋','宋诗','song-poetry','','[]','江表山水區，南昌神仙宅。',96,'全唐诗/poet.song.27000.json','["江表山水區，南昌神仙宅。", "固宜生賢俊，邈與塵土隔。", "昔在君伯氏，實爲萬夫特。", "文采何輝煌，聲名盛赫奕。", "差池中道夭，冥漠神理默。", "德業誰與倫，天倫自準的。", "龍蟠豈終潛，鳥伏必遠擊。", "君今鍾其美，遠到未可測。"]'),
('48402d43-d7c0-49c0-a32a-0ce4adaad5e6','聞官輸竹箭毛翎','劉敞','宋','宋诗','song-poetry','','[]','邊兵未云備，競矜弓弩强。',108,'全唐诗/poet.song.27000.json','["邊兵未云備，競矜弓弩强。", "斯人久銜恩，獻力固所當。", "上山伐檀欒，入林候飛翔。", "豈無解網心，大義須勤王。", "安得會稽嶺，集居共工旁。", "安得解羽澤，在君禮義鄉。", "剪翎副之箭，一一堅且良。", "朝發摧西戎，夕發斃東羌。", "不煩天下民，萬里坐寧康。"]'),
('041ec0f6-b5f2-42d8-a741-d975eb6905fd','秋日','劉敞','宋','宋诗','song-poetry','','[]','平日日在簷，今日日在堂。',72,'全唐诗/poet.song.27000.json','["平日日在簷，今日日在堂。", "西風稍已急，百草不復芳。", "蟋蟀何獨悲，戚戚鳴四牆。", "客子多所感，中夕起徬徨。", "貧病自早衰，何必秋氣涼。", "心憂不能眠，非惟寒夜長。"]'),
('d859d10d-1312-4356-ba8b-67ac1b6edf79','桐軒晚坐','劉敞','宋','宋诗','song-poetry','','[]','孤軒遶危桐，颯颯聞閙雨。',84,'全唐诗/poet.song.27000.json','["孤軒遶危桐，颯颯聞閙雨。", "驚起視前除，飛花亂如舞。", "輕香密伊席，晚景容當戶。", "玉粉散游蜂，珠華濺高宇。", "紛紛綠苔上，半已隨泥土。", "邈彼丹穴鳥，何年翥文羽。", "芳時不可驟，歲晏聊容與。"]'),
('83dcb630-4602-404d-8c8c-db61ceb714ab','李覯以太學助教召曾鞏以進士及第歸俱會郡下素聞兩人之賢留飲涵虚閣','劉敞','宋','宋诗','song-poetry','','[]','孤鸞方北游，威鳳復南翔。',96,'全唐诗/poet.song.27000.json','["孤鸞方北游，威鳳復南翔。", "邂逅中道遇，其音何鏘鏘。", "太平向百年，此固多美祥。", "擾擾都人士，爭先覿輝光。", "雖無醴泉流，江水清且長。", "雖無朝陽桐，翠樹茂且芳。", "念將萬里逝，願得少徬徨。", "爲君賦卷阿，因以謝楚狂。"]'),
('be237b97-33e7-49d9-beb8-37fb0534d4f3','秋晴','劉敞','宋','宋诗','song-poetry','','[]','浮飆解重陰，白日麗青天。',72,'全唐诗/poet.song.27000.json','["浮飆解重陰，白日麗青天。", "凛凛秋氣肅，蕭蕭風景鮮。", "脂車駕我馬，覽物往于田。", "幽興未能盡，中途復來旋。", "古人不可及，獨往秖自憐。", "豈若偃吾室，優游以忘年。"]'),
('59fb24f2-c13c-45d5-827e-152b353a01db','曉晴','劉敞','宋','宋诗','song-poetry','','[]','朝光出屋角，鳥雀聲正喧。',48,'全唐诗/poet.song.27000.json','["朝光出屋角，鳥雀聲正喧。", "天寒未能起，緼袍有餘温。", "智士困朝市，勇士敝中原。", "自古貴高卧，豈嫌長閉門。"]'),
('c4b33cc9-c1a1-4b73-bfd5-ca7592709c84','送蔡奕同年','劉敞','宋','宋诗','song-poetry','','[]','功名貴早達，時俗輕小官。',96,'全唐诗/poet.song.27000.json','["功名貴早達，時俗輕小官。", "念子兩未適，出門何獨歡。", "古賢有祿仕，先聖戒色難。", "義慊固爲美，勢卑豈足歎。", "采蘭歲云暮，接淅心不安。", "宛轉腰間絲，崔嵬頭上冠。", "車馬有光輝，里閭有聳觀。", "勉旃愛玉體，自致青雲端。"]'),
('71f6a768-bae7-461e-871a-30ff0b590c5e','送裴煜同年','劉敞','宋','宋诗','song-poetry','','[]','裴侯江海士，往者未相識。',144,'全唐诗/poet.song.27000.json','["裴侯江海士，往者未相識。", "但聞太學生，素號萬人敵。", "羣雄會南宫，精鑒動宗伯。", "先鳴氣軒昂，一日聲烜赫。", "青雲開岐路，黄鵠張羽翮。", "多幸旅後陳，同時被親策。", "指縦聽高論，灑落駭餘力。", "不意沈下僚，于予有愧色。", "蘭臺校中書，幕府贊婉畫。", "起家固多榮，負米輕遠役。", "此心古人少，于義吾子得。", "秋風感羈旅，道遠思自適。"]'),
('0a863a82-39d2-4c25-ad62-00cba90ec5f0','送楊闢同年','劉敞','宋','宋诗','song-poetry','','[]','昔在谷子雲，語妙氣縦横。',120,'全唐诗/poet.song.27000.json','["昔在谷子雲，語妙氣縦横。", "遨遊五侯間，談笑臨公卿。", "丈夫伸知己，未必老一經。", "懷寶迷其邦，古人誰謂平。", "楊侯東州客，三歲不飛鳴。", "雜沓二府書，繽紛委弓旌。", "結靷西入關，長揖謝諸生。", "風霜豈不永，意氣故自輕。", "伊昔惟一劍，蒯緱吐悲聲。", "當令代舍長，見我珠履榮。"]'),
('1f6d0573-a359-4c20-a388-84456b51cd53','秋月','劉敞','宋','宋诗','song-poetry','','[]','暮歸欲投息，明月强我行。',108,'全唐诗/poet.song.27000.json','["暮歸欲投息，明月强我行。", "越陌復度阡，古人知此情。", "叩門童奴走，升堂兒女驚。", "呼酒徑就醉，益復招友生。", "不可不與飲，子真勝公榮。", "顧聞四壁間，絲竹金石聲。", "此非孔子居，那得爾鏗轟。", "夜闌興不盡，積雲解我醒。", "噫嘻王子猷，浪得千載名。"]'),
('d89fd353-469b-4a76-9735-2eed6be9fc42','韓文公畫像分題','劉敞','宋','宋诗','song-poetry','','[]','微言昔廢絕，大道隨荒榛。',144,'全唐诗/poet.song.27000.json','["微言昔廢絕，大道隨荒榛。", "上下千歲間，天將復斯文。", "若人實命世，述作參鬼神。", "横制萬里波，不爲流俗珍。", "大音破昏聾，有若雷霆震。", "惜乎世莫用，竟以奇怪聞。", "哀哉揭陽貶，勢屈道則伸。", "孔子亦有言，求仁而得仁。", "我昔讀其書，固常見其人。", "邇來觀遺像，忽若平生親。", "輪扁不言巧，丹青豈復真。", "尚存高山意，俯仰冀日新。"]'),
('1f75bc6b-8122-4e5a-8703-31527a752777','楊十一沒後重登見山樓有感','劉敞','宋','宋诗','song-poetry','','[]','平生交一臂，觀化此山川。',48,'全唐诗/poet.song.27000.json','["平生交一臂，觀化此山川。", "俯仰成陳迹，高低俱絕弦。", "浮雲杳何處，衰病兀蕭然。", "擾擾紅塵合，誰予慰目前。"]'),
('881b9c05-3d35-4cc9-9237-15676413fbe7','卧北窗下讀書','劉敞','宋','宋诗','song-poetry','','[]','高枕北窗下，柴門晝仍關。',96,'全唐诗/poet.song.27000.json','["高枕北窗下，柴門晝仍關。", "偶有微風至，欣然解人顔。", "瞑目恣遠想，超遙出塵寰。", "自昔太古來，幾人得此閒。", "讀書取適心，名譽非所攀。", "堯跖本不辨，況乃章句間。", "牛羊死牢筴，麋鹿安深山。", "物性有不齊，何知智與頑。"]'),
('73f7ce9b-b5d2-4dcf-8c33-1d3a414399b6','寄贛','劉敞','宋','宋诗','song-poetry','','[]','相去不在遠，百里若異方。',168,'全唐诗/poet.song.27000.json','["相去不在遠，百里若異方。", "相别不在久，一日如歲長。", "我昔不願仕，會知出處妨。", "因循竟不免，密勿猶自强。", "默默抱遠志，悠悠視流光。", "豈知豢雞鶩，止欲歸稻粱。", "飛鳥呼其儔，羈馬憶故鄉。", "況兹平生懷，奔走非所望。", "朝吟在子邊，夕夢居子旁。", "歲暮菽可採，云誰助傾筐。", "桑落酒當熟，誰復共稱觴。", "忽忽無一歡，昏昏坐中堂。", "拂衣告言歸，念彼穉且狂。", "作此聊自娛，我思不能忘。"]'),
('2955244f-7c06-46af-8120-8d7047c7001e','八月六日寄鄰幾諸君','劉敞','宋','宋诗','song-poetry','','[]','謬爲天官屬，得與選事親。',156,'全唐诗/poet.song.27000.json','["謬爲天官屬，得與選事親。", "略計三百州，綠衣九千人。", "較材迷長短，守法愧因循。", "救末知不足，澄源力難伸。", "諸君備鄉老，多士競國賓。", "鑒形肖止水，播物參洪鈞。", "解論皆造微，詳延必逢真。", "仰成寛吏責，端本慰吾民。", "功則太平始，任非百職倫。", "聚精會冠劍，重鑰閟埃塵。", "寄重地必禁，問迹疏無因。", "風雨何蕭蕭，雞鳴夜將晨。", "一日如三月，況兹别累旬。"]'),
('9afccb0a-3739-4a21-90a8-060014ca0ff1','寄王深甫','劉敞','宋','宋诗','song-poetry','','[]','前日君遠遊，相憐每獨悲。',204,'全唐诗/poet.song.27000.json','["前日君遠遊，相憐每獨悲。", "寧知君未返，自笑還若兹。", "賢者易姓逃，聖者微服馳。", "聖賢不必容，吾道其如飴。", "浮舟潁水清，遠與塵囂違。", "卜鄰西郊郭，得近樵漁期。", "主人文章伯，聲望高一時。", "平生莫往還，見我如舊知。", "勢與年俱忘，胸中坦無疑。", "人當意氣展，何有憂寒饑。", "反思萬類情，紏纒未易推。", "向者雖定居，睽孤常不怡。", "邇來暫奔走，師友足自持。", "物或損而益，吾又何怨爲。", "且苟無陳人，吾豈能至斯。", "歲窮景蕭條，多感令志衰。", "須君濟其弱，嗟子何當來。"]'),
('f87b862b-aa4e-49d6-8efd-e5a3a2328eec','風雨寄貢甫','劉敞','宋','宋诗','song-poetry','','[]','積雨不自已，季秋聞驚雷。',120,'全唐诗/poet.song.27000.json','["積雨不自已，季秋聞驚雷。", "行子方遠道，憔悴感我懷。", "流潦紛縱横，高岡蔚崔嵬。", "左右無所覩，出入蒿與萊。", "百步一躑躅，十步一徘徊。", "村墟斷人煙，沈竈或産蛙。", "日月懸一隅，雲霧安得開。", "天遠人事邇，勞生使心哀。", "獨不如鳧鵠，奮翼超高飛。", "相望空長歎，撫襟泣如頹。"]'),
('c12b7a9c-fbcb-4cd4-8db9-054bba978bd7','寄王深甫','劉敞','宋','宋诗','song-poetry','','[]','城東與城西，相去咫尺耳。',96,'全唐诗/poet.song.27000.json','["城東與城西，相去咫尺耳。", "不得同朝夕，譬如隔山水。", "況兹歷三秋，正復累百里。", "念我誰與遊，悵然豈能已。", "古人稱莫逆，未必居密邇。", "自嫌感豫深，更失笑談理。", "寡陋使心憂，空虚見人喜。", "觀過而知仁，且當謝君子。"]'),
('7d78c35f-3650-420f-ab87-972f1807b310','寄論翊','劉敞','宋','宋诗','song-poetry','','[]','走馬平舒道，初日明三峰。',96,'全唐诗/poet.song.27000.json','["走馬平舒道，初日明三峰。", "嵐光共淡蕩，千丈青芙蓉。", "伊昔臨畫圖，但愛神仙蹤。", "安知復壯麗，翰墨難爲工。", "我行天地間，異景曾此逢。", "至今想見之，秀氣常沖融。", "世事勞人生，壯年成老翁。", "山中定見佳，恨未與君同。"]'),
('35ff396b-7be6-4bf2-9966-ec9a00dd9a2c','寄永叔','劉敞','宋','宋诗','song-poetry','','[]','俱持强漢節，共下承明殿。',96,'全唐诗/poet.song.27000.json','["俱持强漢節，共下承明殿。", "相從不相及，相望不相見。", "平生慕儔侣，宿昔異鄉縣。", "展轉多遠懷，恍惚猶對面。", "桑乾北風度，冰雪捲飛練。", "古來戰伐地，慘澹氣不變。", "贈君貂襜褕，努力犯霜霰。", "一尺握中策，無由奉深眷。"]'),
('d1bd626b-ff00-4f49-8094-86772360cbdc','寄鄰幾','劉敞','宋','宋诗','song-poetry','','[]','昨日非今日，今吾非故吾。',96,'全唐诗/poet.song.27000.json','["昨日非今日，今吾非故吾。", "蠱鳴知歲晚，鬚變哀年徂。", "萬事異俯仰，達者與化俱。", "故人千里外，高義獨何如。", "眷眷尺素書，湛湛雙酒壺。", "勸我加餐食，示我長相於。", "可憐平生好，不異東西居。", "我今心如結，那得從公舒。"]'),
('1d8b817c-4d1f-42e7-8af5-eb68a9c1e326','寄佑之','劉敞','宋','宋诗','song-poetry','','[]','長安風塵地，見子若舊交。',108,'全唐诗/poet.song.27000.json','["長安風塵地，見子若舊交。", "意氣何激昂，骨幹真蒲梢。", "戎胡擾邊封，殺氣連二崤。", "丈人國長城，多壘憂四郊。", "勁兵向海西，千里沸鼓鐃。", "共傳校尉印，勇略如虎虓。", "功業繫感激，念當覆妖巢。", "秋風日夜清，敵人知折膠。", "努力張國家，寄聲慰衡茅。"]'),
('c9dd20d7-b2d5-4392-96d8-dbc7a5809b8a','寄貢甫','劉敞','宋','宋诗','song-poetry','','[]','貧别書信闊，接壤如天涯。',96,'全唐诗/poet.song.27000.json','["貧别書信闊，接壤如天涯。", "沉憂心膓窄，少日如歲時。", "食荼苦在味，集蓼辛在外。", "百感従中生，通夕不遑寐。", "世路豈飄風，游子常轉蓬。", "鏡中見二毛，何啻非老翁。", "晚慕馬少游，結廬守鄉井。", "簡略或易足，長當並形影。"]'),
('92d4a78c-2406-416b-9542-fdde4d84d1db','寄張宜','劉敞','宋','宋诗','song-poetry','','[]','張君于福樂，先進野人也。',132,'全唐诗/poet.song.27000.json','["張君于福樂，先進野人也。", "曩者吾見之，大驚彼何者。", "鬚眉交蒼白，被服必儒雅。", "故善殷周間，不居王鄭下。", "諸士多及門，之子獨在野。", "食有脱粟飯，出無款段馬。", "鄉閭行雖高，時俗知亦寡。", "昨聞修庠序，造士繫陶冶。", "斯人宜聘起，可以專楚檟。", "養賢須勤渠，風教隨用舍。", "望君萬里餘，誰謂我心寫。"]'),
('d868201a-a748-4def-9090-32713953b945','寄阮二舉之楊十七彦文','劉敞','宋','宋诗','song-poetry','','[]','我昔居宋都，潛有伐樹憂。',192,'全唐诗/poet.song.27000.json','["我昔居宋都，潛有伐樹憂。", "不期得君子，卒歲同優游。", "楊生舊相知，情分故綢繆。", "阮公出傾蓋，而肯如白頭。", "古人有忘年，嗟我非此儔。", "譬如羔袖微，豈可參狐裘。", "知人視其友，孔聖稱焉廋。", "所以梁楚間，亦聞東家丘。", "相從未云厭，相别難自留。", "贈我數百言，精神露蛟虬。", "楊子期我用，謂當佐王侯。", "阮公推我文，云可齊尹歐。", "斯言豈易當，斯道豈易求。", "奈何千金珠，中夜而暗投。", "書紳願自勗，雜佩非可酬。", "欲知相憶心，淮水清悠悠。"]'),
('30f50a37-9550-458c-8991-84a42b321f20','寄楊阮','劉敞','宋','宋诗','song-poetry','','[]','中堂明華燈，宥坐湛清酒。',48,'全唐诗/poet.song.27000.json','["中堂明華燈，宥坐湛清酒。", "筆硯居我前，史籍在我後。", "君知我不樂，我念平生友。", "强醉誰與歡，悵然夜將久。"]'),
('98421815-9983-418f-a2e9-1c51ce0175fe','温柑','劉敞','宋','宋诗','song-poetry','','[]','后皇富佳樹，柑實掩羣衆。',168,'全唐诗/poet.song.27000.json','["后皇富佳樹，柑實掩羣衆。", "磊落驪珠圓，參差金壺重。", "剖丹瓊瑤碎，蓄潤霜雪凍。", "封苞萬里險，照耀高堂供。", "憶昔伯禹籍，蒼茫闕斯貢。", "及乎騷人賦，流落遺爾頌。", "反登橘柚輩，海物隨錯綜。", "圖諜迷萬世，不平竟誰訟。", "頗疑古未有，彼故得豪縦。", "溟海通蓬萊，近由仙者種。", "又疑美過絕，讒口斥不用。", "寂寥三王時，此理彌可痛。", "安得舉其族，北遷越巖洞。", "歲比萬戶封，蠲煩與人共。"]'),
('a28fb217-aad9-4a76-b6bd-f553c9f0fc3f','贈山僧','劉敞','宋','宋诗','song-poetry','','[]','貧病不出門，趣與時俗乖。',96,'全唐诗/poet.song.27000.json','["貧病不出門，趣與時俗乖。", "高卧謝賓客，秋葉忽滿階。", "今旦爲誰埽，釋子遠見懷。", "問我平安否，曠然外形骸。", "貌疏意如真，語淡情反諧。", "旅人非一感，及爾能安排。", "聞道常愧晚，智也豈有涯。", "他日更解榻，虚談慰心齋。"]'),
('f965df53-891c-4f0b-8432-01caa8970aeb','達師','劉敞','宋','宋诗','song-poetry','','[]','師雖支離流，于道乃全人。',96,'全唐诗/poet.song.27000.json','["師雖支離流，于道乃全人。", "未嘗事感豫，來者自欲親。", "時時平是非，往往動精神。", "縱横及萬事，慷慨驚四鄰。", "乃知全一身，不必山野民。", "乃知憂當世，不必朝廷臣。", "語默兩有適，動静皆可循。", "彼哉小丈夫，孰能識吾真。"]'),
('d3cbc55a-40a4-4b8e-86db-48b07303cc11','喜晴寄彦猷','劉敞','宋','宋诗','song-poetry','','[]','積陰向十日，不見江南山。',48,'全唐诗/poet.song.27000.json','["積陰向十日，不見江南山。", "何意浮雲盡，依然庭戶間。", "芳草晚已歇，瑤華初可攀。", "故人在遠道，悵望凋朱顔。"]'),
('6233d0e4-27d4-4b3b-a2c7-b17cef0dc349','永叔西齋送沖卿知陜府','劉敞','宋','宋诗','song-poetry','','[]','我求一州牧，竟至無津涯。',48,'全唐诗/poet.song.27000.json','["我求一州牧，竟至無津涯。", "相看佩銅虎，似欲凌青霞。", "分陜本相事，憩棠成棣華。", "優游山河勝，肯厭多風沙。"]'),
('b70b3f1a-4277-4b7b-9b8f-6a61560a98d3','後出郊二首  其一','劉敞','宋','宋诗','song-poetry','','[]','人遠地形曠，氣收天宇高。',48,'全唐诗/poet.song.27000.json','["人遠地形曠，氣收天宇高。", "不辭乘興出，直恐應接勞。", "送雁時揮弦，羨魚復臨濠。", "君知適意樂，未悟生二毛。"]'),
('7c92d53a-2565-4e57-8d11-765062b21375','後出郊二首  其二','劉敞','宋','宋诗','song-poetry','','[]','歲晚農事畢，里閭競歡然。',48,'全唐诗/poet.song.27000.json','["歲晚農事畢，里閭競歡然。", "相見有餘情，獨游頗忘年。", "上懷羲皇世，下感沮溺賢。", "豈以六金印，而輕二頃田。"]'),
('501b7eb3-5bee-45f0-a61d-d546fe30130d','涼榭許道寧畫山','劉敞','宋','宋诗','song-poetry','','[]','許生擅丘壑，融結隨毫端。',48,'全唐诗/poet.song.27000.json','["許生擅丘壑，融結隨毫端。", "醉埽堂上壁，參差皆可觀。", "飛雪暗連峰，對之中夏寒。", "吾能捐萬事，于此聊盤桓。"]'),
('0fd9f06c-7919-4a01-95d1-5ff56eaa5f02','獨釣南湖','劉敞','宋','宋诗','song-poetry','','[]','澄澄春波深，中有魴與鯉。',132,'全唐诗/poet.song.27000.json','["澄澄春波深，中有魴與鯉。", "無人收潛隱，好生得吾子。", "投竿坐孤石，盡日倦未起。", "既失常若驚，有逢忽然喜。", "子心豈殘物，子道豈娛己。", "人誰辨子意，我請盡其理。", "垂釣須得鮮，治國須得賢。", "所以不憚勤，豈在蝦魚間。", "君子愛其君，諷諭以爲先。", "詹何臧丈人，古事皆已然。", "誰將子之術，更誦吾君前。"]'),
('afc6c43b-a94d-413a-9f5b-2ff3d21d1a44','負暄四首  其一','劉敞','宋','宋诗','song-poetry','','[]','歳晚天地閉，積陰凍乾坤。',288,'全唐诗/poet.song.27000.json','["歳晚天地閉，積陰凍乾坤。", "大鈞止亭育，羣鬼私自尊。", "竊弄造化柄，擅令衆陰存。", "幽奸發玄漠，死氣蒸黎元。", "朋黨漸相蔽，大辰訴其冤。", "帝惟百物憂，恐不見陽春。", "敕使拘衆鬼，朝曦送微温。", "大明煥幽鬱，和氣迥崑崙。", "初曉尚餘禀，漸高遂增暄。", "煩冥避窮朔，玉燭調中原。", "衆蟄久僵俘，今來更騰鶱。", "微禽鷃與雀，弄影勢飛翻。", "草木反生意，益思擢鮮繁。", "潛魚離冰穴，無數遊清源。", "嗟我同此慶，兀然坐朝昏。", "緼袍幸可賴，卒歳無復論。", "稍稍出辭氣，仰天荷公恩。", "始知過狐白，願得陳至尊。", "昔宋有愚叟，亦能款君門。", "况今事西討，十萬羅櫜鞬。", "烽火通警急，鐡衣遶夷蕃。", "幸悲墮指魄，少慰無衣魂。", "誠使勝挾纊，豈在衣便蕃。", "斯言出感激，忠信非詐諼。"]'),
('8ad90f73-3b23-471b-b855-30b571757e42','負暄四首  其二','劉敞','宋','宋诗','song-poetry','','[]','南極無永晝，北方多苦寒。',60,'全唐诗/poet.song.27000.json','["南極無永晝，北方多苦寒。", "負暄意頗適，容膝居亦安。", "嘯傲長者轍，崔嵬切雲冠。", "道書異俗味，稚子同大歡。", "不覺老將至，安知利害端。"]'),
('066b5ca9-3fe7-4939-bef5-089e66ce76e3','負暄四首  其三','劉敞','宋','宋诗','song-poetry','','[]','被褐暖不足，負暄温有餘。',60,'全唐诗/poet.song.27000.json','["被褐暖不足，負暄温有餘。", "內慚意氣狹，婉孌在庭除。", "清晨倚西楹，夕暮守東隅。", "常恐浮雲起，冰雪不須臾。", "靳靳懷薄願，安得留飛烏。"]'),
('e3a35db4-834b-4626-b815-91a164998c22','負暄四首  其四','劉敞','宋','宋诗','song-poetry','','[]','日出東南隅，晨光散瞳曨。',72,'全唐诗/poet.song.27000.json','["日出東南隅，晨光散瞳曨。", "山形西北去，暖氣浮冲融。", "天地大逆旅，客身一飄蓬。", "胡雛啼朝霜，邊馬嘶朔風。", "獨懷負暄樂，未許斯人同。", "歸當獻天子，無乃笑愚忠。"]'),
('118a5664-39ab-4801-bc0b-b150c8598973','遊仙','劉敞','宋','宋诗','song-poetry','','[]','焦明忌常處，蟪蛄愁永年。',96,'全唐诗/poet.song.27000.json','["焦明忌常處，蟪蛄愁永年。", "淺俗更相訾，曠懷自邈然。", "我從造化遊，夐立萬物先。", "四海固咫尺，大椿不獨延。", "日月爲我駕，昏明相回旋。", "超遙無終薄，浩蕩遺拘蠻。", "豈與功明士，姝姝以暖暖。", "智極蝸角下，形敝陽榮間。"]'),
('e86c0db1-0788-4345-abcf-c50afcefd469','種萱','劉敞','宋','宋诗','song-poetry','','[]','種萱不種蘭，自謂憂易忘。',48,'全唐诗/poet.song.27000.json','["種萱不種蘭，自謂憂易忘。", "綠葉何萋萋，春愁更茫茫。", "古人有虚語，名實未必當。", "南箕與北斗，燦爛空成章。"]'),
('e7f76e44-a089-4039-896a-b4b48caf6f4a','讀莊子三首  其一','劉敞','宋','宋诗','song-poetry','','[]','簫韶豈不美，爰居終自悲。',72,'全唐诗/poet.song.27000.json','["簫韶豈不美，爰居終自悲。", "俛仰魯城上，驚顧不能怡。", "伊昔舜廷內，鳴鳯爲來儀。", "和聲詎中變，衆聽邈難齊。", "澆淳懸異代，聰昧未殊施。", "咄嗟播鼗武，永乏滄海歸。"]'),
('96803ee8-a449-44b6-a652-bc015a1fc993','讀莊子三首  其二','劉敞','宋','宋诗','song-poetry','','[]','漢陰灌園叟，抱甕力難任。',72,'全唐诗/poet.song.27000.json','["漢陰灌園叟，抱甕力難任。", "規爲一何拙，機事自傷心。", "賜也不受命，愧之汗沾襟。", "至言與世邈，幽操非俗尋。", "以此高宇宙，豈知倦山林。", "彼哉夸奪子，佩服爛朱金。"]'),
('b83ff6d3-556a-4e90-b967-3acdd66f9b6e','讀莊子三首  其三','劉敞','宋','宋诗','song-poetry','','[]','商丘有奇樹，厥生非一朝。',60,'全唐诗/poet.song.27000.json','["商丘有奇樹，厥生非一朝。", "修根走靈社，騰幹拏赤霄。", "拳局無大用，液樠不可彫。", "誰謂非世器，終焉托逍遙。", "致身適有遇，松桂寧免樵。"]'),
('ac48dd5f-d4fa-4ca3-bcc3-96441e3284c7','吳中大水有負郭田在常州云已漂潰作一首示公儀','劉敞','宋','宋诗','song-poetry','','[]','百谷馳東南，三江澆吴會。',96,'全唐诗/poet.song.27000.json','["百谷馳東南，三江澆吴會。", "積陰漏雲漢，涌水翻積塊。", "斯民既昏墊，我稼墮顛沛。", "魚鼈有餘糧，郊原靡遺穗。", "餬口竊自恕，矜寡將何賴。", "天道有盈虚，吾寧罪于歳。", "救饑苦謀拙，禹稷不可待。", "行矣帆長風，因之浮海外。"]'),
('fb0676e3-9006-48dd-9bf2-e35eca1a9099','覽古二首  其一','劉敞','宋','宋诗','song-poetry','','[]','固國不須險，用兵不須强。',72,'全唐诗/poet.song.27000.json','["固國不須險，用兵不須强。", "域民在所守，威敵在所良。", "由余仕諸戎，秦穆警封疆。", "晏子猶在齊，范昭識難亡。", "小國有其人，大國豈易當。", "奈何億萬師，牧野遂煌煌。"]'),
('f5a36f97-0d90-4401-be05-24768f3db947','覽古二首  其二','劉敞','宋','宋诗','song-poetry','','[]','天馬出西極，由來中國用。',60,'全唐诗/poet.song.27000.json','["天馬出西極，由來中國用。", "楩楠秀荆楚，乃作晉梁棟。", "遺材彼興憂，得寶此以重。", "伍員楚亡命，一旦摧郢衆。", "世薄事有然，申胥得無慟。"]'),
('ee5a74a9-ff08-4802-944d-0747e2975699','和聖俞織女無恥羞','劉敞','宋','宋诗','song-poetry','','[]','織女有恥羞，歳一過牽牛。',96,'全唐诗/poet.song.27000.json','["織女有恥羞，歳一過牽牛。", "暫來已遽往，光景不少留。", "會合一何亟，離别一何脩。", "不知靈匹意，正使今人愁。", "河漢清且廣，風波無時休。", "蹇修古不存，烏鵲相爲謀。", "理拙心莫同，誰令結綢繆。", "蛾眉坐自老，紈扇空悲秋。"]'),
('787af740-15ab-4d81-97c7-4afe0fb36d3b','同獻臣七月七日夜詠牛女','劉敞','宋','宋诗','song-poetry','','[]','熒煌昭回章，婉孌靈匹燕。',72,'全唐诗/poet.song.27000.json','["熒煌昭回章，婉孌靈匹燕。", "薄霧垂絪衣，明星綴華瑱。", "潔身奉君子，所幸常顧眷。", "風浪既多艱，歳時劇飛箭。", "會賒别堪疑，那能鬒不變。", "願構虹蜺梁，與君常相見。"]'),
('b55739b3-f00b-4108-9edd-1aa984598176','觀水','劉敞','宋','宋诗','song-poetry','','[]','楚山積陰霖，百谷盛號怒。',120,'全唐诗/poet.song.27000.json','["楚山積陰霖，百谷盛號怒。", "虎豹亡其曹，蛟龍失所据。", "勢排蒼崖列，力與巨石注。", "頃刻浮青天，微茫浸高樹。", "兹城依平原，自古北懸瓠。", "墊溢安敢辭，漂浮實所懼。", "禹功不可及，河伯欲誰惡。", "寧以蛙龜歡，姑爲下民蠧。", "築防力不足，疏瀉志猶慕。", "安得鞭馮蠵，從兹萬里騖。"]'),
('fc1bd402-5461-4ba7-91b8-725bc568ad3b','喜雨','劉敞','宋','宋诗','song-poetry','','[]','海上雨初至，中庭樹交翻。',96,'全唐诗/poet.song.27000.json','["海上雨初至，中庭樹交翻。", "幽人整冠帯，喜見雷電存。", "積潤瀉河漢，餘滋被邱原。", "魚龍倘可活，鼃黽誰嫌喧。", "稍稍秋欲變，微凉入前軒。", "古人致亹亹，吾亦開吾樽。", "御叔小丈夫，頗知笑臧孫。", "賢愚定誰是，興盡忽忘言。"]'),
('142fb9fe-9ea0-4505-b3bf-c80a873005d4','送張氏家姊至丹陽早别','劉敞','宋','宋诗','song-poetry','','[]','曠野凉氣早，八月風已寒。',48,'全唐诗/poet.song.27000.json','["曠野凉氣早，八月風已寒。", "遙雲結層陰，白雲被芳蘭。", "徬徨步高隰，怵惕傷肺肝。", "奈何遠别離，涕下若波瀾。"]'),
('7ded0704-421f-4771-b51a-e1eec31ed01b','木鴈堂','劉敞','宋','宋诗','song-poetry','','[]','聽訟吾猶人，安得終曰間。',72,'全唐诗/poet.song.27000.json','["聽訟吾猶人，安得終曰間。", "從吏已可知，拂衣未能還。", "逍遙及餘暇，苟且寛心顔。", "灑掃延清颷，空凉闢重關。", "古人有所處，才與不才間。", "持此以自娛，將非真隱然。"]'),
('4d27b570-6561-407d-b7fc-d8e08dde23c4','寄題蕭山歳寒堂','劉敞','宋','宋诗','song-poetry','','[]','伊堂早頹挫，松柏亦憔悴。',168,'全唐诗/poet.song.27000.json','["伊堂早頹挫，松柏亦憔悴。", "常惟摧爲薪，中塗失蒼翠。", "昨來始營葺，榱桷復高麗。", "蕭蕭青雲幹，始有百大意。", "神明頓來還，故老咸歔欷。", "朝燕得所常，問誰救其敝。", "吾家渥洼駒，頗有超絕氣。", "好事能復古，愛奇趣起廢。", "後凋甚明白，來者思彷彿。", "此實賢智謀，古人貴豈弟。", "仲尼頌子産，其養民也惠。", "召公憇甘棠，後世歌蔽芾。", "勉旃崇其業，事足伯父繼。", "令名與佳樹，自可俱億歳。"]'),
('7d7dc55b-f84c-405b-a408-4365a3e2bc42','示鄉人陳生','劉敞','宋','宋诗','song-poetry','','[]','我祖學蘆山，潛光玩詩書。',192,'全唐诗/poet.song.27000.json','["我祖學蘆山，潛光玩詩書。", "君家獨先覺，一見矜里閭。", "固有如陳平，長貧賤者乎。", "青雲果自致，遠鑒驚羣愚。", "鳴風兆有媯，懿占信不誣。", "粲然諸子賢，仕各列大夫。", "號稱萬石君，盛事衣冠無。", "聲華輝圖史，豈獨榮枌榆。", "外族繼清高，恥爲事物拘。", "未嘗入城府，奕世風不渝。", "宜有羔鴈求，怪其久闕如。", "君來就鄉賦，信足光慶餘。", "郡守勸駕行，紫庭與計俱。", "努力事學問，豫章擢扶疏。", "游子懷故鄉，矧伊接葭莩。", "勉率爲歌詩，尚能念起予。"]'),
('61df20e7-8b5c-44e8-84fa-7a96fc41928a','聽府妓歌憶春卿資政給事','劉敞','宋','宋诗','song-poetry','','[]','南方酒如澠，醉倒本容易。',96,'全唐诗/poet.song.27000.json','["南方酒如澠，醉倒本容易。", "蔡姬緩聲歌，清響動雲際。", "惜哉知音稀，此輩自難值。", "曩者東山游，一日已三歳。", "人遐成陳迹，興盡失超詣。", "寥寥方外歡，獨數嵇阮輩。", "凍雲臨寒空，掩鬱邁往氣。", "引杯亂愁思，擊節還拊髀。"]'),
('0dfa0078-02aa-49d5-96e1-47edb824ae10','招斁','劉敞','宋','宋诗','song-poetry','','[]','鑿井不及水，雖勞乃無功。',96,'全唐诗/poet.song.27000.json','["鑿井不及水，雖勞乃無功。", "耕田捨終畝，歳暮安俟豐。", "人當少年時，耳目明以聰。", "所爲患不能，所學患不通。", "患之不自勉，老去逾顓蒙。", "雖復欲自力，歳時已飄蓬。", "譬彼陟大水，不能曉西東。", "諭爾安可忘，我嘗夢周公。"]'),
('10ed1fa4-70c5-446e-a843-f714e00f7a7c','朝乘','劉敞','宋','宋诗','song-poetry','','[]','朝乘日車出，暮戴星影還。',48,'全唐诗/poet.song.27000.json','["朝乘日車出，暮戴星影還。", "顛冥朝暮中，出入咫尺間。", "已覺素志非，更知人理艱。", "小利專欲速，大德不踰閑。"]'),
('22001d09-1ef8-480b-8d87-8f9c8daf6247','雪','劉敞','宋','宋诗','song-poetry','','[]','楚塞常閔雪，窮冬未爲晚。',96,'全唐诗/poet.song.27000.json','["楚塞常閔雪，窮冬未爲晚。", "欣看朔風過，想自萬里遠。", "崩騰龍沙飛，浩蕩北溟卷。", "勢排炎荒瘴，力救南國旱。", "悲鴈飛何之，蟄龍卧終偃。", "至神亦憔悴，爾輩何繾綣。", "歳陰倐將改，天運有必反。", "慷慨吾何言，短衣數自挽。"]'),
('aa06f2c3-4635-453d-976c-a7c7826570d6','復雪二首  其一','劉敞','宋','宋诗','song-poetry','','[]','十日三雨雪，同陰坐朝昏。',96,'全唐诗/poet.song.27000.json','["十日三雨雪，同陰坐朝昏。", "幽人感歳晚，更覺日月奔。", "勁風西北來，轟哮動乾坤。", "中州山崑墟，四徹皆璵璠。", "鴻鴈遊可哀，竹柏生僅存。", "念此使心悲，何時見陽春。", "志士則憔悴，薄俗安足論。", "鄉里狐狢兒，反怪天正温。"]'),
('0a032e80-93f6-450f-82b7-717e684f75c7','復雪二首  其二','劉敞','宋','宋诗','song-poetry','','[]','前夕盛雷電，謂言春和發。',168,'全唐诗/poet.song.27000.json','["前夕盛雷電，謂言春和發。", "典衣買春酒，歳事亦可悅。", "不知天難諶，信宿更凝冽。", "朝來雪盈尺，初計頓乖越。", "吾廬甘重塞，敝褐忍百結。", "豈敢咨祁寒，又非慕炎熱。", "陰陽相交錯，萬一成災孽。", "憶昔魯隱公，九年春三月。", "癸酉雨震電，庚辰大雨雪。", "春秋書爲法，其事何照晰。", "曾經聖人筆，下學而上達。", "况此四月間，又當季春末。", "願排閶闔戟，一獻春秋說。", "路遠泥阻深，愁哉卧巖穴。"]'),
('261cd67b-11b3-44e4-bb3a-08b58a54ff5b','書堂','劉敞','宋','宋诗','song-poetry','','[]','客身困旅人，未如負舍蝸。',132,'全唐诗/poet.song.27000.json','["客身困旅人，未如負舍蝸。", "滚滚荆吳間，所居不常家。", "宴安非吾事，但恐髪早華。", "且復一日葺，隨時具生涯。", "白盛爛四壁，塋凈磨疵瑕。", "虚明豁心府，永使思無邪。", "愁來莫與語，起就書龍蛇。", "亦足寫方寸，放歌快咨嗟。", "苦嫌中庭窄，所生野草花。", "故須種松竹，反憶日月遐。", "歳寒與誰共，惆悵終無他。"]'),
('2c1f6aaa-95e5-44bd-a7e0-5ddfe1b6f11e','答江丈雨中','劉敞','宋','宋诗','song-poetry','','[]','繁陰乘炎夏，晦色竟朝暮。',120,'全唐诗/poet.song.27000.json','["繁陰乘炎夏，晦色竟朝暮。", "蛟龍困雲雷，虎豹病氛霧。", "過時畏昏墊，推分縱所遇。", "閉閣空自愁，救饑眇無素。", "江侯卧閭里，本自濟時具。", "方與造物遊，昔同斯人慮。", "作詩破幽憤，極筆紆遠慕。", "磊落三賢人，千秋如面晤。", "道同義相契，未必形影附。", "長謡雞鳴篇，因見君子度。"]'),
('83fc4cd5-a534-4304-94af-8c6e553080b7','九月十日雨中孚先見過圍棋嘗茶','劉敞','宋','宋诗','song-poetry','','[]','幸從大夫後，而無吏事憂。',144,'全唐诗/poet.song.27000.json','["幸從大夫後，而無吏事憂。", "出沐風雨夕，閉門松菊秋。", "素交辱見過，意氣何綢繆。", "車騎皆雨立，富貴若浮雲。", "圍棋紓壯心，酌茗當獻酬。", "豈惟鄰里好，足慰平生游。", "書籍可許通，水火得所求。", "獨恨雞黍薄，無以充淹留。", "我窮若匏瓜，于世良悠悠。", "寂寞守一隅，非君誰見收。", "庶幾除三徑，玩此歳方遒。", "莫令子衿詩，更作商聲謳。"]'),
('72e36f47-5220-4477-a9be-fdedf25104fe','渴雨示府僚','劉敞','宋','宋诗','song-poetry','','[]','東風破窮陰，農者亦望歳。',180,'全唐诗/poet.song.27000.json','["東風破窮陰，農者亦望歳。", "宿雪滋巳消，驕陽更爲沴。", "璣衡運元化，律呂導和氣。", "四序宜平分，斯人尚憔悴。", "關中大兵後，所向半凋敝。", "荆棘獨至今，睠言可涕泣。", "憶昨辭紫宸，從容畫民事。", "焦勞見顔色，曠蕩灑恩惠。", "開倉出其陳，履畝奪浮議。", "乃知聖神心，獨在舜禹際。", "所憂吏不稱，未足效兼濟。", "安得三日雨，滂沱澤厚地。", "百昌奮皆作，吾亦免于戾。", "吁嗟望雲漢，冥漠想萍翳。", "交泰及此時，羣生豈終否。"]'),
('d473a566-640f-425b-8f79-1c0fd5a7fb43','成冬','劉敞','宋','宋诗','song-poetry','','[]','富貴抱憂患，貧賤苦煎熬。',96,'全唐诗/poet.song.27000.json','["富貴抱憂患，貧賤苦煎熬。", "居此二者間，幸無終歳勞。", "養生賴裘葛，卜隱開蓬蒿。", "既不碌碌冗，又不巍巍高。", "炎凉縱所遇，寒暑俱可逃。", "竭力供子職，大歡對兒曹。", "至人貴真樂，名位豈所饕。", "咄嗟路傍子，生死堪悲號。"]'),
('d017a835-1d1d-41f4-a294-6f65c6560c9e','卜居謝晏公','劉敞','宋','宋诗','song-poetry','','[]','燕雀赴廣廈，雞鶩就卑棲。',132,'全唐诗/poet.song.27000.json','["燕雀赴廣廈，雞鶩就卑棲。", "我生共有託，生理與汝齊。", "憂患歷險艱，轉徙疲東西。", "常慕蠻與觸，所居能自賫。", "哀吟蹈楚郊，主人欲招攜。", "卜築煩里旅，婦姑免勃谿。", "此邦非故鄉，習俗素所迷。", "頗以羈見忌，得安糝與藜。", "下見賢相仁，恤隱逾天倪。", "陰德少陽報，眉壽至介圭。", "已當受一廛，終身活灌畦。"]'),
('3a512e1b-220b-432b-922f-c62729719aaa','卜居','劉敞','宋','宋诗','song-poetry','','[]','清波照蓽門，垂柳拂危軒。',48,'全唐诗/poet.song.27000.json','["清波照蓽門，垂柳拂危軒。", "靜境偏相慰，鳴禽時一喧。", "羡魚還結網，引水自疏源。", "嘯傲陶唐世，幽憂不可諼。"]'),
('ac94841f-0d63-4c23-92e7-674ff5d0668c','蘆泉','劉敞','宋','宋诗','song-poetry','','[]','吾山會雨澤，汗漫千里秋。',96,'全唐诗/poet.song.27000.json','["吾山會雨澤，汗漫千里秋。", "不如蘆泉水，來入城中流。", "經營萬餘家，澄澈去無際。", "我樂與衆同，泉能起人意。", "泉旁宜嘉林，時多桐與梓。", "泉間宜美魚，時有魴與鯉。", "誰能捐萬事，來我泉上居。", "我欲解章綬，從之泉上漁。"]'),
('07e4e7e9-7ff2-4560-9981-d55d2b4f13dd','浮光山人','劉敞','宋','宋诗','song-poetry','','[]','先生方獨往，逝與一世辭。',84,'全唐诗/poet.song.27000.json','["先生方獨往，逝與一世辭。", "雖未超雲霞，豈嘗顧喧卑。", "事親止于適，接物能不爲。", "谷中虎豹多，往往行自隨。", "此是真人風，何必太古時。", "吾欲從之遊，自嫌迹尚非。", "寄心逍遙間，聊可以相期。"]'),
('a7405ba2-15d9-47e8-8a40-6c24b71db598','初到東平得雨','劉敞','宋','宋诗','song-poetry','','[]','少服逢掖衣，又爲梁甫吟。',96,'全唐诗/poet.song.27000.json','["少服逢掖衣，又爲梁甫吟。", "謬膺東藩守，似慰畸人心。", "宣布祗上恩，浚明肅官箴。", "治醇俗易美，事半功反深。", "嘉雨蘇旱苗，慶雲結重陰。", "天將假民樂，我以開煩襟。", "鉅野會百川，東山凌衆岑。", "庶幾緩吾带，一一窮登臨。"]'),
('94316725-a1e0-4b67-ac19-f4deee4a3267','雨中送張六','劉敞','宋','宋诗','song-poetry','','[]','秋陰蔽陽光，雨潦如昏墊。',84,'全唐诗/poet.song.27000.json','["秋陰蔽陽光，雨潦如昏墊。", "居人鬱無聊，游子行可念。", "方攜一樽酒，欲别情不厭。", "雖無車馬贈，篇賦私敢占。", "人生遠圖在，離索安足慊。", "願爲東南風，刮日豁長熖。", "取觴醉車軌，千里由此漸。"]'),
('27645d0a-d0cc-4567-be20-af13422085d4','攝領審官六日還印長文戲作五言','劉敞','宋','宋诗','song-poetry','','[]','山野不事事，未嘗中繩墨。',84,'全唐诗/poet.song.27000.json','["山野不事事，未嘗中繩墨。", "得官筆硯間，懶與慢成癖。", "前日承君乏，始親薄領役。", "捶鈎校毫芒，簡髪差寸尺。", "自知非其任，良有不可力。", "君誠神仙人，那得頭不白。", "繇兹謝睎跂，依隱就閒寂。"]'),
('b4cae89b-2ff0-46af-b65a-407310e5cc28','桐花','劉敞','宋','宋诗','song-poetry','','[]','一株青玉立，千葉綠雲委。',48,'全唐诗/poet.song.27000.json','["一株青玉立，千葉綠雲委。", "亭亭五丈餘，高意猶未已。", "仙僧年九十，清淨老不死。", "自云手種時，一顆青桐子。"]'),
('06f7ee5d-29ff-442c-92bb-7ac6655829a0','同梅聖俞送尹郎中監舒川靈仙觀','劉敞','宋','宋诗','song-poetry','','[]','真人西度關，乃祖獨知之。',144,'全唐诗/poet.song.27000.json','["真人西度關，乃祖獨知之。", "强著五千言，竦身棄喧卑。", "靈光無時没，人世自超忽。", "上下千歳間，裔孫亦清出。", "論兵復擊劍，遠與道同符。", "功名不如意，白髪笑桑榆。", "藏書天祿閣，卜居天柱山。", "此職無吏責，去去何時還。", "山中醉白雲，山下弄流水。", "吾已了損益，未知生死耳。", "聊登千仞巔，下視寰中塵。", "更因長風來，揮手謝世人。"]'),
('e3b0a887-76a7-4fa1-8301-5dbc0ce924b1','記所居草樹','劉敞','宋','宋诗','song-poetry','','[]','幽蘭晚已秀，新竹直且疏。',96,'全唐诗/poet.song.27000.json','["幽蘭晚已秀，新竹直且疏。", "樸樕亦巢禽，坳堂自容魚。", "長日肆炎赫，周軒正清虚。", "適心不貴多，一畝覺有餘。", "理會遣孤笑，興來味羣書。", "彼何擾擾爾，我獨欣欣歟。", "人臣無懷安，吏治猶蘧蘆。", "幸及三年淹，庶幾閒燕居。"]'),
('44047514-1476-41d6-bed6-8fa6b4a7665f','銅雀臺瓦硯','劉敞','宋','宋诗','song-poetry','','[]','當時鴛鴦夢，飛入魏宫來。',48,'全唐诗/poet.song.27000.json','["當時鴛鴦夢，飛入魏宫來。", "崇構滅餘香，碧瓦空在哉。", "磨礱變新硯，洗刷滌故苔。", "但取圭角全，何必瓊與瑰。"]'),
('21e36cb4-1fae-4003-8d51-76d856e74c15','樹下二首  其一','劉敞','宋','宋诗','song-poetry','','[]','中庭兩佳樹，密葉如翠帷。',108,'全唐诗/poet.song.27000.json','["中庭兩佳樹，密葉如翠帷。", "擢幹一何高，鋪陰被前墀。", "清風自翩翻，正晝無炎曦。", "拱揖在我前，我常往參之。", "隱几旦復暮，卷書坐忘疲。", "安知非華屋，聊以庇蔭爲。", "瑤室隕帝辛，璧臺喪周姬。", "由來滅亡禍，不爲草野施。", "偃仰更何顧，欣歡方在兹。"]'),
('63c69b1f-7a79-49c4-998f-df334bdd7f15','樹下二首  其二','劉敞','宋','宋诗','song-poetry','','[]','召公愛小棠，百歳俾勿拔。',72,'全唐诗/poet.song.27000.json','["召公愛小棠，百歳俾勿拔。", "仲尼憩大樹，一宿輒已伐。", "聖賢豈殊途，人事有窮達。", "出處何可常，我身固微末。", "上無燕伯遇，下無宋人孽。", "從容聖賢間，得此亦已竊。"]'),
('ecb813c2-ab81-4577-b4c6-e3c4b638b7ce','庭樹','劉敞','宋','宋诗','song-poetry','','[]','中庭無多樹，花盡自成陰。',72,'全唐诗/poet.song.27000.json','["中庭無多樹，花盡自成陰。", "熏風吹清和，午影還蕭森。", "上有出谷鳥，間關鳴好音。", "下有放言人，寂寞卧機心。", "人鳥各相忘，語默不見侵。", "吾廬此最好，豈意在山林。"]'),
('5890c215-91f0-4045-8987-e84a9086071c','送石昌言知宿州','劉敞','宋','宋诗','song-poetry','','[]','宦情重居內，世論輕守藩。',168,'全唐诗/poet.song.27000.json','["宦情重居內，世論輕守藩。", "出處苟自得，重輕安足原。", "昔常怪蕭傅，恥乘太守幡。", "頗獨多嚴生，厭直金馬門。", "優游樹風迹，宣布流上恩。", "何負廷中臣，而貶千乘尊。", "石侯古人風，自令薄夫敦。", "平日不汲汲，左遷更軒軒。", "輕舟趣行裝，合符去天閽。", "高卧可以治，簿書豈所煩。", "我亦羈旅人，不堪市朝喧。", "又無適時用，坐自悲素餐。", "願爲江湖長，聊復育元元。", "子若未北歸，相過識吾言。"]'),
('41c29adb-d626-4991-9f45-173813a931eb','題和弟所居桐樹','劉敞','宋','宋诗','song-poetry','','[]','卜隱謝林藪，考槃寄閭里。',48,'全唐诗/poet.song.27000.json','["卜隱謝林藪，考槃寄閭里。", "嘉樹爲我徒，清風濯塵耳。", "手披漆園書，身擬長梧子。", "窮秋忽感悲，埽榻且歡喜。"]'),
('61e367d2-a343-4405-9d0b-f8514aec775e','冬晚贈深甫','劉敞','宋','宋诗','song-poetry','','[]','客游已昨日，已復歳月改。',48,'全唐诗/poet.song.27000.json','["客游已昨日，已復歳月改。", "流光一如此，故物紛晦在。", "忽使中心悲，悠悠若浮海。", "相思間何闊，此意君當解。"]'),
('d920f7f0-de4d-4c47-a078-c4dba2aca934','效陶潛體','劉敞','宋','宋诗','song-poetry','','[]','出門逢一士，抱書向南山。',108,'全唐诗/poet.song.27000.json','["出門逢一士，抱書向南山。", "問其何爲爾，欲語輒復歎。", "少小貴詩書，志業覬孔顔。", "爾來三十載，鬢髪倐已斑。", "唐虞不可待，世譽亦恥干。", "寧赴巖谷老，行行未遽還。", "其言乃可感，使我再凄然。", "人生歸有命，窮達何足言。", "勸爾飲此酒，唐虞在其間。"]'),
('6b024944-ba90-4afd-a049-76816a55f412','懶詩','劉敞','宋','宋诗','song-poetry','','[]','分表難强營，俗中彌不堪。',60,'全唐诗/poet.song.27000.json','["分表難强營，俗中彌不堪。", "始覺懶亦真，功名焉可貪。", "婆婆玩流光，幽寂信所諳。", "束带愁逢迎，燕處倦交談。", "碌碌史隱間，將爲兹世慚。"]'),
('8baa1f62-a5ca-4b84-8577-9ea5d8c25fda','菖蒲','劉敞','宋','宋诗','song-poetry','','[]','香清自足愛，味厚非所倫。',48,'全唐诗/poet.song.27000.json','["香清自足愛，味厚非所倫。", "如何缺缺徒，反以花爲真。", "花奇不可見，舉世皆忌辛。", "誰將擢仙骨，願比芝苗珍。"]'),
('d7e5ae1f-b074-49c8-a32c-899c7b532cfd','登薦福寺山亭','劉敞','宋','宋诗','song-poetry','','[]','時事如不聞，煩襟尚鬰怫。',96,'全唐诗/poet.song.27000.json','["時事如不聞，煩襟尚鬰怫。", "高亭一何壯，俾我遺外物。", "是時夏景初，竹樹雨飄拂。", "燕雀飛簷楹，喧爭互强倔。", "世紛類如此，小大何得失。", "始知絕羣動，方外真有佛。", "此地可終隱，不惟謝炎鬱。", "逍遙鞭其後，豈恨久蟠屈。"]'),
('c778be7e-d456-4c7a-9d00-2dc54287054a','九曲池','劉敞','宋','宋诗','song-poetry','','[]','廣陵春欲歸，九曲池先暖。',48,'全唐诗/poet.song.27000.json','["廣陵春欲歸，九曲池先暖。", "積雪未全消，流波已全滿。", "宫城落喬木，岸竹排纖簳。", "古事無足悲，登臨苦日短。"]'),
('acce3f44-f9ea-4e9f-9f3b-de3b69d00349','和永叔夜坐鼓琴二首  其一','劉敞','宋','宋诗','song-poetry','','[]','衆人于五音，醜正不醜隨。',60,'全唐诗/poet.song.27000.json','["衆人于五音，醜正不醜隨。", "所以匣中琴，寂寂少人知。", "淳和太平風，簡淡邃古時。", "得意亦忘言，居然見無爲。", "非公藴真樂，此道誰復期。"]'),
('6c7fdd37-79a6-4353-abde-b725f335bf00','和永叔夜坐鼓琴二首  其二','劉敞','宋','宋诗','song-poetry','','[]','知音古亦少，况乃今人乎。',84,'全唐诗/poet.song.27000.json','["知音古亦少，况乃今人乎。", "至和動殊類，此則今世無。", "舜韶舞百獸，事可觀于書。", "但非耳目接，便自疑其虚。", "誰謂今之人，反不如獸歟。", "大音蓋希聲，聾俗或萬殊。", "中孚有不化，嗟嗟乎豚魚。"]'),
('cacd42ed-10f5-4397-a067-1834a842ff44','苦寒行','劉敞','宋','宋诗','song-poetry','','[]','驅馬涉長磧，千里徑無草。',120,'全唐诗/poet.song.27000.json','["驅馬涉長磧，千里徑無草。", "天寒日光淡，積雪常杲杲。", "勁風裂肌膚，狐狢甚魯縞。", "况我被甲鎧，寢遲起常早。", "崔嵬陟高山，日落尚遠道。", "人生各有命，豈憚事遐討。", "飲冰傷心骨，重研如巨棗。", "義深自最勵，身賤寧要好。", "親戚何可逢，功名未自保。", "少年慕壯健，我獨貴疏老。"]'),
('b1cbbdba-f5fb-4ac0-a61d-cd803524b131','送霍邱謝寺丞','劉敞','宋','宋诗','song-poetry','','[]','吾聞歐公客，必皆當世賢。',72,'全唐诗/poet.song.27000.json','["吾聞歐公客，必皆當世賢。", "衆中一見子，始信斯言然。", "綵衣得意歸，笑語春風前。", "輕賫尚方履，去影裊翩翩。", "百里不足仕，桂枝淹華年。", "故須多種秫，爛醉揮鳴絃。"]'),
('e5ccaee2-008b-4d5d-8313-0b4fb22f87c1','答黄寺丞濠梁雜詠','劉敞','宋','宋诗','song-poetry','','[]','閉門委餘事，久矣卧幽寂。',120,'全唐诗/poet.song.27000.json','["閉門委餘事，久矣卧幽寂。", "忽枉臨濠篇，如逮問魚客。", "山川盡寫倣，人物多在昔。", "形倨遊自遠，善行固無迹。", "吁嗟相知晚，起予遽多益。", "乃悟文字工，足兼造化力。", "熒煌淮夷珠，磊落荆山璧。", "他人竭澤求，吾子希世得。", "禽微戒輕彈，路暗慎虛擲。", "如何忽在此，詠歎生感激。"]'),
('2aea0348-e003-4652-b133-dec821dcf629','黄寺丞九月十三日見寄','劉敞','宋','宋诗','song-poetry','','[]','兹年見二毛，秋至獨多悲。',84,'全唐诗/poet.song.27000.json','["兹年見二毛，秋至獨多悲。", "况乃霜露繁，悟彼歳月馳。", "衡門靜無轍，幽徑荒不治。", "眷眷武夷翁，傾蓋成舊知。", "每枉林下步，笑言輒移時。", "目擊良已久，鳯歌復見詒。", "諒君徜徉意，當以振其衰。"]'),
('13089990-d8f9-49e6-8518-1c15abb9792e','生槐','劉敞','宋','宋诗','song-poetry','','[]','苒苒庭下槐，蒼蒼山中檜。',144,'全唐诗/poet.song.27000.json','["苒苒庭下槐，蒼蒼山中檜。", "臭味久矣殊，榮枯莫相待。", "胡爲寓形生，曾不異風概。", "擢幹初無根，交陰忽成籟。", "死生詣膠漆，幼壯姿姿態。", "本同非不佳，末異終恐害。", "吾意造化巧，淫樂爲狡獪。", "玩此三公才，比之女蘿輩。", "不然世俗薄，苟合耻剛介。", "妄彼特立姿，樂附柔弱類。", "誰能極物理，且以嘲大塊。", "陶冶如吾言，庸庸亦何怪。"]'),
('64bce561-7f13-472b-a739-36b1f9bd3216','櫻桃','劉敞','宋','宋诗','song-poetry','','[]','東風吹陳根，萬木含芳華。',108,'全唐诗/poet.song.27000.json','["東風吹陳根，萬木含芳華。", "客愁獨不改，浩蕩津無涯。", "朝光破浮隱，暄鳥聲交加。", "櫻桃此時盛，滿樹紛彤霞。", "當戶仍拂簾，參差自相遮。", "日高卧未起，顧見驚且嗟。", "此復幾日繁，譬如空中花。", "非無一樽酒，玩之到景斜。", "多慮使意衰，悵然奈爾何。"]'),
('53b6b73a-40ab-464b-9346-b75e75f1b66c','摘櫻桃','劉敞','宋','宋诗','song-poetry','','[]','此花前日時，素雪搖東風。',72,'全唐诗/poet.song.27000.json','["此花前日時，素雪搖東風。", "已驚變濃綠，忽更垂繁紅。", "俛仰物三換，歳華終無窮。", "因笑樹下人，未悟成老翁。", "磊落火齊珠，參差珊瑚叢。", "贈遠限道路，成蹊縱兒童。"]'),
('f5f2c816-d9f1-4f86-a182-f55b4cdc23ac','春陰','劉敞','宋','宋诗','song-poetry','','[]','朝日送風光，宿雲濃不卷。',48,'全唐诗/poet.song.27000.json','["朝日送風光，宿雲濃不卷。", "微陰助惆悵，旅思增婉婉。", "新花秀且含，芳草綠更遠。", "樂賞及融怡，春暉未應晚。"]'),
('c42fad46-8381-4620-ac2a-7a35cdddbbe9','除草二首  其一','劉敞','宋','宋诗','song-poetry','','[]','昔歳有壯氣，恥事一室中。',96,'全唐诗/poet.song.27000.json','["昔歳有壯氣，恥事一室中。", "獨願埽萬里，指麾走羣雄。", "少壯意更衰，棄書學老農。", "羈旅無田園，飄如野間蓬。", "徘徊陳蔡間，呰窳見楚風。", "託足不期廣，所存一畝宫。", "秋草日蕪没，荷鋤事兒童。", "歎息念變化，古人頗固窮。"]'),
('1780696f-39a2-445f-b8be-0f428fe681e8','除草二首  其二','劉敞','宋','宋诗','song-poetry','','[]','中庭不踰畝，百草何荒蕪。',108,'全唐诗/poet.song.27000.json','["中庭不踰畝，百草何荒蕪。", "綠葉間紫莖，薫蕕互相渝。", "所憐薄筋力，豈愛不埽除。", "賢者曾蒿萊，吾徒亦何如。", "公侵藩垣出，蔓也自難圖。", "下牀值蛇蟒，依隱行鬱紆。", "至使蚊蚋多，不堪匝肌膚。", "古人遺我言，芳蘭戒必鋤。", "努力蔑小惠，作詩感躊躇。"]'),
('0a3922e2-b830-49d6-89f3-a13e1258ef0e','早發襄城之龍山呈曼叔','劉敞','宋','宋诗','song-poetry','','[]','鳥啼齋前樹，促駕吾當西。',60,'全唐诗/poet.song.27000.json','["鳥啼齋前樹，促駕吾當西。", "朝從良友别，夕赴幽人期。", "方以會合喜，敢曰道路疲。", "予戇昧時利，百事棄不爲。", "惟有好賢心，未愧緇衣詩。"]'),
('b10b9549-1b82-4e6f-8e33-576ce23eb539','敔來速嘗新酒','劉敞','宋','宋诗','song-poetry','','[]','徒咢無與同，徒歌無與和。',72,'全唐诗/poet.song.27000.json','["徒咢無與同，徒歌無與和。", "徒行莫之友，徒語無所破。", "慷慨一無徒，始覺從君過。", "欣聞酒新釀，堂有佳客座。", "歡從尊罍罄，醉聽冠巾墮。", "庶可效名士，因君讀楚些。"]'),
('132b1dd8-b9c6-474c-9023-280bd035f3dd','日醉','劉敞','宋','宋诗','song-poetry','','[]','犀首從横時，無事猶飲酒。',168,'全唐诗/poet.song.27000.json','["犀首從横時，無事猶飲酒。", "我生太平際，日醉亦何有。", "太平多賢才，臺閣固其藪。", "濟世圖功名，汲汲常恐後。", "我寧樂自放，甘與物俱朽。", "顧惟人間迹，澶漫獨已久。", "智謀乏施設，筋力倦奔走。", "幸爲朝廷知，而免職事守。", "人當自量度，快意安所受。", "何能强繩檢，希世視自負。", "晶熒流霞波，泔淡白玉斗。", "歡來無虚席，嘲笑命賓友。", "殘冬雖餘幾，自足數開口。", "浩歌迎春風，安用獨醒叟。"]'),
('b1014b0a-a37d-4237-b923-d93c2a6e5192','寒蘆','劉敞','宋','宋诗','song-poetry','','[]','雖居江上城，不識江邊路。',60,'全唐诗/poet.song.27000.json','["雖居江上城，不識江邊路。", "故移蘆葦叢，粗慰江湖趣。", "翠華侵硯席，疏影入牖戶。", "歳寒待爾共，好尚與時迕。", "勿以比蒹葭，蒼蒼瘁白露。"]'),
('f3a4443b-1ca2-4f34-8859-85df47a47cf1','和兩府諸公馬上作','劉敞','宋','宋诗','song-poetry','','[]','富貴信多士，况乃主恩深。',60,'全唐诗/poet.song.27000.json','["富貴信多士，况乃主恩深。", "京洛多風塵，冠蓋自成陰。", "片言代拱璧，一顧溢千金。", "嗟我固貧賤，處俗謬浮沈。", "咄咄人間世，俯仰愧山林。"]'),
('b2a48dc6-031b-4598-9c46-c32b310a4883','和永叔十九韻送魏廣','劉敞','宋','宋诗','song-poetry','','[]','信陵貴公子，仁義不掛口。',228,'全唐诗/poet.song.27000.json','["信陵貴公子，仁義不掛口。", "猶有三千客，名聲極高厚。", "而况賢者門，四方所奔走。", "豈無青雲士，磊落照前後。", "我雖非其人，慕用意殊久。", "差池混出處，百望乖一隅。", "羈旅陳蔡間，忙如喪家狗。", "擔簦始自致，傾蓋許白首。", "中堂陳詩書，高會置樽酒。", "豈惟聽餘論，復喜識賓友。", "魏侯希世珍，頗爲平生舊。", "他時恨契闊，並生喜邂逅。", "危冠切浮雲，長劍掛南斗。", "同志此莫逆，孤遊信無負。", "切磋變新巧，綵繪飾餘醜。", "自謂當窮年，如何復分手。", "士生得所師，文學致不朽。", "吾衰莫自力，子壯諒何有。", "當取天下名，還爲生人壽。"]'),
('efda4521-a7c8-4610-b7f8-b6736280b40d','遊龍山','劉敞','宋','宋诗','song-poetry','','[]','孟公乘興出，必造龍山頭。',72,'全唐诗/poet.song.27000.json','["孟公乘興出，必造龍山頭。", "回望默不言，夕陽始還輈。", "千年雖悠遠，此意故風流。", "咄嗟無知者，寂寞空荆州。", "霜風蕭騷晚，楚水荒凉愁。", "安得款段馬，往來時獨遊。"]'),
('1b7badff-2913-40cb-a040-17cbd1928b45','放鸇','劉敞','宋','宋诗','song-poetry','','[]','上天賦爾才，若不受羈紲。',108,'全唐诗/poet.song.27000.json','["上天賦爾才，若不受羈紲。", "失身偶見獲，羞與家禽列。", "秋風半夜起，鴻鵠兩飄瞥。", "物生各自適，聽爾歸寥泬。", "白雲入雙眸，尺地肯自屑。", "慎勿逐鷃爵，□□不足絕。", "不過倉廪中，朋黨爲偷竊。", "鴂鶗最堪憎，擅使芳草歇。", "勉力霜霰期，方爲鳥中傑。"]'),
('89c9f65d-4bdd-4017-9a17-1928938bd3bc','嗚蟬','劉敞','宋','宋诗','song-poetry','','[]','芳草久已歇，星火奄向中。',72,'全唐诗/poet.song.27000.json','["芳草久已歇，星火奄向中。", "日暮玄鳴蟬，歳華坐將空。", "輕舉塵壤外，逍遙神仙同。", "豈伊感時節，悲嘯臨長風。", "夕露鮮餘潤，炎颷成藴隆。", "清虚浪自足，高餓亦云窮。"]'),
('c07889aa-4eaa-4cf5-9dcf-91944c130489','和聖俞十二韻','劉敞','宋','宋诗','song-poetry','','[]','處世誠碌碌，白髪生滿頭。',144,'全唐诗/poet.song.27000.json','["處世誠碌碌，白髪生滿頭。", "所以不自慚，數從長者遊。", "醉翁名世者，事業晞孔周。", "獨立千歳外，邈然已難儔。", "韓范青雲姿，奮飛起西州。", "徘徊霄漢間，下視輕蜩鳩。", "詩老最前輩，名聲三十秋。", "篇章被海表，豈獨魯與鄒。", "今我親見之，執鞭乃所求。", "何况登其堂，舉觴預獻酬。", "清談破羣疑，嘲笑寛百憂。", "以此捐歳月，吾生同悠悠。"]'),
('a029c2e6-d31f-4663-a935-db94654119aa','宿綠溪','劉敞','宋','宋诗','song-poetry','','[]','雲昏江水闊，兩淮不可測。',168,'全唐诗/poet.song.27000.json','["雲昏江水闊，兩淮不可測。", "山丘望亦迷，馬牛豈易識。", "高帆乘長風，俄傾屢欹仄。", "未知所趣向，稍稍萬宇黑。", "近津見蘆葦，其外水正白。", "操舟投其間，宿鳥俱闢易。", "水深不可纜，叢梗以爲力。", "蚊蚋秋尚繁，不眠坐通夕。", "中宵風逾厲，潮水相蕩擊。", "安得似人者，謦欬在我側。", "天明啓牖戶，願見白日色。", "莽蒼暘谷間，竟爲霧雨隔。", "追觀宵征處，波惡生悸惕。", "絕糧非陳蔡，從者亦悽惻。"]'),
('d44d08e4-2962-4e75-a116-b0955f6a1fc3','如意臺','劉敞','宋','宋诗','song-poetry','','[]','冷冷清池水，泛泛不繫舟。',72,'全唐诗/poet.song.27000.json','["冷冷清池水，泛泛不繫舟。", "興來可獨往，興盡自難留。", "留無淹回責，往無進取憂。", "世人共擾擾，真賞空悠悠。", "章華楚人困，姑蘇麋鹿遊。", "君看如意臺，乃知賢者謀。"]'),
('d3082aed-abef-4285-a915-c294b7cacc61','閔雨','劉敞','宋','宋诗','song-poetry','','[]','長夏炎氣隆，高田劇焚燒。',72,'全唐诗/poet.song.27000.json','["長夏炎氣隆，高田劇焚燒。", "惜哉淮海卑，無力能沃焦。", "起顧郊野間，離離悉苞蕭。", "日夕多狂風，飛塵蔽招搖。", "誰能起蛟龍，雷雨蘇宿苗。", "眇然坐自想，幽意增煩歊。"]'),
('15602b74-120e-4328-bf9d-a12c0c8a7d65','和過騏驥院觀馬因飲李氏夜歸復與江謝會于敝居','劉敞','宋','宋诗','song-poetry','','[]','子真王濟徒，愛馬有馬癖。',216,'全唐诗/poet.song.27000.json','["子真王濟徒，愛馬有馬癖。", "毎嫌駑駘衆，未覩千里格。", "朅來飛龍廐，一一數白黑。", "始驚麒麟骨，秀出無與敵。", "旗旄亂雲霞，鼓吹喧霹靂。", "從容看回旋，感激私歎息。", "此當逝崑崙，上與天無極。", "奈何局軒陛，終歳老羈靮。", "主人貴公子，埽榻多命客。", "聊欲寛其意，無爲稍戚戚。", "珍羞雜水陸，清酒漾金碧。", "嘲笑心目開，留連日已夕。", "歸來興不盡，駐馬問所適。", "知我方會友，投鞭遽登席。", "貧家竟何如，脯醢乏餘力。", "歌舞復無素，兒童强敦逼。", "多君平生懷，不與貧富隔。", "歡來亦酩酊，俛仰愧三益。"]'),
('794c1ef3-8027-4bb7-92e1-a41b1462b796','早行','劉敞','宋','宋诗','song-poetry','','[]','雨息風亦止，落月猶在天。',120,'全唐诗/poet.song.27000.json','["雨息風亦止，落月猶在天。", "舟人相呼起，稍出蘆葦間。", "暗中各紛拏，四聽聲正讙。", "開戶視所從，大江自漫漫。", "衆星若連珠，纍纍浮深淵。", "津涯杳難知，勢與天地寛。", "俯見舟楫微，萬牛一毛然。", "虎豹嘷岸傍，蛟龍浮其涎。", "兢兢抱危懼，忽忽忘食眠。", "人生誠多憂，况乃行路難。"]'),
('9cb92da8-252d-4a30-9646-ea46f87a5ae2','重陽日得景烈送酒','劉敞','宋','宋诗','song-poetry','','[]','歳晚見黄菊，悲秋空復情。',48,'全唐诗/poet.song.27000.json','["歳晚見黄菊，悲秋空復情。", "故人豈知我，朋酒適平生。", "舉杯遠相屬，目盡歸鴻聲。", "醉眠東籬下，此亦淵明情。"]'),
('5af1e651-6800-42de-9cd2-935e8e36fa88','和焦生石字韻','劉敞','宋','宋诗','song-poetry','','[]','我惟一逢掖，入爲二千石。',84,'全唐诗/poet.song.27000.json','["我惟一逢掖，入爲二千石。", "聲迹不相同，禮貎謂誰敵。", "既許游藩籬，又喜升宴席。", "酌酒澆磥魁，賦詩聽警策。", "朋從常苦少，佳節古所惜。", "既醉忘形骸，笑言俱莫逆。", "使公貴且壽，富有貧賤客。"]'),
('a26eac25-c49e-4b46-a83f-3b8e4a2a444e','寄隱直','劉敞','宋','宋诗','song-poetry','','[]','會短别日長，愁多歡情少。',72,'全唐诗/poet.song.27000.json','["會短别日長，愁多歡情少。", "古來人間世，于道同擾擾。", "我髪日已蒼，我顔日已槁。", "離憂固如此，四十未應老。", "誰能跨浮雲，相與成莽眇。", "吾子心莫逆，庶當悟意表。"]'),
('4c76eb9b-9222-4d62-ad8b-9b3c5589391a','旦日城東渡汝水與鄰幾飲别歸作五言寄之','劉敞','宋','宋诗','song-poetry','','[]','繁霜墮衆木，朝光破初寒。',132,'全唐诗/poet.song.27000.json','["繁霜墮衆木，朝光破初寒。", "游子侵旦發，隱忍行旅艱。", "走馬東郊門，别愁莽無端。", "川長不可厲，泛舟觸波瀾。", "相及墟落遠，解驂請盤桓。", "班荆道路側，酌酒還據鞍。", "殊鄉閲人多，浮俗見子難。", "結交形骸外，生計出處間。", "江湖天一涯，冰雪歳欲闌。", "昔賢往不反，子陵與伯鸞。", "東游信不惡，相望終永歎。"]'),
('f7b8f660-f933-4a7a-b2eb-7165f9f1d808','寄深甫君章','劉敞','宋','宋诗','song-poetry','','[]','爛漫十日飲，未快遠别情。',120,'全唐诗/poet.song.27000.json','["爛漫十日飲，未快遠别情。", "醉魂幾時醒，直見潁水清。", "前歡絕莫尋，離念紛更盈。", "車騎暫休汝，賞晤得時英。", "披襟兩相照，話言僕屢更。", "論史既衮衮，說經亦鏗鏗。", "一觴亦一詠，樂事真相并。", "會合固難常，我獨嗟南行。", "回首念前好，感物非嚶鳴。", "明發成寤歌，勉勉趣遙程。"]'),
('d187d56d-de21-4b40-8aca-dc178c2239f7','寄裴吳江','劉敞','宋','宋诗','song-poetry','','["\u592a\u6e56"]','王喬一雙鳧，乃是尚方履。',144,'全唐诗/poet.song.27000.json','["王喬一雙鳧，乃是尚方履。", "誤逐閶闔風，飄然太湖水。", "湖水連天涯，茫茫湛清輝。", "秋來興不盡，似欲都忘歸。", "玉疊鱠如雪，碧壺酒若澠。", "醉輒問左右，何如張季鷹。", "君乃蓬邱人，神仙有名籍。", "不應自放浪，久爲塵中客。", "我頃卧廣陵，西風見白髪。", "八月觀海濤，壯心謝超越。", "因欲解印綬，從君五湖遊。", "功名非所及，爲具鴟夷舟。"]'),
('4596e33b-8a66-4a74-bfb3-c8349433f211','寄贈獻臣','劉敞','宋','宋诗','song-poetry','','[]','龍興幽泉中，溶雲自潛飛。',72,'全唐诗/poet.song.27000.json','["龍興幽泉中，溶雲自潛飛。", "氣還大淵下，灰籥先察微。", "氣應不必邇，至誠神與歸。", "嗟予接休德，志合無纖譏。", "譬諸死灰然，安事旦夕違。", "胡爲久相越，書問月增稀。"]'),
('851daeac-9c6d-46df-ad5f-48c3715d02db','五言寄江丈鄰幾時往尉氏未還','劉敞','宋','宋诗','song-poetry','','[]','終日相與居，豈知相得懽。',60,'全唐诗/poet.song.27000.json','["終日相與居，豈知相得懽。", "出門一分袂，乃覺攜手難。", "西風過浮雲，急雨生早寒。", "清秋令人悲，兹遊何當還。", "歳月游將晚，念君尚加餐。"]'),
('a5818d60-a537-455b-a536-5d94b12d8205','寄深甫','劉敞','宋','宋诗','song-poetry','','[]','往卜潁上居，徒愛潁上人。',120,'全唐诗/poet.song.27000.json','["往卜潁上居，徒愛潁上人。", "巢由節並世，管鮑必相親。", "而我與夫子，阡陌東西鄰。", "正可白首遊，豈計中道分。", "人生莫自必，一别俄六春。", "入踐西掖垣，出乘兩朱輪。", "佐時乏明略，來往徒紛紛。", "上愧洗耳翁，下慚圖霸臣。", "念欲投劾去，結茅復從君。", "攄我宿昔意，寄聲謝水濱。"]'),
('04991dba-5ab8-4e2f-96e2-0a773e1a6b08','寄楊忱明叔','劉敞','宋','宋诗','song-poetry','','[]','君有湖海氣，沆碭凌斗牛。',72,'全唐诗/poet.song.27000.json','["君有湖海氣，沆碭凌斗牛。", "遠持一卷書，濯我千歳憂。", "大音不衆合，至寶非暗投。", "感激移人心，汍瀾使涕流。", "俗譏陳元龍，世乏劉豫州。", "安得排羣兒，卧君百尺樓。"]'),
('11d820eb-99ee-42c0-af04-517bb1bc58dc','雨中寄徐二','劉敞','宋','宋诗','song-poetry','','[]','北風吹飛雨，中夏變早寒。',108,'全唐诗/poet.song.27000.json','["北風吹飛雨，中夏變早寒。", "浮雲滿天地，坎井成波瀾。", "秋興集我懷，旅愁散無端。", "陽光旦自匿，后土何得乾。", "嗟君貧非病，所寄瓢與簞。", "陋巷無雜賓，商歌激清彈。", "甚願裹薄飯，相從饜朝餐。", "亦思造暘谷，相與晞朝冠。", "力弱泥潦深，乃知行路難。"]'),
('dd2a384a-3c63-4301-a8bf-d320186de377','論交','劉敞','宋','宋诗','song-poetry','','[]','張陳父子游，乃爲白刃仇。',96,'全唐诗/poet.song.27000.json','["張陳父子游，乃爲白刃仇。", "蕭曹平生歡，亦作睚眦讎。", "交合名利間，安得無後憂。", "商山有四人，衰老俱白首。", "但食巖谷芝，終身不相尤。", "未必能獨賢，苟云無他求。", "古稱結交難，成敗視此由。", "作詩告同心，市義誠足羞。"]'),
('eaa5e1a6-c270-48a5-9367-cb4153395e6b','秋霽宴北軒','劉敞','宋','宋诗','song-poetry','','[]','北軒屬秋霽，曉見風葉零。',108,'全唐诗/poet.song.27000.json','["北軒屬秋霽，曉見風葉零。", "置觴命賓友，環坐飛渌醽。", "遇適輒獻笑，放言豁中扃。", "兀然不省醉，起見天上星。", "勉强相勸引，我謡子宜聽。", "幸無兵農憂，稔歳蒙休寧。", "讀書業文外，惟有醉不醒。", "世途若波濤，富貴乃浮萍。", "置之無可稱，視彼鴻冥冥。"]'),
('7318acfb-3673-485f-b45e-d1be9058d814','送楊十七秘丞知瀛州河間','劉敞','宋','宋诗','song-poetry','','[]','洪濤翻金堤，冀州變泥塗。',204,'全唐诗/poet.song.27000.json','["洪濤翻金堤，冀州變泥塗。", "哀哉百萬室，所憂半爲魚。", "流穴接道路，呻吟交里閭。", "若無慈仁長，安使疲疹蘇。", "子在新密時，治聲溢西都。", "大水無麥禾，閔然若疾痛。", "不忍使者求，建言解其粗。", "邦人喜更生，老幼歡以呼。", "繩墨制奸吏，弦歌訓諸儒。", "復新卓侯廟，慕用已不誣。", "今者河朔行，豈其易然乎。", "彼將譽所試，况子材有餘。", "但恨治者小，百里爲區區。", "割雞用牛刀，孔聖所歎吁。", "賢者必愛民，民活心乃愉。", "幼學長行之，固爲聖人徒。", "位下非所恤，勉哉寧君軀。"]'),
('736e8c69-919c-4437-bedb-b962f16c1c60','送梁山軍徐秘丞','劉敞','宋','宋诗','song-poetry','','[]','鷾鴯一何智，俯仰人間遊。',120,'全唐诗/poet.song.27000.json','["鷾鴯一何智，俯仰人間遊。", "落實不給視，去之畏少留。", "高賢在天下，富貴如雲浮。", "得失不概懷，損益寧所憂。", "若人古巳亡，今復得徐侯。", "詞科二十載，朝籍方見收。", "四海厭名聲，廟堂多軰儔。", "後時不自失，觀化君悠悠。", "入辭未央廷，遠牧荒山陬。", "去矣成獨往，豈嫌時俗羞。"]'),
('fe1ae099-27eb-4267-b595-4e80d1b62238','東鄰花','劉敞','宋','宋诗','song-poetry','','[]','卜居非卜鄰，適幸鄰花發。',96,'全唐诗/poet.song.27000.json','["卜居非卜鄰，適幸鄰花發。", "照曜東軒東，暄然二三月。", "露香送清吹，晨艷開繁雪。", "稚子戲牆根，鳴鷄出林樾。", "我來奔羈旅，疑及武陵歇。", "欲訪竟無從，空觀對寥寂。", "爲人懵俗事，鄰里多謝絕。", "獨爾可相親，芬芳未應滅。"]'),
('26983deb-b1e3-4f98-9424-e87b9c2bdc24','憶洞庭','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','少年慷慨輕遠行，岀入楚越多所經。',144,'全唐诗/poet.song.27000.json','["少年慷慨輕遠行，岀入楚越多所經。", "每令百川盡衣带，獨憶岳陽觀洞庭。", "方輿沈潛似無地，倚蓋回還徒見星。", "始疑上帝限南北，恐有漏澤連青冥。", "西風八月氛霧收，曠宇千里令人醒。", "苦爲外境相誘掖，欲棄塵世浮滄溟。", "當時發狂頗自怪，真擬乘興攜湘靈。", "至今局促不如意，坐視歲月無時停。", "涼秋滿眼更多感，回首尚覺君山青。"]'),
('84664d0e-be60-4868-b92a-e19741bfc3d6','聞鴈','劉敞','宋','宋诗','song-poetry','','[]','去年聞鴈江湖邊，爾時異鄉望白雲。',64,'全唐诗/poet.song.27000.json','["去年聞鴈江湖邊，爾時異鄉望白雲。", "今年鴈南身更北，可憐送目懷居人。", "我生羈旅自南北，鴈飛何爲亦遠役。", "浮雲滿天我無翼，相與因風寄消息。"]'),
('e5cb9c2d-97dd-4dc4-a79d-aca61def9c40','庭楸','劉敞','宋','宋诗','song-poetry','','[]','中庭長楸百尺餘，翠葉晻藹當四隅。',96,'全唐诗/poet.song.27000.json','["中庭長楸百尺餘，翠葉晻藹當四隅。", "晨霞夕日自相翳，並坐可得千人俱。", "憶昔河決鉅野溢，定之方中作宫室。", "當時魯人始種此，還賦衛風伐琴瑟。", "春華亹亹六十年，高幹錯落摧寒烟。", "悵望空隨衆木老，中舍至音無與宣。"]'),
('a234d75c-e342-43af-b08f-dae88d5dab31','送張公往建溪','劉敞','宋','宋诗','song-poetry','','[]','秋風駕流溪水急，君帆胡爲破烟入。',64,'全唐诗/poet.song.27000.json','["秋風駕流溪水急，君帆胡爲破烟入。", "仙人近約武夷會，漢祀山頭羽旄立。", "羣山叢叢野波綠，君纓無塵見心曲。", "江淹夢筆靈有餘，君歸何時佇盈軸。"]'),
('e0e6caff-a296-4fb2-aabb-6f61b3360f32','曉起','劉敞','宋','宋诗','song-poetry','','[]','棲烏未動清漏殘，寥寥空堂生早寒。',48,'全唐诗/poet.song.27000.json','["棲烏未動清漏殘，寥寥空堂生早寒。", "相重樹色如潑墨，欲落月采成渥丹。", "市聲嘈嘈入人耳，自笑带星還若此。"]'),
('a225c34d-91de-4c77-98e5-40b1f53047d3','防秋','劉敞','宋','宋诗','song-poetry','','[]','秋霜折膠胡馬壯，邊馬窺邊怒邊將。',96,'全唐诗/poet.song.27000.json','["秋霜折膠胡馬壯，邊馬窺邊怒邊將。", "游騎夜入燒回中，烽火朝傳過隴上。", "關東行客關西來，欲說兵形先啜哀。", "長戈不能斷右臂，壯士無過委黄埃。", "歲輸繒帛顧何益，匈奴反以馳荆棘。", "安得連山如長城，遍限中原郤蠻貊。"]'),
('56356580-03f6-4124-a3fb-da0b3be9441e','打魚','劉敞','宋','宋诗','song-poetry','','[]','南人登魚作膢臘，清潭數里奔舟檝。',112,'全唐诗/poet.song.27000.json','["南人登魚作膢臘，清潭數里奔舟檝。", "層冰始解川氣和，百尺分明見鬐鬛。", "大網如雲遮要津，須臾牽網迴水濱。", "地高勢蹙漸逼窄，忽復逸出黄金鱗。", "釣叟篙師共驚駭，失聲奪氣俱逡巡。", "素魴赤鯉不足數，棄擲千萬如埃塵。", "豈知異物通變化，暫網中還有神戲。"]'),
('8a6f895b-40e6-4dc0-8965-ace136b012df','題西湖中魚','劉敞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','育育水滿湖，中有千金魚。',60,'全唐诗/poet.song.27000.json','["育育水滿湖，中有千金魚。", "浮沈得意似太古，不畏網罟畏鵜鶘。", "綠蒲欲齊藻初密，紅尾差差映朝日。", "疾雷驟雨人莫知，潛有蛟龍取之逸。"]'),
('7c72cf9a-ebba-43aa-b149-07053cf35557','養魚','劉敞','宋','宋诗','song-poetry','','[]','鑿池不容數斛水，養魚才勝十餘尾。',67,'全唐诗/poet.song.27000.json','["鑿池不容數斛水，養魚才勝十餘尾。", "可憐出沒萍藻間，還如泛澹江湖裏。", "君勿笑坳堂坎井無遠期，假有神物君不知。", "風雲變化在倏忽，隨衆幽潛聊爾爲。"]'),
('fa343f28-b2e0-4817-a588-13e83a9b9cbb','和永叔食糟民','劉敞','宋','宋诗','song-poetry','','[]','歲豐飲酒衆同醉，歲饑散糟民亦濟。',146,'全唐诗/poet.song.27000.json','["歲豐飲酒衆同醉，歲饑散糟民亦濟。", "乃知酒酤在官爲長策，上可足財下均利。", "黄頭稚子白髪翁，哺糟相隨塵土中。", "豈嫌身居犬彘後，還喜生值恩施豐。", "翰林仙伯屈主諾，憂民之憂樂民樂。", "禍階六筦不易救，恵及連城自云薄。", "周公以來千百年，希世俗儒玩糟粕。", "排斥酒誥終莫用，感激長謡豈虚作。", "恨公未爲富民侯，此等區區豈所憂。"]'),
('f49c57e0-2d11-44c8-9886-b9a84b1a73e8','漁翁','劉敞','宋','宋诗','song-poetry','','[]','白頭老翁披敗蓑，求魚終日罩淮波。',64,'全唐诗/poet.song.27000.json','["白頭老翁披敗蓑，求魚終日罩淮波。", "波深水闊望不絕，網目雖繁能幾何。", "大魚鱣鱏入淵底，小魚魂鯢登網裏。", "手皸足趼吁可憐，何不爲網大如天。"]'),
('b3724f94-ae32-43db-8b8e-6324efe85ec8','苦雨','劉敞','宋','宋诗','song-poetry','','[]','東風十日不肯回，濃雲猛雨無時開。',128,'全唐诗/poet.song.27000.json','["東風十日不肯回，濃雲猛雨無時開。", "紛然萬瓦垂組練，忽變百里吹塵埃。", "河魚無翼蹈平陸，水鳥哺子升高臺。", "羲和送日不竟夜，陽烏翅濕方摧頽。", "腐薪數吹不堪濕，靈井已滿無用汲。", "大衢泥潦安得出，敗瓦漏缺端愁入。", "街頭紅粟更騰踴，歲晏敝裘方綴緝。", "黄花熒熒獨不憂，悵然爲爾臨風立。"]'),
('82dacb40-36a9-4ef2-aaac-1aeea83c55cf','麻黄州送李斯石銘二十一字','劉敞','宋','宋诗','song-poetry','','[]','麻侯昔爲萊子國，海濱漁人獻文石。',213,'全唐诗/poet.song.27000.json','["麻侯昔爲萊子國，海濱漁人獻文石。", "云是秦始皇帝東巡碑，二十一字李斯迹。", "桑田變海岸爲谷，此石亦沈滄海側。", "浪翻水轉石段空，偶存數尺非人力。", "文章雖傳失首尾，猶與史記無差忒。", "字形訛缺非昔時，蟄龍病虺相排迮。", "念昔屬車八十一，氣如虎狼食中國。", "方士獻策通神仙，諛臣奮筆夸功德。", "始皇未死名已滅，秦地初分石皆泐。", "邇來似覺天意然，欲令後世羞其惑。", "君不見夏禹九鼎傳三王，末年乃隨殷社亡。", "時平往往暫一見，龍文玉鉉曾無傷。", "聖賢作事宜萬代，事非聖賢多立壞。"]'),
('3b61889f-c5b6-46cc-9a51-a98e56a6a65f','畫草蟲扇子','劉敞','宋','宋诗','song-poetry','','[]','周南草蟲但書興，爾雅蟲魚浪多證。',96,'全唐诗/poet.song.27000.json','["周南草蟲但書興，爾雅蟲魚浪多證。", "豈如紈扇裂冰霜，畫出肖翹皆絕勝。", "蠅讒蝶輕螗蜋狷，同類殊名悉相應。", "毗陵老匠含天真，獨得于心非氣孕。", "牸牛落筆殊偶然，秦女驂鸞不相稱。", "因君筆力尤天下，一借微軀聞萬乘。"]'),
('19480507-c3e0-4bb7-8343-7c3f5dc28451','聽江十誦食鱠詩戲簡聖俞','劉敞','宋','宋诗','song-poetry','','[]','長安貧客食無魚，浩歌彈鋏歸來乎。',144,'全唐诗/poet.song.27000.json','["長安貧客食無魚，浩歌彈鋏歸來乎。", "主人聆歌知客意，酌酒買魚相與醉。", "一魚百金不可償，操刀作鱠揮雪霜。", "鱗分骨解珠玉光，舉盤引筯絲線長。", "楚飯彫胡香且潔，吳羮入口如沃雪。", "主歡賦詩客稱壽，裂簡搖毫落寒月。", "我亦羈旅秋蕭條，思鱸回首江漢遙。", "過門大嚼取快意，詠詩忘味如聞韶。", "君若乘風駕滄海，更鱠長鯨且相待。"]'),
('26e9051d-17cd-45ba-918f-6e34d01a16f1','積雪示張翁','劉敞','宋','宋诗','song-poetry','','[]','冥冥同雲晝如墨，十日江城雪三尺。',80,'全唐诗/poet.song.27000.json','["冥冥同雲晝如墨，十日江城雪三尺。", "騏驥長鳴向朔風，鴻鴈悲飛困雙翼。", "此時窮巷多泥塗，念子衰年少筋力。", "時俗反稱少壯賢，丈夫動與饑寒逼。", "乘興能枝笻竹來，煮魚温酒澆胸臆。"]'),
('bd883f53-201d-4475-aa73-fab0b8bfff3b','苦雪','劉敞','宋','宋诗','song-poetry','','[]','積雪冥冥春不淹，流光驟去十之三。',64,'全唐诗/poet.song.27000.json','["積雪冥冥春不淹，流光驟去十之三。", "根拳枝折物可念，衣敝履穿吾自堪。", "天樞回環錯寒燠，地軸開闔差朔南。", "乾坤密移世莫測，安得辨士能劇談。"]'),
('59266707-ec87-4210-8d71-688965befa68','雪夜留二三客飲','劉敞','宋','宋诗','song-poetry','','[]','高樓鼓絕昏鴉宿，疏簾暗幕開明燭。',48,'全唐诗/poet.song.27000.json','["高樓鼓絕昏鴉宿，疏簾暗幕開明燭。", "雪風振海夜未央，酒池無冰春更綠。", "迎年送臘醉莫辭，回環四序長相續。"]'),
('4d1225f4-d8f4-4ddc-b728-8cd36a70125d','奉和聖俞春雪','劉敞','宋','宋诗','song-poetry','','[]','一日朔風三日雪，冬來嚴凝春復結。',96,'全唐诗/poet.song.27000.json','["一日朔風三日雪，冬來嚴凝春復結。", "不知長此終安窮，芳物差池且三月。", "雷公怒號何淬嗟，欲起草木呼龍蛇。", "可憐慘栗奪氣意，正復惟悴哀泥沙。", "紫宸放朝車馬息，鄰里謝交門徑寂。", "解龜換酒聊自樂，浮雲蔽日殊未極。"]'),
('3574f263-78bb-43f0-85df-21c87614080a','同聖俞十二月十三日喜雪','劉敞','宋','宋诗','song-poetry','','[]','楚越祅氛雜炎瘴，憑陵中州冬益壯。',80,'全唐诗/poet.song.27000.json','["楚越祅氛雜炎瘴，憑陵中州冬益壯。", "天兵横厲江湖間，殺氣冥冥逐飛將。", "南風不競寒律回，暮雪遠從閶闔來。", "雲崩濤涌天地閉，埽灑萬里空塵埃。", "公卿入賀陛下聖，海神來朝軍事定。"]'),
('3f8a2571-c026-412d-96a6-e72fb18fb65d','和永叔喜雪','劉敞','宋','宋诗','song-poetry','','[]','陰風觸物生晚勁，積雪經旬戲春令。',224,'全唐诗/poet.song.27000.json','["陰風觸物生晚勁，積雪經旬戲春令。", "氣排水國吁可駭，勢覆山城力誰競。", "繽紛乍逐飛霰奪，慘淡仰見浮雲定。", "稍并日夜明相續，欲亂玄黄色交映。", "丘陵迤邐增更高，市井喧卑聽逾静。", "包荒含垢似天德，履素居純近民性。", "可憐佳境浩無極，非有雄辭豈能詠。", "怱憶避地歌其雱，攜手驅車及寛政。", "邇來盈尺亦何有，高卧閉門方自慶。", "矧占豐歲宜九糓，重抑驕陽敺百病。", "龍蛇在蟄鶯在谷，與我俱欣四時正。", "新詩翩翩摧古人，汝陰太守明廷臣。", "侔色揣稱笑流俗，與民樂賡陽春曲。", "由來曲高和必寡，況我才居郢人下。"]'),
('d106f64c-5532-44df-9116-8ecfcb0dcc9d','去年對雪一首贈江十','劉敞','宋','宋诗','song-poetry','','[]','去年對雪本憶梅，今年看梅更憶雪。',80,'全唐诗/poet.song.27000.json','["去年對雪本憶梅，今年看梅更憶雪。", "繁香浩色他日時，誰爲年年劇胡越。", "乃知古來人間世，十常八九不如意。", "況我與君羈旅人，别多會少誰復計。", "閒來看梅取一笑，對雪更作明年調。"]'),
('3e44e6e5-9c97-4517-8001-c231fe4c4eca','月夜','劉敞','宋','宋诗','song-poetry','','[]','清風卷雲天雨霜，衆星滅沒月騰光。',112,'全唐诗/poet.song.27000.json','["清風卷雲天雨霜，衆星滅沒月騰光。", "紛紜六幕含蒼蒼，瑩如冰壺察毫芒。", "太虚真人河漢旁，攀援桂枝曳霓裳。", "紫貝爲闕白玉堂，珠筵瑤席羅羽觴。", "倚風微吟聲抑揚，揖我起游謂我臧。", "左驂蛟螭左鳯凰，倏忽萬里天路長。", "塵埃下土殊茫茫，樂如何其樂未央。"]'),
('15dd6a5d-04dc-4bff-b36f-f400eaed15f5','依韻和永叔即席送擇之出守陜府','劉敞','宋','宋诗','song-poetry','','[]','驪駒在門且勿喧，主人留客姑進酒。',144,'全唐诗/poet.song.27000.json','["驪駒在門且勿喧，主人留客姑進酒。", "一時轉盼巳陳跡，千里相望更何有。", "祖侯聲名二十年，天下英豪共奔走。", "誰云白髪寄郎曹，更喜朱轓入吾手。", "揚雄天祿就寂寞，召伯甘棠變枯朽。", "乃知人事不如意，自古十常有八九。", "男兒何曾計出處，時運由來有奇偶。", "莫嫌青雲晚著鞭，會取黄金大如斗。", "君能食飲和天倪，餘事無可付莊叟。"]'),
('4d23ca3c-3915-47b0-bdfe-41592a282ff5','飛輪團扇歌','劉敞','宋','宋诗','song-poetry','','[]','赤雲燒天天欲焚，深堂如炮井如饙。',128,'全唐诗/poet.song.27000.json','["赤雲燒天天欲焚，深堂如炮井如饙。", "肴乾不食酒具陳，君胡愁嗟念南熏。", "主人白羽奇且新，捷逾輠膏機有神。", "飛亷舒御旋相奔，晻藹翕霍娛坐賓。", "衣襟飄飄恍凌雲，何用御風絕埃塵。", "主人顧嗟顔色顰，安得救暍通下民。", "羊角扶搖非敢珍，願使大鵬離隱淪。", "上客捧觴起爲賀，君宜千年位卿佐。"]'),
('de0cd321-de02-4c50-9f37-48dc67d97714','雨過前軒偶記','劉敞','宋','宋诗','song-poetry','','[]','江南羈客懷鄉墅，曉起前軒對零雨。',128,'全唐诗/poet.song.27000.json','["江南羈客懷鄉墅，曉起前軒對零雨。", "清波滿目如鑑中，遶岸高松十餘樹。", "砌旁芳草似汀洲，巉巖殿角飛紅樓。", "沈光倒影入浪底，宛是若邪溪上頭。", "薄霧疏烟迷近遠，水色誰能辨深淺。", "忽驚謝去塵中游，不知正自居京輦。", "何人草服倚長松，迴頭誤問釣魚翁。", "眼前景致偶相同，豈異仙術遊壺中。"]'),
('698fed94-0397-4811-9600-8f1c3e24e8ca','贈才元學士','劉敞','宋','宋诗','song-poetry','','[]','待詔先生窮巷居，簞瓢屢空方晏如。',96,'全唐诗/poet.song.27000.json','["待詔先生窮巷居，簞瓢屢空方晏如。", "自操井臼秣羸馬，郤整衣冠迎賜書。", "王人駐車久嘆息，天子聞知動顔色。", "飽死曾不及侏儒，牧民會肯輸筋力。", "詔書朝出蓬萊宫，繡衣還鄉由上衷。", "君今已作二千石，亦復將爲第五公。"]'),
('ff9d1d9b-f8fe-4867-98ea-a2cd7ce83f14','題梅尉春波亭','劉敞','宋','宋诗','song-poetry','','[]','層欄壓湖春水碧，日照高穹同一色。',96,'全唐诗/poet.song.27000.json','["層欄壓湖春水碧，日照高穹同一色。", "東風引浪飛魚鱗，極目傷心如楚澤。", "茫茫白芷連芰荷，倚沼畦瀛遙望多。", "官賢與衆共其樂，漁樵日暮常經過。", "君家德祖吳門子，棄職從仙如脱屣。", "此中吏隱人不知，且濯君纓洗君耳。"]'),
('8ce84e8e-68b9-4783-ac71-8191b762b032','吳宫','劉敞','宋','宋诗','song-poetry','','[]','吳兒歈，鄭女舞，彩衣姣服垂楚楚。',64,'全唐诗/poet.song.27000.json','["吳兒歈，鄭女舞，彩衣姣服垂楚楚。", "姑蘇臺高春日遲，急節新聲閙鐘鼓。", "美人歡醉捧瑤爵，君王萬壽長如許。", "吳宫四面盡山川，越兵那得到城下。"]'),
('0a159e17-2c81-414c-91d4-b70e5faff471','陰山女歌','劉敞','宋','宋诗','song-poetry','','[]','種玉不滿畦，種花易滿枝。',186,'全唐诗/poet.song.27000.json','["種玉不滿畦，種花易滿枝。", "玉生寄石自有處，花飛隨風那得知。", "嬋娟翠髪陰山女，能爲漢裝說漢語。", "春心未知向誰是，夜彈琵琶涙如雨。", "赤車使者過鳯凰，闇中一聞先斷腸。", "碧窗鎖烟未容去，侍兒密獻江南璫。", "鵲飛上天星沈海，人心不同事隨改。", "翦環洗妝許君老，百年如夢情終在。", "妾乘油壁郎乘驄，西陵松柏墨色濃。", "新歡未已舊愁起，水流曲曲山重重。", "周周銜羽鶼比翼，天生相親人豈識。", "雖不及清路塵，猶當作山上石。"]'),
('9136fc01-5df0-46b4-8b14-3997d6211409','遷南行','劉敞','宋','宋诗','song-poetry','','[]','伏波將軍昔征南，功業雖壯身不還。',81,'全唐诗/poet.song.27000.json','["伏波將軍昔征南，功業雖壯身不還。", "曾出封疆鑄銅柱，竟留種族依荒山。", "君不見如今聖天子，埽蕩妖巢悉內徙。", "雕題來作冠带民，鼻飲翻宜伊洛水。", "此功一成萬世寧，五嶺三苗長坦平。"]'),
('0d6fd1af-b80d-493b-b043-b9842dd5f8a2','寄王二子直','劉敞','宋','宋诗','song-poetry','','[]','鴻飛輒上天，魚躍還入淵。',60,'全唐诗/poet.song.27000.json','["鴻飛輒上天，魚躍還入淵。", "故人去我百里餘，我欲附書無由緣。", "俗間離合誰得免，心雖欲近身逾遠。", "少壯相歡長年悲，自恨今爲丈夫淺。"]'),
('57116bf9-f70c-4232-848b-ddfd568887a4','夜寄獻臣','劉敞','宋','宋诗','song-poetry','','[]','同居汴水上，自與君居隔。',60,'全唐诗/poet.song.27000.json','["同居汴水上，自與君居隔。", "月出城頭人盡歸，思君攜手獨不得。", "興來狂歌無與賡，白雲時向望中生。", "城外明月未應減，期君對舉黄金觥。"]'),
('5fa9b00a-1249-47c6-a428-f9dcb570670c','和永叔鳴鳩詩','劉敞','宋','宋诗','song-poetry','','[]','晴鳩讙求雌，雨鳩閙逐婦。',152,'全唐诗/poet.song.27000.json','["晴鳩讙求雌，雨鳩閙逐婦。", "天地有晴陰，嗟爾何欣復何怒。", "柔桑如雲春暮時，吳蠶半眠紫葚肥。", "食不過數粒，寢不過一枝。", "婦子相安可以老，何用汲汲合且離。", "雷公號呼風伯舞，天借之權作霖雨。", "可憐汝愚終不省，反室于怒誰哀汝。", "昔人惡爾巧，今人笑爾拙。", "巧不得近瑤臺，拙不能保家室。", "爾巧爾拙非汝情，天機回闔難自平，世人假爾推陰晴。"]'),
('3f53ccba-06bf-4e84-927a-5e58d17f5d5f','秋蛩','劉敞','宋','宋诗','song-poetry','','[]','促即復促即，秋蛩一何力。',112,'全唐诗/poet.song.27000.json','["促即復促即，秋蛩一何力。", "不見機杼巧，但聞日夜織。", "霜隕木落天下寒，嗟我婦子衣裳單。", "大鈞萬物各有在，爾獨憔悴使人歡。", "一鳴復一飛，秋堂燕將歸。", "四時自興歎，天道不得違。", "憶昔春風和且柔，畏人來入人間游。", "鷹隼横厲自兹始，索寞分散還可愁。"]'),
('272be8d4-f1a8-49bd-b510-4d8ecfa77cc2','三瑞堂','劉敞','宋','宋诗','song-poetry','','[]','甘露被草，朝陽易晞。',126,'全唐诗/poet.song.27000.json','["甘露被草，朝陽易晞。", "池蓮並蒂，及秋變衰。", "獨有長松連理老益壯，十年百年仍附枝。", "昔來一物足爲瑞，何況三異俱稱奇。", "吳中衣冠不勝數，天意自與寧馨兒。", "露乾蓮死不復見，正以青松并驗之。", "凱風孝子嘗悲思，三荆兄弟傷分離。", "此家遺風五十慕，物理推類誰能欺，到客爲爾俱題詩。"]'),
('caccbe3a-a909-4e2a-b3f8-21e96c1f0994','聞轆轤','劉敞','宋','宋诗','song-poetry','','[]','轆轤復轆轤，日夜聲相續。',59,'全唐诗/poet.song.27000.json','["轆轤復轆轤，日夜聲相續。", "長綆無已時，深泉變空谷。", "君不見開闢至今千萬年，斗樞坤軸相迴旋。", "河漢西流亦不息，見爾滄海成桑田。"]'),
('ee769d5e-51d5-463e-a0bb-5c64fb42f046','過王氏弟兄','劉敞','宋','宋诗','song-poetry','','[]','出城問窮僻，負郭正瀟灑。',92,'全唐诗/poet.song.27000.json','["出城問窮僻，負郭正瀟灑。", "主人著書長閉關，佳樹當門宜繫馬。", "下馬上堂還讀書，新詩古琴雙起予。", "昏鴉棲雞欲斂翼，興盡將去猶須臾。", "徒見城中軒冕客，不如吾人一縫掖。", "安得茅茨同里居，子在東阡我南陌。"]'),
('7f90729b-ea4b-4e57-b0e4-3c8e254c712d','同永叔贈沈博士','劉敞','宋','宋诗','song-poetry','','[]','我不識醉翁亭，又不聞醉翁吟。',257,'全唐诗/poet.song.27000.json','["我不識醉翁亭，又不聞醉翁吟。", "但見醉翁詩，愛彼絕境逢良琴。", "上多高峰下流泉，後有芳草前茂林。", "玄猨黄鵠翩翻共悲鳴兮，白雲翠靄倏忽而陽陰。", "此間真意不可盡，未遇知者猶荒岑。", "醉翁昔時逃世紛，戀此酩酊遺朝簪。", "心雖獨醒迹彌晦，舉俗莫得窺浮沈。", "邇來十年定誰覺，獨沈夫子明其心。", "寫之絲桐寄逸賞，曲度寥落含高深。", "絕調衆耳多不省，醉翁一聞能别音。", "乃知精識自有合，何必相與凌崎嶔。", "伯牙鍾子期，目擊意已歆。", "蓬萊三山蕩析不可見，惟有水仙之操傳至今。", "安知後世萬千歲，此地不爲水火侵。", "但存君詩與君曲，雖遠猶可期登臨。", "沈夫子，與醉翁，斯言至悲君更尋。"]'),
('c631c9c5-df0a-4f56-ae65-e2ccbb3c6c06','六月六日自城北還過深甫避暑','劉敞','宋','宋诗','song-poetry','','[]','熱不就惡木枝，渇不近盜泉水。',58,'全唐诗/poet.song.27000.json','["熱不就惡木枝，渇不近盜泉水。", "自古有成言，念我還如此。", "愛君井源百尺深，愛君庭樹千里陰。", "相知豈計一飯報，長嘯聊爲猛虎吟。"]'),
('891bfd74-b378-4426-906a-d1a92414da98','得蕭山書言吏民頗相信又言湘湖之奇及生子名湘戲作此詩','劉敞','宋','宋诗','song-poetry','','[]','吾家千里駒，氣與齒俱壯。',108,'全唐诗/poet.song.27000.json','["吾家千里駒，氣與齒俱壯。", "去年射策雄東堂，今年調官在越上。", "指揮小吏遣簿書，笑語不廢才有餘。", "清酒肥魚宴賓客，時時騎馬臨湘湖。", "湖波無風百里平，人道官心如此清。", "居民愛尹氏爲字，令尹生兒湖作名。", "家家祝君多男子，越中更有餘山水。"]'),
('85beb54d-67c2-44bc-84a3-7d9cbec21aa7','翦楸葉詞','劉敞','宋','宋诗','song-poetry','','[]','涼風天際來，拂我階前樹。',72,'全唐诗/poet.song.27000.json','["涼風天際來，拂我階前樹。", "稍驚枝上禽，復墮葉間露。", "兒童畏我逢秋悲，刻葉作花矜歲時。", "祝我宜秋勸使插，未能免俗復爾爲。", "鬢邊二毛殊不惡，淮南何須傷木落。"]'),
('4e4a426c-7a04-4c2f-a09b-e9c472184d13','寄書','劉敞','宋','宋诗','song-poetry','','[]','十里一反顧，五里一徘徊。',120,'全唐诗/poet.song.27000.json','["十里一反顧，五里一徘徊。", "悠悠三千里，莫知我心哀。", "客愁紛無涯，歲月忽如擲。", "人生莫自料，皓首豈易測。", "節旄未落歸去來，天遣春風隨我回。", "入朝寧食建業水，還家郤賦南山雷。", "婦能秦聲妾趙舞，稚子可使行酒杯。", "急須爲樂娛日夜，何事憔悴淹塵埃。", "行矣乎，歸去來。"]'),
('e4faf5d2-122e-43a3-868d-96e2e447e292','答金陵使君答王待制見寄雜言','劉敞','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','阮公青雲器，寓意必豪縱。',182,'全唐诗/poet.song.27000.json','["阮公青雲器，寓意必豪縱。", "西臨廣武寄一笑，英雄紛紛競如夢。", "有時不能平，途窮即長慟。", "仕哉詠懷篇，千載共悲諷。", "金陵昔爲帝王居，氣象蕭索無復餘。", "長江連天水東注，臺城彷彿存邱墟。", "主人文章謫仙老，感古能無激懷抱。", "作亭正得山水勝，登臨更值風月好。", "賓客滿堂絲竹悲，古今風流自一時。", "君家夷吾雖有慷慨語，快意未必如君詩。", "淮水東流千萬年，此亭方與淮共傳。", "念君歸老廟堂上，未負賡歌留北山。"]'),
('e955f7e7-ffea-4f89-be47-7479dad9cad3','古城','劉敞','宋','宋诗','song-poetry','','[]','古城何巍巍，古墓何纍纍。',76,'全唐诗/poet.song.27000.json','["古城何巍巍，古墓何纍纍。", "生遊市朝死田野，從古到今無免者。", "城荒郤爲狐兔宅，墓在他人種松柏。", "伏羲以來三萬年，此城此墓幾變易。", "誰人聽唱野田詩，能令君悲亦不悲。"]'),
('8b3b6d86-a5d6-4b40-8747-22ab267dd388','築室種樹','劉敞','宋','宋诗','song-poetry','','[]','撫劍欲遠適，舍旃輒復息。',60,'全唐诗/poet.song.27000.json','["撫劍欲遠適，舍旃輒復息。", "四海廣大身正孤，東西南北頗同役。", "築室種樹反開門，閭里小人哀王孫。", "丈夫委順故在俗，餘事悠悠何足論。"]'),
('fe8570bf-376f-43e7-a56d-9be905a3f7b5','風花','劉敞','宋','宋诗','song-poetry','','[]','風花不自知，高下逐風飛。',40,'全唐诗/poet.song.27000.json','["風花不自知，高下逐風飛。", "故有多情處，時來點客衣。", "仙源應在晴溪側，弄雪吹香不忍歸。"]'),
('fcab7563-bc8d-44cd-9b2d-0e0d3fe57aac','種蓮','劉敞','宋','宋诗','song-poetry','','[]','雨餘池上清且滿，浮萍漂漂綠蒲短。',64,'全唐诗/poet.song.27000.json','["雨餘池上清且滿，浮萍漂漂綠蒲短。", "主人惜此芳意薄，移藕丁寧不辭遠。", "南陂芙蓉少人識，疊蘂重房無俗格。", "託根得地今始逢，西風白露爲君容。"]'),
('0f806c41-c454-4681-ae02-6df7f10f4a42','朱雲','劉敞','宋','宋诗','song-poetry','','[]','志士不忘棄溝壑，勇士不忘喪其元。',224,'全唐诗/poet.song.27000.json','["志士不忘棄溝壑，勇士不忘喪其元。", "伏雞搏狸狗襲虎，感激只在精神存。", "漢朝陵替外戚盛，五岳振蕩三辰昏。", "臣强主弱上不悟，庭中唯唯誰能言。", "朱生節義邁金石，面劾不避師傅尊。", "願求上方斬馬劍，誅一厲百清其源。", "天威震怒不我受，利刃接頸雷霆奔。", "當前折檻色不變，命在頃刻誰扳援。", "昔時仲尼魯司寇，七日行戮端乾坤。", "嗟我此生心不就，冥冥后土埋其冤。", "漢家社稷變王氏，張禹虚蒙師保恩。", "卓然先見在物表，佞臣敗國誰復論。", "我願乘雲款天閽，巫陽掌夢招其魂。", "立朝蹇蹇辨邪正，無復奸諛開倖門。"]'),
('0dc0213b-ba1c-427a-8cd2-e9f45ec6b62e','金山廨院','劉敞','宋','宋诗','song-poetry','','[]','門前松響亂頭上，壁上江圖流眼前。',40,'全唐诗/poet.song.27000.json','["門前松響亂頭上，壁上江圖流眼前。", "松聲水響兩不辨，似有疑非心悠然，安得乘興浮輕船。"]'),
('00777b55-dad7-441e-b8e0-2571a0eb34f1','潘道士','劉敞','宋','宋诗','song-poetry','','[]','上清宫中老道士，曾從先皇去封祀。',192,'全唐诗/poet.song.27000.json','["上清宫中老道士，曾從先皇去封祀。", "山頭侯夜窺火輪，汾上掊鈎出金耳。", "雲成龍虎當翠華，豐隆前導清泥沙。", "萬靈扶駕百神護，雜沓仙侶堆雲霞。", "黄衣羽客十有餘，多能引說軒轅初。", "漢廷儒士議迂闊，天子自用申公書。", "金繩玉策埋石壤，神光夜見連空虚。", "天心報貺宸意喜，白茅玉印旌其徒。", "帷宫賜席接虎幄，待之如賓盡誠慤。", "中書秘術使之觀，神動精搖易飛躍。", "鼎湖龍去何超越，日月茫茫自奄忽。", "龍髯墮地秋草生，人世霜華滿頭髪。"]'),
('54f0d2fb-af94-445d-bbed-f7c33ee8274b','遇海舟','劉敞','宋','宋诗','song-poetry','','[]','秦王好神仙，東上琅琊臺。',76,'全唐诗/poet.song.27000.json','["秦王好神仙，東上琅琊臺。", "蛾眉綠髪五千輩，去乘長風款蓬萊。", "此時秦人海旁立，生别死分不敢泣。", "但見高帆雲中沒，野鳥悲鳴爲翔集。", "過海舟，何時還，火焚荆棘空驪山。"]'),
('53948185-75f2-496c-b882-547863bb2b0a','猛虎行','劉敞','宋','宋诗','song-poetry','','[]','陸不辭虎豹怒，水不避蛟龍争。',167,'全唐诗/poet.song.27000.json','["陸不辭虎豹怒，水不避蛟龍争。", "衆人亦有命，大賢豈虚生。", "千歲猶須臾，四野如戶庭。", "解弓掛扶桑，脱劍倚太清。", "騰身騎日月，萬事如蚊𧉬。", "貧賤有固窮，慷慨激中情。", "炎火燎崑邱，乃知白璧精。", "雪霜沒衆草，高松獨青青。", "寧生歌車下，戚促兒女聲。", "時至乘化遷，運頽與物冥。", "震雷不經聽，芥蔕何足嬰。", "君不見賈豎競錐刀，蚍蜉利羶腥。", "何如乘雲御氣遊咸池，長嘯濯我冠與纓。"]'),
('e542e73e-2a56-498b-9657-20f35b3032a5','雷陂勸耕作雜言','劉敞','宋','宋诗','song-poetry','','[]','君不見江都宫，昔時何崔嵬。',159,'全唐诗/poet.song.27000.json','["君不見江都宫，昔時何崔嵬。", "下臨雷陂水，前踞吳王臺。", "臺傾無餘級，水竭空塵埃。", "隋人已曾顧此長嘆息，今世更爲隋人哀。", "乃知天地間，一盛亦一衰。", "但從伏羲已來三十餘萬歲，未有書契勝言哉。", "堯桀是非可兩忘，我欲勸人闢草萊。", "種稻水一方，藝麻陵四頽。", "爽鳩之樂非我有，聊獨玩此田莓莓。", "未知百世間，更復誰當來。", "且欲及閒從賓客，省耕訪此時徘徊。"]'),
('0835d69d-34bc-4e14-b548-1aef343eeac5','碧瀾堂','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','苕溪之水搖空山，霅溪波流無日閒。',240,'全唐诗/poet.song.27000.json','["苕溪之水搖空山，霅溪波流無日閒。", "上有高堂蔭華宇，蒼翠凌亂軒楹間。", "異時客心樂真曠，白鳥鵁鶄期往還。", "解纓敧枕便所適，焉能復問居夷蠻。", "嵐光稜稜聳屏幌，水響濫濫搖瓊環。", "正如明鑑發塵匣，萬象聚眼醒容顔。", "秋風已高白芷老，編荷制蕙文斕斑。", "魂清魄爽弄明月，洞庭跬步尋非艱。", "神仙有無未可信，物色但訝非人寰。", "瑤宫紫府竟何若，茫然遠想令人潸。", "長竿獨繭可以老，安用馳獵盧重鐶。", "況復邦人講文墨，風雅不待仲尼删。", "丞相詞章狀元筆，犖犖神裁無由攀。", "嗟我胡然陷塵滓，不能追逐鷗白鷴。", "發狂醉問二三子，吳溪釣碣何如頑。"]'),
('f4bf5289-4f1a-4339-b50f-a7b6f268d0fa','濉陽歌','劉敞','宋','宋诗','song-poetry','','[]','梁人猶爲濉陽歌，隋人水調能相和。',96,'全唐诗/poet.song.27000.json','["梁人猶爲濉陽歌，隋人水調能相和。", "梁人池臺已平地，隋人岸樹空嵯峨。", "梁人隋人去如水，水聲日夜流不已。", "張巡廟前春草生，里人尚識將軍名。", "國讎已滅心不死，憤氣半夜凌欃槍。", "丈夫節義豈在下，願爲長劍刳長鯨。"]'),
('4210adbd-9b16-4fcd-b92e-95c789c83871','馬蹄硯','劉敞','宋','宋诗','song-poetry','','[]','巴巫之山足奇石，氣含秋雲如黛色。',96,'全唐诗/poet.song.27000.json','["巴巫之山足奇石，氣含秋雲如黛色。", "君家寶硯安所得，圓爲馬蹄螢爲璧。", "宛城路阻流沙長，中國久絕真乘黄。", "惜哉逸足世不識，所存一迹猶形相。", "鄙夫雖非伯樂比，偶見褭蹄識千里。", "願君不惜勤示人，倘有驊騮免空死。"]'),
('aab43336-e257-4bf5-872f-9feb07976441','天中山','劉敞','宋','宋诗','song-poetry','','[]','兹山陂陀但盈尺，其下盤根乃無極。',114,'全唐诗/poet.song.27000.json','["兹山陂陀但盈尺，其下盤根乃無極。", "勇如共工莫可觸，力敵愚父無能役。", "開闢以來傳至今，形勢雖小當天心。", "斗極回旋未易測，日影短長猶可尋。", "石旁陰穴穿洞府，中有神物爲之主。", "禱祠往往見光景，暵旱時時作霖雨。", "由來丘山貴靈不貴大，正復陂陀亦何怪。"]'),
('c84c3734-a982-4919-814e-367877b35acb','岸旁倒樹','劉敞','宋','宋诗','song-poetry','','[]','滄洲老樹生幾秋，幹如墨龍根紫虬。',96,'全唐诗/poet.song.27000.json','["滄洲老樹生幾秋，幹如墨龍根紫虬。", "雨水摧激勢突兀，夭矯出飲滄江流。", "危不見持顛不扶，蕭蕭生意令人愁。", "豈無耕夫與過客，暫時憇爾行則休。", "西風八月海水飛，枯槎昔曾凌斗牛。", "恐爾漂零未終極，掛帆欲去仍回頭。"]'),
('8de0088f-ea81-4556-aba5-4d7b6daab379','黄寺丞井上桐樹爲雷所擊','劉敞','宋','宋诗','song-poetry','','[]','君家井泉深百尺，上有高桐十尋碧。',64,'全唐诗/poet.song.27000.json','["君家井泉深百尺，上有高桐十尋碧。", "鳯鳥不至獨何憂，蛟龍深潛莫能識。", "迅雷烈風來擊時，地軸翻倒海水飛。", "正直摧傷豈天意，爨下成琴殊未遲。"]'),
('9de6c173-39e5-48b6-afcd-c71dd41b2c6f','送人之會稽','劉敞','宋','宋诗','song-poetry','','[]','鷹隼羞逐巢上雛，騏騮恥隨廄中駒。',128,'全唐诗/poet.song.27000.json','["鷹隼羞逐巢上雛，騏騮恥隨廄中駒。", "由來俊邁惡羈縶，子獨三年留上都。", "江南秋風鱸魚美，庖鱠炊粳東入吳。", "腰間蘭佩垂左右，船若神仙人不如。", "會稽古來好風俗，嚴助買臣相繼驅。", "近來太守廷中臣，拔賢好善當朝無。", "子今東去懷自許，解榻非君尚誰與。", "剋日飛聲動洛陽，聽君如聽雷門鼓。"]'),
('0af3c7ac-d41c-42e7-8d55-22422d49b006','題深甫所種樹','劉敞','宋','宋诗','song-poetry','','[]','中庭郤埽無餘地，憐君種樹還有意。',64,'全唐诗/poet.song.27000.json','["中庭郤埽無餘地，憐君種樹還有意。", "重陰覆屋千尺時，徙坐讀書殊可喜。", "似君秀骨不易攀，當援桂枝星漢間。", "豈能玩此便自老，塵俗紛紛聊閉關。"]'),
('84ca1c1e-92cc-4db3-91b1-bd355ee5de79','雷氏子推迹石鼓爲隸古定聖俞作長詩敘之諸公繼作予亦繼其後','劉敞','宋','宋诗','song-poetry','','[]','結繩既亡書契出，文字變化尤倏忽。',256,'全唐诗/poet.song.27000.json','["結繩既亡書契出，文字變化尤倏忽。", "太山七十有二代，遺事昏昏萬無一。", "岐陽石鼓起晚周，宣王之詩史籀筆。", "天下金石凡幾存，此當爲甲彼皆乙。", "體勢鳥迹雜蝌蚪，詞章車攻與吉日。", "六書既廢小雅缺，能使兼存此其實。", "韓公昔甞歌感激，若弦周詩播琴瑟。", "雷生今復隸古定，如破魯璧傳簡帙。", "道之難行乃若兹，二千年間能事畢。", "先王親用必貴本，流俗玩文因喪質。", "此雖于今似不急，豈不班班見儒術。", "藏之天府自其所，大訓河圖亦何物。", "會稽羣玉久冥寞，漆簡韋編尚彷彿。", "昔人雖死名不朽，智者能爲巧當述。", "太學先生事起廢，誦此勤勤救埋沒。", "會令永與天壌傳，不比酒誥俄然失。"]'),
('cc0118d3-304b-49b2-b6c4-8bb89b296bee','城頭烏','劉敞','宋','宋诗','song-poetry','','[]','城頭月出天正白，衆烏驚飛啼夜色。',80,'全唐诗/poet.song.27000.json','["城頭月出天正白，衆烏驚飛啼夜色。", "枝高風多露新滴，畏聲惡影不能息。", "愁人感之援鳴琴，拂弦成聲淚沾襟。", "嗟爾一生八九雛，游翔不過東西林。", "白頭反哺無所恨，桓山分飛獨何心。"]'),
('2c80f324-7cdd-47a2-ae35-dadb80a02d4b','驚烏','劉敞','宋','宋诗','song-poetry','','[]','北林風多丹葉稀，棲烏畏月夜中飛。',64,'全唐诗/poet.song.27000.json','["北林風多丹葉稀，棲烏畏月夜中飛。", "哀音亂發不自得，孤影履翻無所依。", "作巢欲高避彈射，誰道通宵不能息。", "山深林遠去冥冥，清露寒霜損毛翼。"]'),
('f351247a-295d-4618-be2c-bbe11b379fec','梅','劉敞','宋','宋诗','song-poetry','','[]','江東梅樹江西客，僻地相逢眼俱白。',128,'全唐诗/poet.song.27000.json','["江東梅樹江西客，僻地相逢眼俱白。", "雜花亂草鬭青春，玉樹瓊枝比顔色。", "輕陰漠漠寒不返，清雨高風旦連夕。", "惜無白日照芳菲，決雲之劍那能得。", "忽憶曾過上林苑，五柞長楊心所識。", "結根擢秀皆尋常，得地翻宜帝王側。", "后皇嘉樹無遠邇，爾生自合居南國。", "勉留佳實和君羮，丁寧婦女無所摘。"]'),
('d9c09ee2-a5cb-4333-9ef4-39bc4ffda62c','蒲萄','劉敞','宋','宋诗','song-poetry','','[]','蒲萄本自涼州域，漢使移根植中國。',96,'全唐诗/poet.song.27000.json','["蒲萄本自涼州域，漢使移根植中國。", "涼州路絕無遺民，蒲萄更爲中國珍。", "九月肅霜初熟時，寶璫碌碌珠纍纍。", "凍如玉醴甘如飴，江南萍實聊等夷。", "漢時曾用酒一斛，便能用得涼州牧。", "漢薄涼州絕可怪，今看涼州若天外。"]'),
('71061e7a-488a-4181-afc8-eac025d767c1','和道粹探春','劉敞','宋','宋诗','song-poetry','','[]','去歲探花煩兩郎，今年逢春情更長。',64,'全唐诗/poet.song.27000.json','["去歲探花煩兩郎，今年逢春情更長。", "廣文主人似知我，一首新詩能發狂。", "載酒可以過揚子，肩輿不嫌干辟彊。", "東風老去甚容易，百日醉倒我無妨。"]'),
('29b32f50-9bed-44fe-9225-925692862f3a','岳州引水詩','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭清波一千里，城中釀酒常無水。',80,'全唐诗/poet.song.27000.json','["洞庭清波一千里，城中釀酒常無水。", "泥塗遠汲人共悲，缾缶屢空罍亦恥。", "鑿井引竿高下流，清泉泠泠六物修。", "邦人巳息漢陰拙，楚酒無復邯鄲憂。", "誰謂機心有機械，大賢事業終除害。"]'),
('443795cd-50f6-4954-bb6b-664342007151','去年得澄心堂紙甚惜之輒爲一軸邀永叔諸君各賦一篇仍各自書藏以爲翫故先以七言題其首','劉敞','宋','宋诗','song-poetry','','[]','六朝文物江南多，江南君臣玉樹歌。',160,'全唐诗/poet.song.27000.json','["六朝文物江南多，江南君臣玉樹歌。", "擘牋弄翰春風裏，斵冰析玉作宫紙。", "當時百金售一幅，澄心堂中千萬軸。", "摛辭欲卷東海波，乘興未盡南山竹。", "樓船夜濟降幡出，龍驤將軍數軍實。", "舳艫銜尾獻天子，流落人間萬無一。", "我從故府得百枚，憶昔繁麗今塵埃。", "秘藏篋笥自矜玩，亦恐歲久空成灰。", "後人聞名寧復得，就令得之當不識。", "君能賦此哀江南，寫示千秋永無極。"]'),
('25b33e16-f7f8-4ffd-8510-4f4bb1bd5ebb','題永叔白兔同貢甫作','劉敞','宋','宋诗','song-poetry','','[]','梁王兔園三百里，不聞有與雪霜比。',134,'全唐诗/poet.song.27000.json','["梁王兔園三百里，不聞有與雪霜比。", "今公畜此安取之，瑩若寒玉無磷緇。", "春秋書瑞不常有，歷年曠世曾一偶。", "寧知彼非太陰魄，鳯凰麒麟亦郊藪。", "周南之人公腹心，張罝肅肅横中林。", "獻全不損一毫末，顧直肯計千鈞金。", "雕籠密檻回君寵，初不驚人有時拱。", "由來文采絕世必見羈，豈能隨衆碌碌自放原野爲。"]'),
('4b749b88-ba98-4f89-92f7-ce5d4102cf32','三清殿木槿','劉敞','宋','宋诗','song-poetry','','[]','三清殿前木槿樹，朝繁夜暗自相催。',128,'全唐诗/poet.song.27000.json','["三清殿前木槿樹，朝繁夜暗自相催。", "晨光始出洛水上，暮雨又下雲陽臺。", "仙姬神女衣服麗，紫玉雜佩垂玫瑰。", "春餘衆木苦寥落，況乃漸逼清秋來。", "繁花滿目真可惜，稍稍萬戶舖蒼苔。", "黄冠道士情意薄，見似不見年年開。", "清風滿席車馬少，莫與共賞傾金罍。", "嘗疑壺中有仙術，安得升天繫白日。"]'),
('dcc11928-d8b9-41f4-b63c-c43d32762c97','和吳九元會','劉敞','宋','宋诗','song-poetry','','[]','漢家初成長樂宫，亦以十月朝百工。',256,'全唐诗/poet.song.27000.json','["漢家初成長樂宫，亦以十月朝百工。", "武夫崛起少儀節，秦制苟簡非王風。", "猶云始知天子貴，此甚可笑田舍翁。", "聖朝禮樂百年備，文物寖盛兼羲農。", "月正元日古所用，數歲一講賓王公。", "東至日出西太蒙，南極丹穴北崆峒。", "重譯款關惟恐後，奉琛薦幣無不恭。", "太常調樂辨韶武，少府拭璧差桓躬。", "旗常卷舒王路肅，干羽出沒頑民從。", "協風入律效朔易，瑞雪盈尺迎年豐。", "陰慘陽舒變頃刻，天決地闢含沖融。", "君看此等聖人事，豈得復顧叔孫通。", "道旁撃壤九齡叟，校室受書三尺童。", "慣習昇平不自覺，豈悟帝力高無窮。", "賴君作詩播英實，如以鳴鼓祛昏聾。", "吾知朝廷億萬載，與地侔富天比崇。"]'),
('8870e78d-1c60-46bf-94ad-923ab5e5f51c','荆州兒歌','劉敞','宋','宋诗','song-poetry','','[]','都盧小兒歌且舞，口吹鳴笛手擊鼓。',64,'全唐诗/poet.song.27000.json','["都盧小兒歌且舞，口吹鳴笛手擊鼓。", "日落羣遊塵土中，噭咷不分巴與楚。", "年年送臘迎春光，家家相隨夜開戶。", "嗟汝兒曹舞更歌，及爾不爲如老何。"]'),
('8d64c8a6-8d98-4c64-8f8b-fbd18cdb0f4a','贈文顯','劉敞','宋','宋诗','song-poetry','','[]','古來畫工著名者，吳氏鬼神韓氏馬。',128,'全唐诗/poet.song.27000.json','["古來畫工著名者，吳氏鬼神韓氏馬。", "鬼神既僞不足稱，狗馬空難亦多假。", "顯師幼年獨寫人，至今精絕疑有神。", "灑毫便覺面如面，後素倏訝身觀身。", "高冠長劍天子側，他時金聲復玉色。", "師皆對之槃礴臝，衆謂十常八九得。", "諸公固爲廊廟賢，麒麟未畫宜私傳。", "一邱一壑吾亦可，煩仗丹青無間然。"]'),
('1701e084-6827-4376-8e8a-7a85be3e68a6','戲作汎槎篇呈知府給事','劉敞','宋','宋诗','song-poetry','','[]','君不見枯槎去時八月風，海水自與天河通。',99,'全唐诗/poet.song.27000.json','["君不見枯槎去時八月風，海水自與天河通。", "飄飄反出扶桑上，恍惚遍歷羣仙宫。", "宫旁佳人瑩如玉，邂逅相聚歡不足。", "詐言物外日月長，正苦歸來光景促。", "回頭稍與煙霞隔，世人空辨支磯石。", "伯勞燕子東西飛，惆悵中間斷消息。"]'),
('baf2c862-3a3b-449d-9c0f-a53d295d3faf','春日作','劉敞','宋','宋诗','song-poetry','','[]','天王城西金明池，三月欲盡花菲菲。',48,'全唐诗/poet.song.27000.json','["天王城西金明池，三月欲盡花菲菲。", "遊人白馬黄金羈，騑驂結駟來金堤。", "禁城恩波無遠邇，清光面面均流水。"]'),
('6a31cf08-f545-4ee1-a21e-e27b36d1bd37','賞閣後小桃同景純作','劉敞','宋','宋诗','song-poetry','','[]','僕本山野之生民，不堪刺促拘冠紳。',240,'全唐诗/poet.song.27000.json','["僕本山野之生民，不堪刺促拘冠紳。", "江湖自放老將至，豈悟歲月如馳輪。", "謬隨多士貢王府，浪得虚名通紫宸。", "遽從下列居第一，當時頗似稱平津。", "感激更恩報天子，僶俛從事希涓塵。", "濫書閨籍比朝舊，驟上天祿均儒臣。", "肖躬顧影每自愧，譬如蒿艾參松筠。", "未能引分拂衣往，正用飽食慚懸鶉。", "太平中外雖少事，賢哲馳騖猶辛勤。", "幸無官守逃吏責，自可昏醉窮青春。", "夭桃花繁高倚樓，似若有意娛佳賓。", "浩歌大笑忘檢局，座客歡倒知吾真。", "東風瞥來能幾時，況子東西南北人。", "人間會合常苦少，撃鮮舉白毋羞貧。", "林端啼鴂風雨夕，異方相憶空酸辛。"]'),
('2ccc5bec-d6ee-4e88-bfb6-a1a108d6d577','土牛行','劉敞','宋','宋诗','song-poetry','','[]','立春自昔爲土牛，古人設象今人愁。',128,'全唐诗/poet.song.27000.json','["立春自昔爲土牛，古人設象今人愁。", "豈有笵泥作頭角，便可代天熙九疇。", "村夫田婦初不知，繽紛圍遶爭相祈。", "皆云宜蠶又宜穀，拜跪滿前同致詞。", "由來人事常反覆，久立要津寧爾福。", "請看今者拜跪徒，少選分張取其肉。", "牛實無知何用祭，牛能有情豈不愧。", "化育萬物非爾才，世人資爾聊爲戲。"]'),
('c6d0f5fd-00d9-44f4-9bda-635bf48d4f1d','胡九齡畫牛歌','劉敞','宋','宋诗','song-poetry','','[]','書契已來有繪事，畫牛著牛今始二。',128,'全唐诗/poet.song.27000.json','["書契已來有繪事，畫牛著牛今始二。", "胡生戴氏雖異時，形似之間實兄弟。", "鬼神易寫狗馬難，古人舊語乃信然。", "不爾寥寥千萬年，筆墨曠絕無比肩。", "胡生曾畫百一牛，變態曲盡稱爲尤。", "翰林主人題辭古，四海文士歌賦優。", "俗情護前喜排後，此事戴嵩未曾有。", "會知誦玩無已時，畫與胡生俱不朽。"]'),
('232e3302-ccda-45e6-be95-c6ab58110595','同鄰幾觀中道家書畫','劉敞','宋','宋诗','song-poetry','','[]','宋公好古天下聞，法書奇畫多求真。',240,'全唐诗/poet.song.27000.json','["宋公好古天下聞，法書奇畫多求真。", "獨將文雅遺後世，官雖貴達家尤貧。", "近自唐室遠及秦，上下略數千餘春。", "丹青翰墨著名者，一二收拾忘辛勤。", "象賢濟美聲不墜，手澤鉅細皆如新。", "朝廷交遊累千百，未嘗肯示尋常人。", "蔡侯江翁與梅伯，于今磊落稱絕倫。", "退朝相從得盡見，更覺清門無雜賓。", "鑒微賞異極毫髪，四座若獲千金珍。", "往往發狂或大叫，詠詩落筆爭紛綸。", "我隨衆人久碌碌，學殖欲落衣生塵。", "願登羣玉探禹穴，不憚山海馳舟輪。", "此君家近未宜後，率然欲往懷逡巡。", "淹留秖覺歲月老，復恐異物潛通神。", "但傳妙唱想絕蹟，誦歎慷慨書搢紳。"]'),
('07dbf642-54c0-4182-9902-14076ff94893','西戎行','劉敞','宋','宋诗','song-poetry','','[]','吾聞聖人之兵有不戰，不戰之勝善之善。',182,'全唐诗/poet.song.27000.json','["吾聞聖人之兵有不戰，不戰之勝善之善。", "況復良將握天威，西戎雖强安得擅。", "憶昔屬國羽書聞，中宴徹酒詔圖勳。", "丞相陳謀御史請，獨可遣將誅其君。", "吏民詿誤不足治，我以威德周無垠。", "尚書侍郎盡明哲，秉鉞載旆如火烈。", "羽林積卒眀號令，賊兵蹙戚憂巢穴。", "方春緩誅已偷息，天不假易行勦絕。", "太常請獻象功舞，史臣願勒西山岊。", "懸頭藁街敕狂慢，積粟金城撫疲苶。", "西戎行，告爾勿逆果自坑，百蠻來威天下平。"]'),
('5e422aba-4038-4a5b-92e3-a7123d5ed02a','題浙西新學','劉敞','宋','宋诗','song-poetry','','[]','文翁昔時理蜀土，能令蜀人似鄒魯。',176,'全唐诗/poet.song.27000.json','["文翁昔時理蜀土，能令蜀人似鄒魯。", "范公今者鎮江東，亦云教化似文翁。", "文翁范公本同志，蜀人吳人有殊異。", "蜀人之先自魚鳧，不聞道德能過吳。", "吳前泰伯後季札，禮讓繼爲天下師。", "迄今遺風未全滅，得逢賢侯益昭晰。", "本之舊俗已相百，況乃磨礱皆俊傑。", "當時文翁化蜀者，獨有揚雄及司馬。", "後生可畏不可誣，安知不在吳公下。", "吳人于今歌且仰，我公去矣安所倣。", "願公上佐天王明，姬文孔術從兹行。"]'),
('53eb38c1-83d1-490d-a201-1f09275ec257','戲金壺道士法墨走筆雜言寄鄰幾聖俞','劉敞','宋','宋诗','song-poetry','','[]','狂鯨蕩海海逆潮，巨鼇抃山山動搖。',48,'全唐诗/poet.song.27000.json','["狂鯨蕩海海逆潮，巨鼇抃山山動搖。", "疾雷勁風自相薄，潛鱗伏介俱不聊。", "我無巨麴復藉糟，無思遠人心忉忉。"]'),
('af851f55-5f7e-472b-8f60-6ed61a865996','送劉涇州','劉敞','宋','宋诗','song-poetry','','[]','劉侯之弓三百斤，壯氣可以摧浮雲。',112,'全唐诗/poet.song.27000.json','["劉侯之弓三百斤，壯氣可以摧浮雲。", "不忍區區事狐兔，自請治郡當胡塵。", "天子外家異恩禮，秋廟舊鼎多功勛。", "少雖侍中貴省士，匈奴宜避飛將軍。", "憶昔汝南始相得，十年見君我髪白。", "可憐日月如過翼，我誠儒生猶恨惜。", "腰間寶刀手中策，馳騖萬里須努力。"]'),
('93b83d26-76b6-4b84-b209-f17bac597bd2','種桐','劉敞','宋','宋诗','song-poetry','','[]','東園方樹盈百株，四桐晚種皆丈餘。',64,'全唐诗/poet.song.27000.json','["東園方樹盈百株，四桐晚種皆丈餘。", "不緣桃李鬪顔色，不爲琴瑟養肌膚。", "霜秋要成萬葉子，他日與致丹山雛。", "野人此意真不誣，鳳鳥不至吾已夫。"]'),
('f9f16f87-468d-4433-ad10-d2e6e498c2a4','懷歸操二章  其一','劉敞','宋','宋诗','song-poetry','','[]','蟋蟀在堂歲云除，今我不樂鬱以紆。',24,'全唐诗/poet.song.27000.json','["蟋蟀在堂歲云除，今我不樂鬱以紆。", "豈不懷歸畏簡書。"]'),
('390bbc0a-4fa6-4d74-95ef-b530de8f8c23','懷歸操二章  其二','劉敞','宋','宋诗','song-poetry','','[]','蟋蟀在堂歲云逝，今我不樂濡以滯。',24,'全唐诗/poet.song.27000.json','["蟋蟀在堂歲云逝，今我不樂濡以滯。", "豈不懷歸朋友畏。"]'),
('f98abff4-4154-47de-afa2-86ea34b0ec6d','新灘行','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','憶昔秭歸之山崩，震驚千里如雷霆。',96,'全唐诗/poet.song.27000.json','["憶昔秭歸之山崩，震驚千里如雷霆。", "江水逆流洞庭竭，至今蓄怒猶騰凌。", "洄淵沈沈色如墨，彷彿半露峰巒形。", "懸波一瀉三百仞，魚鼈蛟龍俱不寧。", "天公高居漏天隔，無故設險憂羣生。", "時無伯禹真已矣，坐念疏鑿何由能。"]'),
('11fe0a18-0731-4ec6-97b7-960eb69d183e','靈椿館風折椿樹','劉敞','宋','宋诗','song-poetry','','[]','野人獨愛靈椿館，館前靈椿聳危幹。',175,'全唐诗/poet.song.27000.json','["野人獨愛靈椿館，館前靈椿聳危幹。", "風柔雨練三月餘，奕奕中庭蔭華傘。", "清陰及物不自惜，赤日當天損炎旱。", "危簷密牖清有餘，翠竹猗桐何足算。", "南山白虎嘯狂飇，孤根易動枝條散。", "芳華寂寞未及衰，萎遲遂比溝中斷。", "君不見月中紫桂天上榆，有名無實安自如。", "天河均澗易生植，甘露灑葉長扶疏。", "結根得所應自貴，庇蔭雖遠真徒虚。", "靈椿乎，莊子浪叟誠爾徒。", "爾當自取八千歲，今顛蹶矣人誰扶。"]'),
('77096c59-e8a4-45c8-a814-f27bf7b43afc','觀林洪範禹貢山川圖','劉敞','宋','宋诗','song-poetry','','[]','若昔文命熈帝虞，大龜浮洛出元謨。',160,'全唐诗/poet.song.27000.json','["若昔文命熈帝虞，大龜浮洛出元謨。", "翍山瀉澤魑魅走，四海砥定由天扶。", "周摧嬴仆亂疆理，壁中但得司空書。", "先生始病學者惑，爲畫盈尺山川圖。", "職方輿地在眼下，地勢天文高下殊。", "始驚六合可舒卷，吾道指掌何難乎。", "先生當時持此藝，欲以稽古開天意。", "命乖時背竟何爲，于今傳者爲張宜。", "宜生五十頭已白，連蹇不爲州郡辟。", "朝廷何時舉行河，合笑平當未精賾。"]'),
('ac662f28-12b4-4760-8344-d5dbbc872e45','昨日風贈王舒','劉敞','宋','宋诗','song-poetry','','[]','昨日風，今日雨，門前泥坑昨夜土。',64,'全唐诗/poet.song.27000.json','["昨日風，今日雨，門前泥坑昨夜土。", "秋懷悽愴誰最多，江南秀才洛下旅。", "十年麻衣走南北，饑寒不比倉中鼠。", "悠悠暖日庇重雲，舉頭看天不得語。"]'),
('1c912ba3-96b8-44ff-b1a5-13a4c651e83b','同永叔和介甫昭君曲','劉敞','宋','宋诗','song-poetry','','[]','漢家離宫三十六，宫中美女皆勝玉。',128,'全唐诗/poet.song.27000.json','["漢家離宫三十六，宫中美女皆勝玉。", "昭君更是第一人，自知等輩非其倫。", "耻捐黄金買圖畫，不道丹青能亂真。", "别君上馬空反顧，朔風吹沙闇長路。", "此時一見還動人，可憐怏怏使之去。", "早知傾國難再得，不信傍人端自誤。", "黄河入海難郤來，昭君一去不復回。", "青冡消摧人迹絕，惟有琵琶聲正哀。"]'),
('e35d8fc3-d036-439f-9951-11cbd57243a5','子直攜雜文見過','劉敞','宋','宋诗','song-poetry','','[]','王孫少年敏於筆，壯如驊騮勇鸇鶻。',144,'全唐诗/poet.song.27000.json','["王孫少年敏於筆，壯如驊騮勇鸇鶻。", "搖毫裂簡殊多端，因事陳詞不專一。", "春風吹空花滿眼，秋霜縮物寒吹骨。", "元氣回復無常形，四時變化豈定律。", "斯文法天亦自然，古來達者猶識偏。", "今君始冠便如此，後日更老當誰先。", "憶昔孟軻有遺語，取之左右逢其源。", "乃知述作繋根本，根本苟盛枝條繁。", "君能致身取不朽，得世知吾得賢友。"]'),
('702cce91-4acc-4d3c-9722-29f06c020f44','戲題歐陽公廳前白鶴','劉敞','宋','宋诗','song-poetry','','[]','明公雙鶴未易知，志在赤霄萬里外。',80,'全唐诗/poet.song.27000.json','["明公雙鶴未易知，志在赤霄萬里外。", "低頭啄泥不自聊，拊翼向人幾可愛。", "北風崩雲三尺雪，側睨天池頗愁絕。", "不忍鳬鴈争稻梁，誤譏燕雀附炎熱。", "答公厚意終一飛，萬人仰首公看之。"]'),
('89d48d21-53c5-47fb-81b8-99bf454a774e','大風','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嘈嘈大風起朔方，白日不没天蒼蒼。',64,'全唐诗/poet.song.27000.json','["嘈嘈大風起朔方，白日不没天蒼蒼。", "洞庭彭蠡半飛灑，厚地圓天俱抑揚。", "鵾鵬變化不可測，風雲感會生羽翼。", "方春殺氣何時極，生物悲愁少顔色。"]'),
('52539817-92e2-4699-a652-a06a9105f6f5','同永叔哭聖俞','劉敞','宋','宋诗','song-poetry','','[]','子真之後千餘年，人物寥落無幾傳。',264,'全唐诗/poet.song.27000.json','["子真之後千餘年，人物寥落無幾傳。", "聖俞晚出江海壖，眉目自覺真神仙。", "氣如陽秋和以妍，文若河漢清且淵。", "大鈞匠物豈强鐫，飛黄絕塵寧俟鞭。", "名爲實賓道所捐，才與時逆行苦邅。", "起草建禮衰可憐，掌教國子寒無氈。", "誰不富貴君重遷，誰不耄期君疾蹎。", "長松摧壑芝焚烟，誰其尸之當問天。", "遺草大小三千篇，白玉落落珠聯聯。", "此自可敵當世權，物莫兩大猶信然。", "我家江南再世前，與君通家情有連。", "見君總角今華顛，于我莫逆好已偏。", "今也已矣嗟絕絃，涙如翻波正淪漣。", "翰林文章日月懸，鑿石銘德埋九泉。", "上書立後祿紹先，分宅恤窮祭有田。", "嗚呼豈非天下賢。", "義不背死而苟焉，念子可以無悁悁。"]'),
('ff034d3b-fb50-4b31-bc99-3532849a6de4','魯風二首時聞孔中丞卒  其一','劉敞','宋','宋诗','song-poetry','','[]','太山之雲朝觸石，清陰油油麗空碧。',64,'全唐诗/poet.song.27000.json','["太山之雲朝觸石，清陰油油麗空碧。", "塵生東田禾麥槁，季女呼嗟待膏澤。", "北風吹空不成雨，中道無復見形迹。", "嗚呼天高誰問天，人今相說讒風伯。"]'),
('231b6543-552c-44a5-992d-8f13bc74813c','魯風二首時聞孔中丞卒  其二','劉敞','宋','宋诗','song-poetry','','[]','新甫之柏徂徠松，枯根高齊千仞峰。',69,'全唐诗/poet.song.27000.json','["新甫之柏徂徠松，枯根高齊千仞峰。", "天令爾生禀剛直，壽比王喬誰與同。", "驚霆何時發巖底，堅節青姿化爲燬。", "君不見蟠木但以左右爲先容，能令人意尚奇詭。"]'),
('1b0e1bf8-60e3-40a1-a182-1b5422c08d7e','續楊十七挽蘇子美詩','劉敞','宋','宋诗','song-poetry','','[]','吾聞蘇侯不及識，內嘉孤雄世難得。',288,'全唐诗/poet.song.27000.json','["吾聞蘇侯不及識，內嘉孤雄世難得。", "文如翻波氣龍虎，風雲晦明在頃刻。", "中間流落似天意，今雖暫困當永適。", "忽傳長逝既巳矣，知與不知同歎息。", "曩者避地金馬門，獻書著論驚上國。", "材豪志劇少所有，倐忽變化不可測。", "結交必皆天下士，朝廷見人退自斥。", "指揮功名力可取，城郭披露曾不惜。", "廟堂諸公交口薦，天子亦稱萬人敵。", "中道齟齬空歸來，扁州東浮問損益。", "登臨姑蘇睨滄海，憤歎始覺區中窄。", "徉狂爛醉遺日月，欲乘長風掛危席。", "安期洪厓殊彷彿，蓬萊方壺定可陟。", "浩歌秀句凌斗牛，至今紫氣猶融奕。", "若人不應逐物化，吳中好事先巳惑。", "邇來安知非形解，世上蜉蝣限畛域。", "遺編逸藁尚多有，但恐靈物隨變匿。", "君當收拾藏永久，毋以交情死生易。"]'),
('5bcc5104-1f40-4d80-8a25-41bcb42a44b5','大雨行','劉敞','宋','宋诗','song-poetry','','[]','日中驟雨海上來，懸流滂沱正奔猛。',83,'全唐诗/poet.song.27000.json','["日中驟雨海上來，懸流滂沱正奔猛。", "坳堂舊乾不濡足，回頭穿鑿成方井。", "炎凉更代如恍惚，明晦回環不俄頃。", "地形天事無久長，何况人情足馳騁。", "君不見張耳陳餘刎頸交，中道相捐豈終永。"]'),
('01ce645f-5c02-4568-9aa2-9e3cabf42e2e','錦繡溪行','劉敞','宋','宋诗','song-poetry','','[]','金霞卷風漾清碧，翠藻玉沙相歷歷。',112,'全唐诗/poet.song.27000.json','["金霞卷風漾清碧，翠藻玉沙相歷歷。", "旌旗不動蛟龍眠，空濛錦繡張春色。", "五紋婉轉沈吟香，時時飛出雙鴛鴦。", "笑窺貝闕倚瑤瑟，金華射天高下光。", "海近蓬萊郤清淺，星客浮槎莫輕返。", "齋房幾日饜華芝，瑤席香殘舞燕歸。", "錦繡溪邊春幾許，欲尋清淺醉芳菲。"]'),
('c3a5c7f8-e516-4a9d-889c-4c20cce2d8b4','送鄰幾之官兼遊天台四明見于詩中','劉敞','宋','宋诗','song-poetry','','[]','蓬萊謫仙頭半白，搖搖去爲江南客。',64,'全唐诗/poet.song.27000.json','["蓬萊謫仙頭半白，搖搖去爲江南客。", "長風醉送浮海航，宿雨自蠟登山屐。", "山海使人行易迷，君雖吏隱歸何時。", "若攀琪樹亦相憶，三鳥飛來寄消息。"]'),
('7254522f-f664-4bb3-ab71-e3ec0babed91','褒信新蔡兩令言飛蝗所過有大鳥如鸛數千爲羣啄食皆盡幕府從事往按視如言因作短歌記其實','劉敞','宋','宋诗','song-poetry','','[]','廣州奇禽鴻鵠羣，勁羽長翼飛蔽雲。',128,'全唐诗/poet.song.27000.json','["廣州奇禽鴻鵠羣，勁羽長翼飛蔽雲。", "嘯儔命侣自其職，飲水棲林餘不聞。", "今年飛蝗起東國，所過田疇畏蠶食。", "神假之手天誘衷，此鳥乃能去螟賊。", "數十百千如合圍，搜原剔藪無孑遺。", "曆尋古記未曾有，細察物理尤應稀。", "憶昔虞舜德動天，象爲耕地鳥耘田。", "聖時多瑞亦宜爾，請學春秋書有年。"]'),
('2f4db679-9734-4aa1-a5d5-d22d7ff7c895','月夜聞唱歌','劉敞','宋','宋诗','song-poetry','','[]','滿城明月中宵白，淮南唱歌如淮北。',64,'全唐诗/poet.song.27000.json','["滿城明月中宵白，淮南唱歌如淮北。", "春風忽起高入雲，餘聲卻下盤阡陌。", "南音俚曲自相知，時復一笑情熙熙。", "誰道幽蘭白雪好，只見獨謡應獨悲。"]'),
('ed88b035-a394-44db-ab62-8f0bf36848ca','寄楊彦文','劉敞','宋','宋诗','song-poetry','','[]','高冠長劍非一賢，子獨困窮情可憐。',96,'全唐诗/poet.song.27000.json','["高冠長劍非一賢，子獨困窮情可憐。", "差池早爲後曹掾，坎砢復就東山眠。", "昔者結交期白首，邇來傾蓋凡幾年。", "窮轍決江竟寥闊，緼袍共敝無由緣。", "人生如處不如意，自古富貴皆由天。", "天門九重不可問，咄嗟拊髀心拳拳。"]'),
('04559ac4-3686-483a-bbb3-6566a864fa62','寄范十九','劉敞','宋','宋诗','song-poetry','','[]','君毋走馬君竟走，走馬蹶塊傷君手。',96,'全唐诗/poet.song.27000.json','["君毋走馬君竟走，走馬蹶塊傷君手。", "蹭蹬翻成折臂翁，世間肯要三公否。", "西郊虜騎非常壯，年年犯邊殺邊將。", "勁弓長劍如君徒，始堪追逐青海上。", "功名棄置時未可，意氣激昂人所望。", "側身萬里風雪寒，無由贈子黄金丹。"]'),
('b6805f73-3251-4c5a-bdc7-149f705d3b47','劉涇州以所得李士衡觀察家寶硯相示與聖俞玉汝同觀戯作此歌','劉敞','宋','宋诗','song-poetry','','[]','李侯寶硯劉侯得，上有刺史李元刻。',96,'全唐诗/poet.song.27000.json','["李侯寶硯劉侯得，上有刺史李元刻。", "云是天寶八年冬，端州東溪靈卵石。", "我語二客此不然，天寶稱載不稱年。", "刺史爲守州爲郡，此獨云爾奚所傳。", "兩君盧胡爲絕倒，嗟爾于人幾爲寶。", "萬事售僞必眩真，此固區區無足道。"]'),
('7640ad42-c7da-4d01-924b-3dd2ed107b56','和府公觀劉團練寶刀詩','劉敞','宋','宋诗','song-poetry','','[]','吾宗寶刀清如水，東夷昔時獻天子。',128,'全唐诗/poet.song.27000.json','["吾宗寶刀清如水，東夷昔時獻天子。", "孤光晝射滄海寒，殺聲夜吼蛟龍起。", "上爲鐐琫下珧珌，粲如珠璣耀朝日。", "制度還存三代風，精神未是塵中物。", "秘藏武庫人莫窺，外家將軍獨得之。", "四方昇平竟未試，流落功名翻可悲。", "時無薛燭誰賞異，廟堂宗工詩絕世。", "丈夫要取萬里侯，肯令神兵負詩意。"]'),
('16fe64b7-ebae-4e69-a5f1-800402902ee2','與聖俞君章樞言持國飲因以太公大刀王莽錯刀示之','劉敞','宋','宋诗','song-poetry','','[]','君不見九府圜法傾東鄰，齊公大刀又日新。',130,'全唐诗/poet.song.27000.json','["君不見九府圜法傾東鄰，齊公大刀又日新。", "君不見黄牛白腹蕩滄海，亡新錯刀忽遽改。", "一盈一虚更貿遷，勢如流波不復還。", "邇來上下各千歲，何異俛仰須臾間。", "王伯之事百存一，况此錢刀握中物。", "愚智共盡令人悲，興廢相尋空史筆。", "前有一樽酒，浩歌爲君壽。", "君能識此當日醉，身世悠悠復何有。"]'),
('7d513595-4cea-4635-bec2-835850e5bcce','往年築青澗城各有得佩刀者莫知其何世物余按故史則赫連勃勃所鑄也所謂大夏龍雀者是矣客因以遺予爲作七言詩','劉敞','宋','宋诗','song-poetry','','[]','赫連寶刀利且堅，霜鱗錯落龍雀環。',96,'全唐诗/poet.song.27000.json','["赫連寶刀利且堅，霜鱗錯落龍雀環。", "當時鑄作妙一世，赫赫似與天相連。", "雷公祝融借光彩，蓬飛中原鯨振海。", "神物羞爲不義屈，一去人間向千載。", "蛟蟠虎化自有時，氣如投蜺世莫知。", "力能提攜倚天外，一埽雲霧君看之。"]'),
('cc608e94-381c-431f-bb87-d517b91e2a7f','寒林石屏風','劉敞','宋','宋诗','song-poetry','','[]','屏風畫山皆任假，寒林石屏自然者。',144,'全唐诗/poet.song.27000.json','["屏風畫山皆任假，寒林石屏自然者。", "蒼紋紺脈亂交加，短樹高枝自瀟灑。", "觀者寧分畫與非，但怪奇妙非人爲。", "又疑古苔著石瘦，何得本末無纖遺。", "桑田變海松柏死，寒暑不及榮枯期。", "佳哉大鈞育羣類，埏鎔精巧無巨細。", "天真通貎皆生成，俗師筆墨那形似。", "居人幽獨最相宜，樸厚遠謝雕鏤姿。", "城中雲母屏更好，慎勿浪示豪家兒。"]'),
('97794368-cbf0-4072-b55e-306ad1bad196','秋園行','劉敞','宋','宋诗','song-poetry','','[]','空園過霜無餘綠，上有梧楸下蘭菊。',64,'全唐诗/poet.song.27000.json','["空園過霜無餘綠，上有梧楸下蘭菊。", "疏陰雖存不自蔽，殘香已斷誰更續。", "憶昔繁華今九秋，天時人事略相侔。", "放懷未能驚物化，爛醉聊可爲君謀。"]'),
('1adada3b-9851-4fba-a025-08061742965f','槐陰','劉敞','宋','宋诗','song-poetry','','[]','都城廣陌如綺分，綠槐左右結浮雲。',80,'全唐诗/poet.song.27000.json','["都城廣陌如綺分，綠槐左右結浮雲。", "火輪東升又西没，倒影参差朝復曛。", "輕車重馬誰家子，側肩相逢密如蟻。", "共看擇蔭須臾間，可憐争道尋常裏。", "下有溝水日夜流，年華視此俱悠悠。"]'),
('bb940e84-4fa7-4086-9d59-964196bc9e10','春陰','劉敞','宋','宋诗','song-poetry','','[]','楚山春陰誰復數，朝朝出雲暮暮雨。',64,'全唐诗/poet.song.27000.json','["楚山春陰誰復數，朝朝出雲暮暮雨。", "高唐恍惚信有神，晦明代謝今猶古。", "蜀江渺渺水東流，苦霧淒雨翻似秋。", "日月高懸不可遇，眼看卑濕令人愁。"]'),
('7598ba40-225e-48e6-81d5-f1dc68fb835a','桃源','劉敞','宋','宋诗','song-poetry','','[]','武陵谿水清無塵，武陵桃樹花長春。',96,'全唐诗/poet.song.27000.json','["武陵谿水清無塵，武陵桃樹花長春。", "會買漁舟謝賓客，來作武陵山下人。", "秦人洞府晉人谿，碧草紅桃處處迷。", "流水至今堪悵望，問津從古失端倪。", "山川非復壼中見，雞犬猶傳雲外啼。", "頋視人間真敝屣，爲煩仙子託幽棲。"]'),
('a65316a5-c7cd-472c-a3da-66fd625ef8d0','和永叔十二韻','劉敞','宋','宋诗','song-poetry','','[]','愛公猶愛屋上烏，何况公家手種菊。',192,'全唐诗/poet.song.27000.json','["愛公猶愛屋上烏，何况公家手種菊。", "憶昔重陽醉共賞，已落紗帽歡不足。", "誰令繁霜逼芳意，坐使嚴風卷餘馥。", "主人于此情不淺，上客方來强令束。", "馬聲玲瓏搖玉環，屨綦參差破苔綠。", "重尋荒徑憶五柳，因咏東籬憇茅屋。", "巳憐歸鳥有真意，更覺晨風傷局促。", "引杯大釂傾玉壺，擊節應非響喬木。", "物華瞬息暫入夢，世事蚊虻一過目。", "浮邱接袂當鳳舉，俗士歌驪真狗曲。", "衣冠頃來塵土變，形貌今者毛髪秃。", "公詩乃使我忘老，逸調何由能繼屬。"]'),
('87636dde-461b-4d82-ac03-124947ad911d','共城寄仲弟','劉敞','宋','宋诗','song-poetry','','[]','共城稻秧如黍禾，共城木少種竹多。',112,'全唐诗/poet.song.27000.json','["共城稻秧如黍禾，共城木少種竹多。", "熟聞邇來風土美，貧無置錐知奈何。", "百門蒼翠太行麓，百泉清泠淇水澳。", "長安宦遊跬步到，隱居鷄黍終年足。", "人生早念少游言，燕領莫矜飛食肉。", "即今囊空未果歸，且爲黎侯歌式微。", "寄聲好在久良苦，異時自檝來迎汝。"]'),
('bb06fdb5-e72c-498f-aedf-77f2f9a0a749','田家行','劉敞','宋','宋诗','song-poetry','','[]','春耕高原不辭苦，晚歲離離滿百畝。',96,'全唐诗/poet.song.27000.json','["春耕高原不辭苦，晚歲離離滿百畝。", "豈知輸稻如輸金，始信種田虚種黍。", "持黍易金入市行，粳稻踴貴黍價輕。", "十鍾一石亦不憚，三時力農空自驚。", "去年歲荒食丰菽，今年歲豐彌不足。", "物理悠悠難豫謀，誰謂豐荒略相覆。"]'),
('9f60d5c4-e01b-4413-8f45-5e94b16a9576','荒田行','劉敞','宋','宋诗','song-poetry','','[]','大農棄田避征役，小農挈家就兵籍。',64,'全唐诗/poet.song.27000.json','["大農棄田避征役，小農挈家就兵籍。", "良田茫茫少耕者，秋來雨止生荆棘。", "縣官募兵有著令，募兵如率官有慶。", "從今無復官勸農，還逐魚鹽作亡命。"]'),
('de281e63-8028-4a72-a7ac-6f19ede0a1ff','戯作青瓷香球歌','劉敞','宋','宋诗','song-poetry','','[]','藍田仙人採寒玉，藍光照人瑩如燭。',64,'全唐诗/poet.song.27000.json','["藍田仙人採寒玉，藍光照人瑩如燭。", "蟾肪淬刀昆吾石，信手鐫花何委曲。", "濛濛夜氣清且嫮，玉縷噴香如紫霧。", "天明人起朝雲飛，彷彿疑成此中去。"]'),
('f7ce5bb9-81c2-428c-b7c8-799eb91f9963','櫻桃花開留徐二飲','劉敞','宋','宋诗','song-poetry','','[]','晨暉照屋清露晞，櫻桃花房開欲齊。',176,'全唐诗/poet.song.27000.json','["晨暉照屋清露晞，櫻桃花房開欲齊。", "繁花先得造物巧，不與衆卉爭高低。", "参差蕚蕚相照耀，恍惚滿眼令人迷。", "鳥驚風過若無意，雲起雪飛空滿蹊。", "仰攀濃香俯玩影，應接不暇昏鴉棲。", "流光易失動壯士，斗酒相勞和天倪。", "浩歌直欲并日夜，醉耳不能分鼓鼙。", "人間出處未嘗定，暫雖會合終當暌。", "子今躍馬至萬里，脱略塵土排雲霓。", "豫知明年花復發，悵望君子無由携。", "少年且作後日意，更使封植驚淮西。"]'),
('2dda3a87-a0b3-4f83-bd07-b0da3830c42e','萬卷生','劉敞','宋','宋诗','song-poetry','','[]','白頭書生南國賢，讀書萬卷夜忘眠。',64,'全唐诗/poet.song.27000.json','["白頭書生南國賢，讀書萬卷夜忘眠。", "陋巷簞瓢未曾飽，苦心獨行竟誰憐。", "繙經遍窮十二等，陳力夐過三千年。", "莫笑青袍學士老，太平能頌連中弦。"]'),
('e5c5f4f4-8328-4f96-8f8c-5dcb34bf4848','野望','劉敞','宋','宋诗','song-poetry','','[]','重陽去寥落，小雪碧蒼茫。',48,'全唐诗/poet.song.27000.json','["重陽去寥落，小雪碧蒼茫。", "獸起駭枯草，鳥歸横夕陽。", "薄雲低引白，衰菊暗消黄。", "佇立何爲久，愴人非故鄉。"]'),
('eed7faa8-65e7-4105-ac38-7b56df16d03a','蕪城閒望二首  其一','劉敞','宋','宋诗','song-poetry','','[]','幽尋古城上，秋景日悽悽。',48,'全唐诗/poet.song.27000.json','["幽尋古城上，秋景日悽悽。", "落照映原沒，陰蟲當路啼。", "隋宫變蕪蔓，楚分失端倪。", "自是傷亡國，非關醉眼迷。"]'),
('40bf27b7-12f2-4a56-80ba-dbf0d83d690f','蕪城閒望二首  其二','劉敞','宋','宋诗','song-poetry','','[]','春草忽更綠，荒城陰霧滋。',48,'全唐诗/poet.song.27000.json','["春草忽更綠，荒城陰霧滋。", "風存鮑昭賦，秋益宋生悲。", "慨想秦兵出，傳聞羽檄馳。", "江湖歲將晚，空羡逐鴟夷。"]'),
('453b424c-f4d1-41cc-87fa-6e6cbeaedeb4','夏晚','劉敞','宋','宋诗','song-poetry','','[]','閏餘時侯早，夏晚似新秋。',48,'全唐诗/poet.song.27000.json','["閏餘時侯早，夏晚似新秋。", "月出空堂靜，蟬鳴深樹幽。", "健逢鷹學習，喜見火傾流。", "早晚涼飈起，重修白罽裘。"]'),
('a7920258-fef0-4c50-a4a7-c093f0faf399','聽鐘','劉敞','宋','宋诗','song-poetry','','[]','陋巷客回轍，夕陽鐘送秋。',48,'全唐诗/poet.song.27000.json','["陋巷客回轍，夕陽鐘送秋。", "寒聲滿空谷，暝色下高樓。", "陡逐悲風起，微兼遠角收。", "旅懷傷急景，聽此愧淹留。"]'),
('57234a1d-577f-4bfd-863e-601418f82cff','野望','劉敞','宋','宋诗','song-poetry','','[]','江水不可越，扁舟浮夕陽。',48,'全唐诗/poet.song.27000.json','["江水不可越，扁舟浮夕陽。", "高秋露寥落，遠樹出毫芒。", "澗水清兼濁，山苗綠映黄。", "漁翁豈招隱，何待唱滄浪。"]'),
('5c5b9884-0eef-4957-83e6-f64c21336dab','觀南戍士卒作樂','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','簫鼓軍中樂，旌旗歲晚過。',48,'全唐诗/poet.song.27000.json','["簫鼓軍中樂，旌旗歲晚過。", "激昂雙劍舞，慷慨萬人歌。", "睥睨荆衡小，騰凌虎兕多。", "北風隨殺氣，横絕洞庭波。"]'),
('2e85245d-a0d9-4e30-8cd5-c862cc55b000','聞聖俞移官霅上以便歸養','劉敞','宋','宋诗','song-poetry','','[]','親老不擇祿，此心如古人。',48,'全唐诗/poet.song.27000.json','["親老不擇祿，此心如古人。", "戴星捐吏事，戲綵過鄉鄰。", "若下開新酌，汀邊詠白蘋。", "醉吟俱入手，亦未負青春。"]'),
('5dcfb07d-c129-4cb8-a0bc-aee3dde3de56','西域請平三首  其一','劉敞','宋','宋诗','song-poetry','','[]','西域請都護，崆峒獻凱歌。',48,'全唐诗/poet.song.27000.json','["西域請都護，崆峒獻凱歌。", "兩階增羽籥，萬里肅山河。", "甲第旃裘少，春宫苜蓿多。", "雌雄雙匣劍，棄置欲如何。"]'),
('28326df9-2aed-4693-8339-70f6a924ed62','西域請平三首  其二','劉敞','宋','宋诗','song-poetry','','[]','禦戎傳上策，不戰屈人兵。',48,'全唐诗/poet.song.27000.json','["禦戎傳上策，不戰屈人兵。", "遂斷匈奴臂，何須萬里城。", "出車非遠略，高枕得昇平。", "戰骨翻空死，吁嗟壯士名。"]'),
('e4efde33-acb6-489d-ae9f-6bd57655a920','西域請平三首  其三','劉敞','宋','宋诗','song-poetry','','[]','單于貪漢物，中國避天驕。',48,'全唐诗/poet.song.27000.json','["單于貪漢物，中國避天驕。", "賜予金銀貴，行來玉帛遙。", "悲傷賈太傅，慷慨霍嫖姚。", "慟哭辭新第，英雄未可招。"]'),
('8dc35168-2f2a-4105-9d70-0c47698e82f4','雪後登觀風樓','劉敞','宋','宋诗','song-poetry','','[]','雪带郊原闊，城横碧玉齊。',48,'全唐诗/poet.song.27000.json','["雪带郊原闊，城横碧玉齊。", "夕陽寒似落，遠樹望如迷。", "旅鴈情更急，棲鳥饑亂啼。", "强歌非郢客，竟日戀危梯。"]'),
('53cc1993-811a-46ba-abac-265a74a26272','開竹下小徑招君章','劉敞','宋','宋诗','song-poetry','','[]','翠竹生無數，蕭蕭一徑新。',48,'全唐诗/poet.song.27000.json','["翠竹生無數，蕭蕭一徑新。", "陰繁催短日，地僻斷飛塵。", "磐石兼容客，幽禽不避人。", "君能爛漫醉，當及七賢真。"]'),
('78b713c9-3c3d-46bb-8cfc-24ffb0e2f5dd','贈刁十八自蜀還鄉昔與此君别於福唐','劉敞','宋','宋诗','song-poetry','','[]','瘴海三年别，巴山萬里迷。',48,'全唐诗/poet.song.27000.json','["瘴海三年别，巴山萬里迷。", "相逢忻邂逅，即事恨睽攜。", "夢減清江外，愁寛太白西。", "知君偃鄉墅，已忘子規啼。"]'),
('ac1107ac-48bb-4439-86ff-9fab31450b79','送李監丞致仕還鄉','劉敞','宋','宋诗','song-poetry','','[]','耄期吏隱倦，歸去上恩榮。',48,'全唐诗/poet.song.27000.json','["耄期吏隱倦，歸去上恩榮。", "國子瞻師保，鄉人慶父兄。", "揮金慰游舊，擊壤傲昇平。", "遠笑吴門叟，何爲變姓名。"]'),
('4366faca-17a8-43fc-8d24-6407ca4b0f7e','懷陳州舊居所種桐寄黄翁','劉敞','宋','宋诗','song-poetry','','[]','忽憶南軒樹，春風空復來。',48,'全唐诗/poet.song.27000.json','["忽憶南軒樹，春風空復來。", "陳亡韶已矣，孔老鳳悠哉。", "不作溝中斷，應隨爨下灰。", "舊居阡陌並，君到爲徘徊。"]'),
('29e27bd4-f979-4697-a9e9-769ff746be19','荷華','劉敞','宋','宋诗','song-poetry','','[]','水國非人境，芙蕖五月秋。',48,'全唐诗/poet.song.27000.json','["水國非人境，芙蕖五月秋。", "亂香清宿醉，濃豔破征愁。", "魚戲都堪數，鷗飛絕自由。", "會須窮一賞，詰曲任扁舟。"]'),
('dabfe414-6007-47ea-900c-9bc625baeee6','七月二日','劉敞','宋','宋诗','song-poetry','','[]','西風入庭樹，天氣颯然秋。',48,'全唐诗/poet.song.27000.json','["西風入庭樹，天氣颯然秋。", "細雨纔成潤，高雲淡不流。", "平分感一葉，遠興憶扁舟。", "蟋蟀何須急，羈人始欲留。"]'),
('53934105-c3cb-4e3e-a228-39232a049c38','秋雨所居漏濕','劉敞','宋','宋诗','song-poetry','','[]','皇天不愛物，風雨害秋成。',48,'全唐诗/poet.song.27000.json','["皇天不愛物，風雨害秋成。", "未恨泥塗辱，端憂柱石傾。", "淹留驚歲宴，堅臥悵雞鳴。", "吾道還如此，商歌天未明。"]'),
('33799714-3b38-4f73-a997-b01786b9e8a9','秋雨','劉敞','宋','宋诗','song-poetry','','[]','采蕭逼晚歲，飛雨度高雲。',48,'全唐诗/poet.song.27000.json','["采蕭逼晚歲，飛雨度高雲。", "暝色空窗見，秋聲墜葉聞。", "過螢低似滅，遠岫望如分。", "蟋蟀悲虚織，輕絲競欲棼。"]'),
('07d86bd6-f504-4fb7-943e-58bacb117c66','始凉','劉敞','宋','宋诗','song-poetry','','[]','北風吹過雨，晚景留新秋。',48,'全唐诗/poet.song.27000.json','["北風吹過雨，晚景留新秋。", "高臥來一笑，如焚寛百憂。", "精神露鷹隼，意氣激驊騮。", "自覺亦飛動，江湖思遠遊。"]'),
('8744d944-e15c-493c-a9ef-6e9b430e7a86','八月旦始凉','劉敞','宋','宋诗','song-poetry','','[]','騷騷北風急，杳杳白雲飛。',48,'全唐诗/poet.song.27000.json','["騷騷北風急，杳杳白雲飛。", "江漢波新起，蒹葭露欲睎。", "狂歌聞鳳鳥，楚製見荷衣。", "歷歷先賢趣，南浮亦庻幾。"]'),
('cc3831f2-fefb-4e7a-bb7b-7e9055a2e92a','重到謝氏園亭寄裴博士俊叔王主簿宗傑','劉敞','宋','宋诗','song-poetry','','[]','徘徊遠林下，幽草爲誰芳。',48,'全唐诗/poet.song.27000.json','["徘徊遠林下，幽草爲誰芳。", "前日同遊客，今朝俱異郷。", "東風雖淡蕩，陳迹似淒涼。", "何用江千里，春心故易傷。"]'),
('78295742-7059-4887-b411-d4ce5e0d19d9','送晁殿丞僉判鄭州','劉敞','宋','宋诗','song-poetry','','[]','世德緇衣美，天倫玉樹温。',48,'全唐诗/poet.song.27000.json','["世德緇衣美，天倫玉樹温。", "于君如舊識，贈子欲奚言。", "東里賢能宅，成臯戰伐原。", "從容訪耆老，遺蹟尚多存。"]'),
('efece228-c3f3-4f47-93d1-06b856c92f77','檀州','劉敞','宋','宋诗','song-poetry','','[]','窮谷回看盡，孤城平望遙。',48,'全唐诗/poet.song.27000.json','["窮谷回看盡，孤城平望遙。", "市聲衙日集，海蓋午時消。", "冠带才通漢，山川更入遼。", "春風觧冰雪，最覺馬蹄驕。"]'),
('60748e99-fbd4-494b-ae66-30932d2a048d','雨中聞鐘','劉敞','宋','宋诗','song-poetry','','[]','疏鐘不隔雨，迢遞入重城。',48,'全唐诗/poet.song.27000.json','["疏鐘不隔雨，迢遞入重城。", "倦客未能寐，歸禽初不驚。", "霏微通暮色，颯沓隱秋聲。", "簾幕鮮風起，明朝應早晴。"]'),
('6d26845c-7def-4d2d-835a-0a3389c2ef58','珍簟','劉敞','宋','宋诗','song-poetry','','[]','珍簟平鋪水，珠簾半捲風。',48,'全唐诗/poet.song.27000.json','["珍簟平鋪水，珠簾半捲風。", "勞生高枕裏，多事劇棋中。", "性僻非朝隱，民淳賴歲豐。", "翛然對松菊，但覺訟庭空。"]'),
('0566768a-177d-49ae-83d0-83970ee52674','蟬','劉敞','宋','宋诗','song-poetry','','[]','微軀定誰恨，清嘯不知勞。',48,'全唐诗/poet.song.27000.json','["微軀定誰恨，清嘯不知勞。", "屈宋悲秋苦，夷齊臥隱高。", "風林含咽絕，露葉動蕭騷。", "何必催搖落，人今已二毛。"]'),
('5a9062ae-8311-490a-b3cd-678526c0587b','臨雨亭','劉敞','宋','宋诗','song-poetry','','[]','秋至感人思，登臨成惘然。',48,'全唐诗/poet.song.27000.json','["秋至感人思，登臨成惘然。", "浮雲帝鄉外，落日古城邊。", "歸鴈聲相别，幽花色可憐。", "名山負獨往，觸物見徂年。"]'),
('3dd25a0a-26af-442e-aaa1-ab5cba6d32cd','同梅二十五飲永叔家觀所抄集近事','劉敞','宋','宋诗','song-poetry','','[]','陶公一畝宅，尤愛北窗風。',48,'全唐诗/poet.song.27000.json','["陶公一畝宅，尤愛北窗風。", "心遠地成僻，客來樽不空。", "觀書太史氏，全性市門翁。", "予亦何爲者，于兹清賞同。"]'),
('0ba6b8d5-04b5-4c03-956b-3e95d33f8c4f','伏波','劉敞','宋','宋诗','song-poetry','','[]','伏波志慷慨，南涉武溪深。',48,'全唐诗/poet.song.27000.json','["伏波志慷慨，南涉武溪深。", "銅柱功一跌，壺傾悲至今。", "吾聞威四海，亦有失前禽。", "試察兩階舞，應如丹浦心。"]'),
('271900d1-3a2b-4640-b0de-1df9d70eebc8','客有遺予注輦國鸚鵡素服黄冠語音甚清慧此國在海西距中州四十一萬里舟行半道過西王母三年乃遠番禺也','劉敞','宋','宋诗','song-poetry','','[]','四十萬里外，孤舟天與鄰。',48,'全唐诗/poet.song.27000.json','["四十萬里外，孤舟天與鄰。", "應誇王母使，更遇越裳人。", "素質宜姑射，黄冠即羽民。", "那将籠禽比，蕭灑絕埃塵。"]'),
('1feb77be-c699-44bb-b340-763edef06173','九月十四日于雍熙院爲舅氏齋設作','劉敞','宋','宋诗','song-poetry','','[]','他時傷遠别，渭北遽成悲。',48,'全唐诗/poet.song.27000.json','["他時傷遠别，渭北遽成悲。", "今作終天恨，悠悠奈我思。", "平生華屋處，回首不勝悲。", "寂寞西州路，何堪再到時。"]'),
('714a96ba-8373-463d-8f53-74aff41cb7e1','晦日','劉敞','宋','宋诗','song-poetry','','[]','是月佳遊勝，兹辰舊俗同。',48,'全唐诗/poet.song.27000.json','["是月佳遊勝，兹辰舊俗同。", "會須陶一醉，相與送諸窮。", "江柳参差綠，林花點染紅。", "春期猶大半，作意競東風。"]'),
('875000e4-201f-40fb-b02d-41bedb9f4b24','新蟬','劉敞','宋','宋诗','song-poetry','','[]','五月微陰始，鳴蟬高樹幽。',48,'全唐诗/poet.song.27000.json','["五月微陰始，鳴蟬高樹幽。", "倚風偏送曉，迎露欲先秋。", "孤管清兼濁，幺絃斷復留。", "年華自當爾，羈客浪多愁。"]'),
('bb77676c-3b72-4a3e-be96-e62dd8146b81','和江學士聞蟬','劉敞','宋','宋诗','song-poetry','','[]','微陰變潛律，濃霧引疏音。',48,'全唐诗/poet.song.27000.json','["微陰變潛律，濃霧引疏音。", "時化能無感，清吟獨有心。", "蕭條映落日，斷續響中林。", "秋風忽滿眼，嘆息歲華深。"]'),
('161050fe-b6b0-4900-925e-07ff52b03f4c','寄隱直','劉敞','宋','宋诗','song-poetry','','[]','避人非故土，带郭喜幽居。',48,'全唐诗/poet.song.27000.json','["避人非故土，带郭喜幽居。", "淺俗情多畏，新知意尚疏。", "負暄勝構火，汲井足滋疏。", "二物関身外，悠悠謝里閭。"]'),
('e1782a52-e861-40a1-aee3-388e6d1a7c37','寄袁陟','劉敞','宋','宋诗','song-poetry','','[]','巫峽行雲外，春江落日邊。',48,'全唐诗/poet.song.27000.json','["巫峽行雲外，春江落日邊。", "隔年雞黍具，萬里孝亷船。", "遠道比何若，相思長渺然。", "郢中輕白雪，逸響待君傳。"]'),
('07130a44-e075-49cb-b391-d01e77a1c3f6','寄范佑之','劉敞','宋','宋诗','song-poetry','','[]','吾子世罕識，他時醒亦狂。',48,'全唐诗/poet.song.27000.json','["吾子世罕識，他時醒亦狂。", "由來韻高逸，固自得軒昂。", "阮籍哭道路，接輿歌鳳凰。", "之人亦豈病，相嘆不能忘。"]'),
('4bcccda8-286f-4112-91f0-9f8c4919b4aa','寄王二十','劉敞','宋','宋诗','song-poetry','','[]','累累煩書札，悠悠感别離。',48,'全唐诗/poet.song.27000.json','["累累煩書札，悠悠感别離。", "平生義繾綣，相憶路逶迤。", "羈旅老将至，江湖天一涯。", "佯狂人事絕，乘興爾難期。"]'),
('a2b9b1a8-6f54-4883-b718-68209210df9a','寄蘇州張六','劉敞','宋','宋诗','song-poetry','','[]','西風入簾幕，游子念江湖。',48,'全唐诗/poet.song.27000.json','["西風入簾幕，游子念江湖。", "丹橘垂珠實，肥魚薦玉腴。", "他時肯招隱，快意欲乘桴。", "物色煩相候，佯狂興不無。"]'),
('c7bbff77-0c7d-43e9-893c-486059dac375','寄隱直','劉敞','宋','宋诗','song-poetry','','[]','俱爲異鄉客，似伴老僧禪。',48,'全唐诗/poet.song.27000.json','["俱爲異鄉客，似伴老僧禪。", "虚室矜生白，時流笑草玄。", "歲寒差自若，生理直翛然。", "無術能乘興，蒼茫欲雪天。"]'),
('422589db-21cd-4b6a-8296-60042a13245c','寄張獻臣','劉敞','宋','宋诗','song-poetry','','[]','締交從若水，百里絕相過。',48,'全唐诗/poet.song.27000.json','["締交從若水，百里絕相過。", "平日相離索，期年見揣摩。", "從容席上客，清絕郢中歌。", "擬屬陽春和，伊予獨在薖。"]'),
('b84ce2bc-c75c-45c1-b68c-9eee32d056c6','寄張晉卿時棄官還家','劉敞','宋','宋诗','song-poetry','','[]','聞道新安尉，清羸只自如。',48,'全唐诗/poet.song.27000.json','["聞道新安尉，清羸只自如。", "歸來陶令賦，養性子真書。", "情在交遊厚，心于仕進疏。", "人憂棄妻子，獨入剡中居。"]'),
('89b247a7-1f44-408c-82bd-f7bd8bbfcb7e','寄范佑之','劉敞','宋','宋诗','song-poetry','','[]','范子三年别，長安北望深。',48,'全唐诗/poet.song.27000.json','["范子三年别，長安北望深。", "相知非勢利，寄信各浮沉。", "勇鋭百夫敵，軒昂萬里心。", "何時殺羣賊，自取肘邊金。"]'),
('aae79026-b4fe-4482-bba2-1b5583e49c08','寄梅山陰','劉敞','宋','宋诗','song-poetry','','[]','縣與吳門近，居家識舊游。',48,'全唐诗/poet.song.27000.json','["縣與吳門近，居家識舊游。", "山回江表盡，水入鑑中流。", "勝事皆高古，詩懷易滿眸。", "春風花又發，能寄北人不。"]'),
('3b095777-c69b-435d-9ac8-82f89cdebbe0','寄蘇頌兄弟','劉敞','宋','宋诗','song-poetry','','[]','秋風生眼前，客子思悠然。',48,'全唐诗/poet.song.27000.json','["秋風生眼前，客子思悠然。", "羈旅獨無友，别離私自憐。", "賦甘傖父誚，詩許俗人傳。", "他日梁王客，偏懷太子賢。"]'),
('adacaa11-4d72-44fd-8227-0e1bede5fed2','寄因甫','劉敞','宋','宋诗','song-poetry','','[]','昔别大梁下，至今三歲餘。',48,'全唐诗/poet.song.27000.json','["昔别大梁下，至今三歲餘。", "豈無萬里使，不寄一行書。", "風俗與時薄，交游于義疏。", "知君淡如水，非是故忘予。"]'),
('3d4bd123-6bd7-4033-81ca-54413cfe0291','寄張仲謀','劉敞','宋','宋诗','song-poetry','','[]','張也真吾友，今年見老成。',48,'全唐诗/poet.song.27000.json','["張也真吾友，今年見老成。", "自彊雖不息，積習亦諸兄。", "曲講聞師泛，題詩使客驚。", "莫如班定遠，投筆笑諸生。"]'),
('c653aaf8-6f9e-4035-95fa-9f5c40283f0c','和直孺夜涼','劉敞','宋','宋诗','song-poetry','','[]','急雨逐雲過，微風吹月生。',48,'全唐诗/poet.song.27000.json','["急雨逐雲過，微風吹月生。", "寥寥天宇闊，粲粲葛衣輕。", "展轉漏将永，昭回河正横。", "秋槎舊有信，忽憶泛滄瀛。"]'),
('8d4b83d4-e1e8-4422-a8b4-bfaa02129b63','送楘州王學士','劉敞','宋','宋诗','song-poetry','','[]','春草碧将歇，江南鶯亂飛。',48,'全唐诗/poet.song.27000.json','["春草碧将歇，江南鶯亂飛。", "王孫去有適，綵服粲生輝。", "古郡富山水，斯人歌海沂。", "惟應布寛詔，談笑樹風徽。"]'),
('4ea1f4cb-66bf-4698-8799-818efd722899','素屏','劉敞','宋','宋诗','song-poetry','','[]','簡拙違時好，丹青謝爾工。',48,'全唐诗/poet.song.27000.json','["簡拙違時好，丹青謝爾工。", "坐看居士室，想見古人風。", "當戶月常入，過春霜未融。", "物情忌太白，少自晦塵中。"]'),
('a7cfa086-f979-4b0f-a187-333a474b434f','城樓望春','劉敞','宋','宋诗','song-poetry','','[]','高樓新雪後，春意已端倪。',48,'全唐诗/poet.song.27000.json','["高樓新雪後，春意已端倪。", "遶石泉聲急，圍城柳色齊。", "滯流貪適興，幽僻嬾招攜。", "舊種桃千樹，春遊豫恐迷。"]'),
('63badc0f-57aa-4603-8467-defc04283789','送邵武張學士','劉敞','宋','宋诗','song-poetry','','[]','待詔勤穿履，承明厭直廬。',48,'全唐诗/poet.song.27000.json','["待詔勤穿履，承明厭直廬。", "一麾從此去，千騎上頭居。", "歲事畬田早，風謡鴂舌餘。", "班春急乘傳，知不爲鱸魚。"]'),
('4f5623bd-85d1-4294-95ee-f3620462f78c','野思','劉敞','宋','宋诗','song-poetry','','[]','野色行行遠，春輝樹樹繁。',48,'全唐诗/poet.song.27000.json','["野色行行遠，春輝樹樹繁。", "看花頻落帽，聽鳥久忘言。", "遣興惟詩句，開懷獨酒樽。", "誰能顧名利，終歲不窺園。"]'),
('50029d07-5069-44dc-b31c-ce6690d60a27','訪楊異寺丞','劉敞','宋','宋诗','song-poetry','','[]','三徑向松菊，始疑元亮居。',48,'全唐诗/poet.song.27000.json','["三徑向松菊，始疑元亮居。", "但多柳五樹，復對隼雙旟。", "相識是傾蓋，劇談能起予。", "樵蘇不用爨，耳目且清虚。"]'),
('3032cf64-687a-4ce6-a73a-08b3fd5fa87d','黄寺丞風雨中見過','劉敞','宋','宋诗','song-poetry','','[]','節物重陽晚，風雲萬里陰。',48,'全唐诗/poet.song.27000.json','["節物重陽晚，風雲萬里陰。", "君來慰孤憤，語次豁愁心。", "名下如舊識，人間仍陸沈。", "獨醒感庭菊，蕭索萬黄金。"]'),
('33fa28a4-8be6-43f4-8557-3366b9c33f85','送洛南周寺丞','劉敞','宋','宋诗','song-poetry','','[]','不知商洛道，空慕紫芝歌。',48,'全唐诗/poet.song.27000.json','["不知商洛道，空慕紫芝歌。", "從事老将至，送君情獨多。", "雙鳧尚方去，駟馬故鄉過。", "想見揮弦樂，春風初扇和。"]'),
('53853a0e-db4e-452c-be43-02cc10ccd13e','弔南宜守尉','劉敞','宋','宋诗','song-poetry','','[]','百越誰生禍，南宜遂不師。',48,'全唐诗/poet.song.27000.json','["百越誰生禍，南宜遂不師。", "干戈傷耋老，守尉死城陴。", "荒泂招魂遠，官軍請救遲。", "弱妻携稚子，嗟爾欲何之。"]'),
('4d4ad0d7-ed9a-4bbe-9c89-882a24249dfe','弔亡卒','劉敞','宋','宋诗','song-poetry','','[]','厲俗侵王略，祅冤積楚氛。',48,'全唐诗/poet.song.27000.json','["厲俗侵王略，祅冤積楚氛。", "民荒誰念亂，功敗失圖勳。", "天子憂南土，戈船促大軍。", "何時收爾骨，委祭越江濆。"]'),
('15aa62b1-861d-4620-8012-81ca5f53fe99','和楊備國愽弔屈原','劉敞','宋','宋诗','song-poetry','','[]','知音不恨遠，異代忽同聲。',48,'全唐诗/poet.song.27000.json','["知音不恨遠，異代忽同聲。", "靈魂自識路，幽遇亦含情。", "𣶂記屬揚子，臨淵悲賈生。", "鬲文激頽俗，會使衆人清。"]'),
('da0062b4-eac2-4290-9edb-8a6df4062a2b','聞夏太尉自長安徙備西邊','劉敞','宋','宋诗','song-poetry','','[]','防秋未得還，戰士出長安。',48,'全唐诗/poet.song.27000.json','["防秋未得還，戰士出長安。", "地利山河險，天時關塞寒。", "羌夷避飛将，天子倚良翰。", "見說成功近，秦中意似寛。"]'),
('a8ac1aeb-5605-498e-b116-cd52f30434b9','三月四日上方寺送隨州十一屯田','劉敞','宋','宋诗','song-poetry','','[]','載酒憐春盡，尋芳到翠微。',48,'全唐诗/poet.song.27000.json','["載酒憐春盡，尋芳到翠微。", "綿綿芳草遠，颺颺雜花飛。", "俯仰悲陳迹，淹留恨落暉。", "青楓千里目，那復送将歸。"]'),
('bbb7b6eb-04e1-46d4-a97b-248a29e18876','嘯臺','劉敞','宋','宋诗','song-poetry','','[]','尚有高臺在，遺名幸未空。',48,'全唐诗/poet.song.27000.json','["尚有高臺在，遺名幸未空。", "不時嗟眼白，失所念途窮。", "已矣先生意，蕭然烈士風。", "清芬定誰嗣，漫嘯白雲中。"]'),
('ef9b72e1-4a63-47ad-b023-5e3c7b414c46','日晚夜步過孫監丞','劉敞','宋','宋诗','song-poetry','','[]','幽居巷南北，雞犬略相聞。',48,'全唐诗/poet.song.27000.json','["幽居巷南北，雞犬略相聞。", "乘興偶有適，杖藜聊復勤。", "高城秋草落，密樹夕光曛。", "微爾開三徑，悠悠麋鹿羣。"]'),
('40fad924-8c54-438b-a3d7-67bf1b0022c0','浮舟西陽池中','劉敞','宋','宋诗','song-poetry','','[]','愛水都成癖，浮舟不厭頻。',48,'全唐诗/poet.song.27000.json','["愛水都成癖，浮舟不厭頻。", "寒泉清見底，刳木略容人。", "故故乘流往，飄飄得意真。", "槎頭尺許地，鷗鳥欲相馴。"]'),
('f6c1f572-b7c1-44a2-830a-439c325231bc','乏酒','劉敞','宋','宋诗','song-poetry','','[]','搖落偏悲客，清寒昜中人。',48,'全唐诗/poet.song.27000.json','["搖落偏悲客，清寒昜中人。", "寂寥那自守，淡泊亦殊真。", "浮俗仍皆醉，虚談浪飲醇。", "高歌傲燕市，忽憶重千鈞。"]'),
('4b30c71e-bd6c-4858-9c46-6ee38d98a6c4','西戎乞降','劉敞','宋','宋诗','song-poetry','','[]','南國傳消息，西戎送好音。',48,'全唐诗/poet.song.27000.json','["南國傳消息，西戎送好音。", "懷柔知帝力，啟佑亦天心。", "御酒葡萄遠，離宫苜蓿深。", "仍聞編舊里，五嶽望君臨。"]'),
('82ca6e9a-3cc1-4104-af0b-eb51ecd1dac6','壽山','劉敞','宋','宋诗','song-poetry','','[]','白隰見層峰，巉巖倚碧空。',48,'全唐诗/poet.song.27000.json','["白隰見層峰，巉巖倚碧空。", "上多千歲木，下有百年翁。", "櫟社不材永，東陵非義終。", "吾聞仁且壽，故在太平中。"]'),
('3dfdb0e7-1f15-42bc-8f60-fc4a8c059090','山寺','劉敞','宋','宋诗','song-poetry','','[]','野竹檀欒翠，孤峰杳靄青。',48,'全唐诗/poet.song.27000.json','["野竹檀欒翠，孤峰杳靄青。", "山樓隨詰曲，石路上青冥。", "雲色移時合，鐘聲隔水聽。", "似聞堪避世，遊子未嘗經。"]'),
('dc0b9af2-ad70-43cf-8a64-47f78c4c7c0c','城南泛舟三首  其一','劉敞','宋','宋诗','song-poetry','','[]','乘興隨所適，出郊聊泛然。',48,'全唐诗/poet.song.27000.json','["乘興隨所適，出郊聊泛然。", "青波能照髮，白鷺巧迎船。", "老樹悲秋雨，高風急暮蟬。", "孤城隱不見，落日暝浮烟。"]'),
('a5355d6b-82cb-4454-b9d0-fe7ba8d5b461','城南泛舟三首  其二','劉敞','宋','宋诗','song-poetry','','[]','不踏城南陌，從春及素秋。',48,'全唐诗/poet.song.27000.json','["不踏城南陌，從春及素秋。", "蕭條非復昔，顧眄莾堪愁。", "白露蒹葭老，清風蘭杜幽。", "佯狂驚楚俗，應識棹夷猶。"]'),
('5391731a-165f-4f1b-8941-f1d9d5ab3410','城南泛舟三首  其三','劉敞','宋','宋诗','song-poetry','','[]','高岸看爲谷，通波幾覆城。',48,'全唐诗/poet.song.27000.json','["高岸看爲谷，通波幾覆城。", "橧巢非太古，野俗競偷生。", "雨逐行雲過，山依返照明。", "楚歌搖落際，更動北歸情。"]'),
('c4a4938f-c1bf-4b1d-ae79-f70abc4686e7','斁除蘇州掾','劉敞','宋','宋诗','song-poetry','','[]','三年不相見，萬里比何如。',48,'全唐诗/poet.song.27000.json','["三年不相見，萬里比何如。", "聞道詞曹掾，新承選部書。", "弓裘傳習在，簪笏抗塵初。", "努力人間世，毋爲薄詔除。"]'),
('a4f4e1d8-45ea-4bd3-8456-dd82ec486a82','黄州臨臯亭','劉敞','宋','宋诗','song-poetry','','[]','春秋黄子國，楚越穆陵關。',48,'全唐诗/poet.song.27000.json','["春秋黄子國，楚越穆陵關。", "比屋皆編竹，孤城半踐山。", "岸泥觀虎迹，雲水暗荆蠻。", "三入承明客，那能鬢不斑。"]'),
('ed9a7f3b-d1e0-4f23-8759-c92978833fcf','暴雨','劉敞','宋','宋诗','song-poetry','','[]','山晚雲霧合，江秋風雨多。',48,'全唐诗/poet.song.27000.json','["山晚雲霧合，江秋風雨多。", "憑夷何事舞，楚水忽翻波。", "黯黯夕陽盡，翩翩暮鳥過。", "輕舟送兩槳，聞唱石城歌。"]'),
('0acea53d-5675-46c1-94c2-0737bb458ee3','驟雨','劉敞','宋','宋诗','song-poetry','','[]','炎日大冶沸，清風愁意蘇。',48,'全唐诗/poet.song.27000.json','["炎日大冶沸，清風愁意蘇。", "黑雲過山岳，白雨覆江湖。", "彷彿鬼神戰，騰凌車騎趋。", "森然異氣象，真復慰泥塗。"]'),
('5e6de8cb-e48b-4116-802d-43d45dd53456','夏夜暴雨','劉敞','宋','宋诗','song-poetry','','[]','大暑積炎夏，沈陰昏楚天。',48,'全唐诗/poet.song.27000.json','["大暑積炎夏，沈陰昏楚天。", "疾雷五河裂，飛電萬星懸。", "漲澤通南國，孤城鬥百川。", "似傳黄鳥語，欲反濯龍淵。"]'),
('441ab4fa-6c7e-42cc-a8df-b5034c8d2b81','久雨','劉敞','宋','宋诗','song-poetry','','[]','祇憶風回雪，俄驚地出雷。',48,'全唐诗/poet.song.27000.json','["祇憶風回雪，俄驚地出雷。", "沈陰連甲子，春事總歸來。", "湖水寒侵夜，江雲去復回。", "開年厭卑濕，不待熟黄梅。"]'),
('8f389c1f-3d9a-4d0e-842b-77268f246e69','久雨二首  其一','劉敞','宋','宋诗','song-poetry','','[]','江雨黄梅實，湖雲起蟄龍。',48,'全唐诗/poet.song.27000.json','["江雨黄梅實，湖雲起蟄龍。", "寒生夜牀簟，聲絕暮山鐘。", "藥裹添新粉，書編坼舊縫。", "雖知恨卑濕，涼夜尚吾容。"]'),
('53d8f34b-940e-4307-bea7-f80e128f19ea','久雨二首  其二','劉敞','宋','宋诗','song-poetry','','[]','頗憶家居日，朝眠一事無。',48,'全唐诗/poet.song.27000.json','["頗憶家居日，朝眠一事無。", "邇來趨幕府，曙雨踏泥塗。", "城郭飛鳴鶴，階除戲浴鳧。", "秋風殊不遠，行欲問江鱸。"]'),
('07aeb0a8-b018-443a-acc7-9b53132f3c79','茶山送道粹','劉敞','宋','宋诗','song-poetry','','[]','海上相逢少，山中别恨多。',48,'全唐诗/poet.song.27000.json','["海上相逢少，山中别恨多。", "浮雲自向闕，秋水更增波。", "攜手意不盡，班荆情若何。", "徘徊强一醉，且勿奏驪歌。"]'),
('d469c23e-102e-4d53-99ca-788d8c687337','招晉卿時晉卿到丹陽','劉敞','宋','宋诗','song-poetry','','[]','識心非識面，常恨不相從。',48,'全唐诗/poet.song.27000.json','["識心非識面，常恨不相從。", "那作經年别，曾無一日逢。", "興來清剡雪，吟出暮山峰。", "浄埽門前路，期君馬繫松。"]'),
('f6979a20-97cc-4d96-9424-0b23645612c2','女郞臺','劉敞','宋','宋诗','song-poetry','','[]','城郭臨湖盡，樓臺此地偏。',48,'全唐诗/poet.song.27000.json','["城郭臨湖盡，樓臺此地偏。", "動搖浮積水，高絕近諸天。", "應接都無暇，虚空足悟禪。", "塵中故易厭，興盡惜回船。"]'),
('3bb6ff25-2ac8-4f62-88b0-ff1d6b6cf58f','閔雨','劉敞','宋','宋诗','song-poetry','','[]','風伯會何憾，高雲不少留。',48,'全唐诗/poet.song.27000.json','["風伯會何憾，高雲不少留。", "聲如鬼神過，勢卷日星浮。", "河漢漠無象，魚龍方自憂。", "古書難盡信，雩舞竟悠悠。"]'),
('7896b934-d7b4-47f0-81ec-816ccf8acff6','砧婦','劉敞','宋','宋诗','song-poetry','','[]','清霜石上乾，孤響耳中酸。',48,'全唐诗/poet.song.27000.json','["清霜石上乾，孤響耳中酸。", "歲逼秋芳盡，風量板屋寒。", "君行自悠遠，妾意亦艱難。", "此夜關山月，應知带日寛。"]'),
('434d52cb-bd6d-41c0-a510-88a411c39fd7','李太傅挽詞三首  其一','劉敞','宋','宋诗','song-poetry','','[]','數聞伏閣議，屢上薦賢書。',48,'全唐诗/poet.song.27000.json','["數聞伏閣議，屢上薦賢書。", "任重道空遠，名榮身反疏。", "異鄉悲鵩鳥，清詔隔公車。", "招隱真虚語，江湖萬里餘。"]'),
('40388829-a603-44fa-bcc3-468bdbe7f747','李太傅挽詞三首  其二','劉敞','宋','宋诗','song-poetry','','[]','報國念推轂，逢憂甘噬臍。',48,'全唐诗/poet.song.27000.json','["報國念推轂，逢憂甘噬臍。", "孤鳴一垂翅，舉俗競吹齋。", "山鬼離居遠，靈魂失路迷。", "天高不可問，愁意日淒淒。"]'),
('7c38673b-3cf8-433a-b05b-684e67cdedb3','李太傅挽詞三首  其三','劉敞','宋','宋诗','song-poetry','','[]','識理未曾誤，疾邪惟過深。',48,'全唐诗/poet.song.27000.json','["識理未曾誤，疾邪惟過深。", "豈忘事反覆，不忍俗浮沈。", "去國尚回顧，埋名方自今。", "異時山水意，惻惻弔鳴琴。"]'),
('43b44854-d890-44a9-95d3-7cbae6113076','魯拾遺挽詞二首  其一','劉敞','宋','宋诗','song-poetry','','[]','市朝非故日，年代屬傳聞。',48,'全唐诗/poet.song.27000.json','["市朝非故日，年代屬傳聞。", "始兆滕公室，來觀季子墳。", "埋名書故事，編簡屬遺文。", "苦恨相如賦，俱隨諫草焚。"]'),
('3de56750-67ce-4f1c-913f-bb1e93054431','魯拾遺挽詞二首  其二','劉敞','宋','宋诗','song-poetry','','[]','西晉登賢日，東堂第一人。',48,'全唐诗/poet.song.27000.json','["西晉登賢日，東堂第一人。", "競推天下士，爭辟幕中賓。", "故國無喬木，流風及搢紳。", "新阡廣陵上，荒草欲含春。"]'),
('8d04c6e6-1e7f-4b83-af93-0b3f33f304ff','庶幾堂','劉敞','宋','宋诗','song-poetry','','[]','閉門吾自足，況亦近墻東。',48,'全唐诗/poet.song.27000.json','["閉門吾自足，況亦近墻東。", "滴滴階鳴雨，梢梢竹過風。", "綠苔侵杖屨，秋色近梧桐。", "高臥殊多興，詩成寂寞中。"]'),
('efea32d1-bddc-4b0d-acb4-2e2c87ac84d8','延州沈待制挽詞','劉敞','宋','宋诗','song-poetry','','[]','詩書謀國體，談笑卻邊塵。',48,'全唐诗/poet.song.27000.json','["詩書謀國體，談笑卻邊塵。", "已矣今成昔，歸來悲故人。", "餘忠焚諫草，遺恨畫麒麟。", "禁角聞鼙鼓，能無憶虎臣。"]'),
('826c470a-1bd5-4e5d-9176-f437bf0e29e8','祠部王郞中送山水枕屏作','劉敞','宋','宋诗','song-poetry','','[]','枕上萬峰合，蒼蒼驚夢魂。',48,'全唐诗/poet.song.27000.json','["枕上萬峰合，蒼蒼驚夢魂。", "如浮武林水，臥向桃花源。", "杖屨幾時士，茅茨何處村。", "悠然獨往意，欲問復忘言。"]'),
('7fa5d1ae-f573-4d37-9f81-6a66b7500199','城樓望水','劉敞','宋','宋诗','song-poetry','','[]','遠水全無地，高城略近天。',48,'全唐诗/poet.song.27000.json','["遠水全無地，高城略近天。", "龍吟忽半見，虹飲競相鮮。", "魚鼈争乘渚，兒童狹濟川。", "秋風只昨日，物意已蕭然。"]'),
('8cadcd54-2104-48cb-8015-be5ace050003','送南昌郭主簿','劉敞','宋','宋诗','song-poetry','','[]','楚劍炟照地，梅真從吏鄉。',48,'全唐诗/poet.song.27000.json','["楚劍炟照地，梅真從吏鄉。", "簿書非急務，鴻鴈試高翔。", "貍品牛尾貴，茶牙鷹瓜長。", "因君訪風土，游子不能忘。"]'),
('595236f7-23fd-4a6e-b1a4-e48c00e54198','戯和同年時在薦福寺','劉敞','宋','宋诗','song-poetry','','[]','逃暑涓涓酒，開襟細細風。',48,'全唐诗/poet.song.27000.json','["逃暑涓涓酒，開襟細細風。", "過雲催急雨，落日澹秋空。", "樹影經行熟，泉聲笑語通。", "少年興不淺，寧與老人同。"]'),
('5365a081-0a12-4eef-bfdb-ca53a2d86d31','鍊丹井','劉敞','宋','宋诗','song-poetry','','[]','丹成人已去，泉在月空沉。',48,'全唐诗/poet.song.27000.json','["丹成人已去，泉在月空沉。", "輕舉非吾事，泓澄似客心。", "飲雖資一腹，貪不近千金。", "更愛雙桐好，曾非惡木陰。"]'),
('43f31728-3ad3-4873-ad8e-bb7a8163e426','水齋','劉敞','宋','宋诗','song-poetry','','[]','野塘春水平，間客自揚舲。',48,'全唐诗/poet.song.27000.json','["野塘春水平，間客自揚舲。", "鷗鷺時相近，波濤亦俯聽。", "榜歌漁父曲，醉讀屈平經。", "便欲從兹去，秋河泛客星。"]'),
('e7f60bb5-b1dc-4ca5-8092-f3e37213d827','長蘆口','劉敞','宋','宋诗','song-poetry','','[]','泱漭東流白，微茫遠嶼青。',48,'全唐诗/poet.song.27000.json','["泱漭東流白，微茫遠嶼青。", "風飈萬里浪，性命一浮萍。", "飛鳥戢倦翼，潛蛟浮暗腥。", "由來限南北，天意亦冥冥。"]'),
('1cd63336-4aa8-4ec4-87fa-9ec600ffb197','登東城樓二首  其一','劉敞','宋','宋诗','song-poetry','','[]','搖落客愁亂，登臨秋色空。',48,'全唐诗/poet.song.27000.json','["搖落客愁亂，登臨秋色空。", "溪流寒更碧，霜樹晚增紅。", "曠野駐殘日，虚軒來朔風。", "懷歸復感别，不語向征鴻。"]'),
('fc3a43d6-9ebb-44ae-8375-0da0e7327f01','登東城樓二首  其二','劉敞','宋','宋诗','song-poetry','','[]','高樓望不極，野興遠相宜。',48,'全唐诗/poet.song.27000.json','["高樓望不極，野興遠相宜。", "宇宙一長嘯，山川多所思。", "薄寒才勝酒，短景不禁棋。", "俯仰哀羣動，遼遼見爾爲。"]'),
('64b8f5e1-8864-4c47-a159-84e6ff380ec1','送人之嶺南','劉敞','宋','宋诗','song-poetry','','[]','君去炎方遠，行行萬里餘。',48,'全唐诗/poet.song.27000.json','["君去炎方遠，行行萬里餘。", "漸驚南瘴酷，益見北人疏。", "山谷藏雄虺，谿潭養鱷魚。", "秋風鴈不到，何處俟歸書。"]'),
('dce91ca0-3f8e-4bb0-907d-9b3858737e93','城樓避暑','劉敞','宋','宋诗','song-poetry','','[]','積水動微吹，高樓浮薄陰。',48,'全唐诗/poet.song.27000.json','["積水動微吹，高樓浮薄陰。", "登臨倦非土，瀟灑勸披襟。", "滌滌原野曠，熹熹城郭深。", "浮雲空蔽日，無意欲爲霖。"]'),
('c62e98c2-4550-428c-a171-78d108072b84','寄內','劉敞','宋','宋诗','song-poetry','','[]','風雨驚春老，山川入夢遙。',48,'全唐诗/poet.song.27000.json','["風雨驚春老，山川入夢遙。", "此時看破鏡，何處正吹簫。", "舊種萱叢碧，新歸燕語嬌。", "佳期漫自笑，不似浙江潮。"]'),
('77ee16ab-61fe-452f-a296-cbbe5d13006c','送祖學士使北','劉敞','宋','宋诗','song-poetry','','[]','漢廷用五餌，無復請長纓。',48,'全唐诗/poet.song.27000.json','["漢廷用五餌，無復請長纓。", "猶是輶軒使，時通絕域情。", "山川資覽眺，戰伐想縱横。", "不負四方志，那辭萬里行。"]'),
('76fa0481-363f-4ccb-a2c5-3a134605f434','聞張六復棄官歸','劉敞','宋','宋诗','song-poetry','','[]','應懷折腰辱，復作棄官行。',48,'全唐诗/poet.song.27000.json','["應懷折腰辱，復作棄官行。", "頗似陶彭澤，兼疑尚子平。", "兵戈未消散，盜賊苦縱横。", "余亦存丘壑，相期作耦耕。"]'),
('d5ba9a20-5747-4c81-be32-439258905c36','螢','劉敞','宋','宋诗','song-poetry','','[]','翩翩豈自知，歷歷眩羣飛。',48,'全唐诗/poet.song.27000.json','["翩翩豈自知，歷歷眩羣飛。", "故作穿疏牖，時來鍳薄帷。", "助明清夜永，除害一身微。", "秋草隋宫路，茫茫舊賞非。"]'),
('adff97a6-a9f1-4abc-b8e7-d43d9eb7c3c8','送簽判雍秘丞還朝','劉敞','宋','宋诗','song-poetry','','[]','我有幕中士，名高天下聞。',48,'全唐诗/poet.song.27000.json','["我有幕中士，名高天下聞。", "方從玉堂召，欲就子虚文。", "相得已非早，送歸寧易分。", "期君望此府，急自致青雲。"]'),
('824e102c-404b-4e33-8edd-72127a5c348e','定水二首  其一','劉敞','宋','宋诗','song-poetry','','[]','定水涵空碧，羣山凝遠嵐。',48,'全唐诗/poet.song.27000.json','["定水涵空碧，羣山凝遠嵐。", "淵魚頗易得，菱實最餘甘。", "曠野應人語，凉風快酒酣。", "誰云陵谷換，自此識南潭。"]'),
('726c3b96-1fe5-4319-953a-d1e831122665','定水二首  其二','劉敞','宋','宋诗','song-poetry','','[]','此地去人近，向來幽賞違。',48,'全唐诗/poet.song.27000.json','["此地去人近，向來幽賞違。", "使君留隼旆，烟水浄魚磯。", "秋入冷蛩急，波明白鷺飛。", "異時江漢興，撫事更懷歸。"]'),
('f974faf5-1478-4e7b-9685-2246047a427c','索米','劉敞','宋','宋诗','song-poetry','','[]','索米東方朔，端居陸士衡。',48,'全唐诗/poet.song.27000.json','["索米東方朔，端居陸士衡。", "書仍聞北闕，賦亦讓南傖。", "感激秋風起，提攜夜劍横。", "南軍敗王略，誰事請長纓。"]'),
('0e187bd1-67af-452b-8cec-af59a6cd09ce','王屯田歸望山别墅','劉敞','宋','宋诗','song-poetry','','[]','岱陰宿雨霽，汶北秋風過。',48,'全唐诗/poet.song.27000.json','["岱陰宿雨霽，汶北秋風過。", "獨往予所慕，躬耕人謂何。", "林間雞黍具，日慕漁樵歌。", "郤望青山郭，應知惆悵多。"]'),
('fe58d882-cde2-41c0-b5b5-2e3b17755384','送高處士歸豐邑别墅','劉敞','宋','宋诗','song-poetry','','[]','不及西京盛，空知鄠杜間。',48,'全唐诗/poet.song.27000.json','["不及西京盛，空知鄠杜間。", "衣冠爲我累，丘壑羡君還。", "隴麥逢春秀，林花着雨斑。", "雞豚社下醉，多與謝南山。"]'),
('e19f5bb3-2ffb-4e11-add1-9e92fe1026c2','射雕','劉敞','宋','宋诗','song-poetry','','[]','將軍樂射雕，壯士挟烏號。',48,'全唐诗/poet.song.27000.json','["將軍樂射雕，壯士挟烏號。", "影捩重雲静，聲翻一箭高。", "獵酣生鼻火，空闊散風毛。", "快意中原捷，何辭汗馬勞。"]'),
('76d8898b-72f1-479b-9f12-ea47ed426a5d','和楊褒雨中見寄二首  其一','劉敞','宋','宋诗','song-poetry','','[]','佳雨雲龍會，高堂河漢聲。',48,'全唐诗/poet.song.27000.json','["佳雨雲龍會，高堂河漢聲。", "驅除三伏過，埽蕩九衢清。", "造物不無意，爲霖真有情。", "憐君獨高臥，亹亹向羣生。"]'),
('7977ec92-3ea1-4986-aa1b-e304ca9bb287','和楊褒雨中見寄二首  其二','劉敞','宋','宋诗','song-poetry','','[]','明暗變窗色，蕭騷翻樹聲。',48,'全唐诗/poet.song.27000.json','["明暗變窗色，蕭騷翻樹聲。", "閉門無所詣，高枕有餘清。", "櫪馬正局迹，韝鷹多遠情。", "分明動秋興，似欲惱潘生。"]'),
('b6598fe7-456b-4b91-9762-6837f369d77f','貰酒','劉敞','宋','宋诗','song-poetry','','[]','小徑入村塢，風帘拂暮霞。',48,'全唐诗/poet.song.27000.json','["小徑入村塢，風帘拂暮霞。", "桃源還可宿，樽酒亦容赊。", "舉眼青山秀，隨松白露斜。", "尋常出郊少，未醉莫還家。"]'),
('95d7092f-3712-413f-adb8-4a4585d17b80','張學士送酒','劉敞','宋','宋诗','song-poetry','','[]','秋風埽飛葉，客子鬢垂斑。',48,'全唐诗/poet.song.27000.json','["秋風埽飛葉，客子鬢垂斑。", "好事煩攜酒，懷情惬閉關。", "坐看凉月墮，醉送暮鴻還。", "後日相思意，蕭蕭叢菊間。"]'),
('3677afb8-9b49-4210-9861-68e114a7f266','朱橋','劉敞','宋','宋诗','song-poetry','','[]','朱橋柳映潭，忽見似江南。',48,'全唐诗/poet.song.27000.json','["朱橋柳映潭，忽見似江南。", "風物依然是，登臨昔所諳。", "犬聲寒隔水，山氣晚成嵐。", "留恨無人境，幽奇不盡探。"]'),
('bc75b09d-9ce0-48f5-9435-b04c8da2b935','閏月朔日寄府公給事二首  其一','劉敞','宋','宋诗','song-poetry','','[]','良閏百年逢，佳辰獻歲同。',48,'全唐诗/poet.song.27000.json','["良閏百年逢，佳辰獻歲同。", "春應隨北斗，天與緩東風。", "柳帯参差翠，花英點染紅。", "韶華供醉眼，未負黑頭翁。"]'),
('06678412-f30e-43e7-b749-eeea4d876fe2','閏月朔日寄府公給事二首  其二','劉敞','宋','宋诗','song-poetry','','[]','嘉月重非常，芳期及載陽。',48,'全唐诗/poet.song.27000.json','["嘉月重非常，芳期及載陽。", "卻因春意晚，得見歲華長。", "餘雪留寒色，新梅著早香。", "祗應勤一醉，持以答風光。"]'),
('66ab26ec-1ef0-4607-8507-1fe73cb6d668','晦日自薦福院泛舟上女郎臺','劉敞','宋','宋诗','song-poetry','','[]','晦日疑春晚，佳辰强客游。',48,'全唐诗/poet.song.27000.json','["晦日疑春晚，佳辰强客游。", "放船無用楫，置酒不驚鷗。", "牽率忘多病，登臨亂百憂。", "繁陰欺白日，容易暮雲浮。"]'),
('34ceeacf-70b3-47b9-9296-b0e13aa2980f','新鴈二首  其一','劉敞','宋','宋诗','song-poetry','','[]','逢時志萬里，非爲稻粱謀。',48,'全唐诗/poet.song.27000.json','["逢時志萬里，非爲稻粱謀。", "眇眇江漢阻，蕭蕭霜露秋。", "知機自有素，側翅莫多愁。", "風起浮雲暮，空看片影流。"]'),
('80933086-f45f-4215-9a70-fefc8d1a312b','新鴈二首  其二','劉敞','宋','宋诗','song-poetry','','[]','萬里南飛鴈，今年復此逢。',48,'全唐诗/poet.song.27000.json','["萬里南飛鴈，今年復此逢。", "自難隨燕雀，非不病秋冬。", "風急聲高下，雲深影疊重。", "江湖雖異土，泛泛爾能容。"]'),
('eab5b64f-290a-42ad-9161-f8ae1d96ab71','白河逢鴈','劉敞','宋','宋诗','song-poetry','','[]','白河見歸鴈，顧我影徘徊。',48,'全唐诗/poet.song.27000.json','["白河見歸鴈，顧我影徘徊。", "憶昔從此逝，相看經歲回。", "春生聊自樂，鄉近不須哀。", "爲問經南國，能無尺素來。"]'),
('dbde9f51-5486-4b21-8601-78db24962e4a','雪中鴈','劉敞','宋','宋诗','song-poetry','','[]','萬里羽毛弱，經時霰雪紛。',48,'全唐诗/poet.song.27000.json','["萬里羽毛弱，經時霰雪紛。", "江湖更何取，天地正同雲。", "影困低如落，聲悲遠似聞。", "識時端北向，送目感離羣。"]'),
('67775d6f-907c-4063-963d-56090b06a91e','燈花','劉敞','宋','宋诗','song-poetry','','[]','寒燈不及鄰，花艷競爭新。',48,'全唐诗/poet.song.27000.json','["寒燈不及鄰，花艷競爭新。", "重疊芝三秀，分明桂半輪。", "東風誰變律，芳意自驚春。", "流玩堪通夕，長眉莫效顰。"]'),
('320df4af-0621-458b-91b2-b893aaf226b9','王秀才自蜀之京留月餘歸南都','劉敞','宋','宋诗','song-poetry','','[]','相逢暫相會，又向睢陽行。',48,'全唐诗/poet.song.27000.json','["相逢暫相會，又向睢陽行。", "險夢尚存蜀，緇衣空厭京。", "故園見樹喜，舊友出郊迎。", "幸去君家近，飛鴻時寄聲。"]'),
('b538be5e-0c7a-4243-bb92-d9c630694275','哀王十三都官','劉敞','宋','宋诗','song-poetry','','[]','把臂猶昨日，如何長不歸。',48,'全唐诗/poet.song.27000.json','["把臂猶昨日，如何長不歸。", "賓天亦有似，招隱固疑非。", "玉折謝庭樹，綵餘萊子衣。", "永懷想平昔，涕下不能揮。"]'),
('d9d7306c-f1b9-45ec-aedd-c8ad7298bcc7','始秋二首  其一','劉敞','宋','宋诗','song-poetry','','[]','暑兼流火逝，秋共北風迴。',48,'全唐诗/poet.song.27000.json','["暑兼流火逝，秋共北風迴。", "歲晏蒹葭色，宵征蟀蟋哀。", "平分感搖落，留滯悵徘徊。", "知負滄洲約，枯槎八月來。"]'),
('1f5562c8-732b-4c34-85b6-15392ab86e6e','始秋二首  其二','劉敞','宋','宋诗','song-poetry','','[]','秋色忽已改，旅程殊未央。',48,'全唐诗/poet.song.27000.json','["秋色忽已改，旅程殊未央。", "水雲含變態，山雨送凄凉。", "杳杳青楓暮，菲菲白芷香。", "多才悲宋屈，搖落近滄浪。"]'),
('9175ae3d-1fb8-4192-83cd-0d12354df1a3','送張器判官','劉敞','宋','宋诗','song-poetry','','[]','王國推多士，聞名二十年。',48,'全唐诗/poet.song.27000.json','["王國推多士，聞名二十年。", "白頭傾敝蓋，珠履尚賓筵。", "禮樂期先進，功名望昔賢。", "激昂知己晚，意氣歘飄然。"]'),
('64cbbb92-e934-49c9-b7f2-d8e067393bbf','隱直感秋思南游予欲北還未得','劉敞','宋','宋诗','song-poetry','','[]','櫪馬常嘶北，邊鴻郤願南。',48,'全唐诗/poet.song.27000.json','["櫪馬常嘶北，邊鴻郤願南。", "一時秋氣感，兩地物情諳。", "俗怪玄尚白，自疑青出藍。", "何當鹿門隱，數就德公談。"]'),
('491a5928-5c9f-4557-85cc-51dc624fa156','始聞鴈','劉敞','宋','宋诗','song-poetry','','[]','長風送羽翼，千里逐陽和。',48,'全唐诗/poet.song.27000.json','["長風送羽翼，千里逐陽和。", "朔漠應飛雪，江湖始見波。", "識時機不淺，愁旅叫空多。", "勿以稻梁故，早飛乘網羅。"]'),
('a9ff4a44-cab2-4a19-86e5-1a24fc1628a7','府公說牡丹盛開是日逼晚意不及觀','劉敞','宋','宋诗','song-poetry','','[]','落日含明艶，輕風襲煖香。',48,'全唐诗/poet.song.27000.json','["落日含明艶，輕風襲煖香。", "傳聞亂人意，相見弄春光。", "醉裏歲空晏，愁中夜未央。", "異時驚麗絕，秉燭正難忘。"]'),
('d71b70e8-f072-4c84-b359-cadc22893326','與楊十二廷評同登城東門','劉敞','宋','宋诗','song-poetry','','[]','綠樹浮萍合，青山畫障開。',48,'全唐诗/poet.song.27000.json','["綠樹浮萍合，青山畫障開。", "登臨共今古，壯觀雜歡哀。", "長日消棋局，微風引酒杯。", "浮雲滿西北，容易雨飛來。"]'),
('53561435-a0ad-4d4d-af2a-615254602139','春暮聞鶯','劉敞','宋','宋诗','song-poetry','','[]','醉裏春空盡，江邊客未歸。',48,'全唐诗/poet.song.27000.json','["醉裏春空盡，江邊客未歸。", "可憐鳴晛晥，似欲訴芳菲。", "珍樹移時語，殘花入眼稀。", "離居亦幽獨，求友莫相違。"]'),
('28418c3b-4a28-4865-8888-41b7f5c85fce','除日雪','劉敞','宋','宋诗','song-poetry','','[]','迎年椒獻頌，駐臘雪留寒。',48,'全唐诗/poet.song.27000.json','["迎年椒獻頌，駐臘雪留寒。", "偏坐春華早，微增暮景寛。", "瓊瑤九城闕，玉帛萬衣冠。", "欲書甘泉會，他時盛暑看。"]'),
('69fe9227-8884-4a54-bcd4-d97c49f4489f','秋鶯','劉敞','宋','宋诗','song-poetry','','[]','高舉慕求友，翩然辭谷中。',48,'全唐诗/poet.song.27000.json','["高舉慕求友，翩然辭谷中。", "那知改春序，又復到秋風。", "節物感歸燕，異聲嗟遠鴻。", "歸非今正好，霜露脱梧桐。"]'),
('6fd8e1bc-6071-4b23-ae87-dbbaf15233d4','凉夜露卧','劉敞','宋','宋诗','song-poetry','','[]','風露清相襲，銀河湛不流。',48,'全唐诗/poet.song.27000.json','["風露清相襲，銀河湛不流。", "澄輝亦終夕，爽氣特先秋。", "高臥自微尚，冥煩嗟倦游。", "不眠計萬事，出處竟悠悠。"]'),
('caa705c5-07c1-4cba-b9b9-6f5222ead59d','空釣得魚','劉敞','宋','宋诗','song-poetry','','[]','持鈎非有釣，吾猶臧丈人。',48,'全唐诗/poet.song.27000.json','["持鈎非有釣，吾猶臧丈人。", "何知引纖繭，忽復得潛鱗。", "獨樂意逾適，儻來情亦真。", "君看渭旁叟，八十老垂綸。"]'),
('547255f8-4b4e-4324-9246-a93b9a78a2b3','秋月','劉敞','宋','宋诗','song-poetry','','[]','蟾光瑩碧墀，天色凍琉璃。',48,'全唐诗/poet.song.27000.json','["蟾光瑩碧墀，天色凍琉璃。", "市響新晴後，風和欲暖時。", "杉松冷岑寂，樓殿黑参差。", "静者非無趣，長吹遺所思。"]'),
('99045ccf-bd87-4201-b9f2-34d01ef9cf91','月夜二首  其一','劉敞','宋','宋诗','song-poetry','','[]','月出浮雲盡，風生中夜清。',48,'全唐诗/poet.song.27000.json','["月出浮雲盡，風生中夜清。", "星辰競搖動，河漢湛虚明。", "老樹稀疏影，驚禽斷續聲。", "秋懷先已亂，蟋蟀更宵征。"]'),
('1defc89d-4d8b-46fd-b0b4-3911ab7ba026','月夜二首  其二','劉敞','宋','宋诗','song-poetry','','[]','涼月含秋色，江天復雨晴。',48,'全唐诗/poet.song.27000.json','["涼月含秋色，江天復雨晴。", "風雪異明滅，河漢亦凄清。", "驚鵲時翻樹，悲笳遠過城。", "不眠看列宿，磊落背人傾。"]'),
('17808b71-eedf-4063-be3d-8218bcd11cf9','送同年王殿丞知鄞縣','劉敞','宋','宋诗','song-poetry','','[]','同日大梁客，共登青雲梯。',48,'全唐诗/poet.song.27000.json','["同日大梁客，共登青雲梯。", "逢時方躍馬，從政暫驅鷄。", "萬水會東海，干巖開郯溪。", "遠游觀益壯，肯爲簿書迷。"]'),
('965906bd-4f5e-4065-adfd-ee3bcd83acbc','風雨','劉敞','宋','宋诗','song-poetry','','[]','園林自有主，風雨苦無情。',48,'全唐诗/poet.song.27000.json','["園林自有主，風雨苦無情。", "密葉枝枝綠，飛花片片輕。", "眼看春不住，醉任酒頻傾。", "何處鶯求友，時聞囀一聲。"]'),
('94d083aa-e4dd-4fb5-ae37-b6510ed6647b','送汝南張秘校及第後之官','劉敞','宋','宋诗','song-poetry','','[]','從我陳蔡者，憐君不及門。',48,'全唐诗/poet.song.27000.json','["從我陳蔡者，憐君不及門。", "青雲期自致，鳴鶴果孤鶱。", "仕道半綸重，及親三釜尊。", "因聲謝汝士，爲喜月告存。"]'),
('57d8c842-bb4f-4f5d-93fc-25cf8498ba22','戯呈府公','劉敞','宋','宋诗','song-poetry','','[]','殘春亦無幾，短夜不須眠。',48,'全唐诗/poet.song.27000.json','["殘春亦無幾，短夜不須眠。", "翠幕深燈燭，清風引管絃。", "詼諧玩兹世，醉倒忘吾年。", "不作方外趣，安知濠上賢。"]'),
('57ca81c0-6bdf-439b-847b-1e33d22aeb71','度支蘇員外才翁挽歌二首  其一','劉敞','宋','宋诗','song-poetry','','[]','湖海青雲士，元龍如古人。',48,'全唐诗/poet.song.27000.json','["湖海青雲士，元龍如古人。", "草書到聖地，詞學洎天倫。", "零落風流盡，平生意氣親。", "空存華屋處，寂寞已埃塵。"]'),
('d7e1c995-53a9-43d4-a64a-90be0a18a89d','度支蘇員外才翁挽歌二首  其二','劉敞','宋','宋诗','song-poetry','','[]','愛客毎傾蓋，傳家能象賢。',48,'全唐诗/poet.song.27000.json','["愛客毎傾蓋，傳家能象賢。", "猶多嫌白眼，自不廢青氈。", "吏隱如他日，郎潛遂幾年。", "人琴俱已矣，情至一潸然。"]'),
('a3e8c552-52fe-4870-9e36-e885a4c1c2dd','挽宋道中詞','劉敞','宋','宋诗','song-poetry','','[]','交游日零落，之子復云亡。',48,'全唐诗/poet.song.27000.json','["交游日零落，之子復云亡。", "常恨神鋒雋，端成中道傷。", "文章不用世，詞賜僅爲郎。", "名士如君輩，風流豈易忘。"]'),
('f42e7864-d8c2-4177-a641-90c853d7bc65','吳侍郎挽詞二首  其一','劉敞','宋','宋诗','song-poetry','','[]','高第賢良策，朝廷擢季功。',48,'全唐诗/poet.song.27000.json','["高第賢良策，朝廷擢季功。", "固疑多直諌，不得久居中。", "長嘯臨邊月，孤飛避遠鴻。", "盤桓周召際，重見二南風。"]'),
('f1b0506b-c316-4df9-8743-da233336553f','吳侍郎挽詞二首  其二','劉敞','宋','宋诗','song-poetry','','[]','臨汝休車騎，治中愧後門。',48,'全唐诗/poet.song.27000.json','["臨汝休車騎，治中愧後門。", "平生一傾蓋，談笑極忘言。", "契闊聲塵遠，差池歲月奔。", "匣中寶刀贈，知辱故交恩。"]'),
('d4f3b36d-51a1-46b1-89a4-d74e8a4c1c74','與黄寺丞卜鄰','劉敞','宋','宋诗','song-poetry','','[]','卜居先卜鄰，相望成相親。',48,'全唐诗/poet.song.27000.json','["卜居先卜鄰，相望成相親。", "無復羈旅恨，况逢性情真。", "食薇亦自足，傾蓋不爲新。", "杖屨通阡陌，誰能倦角巾。"]'),
('28d266cf-8ac5-448a-a137-92c3f8f2ad66','聞徙關中兵備河東','劉敞','宋','宋诗','song-poetry','','[]','胡兵絕當路，戍卒下河源。',48,'全唐诗/poet.song.27000.json','["胡兵絕當路，戍卒下河源。", "烽火飛狐口，旌旗積鴈門。", "和親固下策，薄伐本中原。", "誰斷匈奴臂，非無國士恩。"]'),
('ef0d0d86-75db-4733-8ad1-f3b21d51a552','立冬後風雨','劉敞','宋','宋诗','song-poetry','','[]','冷雨欲成雪，高風催過雲。',48,'全唐诗/poet.song.27000.json','["冷雨欲成雪，高風催過雲。", "流光隨衮衮，吹蘀共紛紛。", "此去天地閉，向來金石焚。", "敝貂寧獨恨，四序欲平分。"]'),
('f30a8cba-8cc7-4d52-9188-ba6db48150ca','别西掖手種小梧桐贈三閣老','劉敞','宋','宋诗','song-poetry','','[]','亭亭高未足，玩玩意空深。',48,'全唐诗/poet.song.27000.json','["亭亭高未足，玩玩意空深。", "頗似少陵叟，能留一院陰。", "幸今長勿翦，無用晚知音。", "莫作吳儂態，翻從爨下尋。"]'),
('fd5ddc5c-0805-4dab-87ad-7ec9389aa011','西風','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西風木葉下，遠想洞庭秋。',48,'全唐诗/poet.song.27000.json','["西風木葉下，遠想洞庭秋。", "物色摧年老，天時助客愁。", "李衡千樹橘，張翰一漁舟。", "亦自人間樂，功名安足謀。"]'),
('7792a07b-9229-4ba6-8814-34a162766283','北風','劉敞','宋','宋诗','song-poetry','','[]','北風動江海，飛雨濕清秋。',48,'全唐诗/poet.song.27000.json','["北風動江海，飛雨濕清秋。", "蝉噪曾何急，猿啼不自愁。", "冥冥高葉下，莽莽亂雲浮。", "正復開人意，披襟百尺樓。"]'),
('8f0bbd02-8c08-42c5-94a0-c2bd996a3232','盗賊','劉敞','宋','宋诗','song-poetry','','[]','村落枹鼓起，城樓刁斗頻。',48,'全唐诗/poet.song.27000.json','["村落枹鼓起，城樓刁斗頻。", "畏塗深虎豹，行路入荆榛。", "故老人人怨，烽烟處處新。", "桃源容客棹，屬意武陵春。"]'),
('93ee7904-9d5d-4eea-ae05-bd3634dce17d','風雨','劉敞','宋','宋诗','song-poetry','','[]','春光從此半，無復强淹留。',48,'全唐诗/poet.song.27000.json','["春光從此半，無復强淹留。", "風雨仍何急，鶯花各自愁。", "登臨非故土，搖落自清秋。", "物物驚人眼，應須與醉謀。"]'),
('b5c7757d-d09b-4692-bd28-827321c6304c','黛陀石馬蹄硯','劉敞','宋','宋诗','song-poetry','','[]','一片蒼山石，遙憐巧匠心。',48,'全唐诗/poet.song.27000.json','["一片蒼山石，遙憐巧匠心。", "能存辟雍法，宛是褭啼金。", "氣奪秋雲濕，光含墨海深。", "魚龍隨醉筆，變化出幽岑。"]'),
('fde5876e-9959-4525-934b-553beca86fbe','離鄂州至漢陽','劉敞','宋','宋诗','song-poetry','','[]','小郡緣山腹，孤城闇夕楓。',48,'全唐诗/poet.song.27000.json','["小郡緣山腹，孤城闇夕楓。", "蛟龍戯霧雨，鼓角亂西東。", "江漢浮南紀，秋冬擬緒風。", "離騷楚人恨，過半夕陽中。"]'),
('6586e61a-5195-42d7-8e5c-a6ec330ece5a','初冬','劉敞','宋','宋诗','song-poetry','','[]','陽光轉南極，漸喜入吾廬。',48,'全唐诗/poet.song.27000.json','["陽光轉南極，漸喜入吾廬。", "物色經霜後，雲容欲雪初。", "嚴風動枯槁，凛氣益蕭疏。", "何日陽春筦，潛興冰下魚。"]'),
('9b9a040a-b19c-42e3-902c-f8aef6623cee','三月九日過正衙','劉敞','宋','宋诗','song-poetry','','[]','去事駒過隙，此身江載萍。',48,'全唐诗/poet.song.27000.json','["去事駒過隙，此身江載萍。", "赤墀容再謁，清涕忽雙零。", "海鳥眩韶舞，天潢愁客星。", "平生鴻鵠志，獨有去冥冥。"]'),
('99c58c51-fa72-425f-9310-78a98cda8da2','病中辱聖從龍圖侍郎見訪聞便赴西州不及款曲偶成五言奉呈','劉敞','宋','宋诗','song-poetry','','[]','衰病淹歲晚，分飛愁遠行。',48,'全唐诗/poet.song.27000.json','["衰病淹歲晚，分飛愁遠行。", "能回長者轍，因見故人情。", "後會知何地，相看疑此生。", "不爲習鑿齒，應作左丘明。"]'),
('a0b4bd48-6e8a-4e74-bb09-01db9719c4cb','君章見過','劉敞','宋','宋诗','song-poetry','','[]','衡門入秋草，幽獨得棲遲。',48,'全唐诗/poet.song.27000.json','["衡門入秋草，幽獨得棲遲。", "車馬來何屢，樵蘇不自期。", "書成玄尚白，衣敝素爲緇。", "予亦貧非病，君應信所爲。"]'),
('356987c4-cea6-4687-bae2-a0de75079141','鄰幾君章見過','劉敞','宋','宋诗','song-poetry','','[]','兩君共羈旅，三徑肯淹留。',48,'全唐诗/poet.song.27000.json','["兩君共羈旅，三徑肯淹留。", "秀色映凉月，清風生早秋。", "樵蘇亦不爨，樽酒自相酬。", "歡然夜遂永，河漢西南流。"]'),
('a5e1e960-80ee-420d-8749-0fadabf8ba71','新燕','劉敞','宋','宋诗','song-poetry','','[]','無奈春還老，秪看燕復來。',48,'全唐诗/poet.song.27000.json','["無奈春還老，秪看燕復來。", "凌風舞輕健，盡日語徘徊。", "久客宜相識，重簾爲爾開。", "畏人俱混俗，出處免沈猜。"]'),
('216e5c84-827d-493f-b239-823c5d712bad','馴燕','劉敞','宋','宋诗','song-poetry','','[]','非無鷹隼慮，自識主人歸。',48,'全唐诗/poet.song.27000.json','["非無鷹隼慮，自識主人歸。", "立語移窗日，翻飛試羽衣。", "江湖萬里闊，天地一身微。", "不作驚鷗别，何須强察機。"]'),
('3ce39491-b2b2-41d5-9eb4-04223aacfa15','雨中出城行汝水上','劉敞','宋','宋诗','song-poetry','','[]','東野宜獨往，此中如舊溪。',48,'全唐诗/poet.song.27000.json','["東野宜獨往，此中如舊溪。", "好風凉送雨，流水碧循堤。", "樹密扶行蓋，沙平印馬啼。", "城樓隔雲霧，歸路欲全迷。"]'),
('bd35cbf8-d43c-4152-b617-8ddf90d13ee1','次韻奉和鄰幾汎汝水作','劉敞','宋','宋诗','song-poetry','','[]','少濯滄浪水，成君真隱高。',48,'全唐诗/poet.song.27000.json','["少濯滄浪水，成君真隱高。", "虚舟姿上下，樽酒寄遊遨。", "静境惬外奨，緩歌忘我勞。", "興餘可逕返，落日麗平臯。"]'),
('5c0e0391-23ed-4c9a-92a6-1f67707fff95','西浦阻雨','劉敞','宋','宋诗','song-poetry','','[]','黑雲連海面，急雨漲淮潮。',48,'全唐诗/poet.song.27000.json','["黑雲連海面，急雨漲淮潮。", "稍稍州渚沒，昏昏城郭遙。", "畏塗仗忠信，高舉幸扶搖。", "不作圖南興，誰當慰寂寥。"]'),
('debc9063-7f69-48bb-8ffc-0606df30516d','黑雲','劉敞','宋','宋诗','song-poetry','','[]','屯雲望如墨，萬里横空浮。',48,'全唐诗/poet.song.27000.json','["屯雲望如墨，萬里横空浮。", "白日變玄夜，朱明成素秋。", "疾風動屋瓦，急雨落河流。", "俯仰駭神化，精微難與謀。"]'),
('f2bc8dc0-98e8-4f59-a237-90f8656f9191','傷梅公異二首  其一','劉敞','宋','宋诗','song-poetry','','[]','已矣梅公異，鄉庠漫貢生。',48,'全唐诗/poet.song.27000.json','["已矣梅公異，鄉庠漫貢生。", "竟無楊得意，終失馬相如。", "道德生何負，心懷死不攄。", "新墳帝城外，贈淚獨沾裾。"]'),
('cbc22ec6-376e-4502-9135-7429d44b18cd','傷梅公異二首  其二','劉敞','宋','宋诗','song-poetry','','[]','刻苦身常病，憂愁壽易侵。',48,'全唐诗/poet.song.27000.json','["刻苦身常病，憂愁壽易侵。", "空令武子死，誰聽伯牙琴。", "寥落書盈篋，肅條風滿林。", "惟應都下士，能記洛生吟。"]'),
('32e3be67-1180-4930-bb8f-4db88091b8f1','傷胡二湘','劉敞','宋','宋诗','song-poetry','','[]','知心不易得，此别定終天。',48,'全唐诗/poet.song.27000.json','["知心不易得，此别定終天。", "自古皆有死，夫君獨少年。", "論文真已矣，揮涕默澘然。", "會有清琴在，祗應永絕絃。"]'),
('2ee2a933-9717-46a6-ae56-a06cdc0e976a','閔雨','劉敞','宋','宋诗','song-poetry','','[]','膚寸無時合，昭回此夜逢。',48,'全唐诗/poet.song.27000.json','["膚寸無時合，昭回此夜逢。", "春秋還閔雨，郡國共憂農。", "詞欲讒風伯，書將詰亂龍。", "關西兵税急，懼失萬餘鍾。"]'),
('cc339bde-2d59-45f7-8982-d3b88bc9a738','寄江東弟兄二首  其一','劉敞','宋','宋诗','song-poetry','','[]','分手如昨日，清秋獨異鄉。',48,'全唐诗/poet.song.27000.json','["分手如昨日，清秋獨異鄉。", "長年悲落木，短髪怯初涼。", "歸燕自有適，幽蘭誰爲芳。", "裁書寄鴻鴈，相與訪滄浪。"]'),
('fcbcf91b-381e-4846-951a-8e717921cddd','寄江東弟兄二首  其二','劉敞','宋','宋诗','song-poetry','','[]','卻埽與人絕，悲秋驚歲徂。',48,'全唐诗/poet.song.27000.json','["卻埽與人絕，悲秋驚歲徂。", "山川舉俗異，宇宙此身孤。", "弔影臨清月，書空向瞑烏。", "懷歸屬吾黨，浮海待乘桴。"]'),
('e3cf22f5-fa7c-4ff8-a238-88d1cc993ee9','薦福寺竹亭','劉敞','宋','宋诗','song-poetry','','[]','兹亭四時好，秀色映長松。',48,'全唐诗/poet.song.27000.json','["兹亭四時好，秀色映長松。", "静境非千畝，幽人如素封。", "吹聲偏洗耳，暑晝亦成冬。", "暫到還忘返，心知叔夜慵。"]'),
('a18029a9-2a36-406a-9921-7b5312ad4e5c','觀陜西圖二首  其一','劉敞','宋','宋诗','song-poetry','','[]','險固非天意，承平怪主憂。',48,'全唐诗/poet.song.27000.json','["險固非天意，承平怪主憂。", "三年勞將帥，萬里問旃裘。", "尚記安西道，空悲定遠侯。", "大河知所向，日夜正東流。"]'),
('0175ed86-16e5-4401-977e-daabbd0ee8b1','觀陜西圖二首  其二','劉敞','宋','宋诗','song-poetry','','[]','憶昨傳消息，羌來渭水旁。',48,'全唐诗/poet.song.27000.json','["憶昨傳消息，羌來渭水旁。", "信知秦地險，未覺漢兵强。", "青海通西域，長城起朔方。", "分明見地里，悵望隔要荒。"]'),
('8b7bde09-dc42-4d79-86a3-cbf13ae22f5c','送張六','劉敞','宋','宋诗','song-poetry','','[]','將漕煩明府，東遊慰越吟。',48,'全唐诗/poet.song.27000.json','["將漕煩明府，東遊慰越吟。", "斲冰雖楚水，乘興即山陰。", "去去陶嘉月，悠悠見子衿。", "因君倚城關，送目亂愁心。"]'),
('c086d3f6-6c90-4ee2-9087-270d5ae20733','送楊慥','劉敞','宋','宋诗','song-poetry','','[]','著書非白首，待詔已公車。',48,'全唐诗/poet.song.27000.json','["著書非白首，待詔已公車。", "試吏何用喜，慰親聊自如。", "還從近關出，稍與京塵疏。", "豈謂三年久，君方就子虚。"]'),
('8a65f619-3c7e-4a98-8fb2-9a2b48f97b30','送范貫之','劉敞','宋','宋诗','song-poetry','','[]','范叔貧如此，誰當與敝袍。',48,'全唐诗/poet.song.27000.json','["范叔貧如此，誰當與敝袍。", "哀歌困牛角，異味笑鄉豪。", "相得空長鋏，徒歸欲二毛。", "多慚訪夷節，無以慰滔滔。"]'),
('1c35d0ec-bd93-41f1-833c-d2c0c81d2173','送隱直','劉敞','宋','宋诗','song-poetry','','[]','久客意無賴，送歸私自憐。',48,'全唐诗/poet.song.27000.json','["久客意無賴，送歸私自憐。", "悠悠想行路，苒苒背流年。", "雪過兔園少，春歸楚澤偏。", "君應解冠冕，笑傲辟人賢。"]'),
('84c084d7-841f-46a8-9b20-2ed8ae6f6eb0','送衛州賈雲卿','劉敞','宋','宋诗','song-poetry','','[]','淇奥文雅地，相門英妙才。',48,'全唐诗/poet.song.27000.json','["淇奥文雅地，相門英妙才。", "春風萬人喜，都城千騎來。", "嘯激鸞鳯響，歌傳松柏哀。", "懷賢復訪古，處處爲徘徊。"]'),
('d8a63d5f-9f61-45ff-b64e-cf9097dd8288','送史館齊學士知荆南唐相映之孫有權文公行修國史制書在','劉敞','宋','宋诗','song-poetry','','[]','間代唐丞相，當時太史公。',48,'全唐诗/poet.song.27000.json','["間代唐丞相，當時太史公。", "白麻存舊物，青簡見遺風。", "鳴玉蓬丘峻，專城楚澤雄。", "由來稽古力，肯效一經窮。"]'),
('08ec8aa1-b0b3-4e7c-86fe-eb2f2a410a3e','近無西事消息','劉敞','宋','宋诗','song-poetry','','[]','此心除國讎，安得借前籌。',48,'全唐诗/poet.song.27000.json','["此心除國讎，安得借前籌。", "未報將軍捷，空增壯士憂。", "誰能占太白，試爲上高樓。", "自恐匣中劍，精光犯斗牛。"]'),
('e14b3863-c86e-40c1-a85b-bc283abefdfc','細雨','劉敞','宋','宋诗','song-poetry','','[]','細雨春城暗，空郊草色微。',48,'全唐诗/poet.song.27000.json','["細雨春城暗，空郊草色微。", "峽雲朝復暮，沙燕語還飛。", "柳帯柔堪結，梅香冷漸稀。", "旅遊時畏失，數醉得忘歸。"]'),
('f0b67b13-6d20-4ff2-86fd-d9057ed62f36','小雨四首  其一','劉敞','宋','宋诗','song-poetry','','[]','微風載雲起，好雨與風俱。',48,'全唐诗/poet.song.27000.json','["微風載雲起，好雨與風俱。", "暝色經時合，凉聲入夜疏。", "炎蒸暫灑埽，天事有驅除。", "倦客倚危枕，明燈照舊書。"]'),
('da9eda30-6124-48d1-a67c-a2768575b6f8','小雨四首  其二','劉敞','宋','宋诗','song-poetry','','[]','泱漭輕雲濕，飄瀟晝雨來。',48,'全唐诗/poet.song.27000.json','["泱漭輕雲濕，飄瀟晝雨來。", "稍霑飛絮重，競逼柳花開。", "江面春陰闊，天涯暮色催。", "郢中詞客意，最識楚王臺。"]'),
('98a1665e-33bc-4569-96c3-df2a37d83998','小雨四首  其三','劉敞','宋','宋诗','song-poetry','','[]','漠漠雲蒸柱，蕭蕭雨過城。',48,'全唐诗/poet.song.27000.json','["漠漠雲蒸柱，蕭蕭雨過城。", "不時變炎景，竟日度秋聲。", "灑濯林光淨，歸飛燕羽輕。", "野夫學爲圃，因欲事躬耕。"]'),
('86fa7534-1ecc-4d8e-a769-f7019f410689','小雨四首  其四','劉敞','宋','宋诗','song-poetry','','[]','春城頻過雨，一望一增新。',48,'全唐诗/poet.song.27000.json','["春城頻過雨，一望一增新。", "欲曉雲成錦，初晴草似茵。", "和聲散喧鳥，芳意屬游人。", "向晚車馬息，東風吹暗塵。"]'),
('d759004b-3ebb-471e-9257-10f12426c493','喜從兄自京回','劉敞','宋','宋诗','song-poetry','','[]','曾作東都賦，無人與共論。',48,'全唐诗/poet.song.27000.json','["曾作東都賦，無人與共論。", "欣逢京輦客，仍是鶺鴒原。", "耳接天韶盛，塵棲素袂昏。", "秋風江海上，歸夢入夷門。"]'),
('a9640f23-97fd-452f-a702-7f55b63d4710','秋晴西樓','劉敞','宋','宋诗','song-poetry','','[]','清風卷氛翳，廣野露秋毫。',48,'全唐诗/poet.song.27000.json','["清風卷氛翳，廣野露秋毫。", "木落山覺瘦，雨晴天似高。", "開窗置樽酒，看月湧江濤。", "高卧淹湖海，非關氣獨豪。"]'),
('9f67b4cb-7ec2-45a3-8bb2-4eb6c47fd7d8','春日樓上二首  其一','劉敞','宋','宋诗','song-poetry','','[]','春流抱城郭，暖色媚樓臺。',48,'全唐诗/poet.song.27000.json','["春流抱城郭，暖色媚樓臺。", "麥秀聞雉雊，鸛鳴知雨來。", "浮煙著垂柳，晴雪落新梅。", "此地春愁闊，無人共一杯。"]'),
('a60ca734-e2f1-4a82-9827-f6361ada4666','春日樓上二首  其二','劉敞','宋','宋诗','song-poetry','','[]','躍魚依暖景，歸鴈逐輕風。',48,'全唐诗/poet.song.27000.json','["躍魚依暖景，歸鴈逐輕風。", "隔水麥苗綠，入簷花蕚紅。", "郊原共欎欎，雲日故融融。", "醉眼傷千里，非關江上風。"]'),
('8902291d-84a2-46bb-9350-28f237f15a9b','醉後','劉敞','宋','宋诗','song-poetry','','[]','舉眼醉向晚，甘心醒似狂。',48,'全唐诗/poet.song.27000.json','["舉眼醉向晚，甘心醒似狂。", "形骸隨酩酊，談笑助軒昂。", "舞袖翻宜窄，歌聲不厭長。", "高城湧明月，風景正虚涼。"]'),
('ce29349f-d699-4991-a424-4ba05091e04b','樹陰偶坐','劉敞','宋','宋诗','song-poetry','','[]','朝陽送微暖，晴靄入寒空。',48,'全唐诗/poet.song.27000.json','["朝陽送微暖，晴靄入寒空。", "負暄春盎盎，探策樂融融。", "松下坐忘返，樹端遙見紅。", "喟然感時節，舉酒屬鄰翁。"]'),
('68904ed9-c4a3-485a-a224-9731a2d7733b','春陰','劉敞','宋','宋诗','song-poetry','','[]','江上浮雲聚，城中暮景兼。',48,'全唐诗/poet.song.27000.json','["江上浮雲聚，城中暮景兼。", "東風酒味溢，小雨客愁添。", "寒色端侵牖，斜陽不滿簾。", "滯留成楚老，卑濕意無嫌。"]'),
('234a8a22-2698-4271-b745-2bc0fa3fe37c','雨後小亭','劉敞','宋','宋诗','song-poetry','','[]','疏雨纔能潤，微風未肯凉。',48,'全唐诗/poet.song.27000.json','["疏雨纔能潤，微風未肯凉。", "低松無限碧，白芷可憐香。", "埽榻從高卧，歸禽不亂行。", "悠悠對老圃，幾與爾俱忘。"]'),
('2a421eb1-ed14-4cb3-8708-0ac6d70d9579','同伯鎮寄贈北都定雅禪師','劉敞','宋','宋诗','song-poetry','','[]','逍遙方外禪，宴坐不知年。',48,'全唐诗/poet.song.27000.json','["逍遙方外禪，宴坐不知年。", "合抱平生柏，成區社長蓮。", "公卿盡隨喜，語默兩忘筌。", "聞有詩三百，無由一一弦。"]'),
('11d1ab5e-f5c1-4cd2-987c-d74319ef5bf6','夜坐因讀隱直書寄之','劉敞','宋','宋诗','song-poetry','','[]','徂歲曾何急，清宵不復長。',48,'全唐诗/poet.song.27000.json','["徂歲曾何急，清宵不復長。", "蹉跎問甲子，愁寂看燈光。", "峽雨蕭蕭冷，江雲澹澹黄。", "殷勤故人别，容易二年彊。"]'),
('c9614fb4-2bb6-4c3c-9f7c-08ea3f5d0003','和孫監丞送書生南游','劉敞','宋','宋诗','song-poetry','','[]','歷國向七十，滔滔何日還。',48,'全唐诗/poet.song.27000.json','["歷國向七十，滔滔何日還。", "輕賫一劍在，壯節二毛斑。", "浮俗風波裏，高情天地間。", "滯留多愠見，送遠愧登山。"]'),
('b75bcf91-7cbe-4fef-8d01-6054fe6ceacd','夏寒','劉敞','宋','宋诗','song-poetry','','[]','冥冥梅送雨，椮椮麥迎秋。',48,'全唐诗/poet.song.27000.json','["冥冥梅送雨，椮椮麥迎秋。", "四月應徂暑，南方復重裘。", "崑崙搖地軸，渤海漲河流。", "天事無端錯，民生若許愁。"]'),
('72549850-f378-48ba-92ed-f9e83debcb6a','同黄子温小寒','劉敞','宋','宋诗','song-poetry','','[]','陰老疑龍戰，風高怯海飛。',48,'全唐诗/poet.song.27000.json','["陰老疑龍戰，風高怯海飛。", "枯蓬不自息，歸鳥競相依。", "時節驚流水，生涯託墐扉。", "哀歌向妻子，吾道亦牛衣。"]'),
('15f423e5-812e-4217-a435-f0345700d245','晨至西陽池示同行','劉敞','宋','宋诗','song-poetry','','[]','風定水逾静，雨收天倍高。',48,'全唐诗/poet.song.27000.json','["風定水逾静，雨收天倍高。", "分明寫冰鑑，深淺露秋毫。", "車馬情頗厭，山林心正勞。", "觀魚近至樂，相與更臨濠。"]'),
('72a1bef8-504a-4216-8067-0e02c11cc2c3','又過西陽池','劉敞','宋','宋诗','song-poetry','','[]','役役輕日月，回回分簿書。',48,'全唐诗/poet.song.27000.json','["役役輕日月，回回分簿書。", "悵然面止水，樂矣羡游魚。", "鷗鳥舞迎客，江湖興起予。", "顧邀二三子，退食未宜疏。"]'),
('1cb55fc9-e890-42de-94a5-e7d750a6fd17','送信陽舒使君','劉敞','宋','宋诗','song-poetry','','[]','聞名自夙昔，已作舊相知。',48,'全唐诗/poet.song.27000.json','["聞名自夙昔，已作舊相知。", "傾蓋成邂逅，如何還别離。", "軍聲咽鼓角，行色滿旌麾。", "莫怪樽前醉，親鄰心所期。"]'),
('ab7a0e77-0e87-403b-93a4-e89ba47557b2','送南儀守黄中允','劉敞','宋','宋诗','song-poetry','','[]','十年幕中客，萬里海南州。',48,'全唐诗/poet.song.27000.json','["十年幕中客，萬里海南州。", "命服仍朱紱，夸鄉未白頭。", "山城時晝黑，嶺水或西流。", "問道林多桂，王孫莫自留。"]'),
('7e387927-db30-4f42-a082-7765435d233c','和閻工部新作西齋','劉敞','宋','宋诗','song-poetry','','[]','逍遙不期遠，趣足外囂塵。',48,'全唐诗/poet.song.27000.json','["逍遙不期遠，趣足外囂塵。", "誰謂持斧客，翻同高卧人。", "江蘆烟葉重，巖菊露香勻。", "愛惜凌寒意，留歡過小春。"]'),
('39885b5e-e1fb-4844-b13a-d33f743417cf','次韻王寺丞北城','劉敞','宋','宋诗','song-poetry','','[]','專城空歲月，報國愧纖毫。',48,'全唐诗/poet.song.27000.json','["專城空歲月，報國愧纖毫。", "幸及農功暇，初成壁壘高。", "飛翬鄰雉堞，縈帯俯魚濠。", "與聽輿人誦，無令板築勞。"]'),
('a66fb750-ba06-43a0-bee3-1dc708e8fdb1','同年陳君制策高第改佐著作東還餘杭作五言送行兼寄彦猷閣老使君二兄','劉敞','宋','宋诗','song-poetry','','[]','江海一遠别，見君金馬門。',48,'全唐诗/poet.song.27000.json','["江海一遠别，見君金馬門。", "先鳴二三子，强著五千言。", "清望開中秘，英辭動至尊。", "薦賢受上賞，時論重西垣。"]'),
('19a9c2c7-cadd-4869-96e5-b874f5bbe8c9','興慶池送客','劉敞','宋','宋诗','song-poetry','','[]','紅蕖千頃合，碧樹百年藤。',48,'全唐诗/poet.song.27000.json','["紅蕖千頃合，碧樹百年藤。", "長日宜沿泝，清風破欎蒸。", "别離情易惡，衰老醉那能。", "還望邯鄲道，悲歌不自勝。"]'),
('b3411da5-1383-4b11-aba8-5c1d939756e1','立春日齋祠畢還過金明池寄永叔','劉敞','宋','宋诗','song-poetry','','[]','宿雨原野潤，朝雲宫殿明。',48,'全唐诗/poet.song.27000.json','["宿雨原野潤，朝雲宫殿明。", "東風未半日，佳氣滿重城。", "渙渙泉披凍，欣欣木向榮。", "江頭景如此，公起探春晴。"]'),
('b31d2815-a6bb-4319-a60b-f7fd9c73da28','送次子敏歸河陰','劉敞','宋','宋诗','song-poetry','','[]','表裏山河險，成皋廣武間。',48,'全唐诗/poet.song.27000.json','["表裏山河險，成皋廣武間。", "仕貧寧自佚，待次復空還。", "壽酒千秋祝，兒衣五綵斑。", "人生此樂少，何事慘離顔。"]'),
('f8272692-7b01-4471-b9f5-a9066a2210d4','泛舟','劉敞','宋','宋诗','song-poetry','','[]','溪流向人急，野色背人偏。',48,'全唐诗/poet.song.27000.json','["溪流向人急，野色背人偏。", "輕浪仍堪鑑，虚舟不費牽。", "柳長勤拂面，鷗戯巧隨船。", "幽興終難盡，禽魚莫間然。"]'),
('dc7b6f92-59b2-43a5-bd0f-1be90291a869','九日對酒二首  其一','劉敞','宋','宋诗','song-poetry','','[]','慘慘霜天迥，紛紛風葉黄。',48,'全唐诗/poet.song.27000.json','["慘慘霜天迥，紛紛風葉黄。", "須傾一樽酒，少浣九回腸。", "世事渾無定，秋容毎自傷。", "登高何必賦，會使鬢毛蒼。"]'),
('ea01df46-c2af-4e0c-bc8b-96db79ee9380','九日對酒二首  其二','劉敞','宋','宋诗','song-poetry','','[]','懰慄看秋盡，差池感歲窮。',48,'全唐诗/poet.song.27000.json','["懰慄看秋盡，差池感歲窮。", "薄寒侵白罽，危葉隕青楓。", "零落茱萸佩，淹留桂樹叢。", "年光不可玩，生意羡冥鴻。"]'),
('4e785069-4a79-4e63-9968-e7c9fa3622ab','對酒憶獻臣二首  其一','劉敞','宋','宋诗','song-poetry','','[]','舉酒惜春盡，緩歌傷别離。',48,'全唐诗/poet.song.27000.json','["舉酒惜春盡，緩歌傷别離。", "江山空發興，雞黍若爲期。", "醉起疑千日，愁來獨五噫。", "皋橋羈旅客，惆悵不同時。"]'),
('62fadc9e-1434-48f7-9883-43fdc242eb28','對酒憶獻臣二首  其二','劉敞','宋','宋诗','song-poetry','','[]','春日懷吾子，羈遊各異方。',48,'全唐诗/poet.song.27000.json','["春日懷吾子，羈遊各異方。", "況逢青眼絕，早識白眉良。", "樹逐相思老，江回去路長。", "感時惟尚寐，終日醉無妨。"]'),
('c85a4400-68c5-4b41-9644-7b451ddd9838','汝陰送揚州通判廣陵高秘丞','劉敞','宋','宋诗','song-poetry','','[]','朱轓垂絲旒，千里下揚州。',48,'全唐诗/poet.song.27000.json','["朱轓垂絲旒，千里下揚州。", "本郡榮何甚，治中望最優。", "高人孫綽貴，節婦孟光尤。", "問俗應賓禮，清風遠鎮浮。"]'),
('63dde46d-342c-4a47-976d-fa026175f35a','新作小橋','劉敞','宋','宋诗','song-poetry','','[]','幽池舊徒涉，春漲得新橋。',48,'全唐诗/poet.song.27000.json','["幽池舊徒涉，春漲得新橋。", "自恨濟川小，欣忘渡水遙。", "中流横螮蝀，别徑會漁樵。", "更愛憑欄處，東風柳萬條。"]'),
('6d2cdba2-a0cc-4211-a01d-0b42b683eb47','五月十一日早行是日風寒如八九月','劉敞','宋','宋诗','song-poetry','','[]','晨興事朝謁，星漢已闌干。',48,'全唐诗/poet.song.27000.json','["晨興事朝謁，星漢已闌干。", "雲薄露猶濕，風高天正寒。", "塵衣先改素，蓬鬢强彈冠。", "興在江湖永，空歌行路難。"]'),
('1ff05b3a-6306-4b05-a5c0-30294473b521','月夜獨飲','劉敞','宋','宋诗','song-poetry','','[]','霜落月更白，雲開天正青。',48,'全唐诗/poet.song.27000.json','["霜落月更白，雲開天正青。", "捲簾邀玉兔，引酒勸天星。", "起舞憑相屬，高歌願共聽。", "春宵誰謂短，罍罄適添缾。"]'),
('823ee827-734f-49a7-aba2-1ee4a50633de','雨中贈徐監簿','劉敞','宋','宋诗','song-poetry','','[]','明闇雲移影，蕭騷雨送涼。',48,'全唐诗/poet.song.27000.json','["明闇雲移影，蕭騷雨送涼。", "遠林寒起霧，清簟潤浮霜。", "小隱交遊絕，微吟杖履妨。", "奕棋還偃几，幽趣亦難忘。"]'),
('2dc03b73-55a2-4bb0-a542-b3907d385529','寄和弟','劉敞','宋','宋诗','song-poetry','','[]','鶺鴿飛砌下，廣莫起寒風。',48,'全唐诗/poet.song.27000.json','["鶺鴿飛砌下，廣莫起寒風。", "感物念游子，賦詩同召公。", "楚歌還落木，淮月更虛弓。", "羈旅傷離别，如何歲亦窮。"]'),
('3c4be988-626f-429e-8c5b-d35d02e4d02d','九日寄因甫','劉敞','宋','宋诗','song-poetry','','[]','遙想登高處，姑蘇秋草多。',48,'全唐诗/poet.song.27000.json','["遙想登高處，姑蘇秋草多。", "那無萬古恨，少作五噫歌。", "野菊蕭蕭晚，江鴻疊疊過。", "尺書不可託，送目奈愁何。"]'),
('2d3adc1b-5d45-4212-b9db-f234df136451','九日登城北門送孫許州','劉敞','宋','宋诗','song-poetry','','[]','紅葉迎霜隕，高樓近日暄。',48,'全唐诗/poet.song.27000.json','["紅葉迎霜隕，高樓近日暄。", "送歸仍暮節，極望正平原。", "容易風吹帽，殷勤菊滿樽。", "豈嫌徑先醉，當識别銷魂。"]'),
('e741f4eb-5faf-4b1a-b79d-d3f0c14c4973','九日','劉敞','宋','宋诗','song-poetry','','[]','采采黄花菊，飄飄閶闔風。',48,'全唐诗/poet.song.27000.json','["采采黄花菊，飄飄閶闔風。", "醉從紗帽落，興與古人同。", "北岳烽烟隔，甘泉侯騎通。", "悲歌傷遠目，不獨爲青楓。"]'),
('589594af-533f-4326-9a8b-4682c419b1a2','閣下紫薇花','劉敞','宋','宋诗','song-poetry','','[]','宫中萬年樹，天上紫薇垣。',48,'全唐诗/poet.song.27000.json','["宫中萬年樹，天上紫薇垣。", "此地飛塵隔，經時絳雪翻。", "幽香通複閣，密影半層軒。", "已後陽春節，無辭白露繁。"]'),
('d5b82b57-e135-458b-be3b-864b77dd8aec','懷襄陽郭戶曹','劉敞','宋','宋诗','song-poetry','','[]','遠身適荆楚，苦掾寄書題。',48,'全唐诗/poet.song.27000.json','["遠身適荆楚，苦掾寄書題。", "他日相思甚，終年引望迷。", "銷憂峴山醉，招隱鹿門樓。", "勿以徒勞故，全家自此攜。"]'),
('895d95db-d4a1-4f26-8176-e48383e16e6b','竹西亭送二十六弟赴定州去年三月亦于此相别即崑岡蒙谷之陽','劉敞','宋','宋诗','song-poetry','','[]','山中招隱地，江上未歸人。',48,'全唐诗/poet.song.27000.json','["山中招隱地，江上未歸人。", "那可連年别，俱逢欲暮春。", "亂飛鶯戀友，北向鴈辭賓。", "自覺雙蓬鬢，蕭蕭日更新。"]'),
('051da968-c16d-4103-9687-9483bb91f44e','送和弟通判陜府','劉敞','宋','宋诗','song-poetry','','[]','丹紱雙紋綬，朱轓左畫輪。',48,'全唐诗/poet.song.27000.json','["丹紱雙紋綬，朱轓左畫輪。", "平生固自負，歸去亦榮親。", "美俗餘分陜，悲歌激在陳。", "别離俱未易，因目二毛新。"]'),
('092dbcf8-7572-492a-911d-d1afce348709','蕭山舍弟將發南都以詩候之','劉敞','宋','宋诗','song-poetry','','[]','聞道雙飛舄，看來萬里流。',48,'全唐诗/poet.song.27000.json','["聞道雙飛舄，看來萬里流。", "傳聲淮口渡，審侯越儂謳。", "霜蟹人人得，春醪盎盎浮。", "襄賁差不惡，須汝共銷憂。"]'),
('bed1182d-09c6-4ffb-91de-0e4e6428ee69','春晴小園偶步','劉敞','宋','宋诗','song-poetry','','[]','弱弱纖纖柳，朱朱白白花。',48,'全唐诗/poet.song.27000.json','["弱弱纖纖柳，朱朱白白花。", "春風最無賴，客鬢亦空華。", "草色明深徑，泉聲落淺沙。", "江楓千里思，醉眼向天涯。"]'),
('270dc485-a6ef-4560-8ef0-09b91187f8ea','寄鹽城舍弟得書言歲大稔兼求作夫子廟記','劉敞','宋','宋诗','song-poetry','','[]','海邑近蟠桃，銅章肯許勞。',48,'全唐诗/poet.song.27000.json','["海邑近蟠桃，銅章肯許勞。", "公田都種秫，霜蟹饜持螯。", "宫廟比洙泗，弦歌通掾曹。", "想多記石柱，非復笑牛刀。"]'),
('f3231a11-a979-465b-8889-97021cf67e74','蟻鬥','劉敞','宋','宋诗','song-poetry','','[]','擾擾嗟何急，營營若有侵。',48,'全唐诗/poet.song.27000.json','["擾擾嗟何急，營營若有侵。", "由來穴知雨，非爾旱爲霖。", "王霸强并弱，興亡古到今。", "願君推達觀，安得異機心。"]'),
('419e42b8-c7e7-4810-bfd2-1aa8ccf1898c','酒後登清風亭','劉敞','宋','宋诗','song-poetry','','[]','清笳轉不極，碧水望偏多。',48,'全唐诗/poet.song.27000.json','["清笳轉不極，碧水望偏多。", "醲酒春先醉，晴陽晚更和。", "起提如意舞，自擊唾壺歌。", "芳樹知多少，春游奈汝何。"]'),
('f84a68a7-e6bb-40b8-b1fc-73f11a9f87d9','同持國過江十新作池亭三首  其一','劉敞','宋','宋诗','song-poetry','','[]','築榭因高柳，疏泉激淺沙。',48,'全唐诗/poet.song.27000.json','["築榭因高柳，疏泉激淺沙。", "登臨容展席，游泛足浮槎。", "露盌涵醇醴，冰盤餉美瓜。", "愛君難興盡，未醉惜還家。"]'),
('29ab7732-13d3-425d-a5db-9b117ed77315','同持國過江十新作池亭三首  其二','劉敞','宋','宋诗','song-poetry','','[]','菡萏千枝發，池塘五月秋。',48,'全唐诗/poet.song.27000.json','["菡萏千枝發，池塘五月秋。", "香繁初過雨，影密欲藏舟。", "魚躍知琴樂，鷗飛爲客留。", "江湖未成往，愧此意悠悠。"]'),
('d8d0353e-e90e-4d7d-878c-33f09b74ea45','同持國過江十新作池亭三首  其三','劉敞','宋','宋诗','song-poetry','','[]','吏隱由來事，郊居故自宜。',48,'全唐诗/poet.song.27000.json','["吏隱由來事，郊居故自宜。", "池臺隨意定，泉石象天爲。", "珍樹移時語，清風竟日棋。", "市朝情久厭，野老不相疑。"]'),
('483e1ead-9195-4130-b5fa-424e70598bd4','寄鳯翔舍弟  其一','劉敞','宋','宋诗','song-poetry','','[]','早悟出處際，同歸羈旅間。',48,'全唐诗/poet.song.27000.json','["早悟出處際，同歸羈旅間。", "從軍差復樂，捧檄莫思還。", "百仞磻溪水，千巖大白山。", "異時曾想見，乘興輒躋攀。"]'),
('4c2b8aeb-8ced-40e3-b32c-480c1b6f9fd3','寄鳯翔舍弟  其二','劉敞','宋','宋诗','song-poetry','','[]','百里異形影，況今殊楚秦。',48,'全唐诗/poet.song.27000.json','["百里異形影，況今殊楚秦。", "隴雲虚引領，江月漫隨人。", "愁恨西山雪，驚心絕塞塵。", "寄書懸勝夢，鴈足莫嫌頻。"]'),
('5843ebee-9076-48de-99e3-48ad1ec6a46a','俞氏甥及第後赴壽春尉立别','劉敞','宋','宋诗','song-poetry','','[]','爾門大父行，俱是雲霄人。',48,'全唐诗/poet.song.27000.json','["爾門大父行，俱是雲霄人。", "諸孫自駿骨，高第復青春。", "試吏小山下，還家芳桂新。", "當成我宅相，寧肯滯埃塵。"]'),
('6212fd38-c605-43c1-8dd5-203fde1dbe65','勸耕亭晚望田家作','劉敞','宋','宋诗','song-poetry','','[]','田廬非一處，微徑自相通。',48,'全唐诗/poet.song.27000.json','["田廬非一處，微徑自相通。", "日下耕釣息，林邊言笑同。", "此雖人問俗，獨有方外風。", "吾亦畢婚嫁，還從擊壤翁。"]'),
('8a83ec64-f3e1-4b09-89ab-dfa59140b873','危樓','劉敞','宋','宋诗','song-poetry','','[]','尚有危樓在，猶傳羽駕歸。',48,'全唐诗/poet.song.27000.json','["尚有危樓在，猶傳羽駕歸。", "悲歌城郭是，故老姓名非。", "積水浮天宇，孤雲遶翠微。", "遠遊悲世俗，思見菊花衣。"]'),
('7d91c250-5286-4192-866c-cfaee152aa42','四望樓二首  其一','劉敞','宋','宋诗','song-poetry','','[]','白露參差晚，丹楓點染深。',48,'全唐诗/poet.song.27000.json','["白露參差晚，丹楓點染深。", "高樓延遠恨，嘶馬動歸心。", "留客小山桂，愁人思婦砧。", "昏鴉稍欲集，塹黑倒城陰。"]'),
('9e11cd34-a43a-454e-b0da-e72eaaa517bf','四望樓二首  其二','劉敞','宋','宋诗','song-poetry','','[]','展步乘幽興，登臨當遠遊。',48,'全唐诗/poet.song.27000.json','["展步乘幽興，登臨當遠遊。", "涼軒不用扇，高樹自知秋。", "月出潮聲湧，雲生岳色浮。", "旅懷雖易失，無奈角聲愁。"]'),
('6de68c66-8d17-49e2-b9c1-ed2e17b4c6fb','中元雨後招兩漕','劉敞','宋','宋诗','song-poetry','','[]','積水吾山溢，輕風汶篠秋。',48,'全唐诗/poet.song.27000.json','["積水吾山溢，輕風汶篠秋。", "微涼禁魯酒，清唱發齊謳。", "小雨何須急，高雲更肯留。", "知公興不淺，能醉月邊樓。"]'),
('69da34c5-08b1-44b3-8e3c-f57fbbb73143','小雨朝歸東軒','劉敞','宋','宋诗','song-poetry','','[]','小雨車馬息，微風窗戶虛。',48,'全唐诗/poet.song.27000.json','["小雨車馬息，微風窗戶虛。", "塵埃頃灑埽，蠅蚋一謳除。", "高枕華胥夢，忘言藏室書。", "不知吾喪我，安更問其餘。"]'),
('75098bf3-085d-43e2-9b3e-6776da33f515','雨中北軒','劉敞','宋','宋诗','song-poetry','','[]','草樹朱明晚，雲霓白日頽。',48,'全唐诗/poet.song.27000.json','["草樹朱明晚，雲霓白日頽。", "幽居誰與適，山鳥獨無猜。", "蠧實危將墮，衰花冷自開。", "秋光殊不意，頓入眼前來。"]'),
('1b30729e-8f77-4de4-9932-2cdbe51815a9','西郊候客','劉敞','宋','宋诗','song-poetry','','[]','西郊逢故人，傾蓋暫相親。',48,'全唐诗/poet.song.27000.json','["西郊逢故人，傾蓋暫相親。", "車馬有行色，衣裳棲洛塵。", "問笻出冉筰，詢道自峨岷。", "卻話别時意，悠然已四春。"]'),
('7f8dfbf4-5401-46c3-ab96-5a4effcec403','中秋月榭飲會','劉敞','宋','宋诗','song-poetry','','[]','清秋望不極，涼月夜還新。',48,'全唐诗/poet.song.27000.json','["清秋望不極，涼月夜還新。", "河漢初無際，山川共絕塵。", "舉杯光可挹，起舞影相親。", "此興何曾淺，風流憶古人。"]'),
('e36c12ba-17e0-4a9d-8269-5a7cc6a12bdc','獨行','劉敞','宋','宋诗','song-poetry','','[]','南山半雲雨，天氣雜暄寒。',48,'全唐诗/poet.song.27000.json','["南山半雲雨，天氣雜暄寒。", "野興宜獨往，春愁無定端。", "鳥聲來静聽，柳色入遙看。", "卻謝芳樽酒，悠悠誰與歡。"]'),
('dce688b8-4fbd-4405-8769-1114b0c5714d','石少傅致仕','劉敞','宋','宋诗','song-poetry','','[]','獨持子房計，欲伴赤松仙。',48,'全唐诗/poet.song.27000.json','["獨持子房計，欲伴赤松仙。", "猶行少傅事，更覺大夫賢。", "詔策容就問，子孫隨拜前。", "顧嫌越相國，遠泛五湖船。"]'),
('37278f9f-7b26-40b5-aa68-82837f462d8b','望沙樓','劉敞','宋','宋诗','song-poetry','','[]','朱軒映粉堞，遙出夕陽中。',48,'全唐诗/poet.song.27000.json','["朱軒映粉堞，遙出夕陽中。", "雲雨通巫峽，江山入楚宫。", "登臨餘壯觀，瀟灑向雄風。", "萬事隨陵谷，滔滔水向東。"]'),
('fa84216d-dfa0-4846-94d1-812ce8844ceb','楊子寺送彦猷閣老去年四月某别彦猷于京師到今適期年矣','劉敞','宋','宋诗','song-poetry','','[]','一年再遠别，塵世令人嗟。',48,'全唐诗/poet.song.27000.json','["一年再遠别，塵世令人嗟。", "況復江湖永，空驚鬢髪華。", "青山浮海上，遠水即天涯。", "出處俱萍泛，懸知後會賖。"]'),
('c82f58a8-9996-4c1d-ab38-615e75d87507','出山','劉敞','宋','宋诗','song-poetry','','[]','萬里亘東西，連峰隱朔陲。',48,'全唐诗/poet.song.27000.json','["萬里亘東西，連峰隱朔陲。", "氣纒冰雪慘，險極鬼神爲。", "偪仄單車度，盤桓壯士悲。", "今朝識天意，正欲限華夷。"]'),
('d8af7b16-6afd-4c9c-8034-bdae9a6ce0c1','陰山','劉敞','宋','宋诗','song-poetry','','[]','陰山天下險，鳥道上稜層。',48,'全唐诗/poet.song.27000.json','["陰山天下險，鳥道上稜層。", "抱石千年樹，懸崖萬丈冰。", "悲歌愁倚劍，側步怯扶繩。", "更覺長安遠，朝光午未升。"]'),
('42ed6da0-f594-463a-9bb6-6b67840c6644','占晴三首  其一','劉敞','宋','宋诗','song-poetry','','[]','小雨何曾濕，輕雲苦易開。',48,'全唐诗/poet.song.27000.json','["小雨何曾濕，輕雲苦易開。", "蛟龍自喣沬，江漢欲飛埃。", "碧草寒仍短，喧禽去不回。", "楚山長對日，未信有陽臺。"]'),
('f3b4acfc-45fb-45d7-9327-c2f99fd519c9','占晴三首  其二','劉敞','宋','宋诗','song-poetry','','[]','白日麗江上，初晴風景饒。',48,'全唐诗/poet.song.27000.json','["白日麗江上，初晴風景饒。", "春愁來集眼，暖氣起連宵。", "曠野蒼茫合，饑鳶上下飄。", "長亭送行處，稍復柳垂條。"]'),
('32be2fe7-4738-4f92-818e-7970e00ca677','占晴三首  其三','劉敞','宋','宋诗','song-poetry','','[]','巫峽空多雨，江南自有春。',48,'全唐诗/poet.song.27000.json','["巫峽空多雨，江南自有春。", "瘴排寒色早，晴發歲華新。", "地暖仍餘濕，風和欲起塵。", "舊傷千里目，巳復覺愁人。"]'),
('674e63f2-7cfe-4b3f-82e7-af689e4131de','登揚州城北門予昔侍親寓居此城下驛舍十八年矣愴然感動','劉敞','宋','宋诗','song-poetry','','[]','昔釣城下水，今來十八年。',48,'全唐诗/poet.song.27000.json','["昔釣城下水，今來十八年。", "居人幾能在，里巷獨依然。", "手種成喬木，躬耕有廢田。", "悲歌顧千騎，不覺涕淪漣。"]'),
('34bde267-6262-4dce-b093-3ffff75cc391','有懷北歸寄張四和弟','劉敞','宋','宋诗','song-poetry','','[]','安得生羽翼，超然成遠遊。',48,'全唐诗/poet.song.27000.json','["安得生羽翼，超然成遠遊。", "探書下禹穴，問禮適東周。", "賢聖有遺迹，江山俱早秋。", "西風日夜急，無事獨淹留。"]'),
('1a8dbab7-096e-4898-b26e-10d3986b28bf','金山寺','劉敞','宋','宋诗','song-poetry','','[]','水面塵土少，山頭炎景微。',48,'全唐诗/poet.song.27000.json','["水面塵土少，山頭炎景微。", "蛟龍能護法，魚鳥各忘機。", "空寂見佛事，幽閒滯客歸。", "蓬萊似咫尺，擬縱海帆飛。"]'),
('e5a68cae-3740-4d34-90aa-d4d17e3f9ea7','送張介歸山中','劉敞','宋','宋诗','song-poetry','','[]','君歸湖上山，寄傲白雲間。',48,'全唐诗/poet.song.27000.json','["君歸湖上山，寄傲白雲間。", "巖樹定未改，春條應可攀。", "曾隨太守薦，近揖上公還。", "知子不貪貴，令人思閉關。"]'),
('583ba501-090d-4bed-b476-094c3907fcdc','寒鴉','劉敞','宋','宋诗','song-poetry','','[]','天清北風厲，日落亂鴉栖。',48,'全唐诗/poet.song.27000.json','["天清北風厲，日落亂鴉栖。", "望遠影如疊，聽長聲漸低。", "月中驚不定，城上暗仍啼。", "出處乘朝夕，應無失旦迷。"]'),
('3107219c-6caf-4b2c-9205-c8b17e2c7e15','舍弟及楊十七尊兄同年登科賀彦文','劉敞','宋','宋诗','song-poetry','','[]','紫禁過從密，青雲步武通。',48,'全唐诗/poet.song.27000.json','["紫禁過從密，青雲步武通。", "文章一朝盛，兄弟兩家同。", "結綬輕蕭育，忘年似孔融。", "相看各相喜，安得恨途窮。"]'),
('65b45fcb-431e-472b-8cf2-72e21f340b93','冬暖','劉敞','宋','宋诗','song-poetry','','[]','南服已卑濕，隆冬方晏温。',48,'全唐诗/poet.song.27000.json','["南服已卑濕，隆冬方晏温。", "夏蟲輕火伏，葛履易霜繁。", "誰復謀吹律，吾真笑負暄。", "爰居或避地，亦慰異鄉魂。"]'),
('e4ef5238-8956-485f-8b8d-31c47c0c48a6','山暖','劉敞','宋','宋诗','song-poetry','','[]','通谷近中原，初陽生舊年。',48,'全唐诗/poet.song.27000.json','["通谷近中原，初陽生舊年。", "欣欣林動色，漠漠野浮烟。", "鳴雉飛朝日，新芽發暖泉。", "東風彊人意，車馬亦翩翩。"]'),
('fed947e7-1067-4366-98a2-f9b80614eddd','銅陵阻風','劉敞','宋','宋诗','song-poetry','','[]','驚浪乘風疾，浮雲映水低。',48,'全唐诗/poet.song.27000.json','["驚浪乘風疾，浮雲映水低。", "卷帆高卧熟，看鷁退飛迷。", "山遠微分樹，村深略辨雞。", "蒹葭縈客恨，極望正萋萋。"]'),
('aa7052cf-5eac-45f7-861c-99e6a073f14f','螳螂','劉敞','宋','宋诗','song-poetry','','[]','玄蟬無所營，風露正淒清。',48,'全唐诗/poet.song.27000.json','["玄蟬無所營，風露正淒清。", "執翳機何密，當車勇自輕。", "将迷黄雀患，已變玉琴聲。", "得喪還相召，南華所以驚。"]'),
('01a69e2e-1485-49f6-971a-390f86d4808d','雨中入省','劉敞','宋','宋诗','song-poetry','','[]','簡書無暇日，風雨送殘秋。',48,'全唐诗/poet.song.27000.json','["簡書無暇日，風雨送殘秋。", "車馬常侵旦，泥塗空自愁。", "平生本迂拙，歲暮强淹留。", "會将投劾去，偃息謝交游。"]'),
('6933bbc2-f788-4ff1-837d-6a75492e287c','旅居雨中','劉敞','宋','宋诗','song-poetry','','[]','塵垢厭淟涊，風雨爲驅除。',48,'全唐诗/poet.song.27000.json','["塵垢厭淟涊，風雨爲驅除。", "稍稍煩襟盡，蕭蕭秋氣初。", "堪憂忘陋巷，匡坐讀羣書。", "半夜梁山操，悲歌問起予。"]'),
('69381680-ee58-4a3f-a711-680a3217a7e5','雨中','劉敞','宋','宋诗','song-poetry','','[]','蕭蕭過軒雨，物色送春歸。',48,'全唐诗/poet.song.27000.json','["蕭蕭過軒雨，物色送春歸。", "樹綠初成蓋，垣青半長衣。", "吟懷空擾擾，愁思動依依。", "想似江南景，草長鶯亂飛。"]'),
('64f7b567-69e9-4ea6-ba3c-e488da3bab89','北窗聞雨','劉敞','宋','宋诗','song-poetry','','[]','泄雲霏棟宇，危葉墮霜枝。',48,'全唐诗/poet.song.27000.json','["泄雲霏棟宇，危葉墮霜枝。", "忽忽時空晚，蕭蕭坐自悲。", "竟無高枕興，還有閉關宜。", "生事安蓬藋，商歌恣所爲。"]'),
('9b1bcd10-0fa6-4c2f-b2e3-215a5c2f85b3','送因甫宰湘鄉','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','相思恨不見，今子去長沙。',48,'全唐诗/poet.song.27000.json','["相思恨不見，今子去長沙。", "幸有國百里，可憐天一涯。", "春風洞庭水，殊俗楚人家。", "回首傷卑濕，知君髪易華。"]');
